window.COURSE_REGISTRY["c10-exam"] = [
  {"id":1,"sec":"Planning & Estimation","block":1,"q":"A 120 V circuit supplies a heating element with a resistance of 20 ohms; what is the current draw?","opts":["2 A","0.17 A","6 A","2400 A"],"correct":2,"re":"By Ohm's law, I = V/R = 120/20 = 6 A.","qr":"Цепь 120 В питает нагревательный элемент сопротивлением 20 Ом; какой ток потребляется?","optsr":["2 А","0,17 А","6 А","2400 А"],"rr":"По закону Ома, I = V/R = 120/20 = 6 А.","qs":"Un circuito de 120 V alimenta un elemento calefactor con una resistencia de 20 ohmios; ¿cuál es el consumo de corriente?","optss":["2 A","0.17 A","6 A","2400 A"],"rs":"Por la ley de Ohm, I = V/R = 120/20 = 6 A."},
  {"id":2,"sec":"Rough Wiring","block":1,"q":"Which conductor insulation type is rated 90°C in dry locations but is NOT approved for use in wet locations?","opts":["THWN-2","THHN","XHHW-2","USE-2"],"correct":1,"re":"THHN is a 90°C dry/damp-location insulation; for wet locations THWN-2 or XHHW-2 is used. See NEC Table 310.4(A).","qr":"Какой тип изоляции проводника рассчитан на 90°C в сухих помещениях, но НЕ разрешён для применения во влажных местах?","optsr":["THWN-2","THHN","XHHW-2","USE-2"],"rr":"THHN — это изоляция на 90°C для сухих/слегка влажных мест; для влажных мест используют THWN-2 или XHHW-2. См. NEC Table 310.4(A).","qs":"¿Qué tipo de aislamiento de conductor está clasificado para 90°C en lugares secos pero NO está aprobado para uso en lugares mojados?","optss":["THWN-2","THHN","XHHW-2","USE-2"],"rs":"THHN es un aislamiento de 90°C para lugares secos/húmedos; para lugares mojados se usa THWN-2 o XHHW-2. Véase NEC Table 310.4(A)."},
  {"id":3,"sec":"Finish Wiring & Trim","block":1,"q":"In a dwelling unit habitable room, what is the maximum horizontal distance from any point along the wall line to a receptacle outlet?","opts":["3 feet","12 feet","10 feet","6 feet"],"correct":3,"re":"NEC 210.52(A) requires that no point along the floor line of a wall be more than 6 ft from a receptacle, so that an appliance cord of 6 ft can reach an outlet from either direction.","qr":"В жилом помещении, какое максимальное горизонтальное расстояние от любой точки вдоль линии стены до розетки?","optsr":["3 фута","12 футов","10 футов","6 футов"],"rr":"NEC 210.52(A) требует, чтобы ни одна точка вдоль линии пола стены не находилась далее 6 футов от розетки, чтобы шнур прибора длиной 6 футов мог дотянуться до розетки с любой стороны.","qs":"En una habitación habitable de una unidad de vivienda, ¿cuál es la distancia horizontal máxima desde cualquier punto a lo largo de la línea de pared hasta una salida de tomacorriente?","optss":["3 pies","12 pies","10 pies","6 pies"],"rs":"NEC 210.52(A) requiere que ningún punto a lo largo de la línea del piso de una pared esté a más de 6 ft de un tomacorriente, de modo que un cordón de electrodoméstico de 6 ft pueda alcanzar una salida desde cualquier dirección."},
  {"id":4,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"Per NEC 430.22, what is the minimum branch-circuit conductor ampacity required for a single continuous-duty motor with a full-load current of 28 amps?","opts":["28 amps","31 amps","40 amps","35 amps"],"correct":3,"re":"NEC 430.22 requires branch-circuit conductors for a single motor to have an ampacity of at least 125% of the motor full-load current: 28 A x 1.25 = 35 A.","qr":"Согласно NEC 430.22, какая минимальная допустимая токовая нагрузка проводника ответвления требуется для одного двигателя длительного режима с током полной нагрузки 28 ампер?","optsr":["28 ампер","31 ампер","40 ампер","35 ампер"],"rr":"NEC 430.22 требует, чтобы проводники ответвления для одного двигателя имели допустимую токовую нагрузку не менее 125% от тока полной нагрузки двигателя: 28 А x 1.25 = 35 А.","qs":"Según NEC 430.22, ¿cuál es la ampacidad mínima del conductor del circuito ramal requerida para un solo motor de servicio continuo con una corriente a plena carga de 28 amperios?","optss":["28 amperios","31 amperios","40 amperios","35 amperios"],"rs":"NEC 430.22 requiere que los conductores del circuito ramal para un solo motor tengan una ampacidad de al menos el 125% de la corriente a plena carga del motor: 28 A x 1.25 = 35 A."},
  {"id":5,"sec":"Safety","block":1,"q":"Under Cal/OSHA Title 8 Section 3314, what is the primary purpose of a lockout/tagout procedure?","opts":["To control hazardous energy so equipment cannot be unexpectedly energized or started during service or maintenance","To document the qualifications of each electrician on the job site","To reduce the available fault current at the equipment terminals","To provide a backup ground path for the electrical system"],"correct":0,"re":"Cal/OSHA T8 Section 3314 requires control of hazardous energy through lockout/tagout so machines or equipment are isolated and cannot start up unexpectedly during servicing.","qr":"Согласно разделу 3314 Title 8 Cal/OSHA, какова основная цель процедуры lockout/tagout (LOTO)?","optsr":["Контролировать опасную энергию, чтобы оборудование не могло неожиданно получить питание или запуститься во время обслуживания или ремонта","Документировать квалификацию каждого электрика на объекте","Снизить доступный ток короткого замыкания на клеммах оборудования","Обеспечить резервный путь заземления для электрической системы"],"rr":"Раздел 3314 Title 8 Cal/OSHA требует контроля опасной энергии посредством lockout/tagout, чтобы оборудование было изолировано и не могло неожиданно запуститься во время обслуживания.","qs":"Según Cal/OSHA Title 8 Section 3314, ¿cuál es el propósito principal de un procedimiento de bloqueo/etiquetado (lockout/tagout)?","optss":["Controlar la energía peligrosa para que el equipo no pueda ser energizado o arrancado de forma inesperada durante el servicio o mantenimiento","Documentar las calificaciones de cada electricista en el sitio de trabajo","Reducir la corriente de falla disponible en las terminales del equipo","Proporcionar una trayectoria de tierra de respaldo para el sistema eléctrico"],"rs":"Cal/OSHA T8 Section 3314 requiere el control de la energía peligrosa mediante bloqueo/etiquetado para que las máquinas o equipos queden aislados y no puedan arrancar de forma inesperada durante el servicio."},
  {"id":6,"sec":"Rough Wiring","block":1,"q":"What does the 'W' in the conductor insulation designation THWN-2 indicate?","opts":["Wound (stranded) construction","Wire is solid","White color coding","Suitable for wet locations"],"correct":3,"re":"In NEC insulation lettering, 'W' means the conductor is rated for wet locations. See NEC Table 310.4(A) and Annex.","qr":"Что обозначает буква 'W' в маркировке изоляции проводника THWN-2?","optsr":["Многопроволочная (скрученная) конструкция","Провод одножильный","Белая цветовая маркировка","Пригоден для влажных мест"],"rr":"В буквенной маркировке изоляции NEC буква 'W' означает, что проводник рассчитан на влажные места. См. NEC Table 310.4(A).","qs":"¿Qué indica la 'W' en la designación de aislamiento de conductor THWN-2?","optss":["Construcción trenzada (cableada)","El alambre es sólido","Codificación de color blanco","Apto para lugares mojados"],"rs":"En la nomenclatura de aislamiento del NEC, la 'W' significa que el conductor está clasificado para lugares mojados. Véase NEC Table 310.4(A) y su Anexo."},
  {"id":7,"sec":"Planning & Estimation","block":1,"q":"What is the power dissipated by a 240 V appliance that draws 12.5 A?","opts":["3000 W","19.2 W","252.5 W","1920 W"],"correct":0,"re":"Using P = V x I = 240 x 12.5 = 3000 W.","qr":"Какую мощность рассеивает прибор на 240 В, потребляющий 12,5 А?","optsr":["3000 Вт","19,2 Вт","252,5 Вт","1920 Вт"],"rr":"По формуле P = V x I = 240 x 12,5 = 3000 Вт.","qs":"¿Cuál es la potencia disipada por un electrodoméstico de 240 V que consume 12.5 A?","optss":["3000 W","19.2 W","252.5 W","1920 W"],"rs":"Usando P = V x I = 240 x 12.5 = 3000 W."},
  {"id":8,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"When sizing branch-circuit conductors for a single motor under NEC 430.22, which value should be used as the basis for the calculation?","opts":["The full-load current value from the NEC tables","The full-load current from the motor nameplate","The locked-rotor current of the motor","The service-factor amperage stamped on the nameplate"],"correct":0,"re":"NEC 430.6(A) specifies that conductor and overcurrent device sizing per 430.22 is based on the table values (such as Table 430.248/430.250), not the nameplate FLA.","qr":"При выборе проводников ответвления для одного двигателя согласно NEC 430.22 какое значение следует использовать как основу для расчёта?","optsr":["Значение тока полной нагрузки из таблиц NEC","Ток полной нагрузки с заводской таблички двигателя","Ток заторможенного ротора двигателя","Ток сервис-фактора, указанный на табличке"],"rr":"NEC 430.6(A) указывает, что выбор проводника и устройства защиты по 430.22 основан на табличных значениях (таблицы 430.248/430.250), а не на токе FLA с таблички.","qs":"Al dimensionar los conductores del circuito ramal para un solo motor según NEC 430.22, ¿qué valor debe usarse como base para el cálculo?","optss":["El valor de corriente a plena carga de las tablas del NEC","La corriente a plena carga de la placa de identificación del motor","La corriente a rotor bloqueado del motor","El amperaje del factor de servicio estampado en la placa de identificación"],"rs":"NEC 430.6(A) especifica que el dimensionamiento del conductor y del dispositivo de sobrecorriente según 430.22 se basa en los valores de las tablas (como Table 430.248/430.250), no en la FLA de la placa de identificación."},
  {"id":9,"sec":"Safety","block":1,"q":"According to NFPA 70E, what is the general rule regarding working on electrical equipment?","opts":["Equipment must be placed in an electrically safe work condition (de-energized) unless de-energizing introduces additional hazards or is infeasible","Equipment may stay energized as long as a second worker is present","Equipment must remain energized so voltage can be verified at all times","Energized work is always acceptable if rubber gloves are worn"],"correct":0,"re":"NFPA 70E requires establishing an electrically safe work condition before work begins; energized work is only permitted when de-energizing introduces additional or increased hazards or is infeasible due to equipment design or operational limitations.","qr":"Согласно NFPA 70E, каково общее правило относительно работы на электрооборудовании?","optsr":["Оборудование должно быть приведено в электробезопасное рабочее состояние (обесточено), если только обесточивание не создаёт дополнительных опасностей или невыполнимо","Оборудование может оставаться под напряжением, пока присутствует второй работник","Оборудование должно оставаться под напряжением, чтобы напряжение можно было проверять в любое время","Работа под напряжением всегда допустима, если надеты резиновые перчатки"],"rr":"NFPA 70E требует создания электробезопасного рабочего состояния до начала работы; работа под напряжением допускается только когда обесточивание создаёт дополнительные или повышенные опасности либо невыполнимо из-за конструкции оборудования или эксплуатационных ограничений.","qs":"De acuerdo con NFPA 70E, ¿cuál es la regla general respecto al trabajo en equipos eléctricos?","optss":["El equipo debe colocarse en una condición de trabajo eléctricamente segura (desenergizado) a menos que desenergizarlo introduzca peligros adicionales o sea inviable","El equipo puede permanecer energizado siempre que haya un segundo trabajador presente","El equipo debe permanecer energizado para poder verificar el voltaje en todo momento","El trabajo energizado siempre es aceptable si se usan guantes de goma"],"rs":"NFPA 70E requiere establecer una condición de trabajo eléctricamente segura antes de iniciar el trabajo; el trabajo energizado solo se permite cuando desenergizar introduce peligros adicionales o mayores, o es inviable debido al diseño del equipo o a limitaciones operativas."},
  {"id":10,"sec":"Rough Wiring","block":1,"q":"Which insulation type is specifically intended for underground service-entrance use and is suitable for direct burial?","opts":["THHN","USE","RHW","TW"],"correct":1,"re":"USE (Underground Service Entrance) is rated for direct burial and underground use. See NEC Table 310.4(A).","qr":"Какой тип изоляции специально предназначен для подземного ввода и пригоден для прямой укладки в грунт?","optsr":["THHN","USE","RHW","TW"],"rr":"USE (Underground Service Entrance) рассчитан на прямую укладку в грунт и подземное применение. См. NEC Table 310.4(A).","qs":"¿Qué tipo de aislamiento está destinado específicamente para uso en acometida subterránea y es apto para enterramiento directo?","optss":["THHN","USE","RHW","TW"],"rs":"USE (Underground Service Entrance) está clasificado para enterramiento directo y uso subterráneo. Véase NEC Table 310.4(A)."},
  {"id":11,"sec":"Planning & Estimation","block":1,"q":"A resistor of 8 ohms carries a current of 5 A; how much power does it dissipate?","opts":["200 W","40 W","1.6 W","320 W"],"correct":0,"re":"Using P = I squared x R = 5 squared x 8 = 25 x 8 = 200 W.","qr":"Резистор 8 Ом проводит ток 5 А; какую мощность он рассеивает?","optsr":["200 Вт","40 Вт","1,6 Вт","320 Вт"],"rr":"По формуле P = I в квадрате x R = 5 в квадрате x 8 = 25 x 8 = 200 Вт.","qs":"Una resistencia de 8 ohmios conduce una corriente de 5 A; ¿cuánta potencia disipa?","optss":["200 W","40 W","1.6 W","320 W"],"rs":"Usando P = I al cuadrado x R = 5 al cuadrado x 8 = 25 x 8 = 200 W."},
  {"id":12,"sec":"Finish Wiring & Trim","block":1,"q":"Under the dwelling receptacle spacing rule, what is the maximum spacing permitted between adjacent general-use receptacles along a wall?","opts":["6 feet","20 feet","15 feet","12 feet"],"correct":3,"re":"Because no point may be more than 6 ft from a receptacle, receptacles spaced evenly along a wall may be up to 12 ft apart (6 ft reach from each), per NEC 210.52(A).","qr":"Согласно правилу размещения розеток в жилье, какое максимальное расстояние допускается между соседними розетками общего назначения вдоль стены?","optsr":["6 футов","20 футов","15 футов","12 футов"],"rr":"Поскольку ни одна точка не может находиться далее 6 футов от розетки, розетки, равномерно расположенные вдоль стены, могут отстоять друг от друга до 12 футов (по 6 футов с каждой стороны), согласно NEC 210.52(A).","qs":"Según la regla de espaciamiento de tomacorrientes en viviendas, ¿cuál es el espaciamiento máximo permitido entre tomacorrientes de uso general adyacentes a lo largo de una pared?","optss":["6 pies","20 pies","15 pies","12 pies"],"rs":"Debido a que ningún punto puede estar a más de 6 ft de un tomacorriente, los tomacorrientes espaciados uniformemente a lo largo de una pared pueden estar separados hasta 12 ft (alcance de 6 ft desde cada uno), según NEC 210.52(A)."},
  {"id":13,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"A three-phase continuous-duty motor has a full-load current of 80 amps; what is the minimum branch-circuit conductor ampacity required by NEC 430.22?","opts":["100 amps","92 amps","80 amps","125 amps"],"correct":0,"re":"NEC 430.22 requires 125% of the motor FLC: 80 A x 1.25 = 100 A minimum conductor ampacity.","qr":"Трёхфазный двигатель длительного режима имеет ток полной нагрузки 80 ампер; какая минимальная допустимая токовая нагрузка проводника ответвления требуется по NEC 430.22?","optsr":["100 ампер","92 ампера","80 ампер","125 ампер"],"rr":"NEC 430.22 требует 125% от тока полной нагрузки двигателя: 80 А x 1.25 = 100 А минимальная допустимая токовая нагрузка проводника.","qs":"Un motor trifásico de servicio continuo tiene una corriente a plena carga de 80 amperios; ¿cuál es la ampacidad mínima del conductor del circuito ramal requerida por NEC 430.22?","optss":["100 amperios","92 amperios","80 amperios","125 amperios"],"rs":"NEC 430.22 requiere el 125% de la FLC del motor: 80 A x 1.25 = 100 A de ampacidad mínima del conductor."},
  {"id":14,"sec":"Safety","block":1,"q":"Which procedure is used to verify that a circuit is de-energized before a qualified person begins work?","opts":["The live-dead-live (test-before-touch) method using an adequately rated voltage tester","Confirming the utility meter has stopped spinning","Visual inspection of the panel labels only","Touching the conductor briefly with the back of the hand"],"correct":0,"re":"The live-dead-live method requires testing the voltage tester on a known live source, testing the de-energized conductors, then re-testing on the known live source to confirm the tester still works, verifying the absence of voltage.","qr":"Какая процедура используется для проверки того, что цепь обесточена, прежде чем квалифицированный специалист начнёт работу?","optsr":["Метод live-dead-live (проверка перед прикосновением) с использованием детектора напряжения соответствующего класса","Подтверждение того, что счётчик коммунальной службы перестал вращаться","Только визуальный осмотр маркировки щита","Кратковременное прикосновение тыльной стороной ладони к проводнику"],"rr":"Метод live-dead-live требует проверки детектора напряжения на заведомо живом источнике, проверки обесточенных проводников, а затем повторной проверки на заведомо живом источнике для подтверждения работоспособности прибора, что подтверждает отсутствие напряжения.","qs":"¿Qué procedimiento se utiliza para verificar que un circuito está desenergizado antes de que una persona calificada comience a trabajar?","optss":["El método vivo-muerto-vivo (probar antes de tocar) usando un comprobador de voltaje con clasificación adecuada","Confirmar que el medidor de la empresa de servicios dejó de girar","Inspección visual únicamente de las etiquetas del tablero","Tocar brevemente el conductor con el dorso de la mano"],"rs":"El método vivo-muerto-vivo requiere probar el comprobador de voltaje en una fuente viva conocida, probar los conductores desenergizados y luego volver a probar en la fuente viva conocida para confirmar que el comprobador sigue funcionando, verificando la ausencia de voltaje."},
  {"id":15,"sec":"Rough Wiring","block":1,"q":"RHW insulation is rated for which maximum operating temperature?","opts":["75°C","90°C","60°C","105°C"],"correct":0,"re":"RHW is a thermoset insulation rated 75°C for wet and dry locations. See NEC Table 310.4(A).","qr":"На какую максимальную рабочую температуру рассчитана изоляция RHW?","optsr":["75°C","90°C","60°C","105°C"],"rr":"RHW — термореактивная изоляция, рассчитанная на 75°C для влажных и сухих мест. См. NEC Table 310.4(A).","qs":"¿Para qué temperatura máxima de operación está clasificado el aislamiento RHW?","optss":["75°C","90°C","60°C","105°C"],"rs":"RHW es un aislamiento termoestable clasificado para 75°C en lugares mojados y secos. Véase NEC Table 310.4(A)."},
  {"id":16,"sec":"Planning & Estimation","block":1,"q":"A 120 V source is connected across a 60 ohm resistor; what power is dissipated?","opts":["2 W","7200 W","240 W","120 W"],"correct":2,"re":"Using P = V squared / R = 120 squared / 60 = 14400 / 60 = 240 W.","qr":"Источник 120 В подключён к резистору 60 Ом; какая мощность рассеивается?","optsr":["2 Вт","7200 Вт","240 Вт","120 Вт"],"rr":"По формуле P = V в квадрате / R = 120 в квадрате / 60 = 14400 / 60 = 240 Вт.","qs":"Una fuente de 120 V está conectada a través de una resistencia de 60 ohmios; ¿qué potencia se disipa?","optss":["2 W","7200 W","240 W","120 W"],"rs":"Usando P = V al cuadrado / R = 120 al cuadrado / 60 = 14400 / 60 = 240 W."},
  {"id":17,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"For a continuous-duty motor with a marked service factor of 1.15, what percentage of the motor nameplate full-load current is used to size the separate overload protection per NEC 430.32?","opts":["125%","115%","140%","250%"],"correct":0,"re":"NEC 430.32(A)(1) permits overload protection at 125% of nameplate FLA when the service factor is 1.15 or greater (or the temperature rise is 40°C or less).","qr":"Для двигателя длительного режима с указанным сервис-фактором 1.15 какой процент от тока полной нагрузки с таблички двигателя используется для выбора отдельной защиты от перегрузки по NEC 430.32?","optsr":["125%","115%","140%","250%"],"rr":"NEC 430.32(A)(1) допускает защиту от перегрузки на уровне 125% от FLA с таблички, когда сервис-фактор составляет 1.15 или более (или превышение температуры 40°C или менее).","qs":"Para un motor de servicio continuo con un factor de servicio marcado de 1.15, ¿qué porcentaje de la corriente a plena carga de la placa de identificación del motor se usa para dimensionar la protección de sobrecarga separada según NEC 430.32?","optss":["125%","115%","140%","250%"],"rs":"NEC 430.32(A)(1) permite la protección de sobrecarga al 125% de la FLA de la placa de identificación cuando el factor de servicio es 1.15 o mayor (o el aumento de temperatura es de 40°C o menos)."},
  {"id":18,"sec":"Safety","block":1,"q":"Per NFPA 70E, which boundary may only be crossed by a qualified person using appropriate shock PPE?","opts":["The arc-flash boundary for unqualified observers","The limited approach boundary for escorted visitors","The restricted approach boundary","The outer property fence line"],"correct":2,"re":"Under NFPA 70E, the restricted approach boundary may be crossed only by a qualified person who has a documented plan and is using appropriate shock-protection PPE because of the increased risk of contact with energized parts.","qr":"Согласно NFPA 70E, какую границу может пересекать только квалифицированный специалист с использованием соответствующих СИЗ от поражения током?","optsr":["Границу дугового разряда для неквалифицированных наблюдателей","Границу limited approach для сопровождаемых посетителей","Ограниченную границу приближения (restricted approach boundary)","Внешнюю границу ограждения территории"],"rr":"Согласно NFPA 70E, restricted approach boundary может пересекать только квалифицированный специалист, имеющий документированный план и использующий соответствующие СИЗ от поражения током из-за повышенного риска контакта с частями под напряжением.","qs":"Según NFPA 70E, ¿qué límite solo puede ser cruzado por una persona calificada que use el EPP de protección contra descargas apropiado?","optss":["El límite de arco eléctrico para observadores no calificados","El límite de aproximación limitada para visitantes escoltados","El límite de aproximación restringida","La cerca perimetral exterior de la propiedad"],"rs":"Según NFPA 70E, el límite de aproximación restringida solo puede ser cruzado por una persona calificada que tenga un plan documentado y use el EPP de protección contra descargas apropiado, debido al mayor riesgo de contacto con partes energizadas."},
  {"id":19,"sec":"Rough Wiring","block":1,"q":"XHHW is a thermoset insulation; what is its temperature rating in a dry location?","opts":["60°C","75°C","110°C","90°C"],"correct":3,"re":"XHHW is rated 90°C in dry/damp locations (and 75°C in wet locations). See NEC Table 310.4(A).","qr":"XHHW — это термореактивная изоляция; на какую температуру она рассчитана в сухом помещении?","optsr":["60°C","75°C","110°C","90°C"],"rr":"XHHW рассчитана на 90°C в сухих/слегка влажных местах (и 75°C во влажных). См. NEC Table 310.4(A).","qs":"XHHW es un aislamiento termoestable; ¿cuál es su clasificación de temperatura en un lugar seco?","optss":["60°C","75°C","110°C","90°C"],"rs":"XHHW está clasificado para 90°C en lugares secos/húmedos (y 75°C en lugares mojados). Véase NEC Table 310.4(A)."},
  {"id":20,"sec":"Planning & Estimation","block":1,"q":"Three resistors of 10 ohms, 15 ohms, and 25 ohms are connected in series; what is the total resistance?","opts":["4.84 ohms","5 ohms","50 ohms","3750 ohms"],"correct":2,"re":"Series resistances add: 10 + 15 + 25 = 50 ohms.","qr":"Три резистора 10 Ом, 15 Ом и 25 Ом соединены последовательно; каково общее сопротивление?","optsr":["4,84 Ом","5 Ом","50 Ом","3750 Ом"],"rr":"Последовательные сопротивления складываются: 10 + 15 + 25 = 50 Ом.","qs":"Tres resistencias de 10 ohmios, 15 ohmios y 25 ohmios se conectan en serie; ¿cuál es la resistencia total?","optss":["4.84 ohmios","5 ohmios","50 ohmios","3750 ohmios"],"rs":"Las resistencias en serie se suman: 10 + 15 + 25 = 50 ohmios."},
  {"id":21,"sec":"Finish Wiring & Trim","block":1,"q":"For the purpose of dwelling receptacle spacing, any wall space how wide or wider must be provided with a receptacle outlet?","opts":["12 inches (1 ft) or wider","24 inches (2 ft) or wider","18 inches or wider","36 inches (3 ft) or wider"],"correct":1,"re":"NEC 210.52(A)(2) defines a wall space that must be counted as any space 2 ft (600 mm) or more in width, including space measured around corners.","qr":"Для целей размещения розеток в жилье, любое пространство стены какой ширины или шире должно быть оборудовано розеткой?","optsr":["12 дюймов (1 фут) или шире","24 дюйма (2 фута) или шире","18 дюймов или шире","36 дюймов (3 фута) или шире"],"rr":"NEC 210.52(A)(2) определяет пространство стены, которое должно учитываться, как любое пространство шириной 2 фута (600 мм) или более, включая пространство, измеренное вокруг углов.","qs":"Para los fines del espaciamiento de tomacorrientes en viviendas, ¿de qué ancho o mayor debe ser cualquier espacio de pared para que se le deba proveer una salida de tomacorriente?","optss":["12 pulgadas (1 ft) o más ancho","24 pulgadas (2 ft) o más ancho","18 pulgadas o más ancho","36 pulgadas (3 ft) o más ancho"],"rs":"NEC 210.52(A)(2) define un espacio de pared que debe contarse como cualquier espacio de 2 ft (600 mm) o más de ancho, incluido el espacio medido alrededor de las esquinas."},
  {"id":22,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"A continuous-duty motor has a service factor of 1.0 and a temperature rise of 50°C; what percentage of nameplate full-load current is allowed for sizing its overload protection under NEC 430.32?","opts":["100%","130%","125%","115%"],"correct":3,"re":"NEC 430.32(A)(1) limits overload protection to 115% of nameplate FLA for motors that do not have a service factor of 1.15+ or a temperature rise of 40°C or less.","qr":"Двигатель длительного режима имеет сервис-фактор 1.0 и превышение температуры 50°C; какой процент от тока полной нагрузки с таблички разрешён для выбора его защиты от перегрузки согласно NEC 430.32?","optsr":["100%","130%","125%","115%"],"rr":"NEC 430.32(A)(1) ограничивает защиту от перегрузки до 115% от FLA с таблички для двигателей, которые не имеют сервис-фактора 1.15+ или превышения температуры 40°C или менее.","qs":"Un motor de servicio continuo tiene un factor de servicio de 1.0 y un aumento de temperatura de 50°C; ¿qué porcentaje de la corriente a plena carga de la placa de identificación se permite para dimensionar su protección de sobrecarga según NEC 430.32?","optss":["100%","130%","125%","115%"],"rs":"NEC 430.32(A)(1) limita la protección de sobrecarga al 115% de la FLA de la placa de identificación para motores que no tienen un factor de servicio de 1.15+ ni un aumento de temperatura de 40°C o menos."},
  {"id":23,"sec":"Rough Wiring","block":1,"q":"A run requires conductors in a conduit that will be installed in a continuously wet underground location; which insulation is appropriate?","opts":["THWN-2","TW only","THHN only","RHH"],"correct":0,"re":"THWN-2 carries a 'W' rating and is suitable for wet locations; THHN, TW (60°C), and RHH (dry) are less appropriate here. See NEC Table 310.4(A).","qr":"Для трассы нужны проводники в трубе, прокладываемой в постоянно влажном подземном месте; какая изоляция подходит?","optsr":["THWN-2","Только TW","Только THHN","RHH"],"rr":"THWN-2 имеет маркировку 'W' и пригоден для влажных мест; THHN, TW (60°C) и RHH (сухие) здесь подходят хуже. См. NEC Table 310.4(A).","qs":"Un tendido requiere conductores en un conduit que se instalará en un lugar subterráneo continuamente mojado; ¿qué aislamiento es apropiado?","optss":["THWN-2","Solo TW","Solo THHN","RHH"],"rs":"THWN-2 lleva clasificación 'W' y es apto para lugares mojados; THHN, TW (60°C) y RHH (seco) son menos apropiados aquí. Véase NEC Table 310.4(A)."},
  {"id":24,"sec":"Safety","block":1,"q":"What document is required by NFPA 70E before performing justified energized work inside the restricted approach or arc-flash boundary?","opts":["A material safety data sheet","A building occupancy certificate","An energized electrical work permit","A load calculation worksheet"],"correct":2,"re":"NFPA 70E requires an energized electrical work permit, signed by authorized management, when work is performed inside the restricted approach boundary or where an arc-flash hazard exists and the work cannot be done de-energized.","qr":"Какой документ требуется по NFPA 70E перед выполнением обоснованной работы под напряжением внутри restricted approach или границы дугового разряда?","optsr":["Паспорт безопасности материала (MSDS)","Сертификат о вводе здания в эксплуатацию","Разрешение на электрические работы под напряжением (energized electrical work permit)","Лист расчёта нагрузки"],"rr":"NFPA 70E требует разрешения на электрические работы под напряжением, подписанного уполномоченным руководством, когда работа выполняется внутри restricted approach boundary или там, где существует опасность дугового разряда и работа не может быть выполнена в обесточенном состоянии.","qs":"¿Qué documento requiere NFPA 70E antes de realizar trabajo energizado justificado dentro del límite de aproximación restringida o de arco eléctrico?","optss":["Una hoja de datos de seguridad de materiales","Un certificado de ocupación del edificio","Un permiso de trabajo eléctrico energizado","Una hoja de cálculo de carga"],"rs":"NFPA 70E requiere un permiso de trabajo eléctrico energizado, firmado por la gerencia autorizada, cuando el trabajo se realiza dentro del límite de aproximación restringida o donde existe un peligro de arco eléctrico y el trabajo no puede realizarse desenergizado."},
  {"id":25,"sec":"Planning & Estimation","block":1,"q":"Two 20 ohm resistors are connected in parallel; what is the equivalent resistance?","opts":["40 ohms","10 ohms","20 ohms","0.1 ohms"],"correct":1,"re":"For two equal parallel resistors, R = R/2 = 20/2 = 10 ohms.","qr":"Два резистора по 20 Ом соединены параллельно; каково эквивалентное сопротивление?","optsr":["40 Ом","10 Ом","20 Ом","0,1 Ом"],"rr":"Для двух равных параллельных резисторов R = R/2 = 20/2 = 10 Ом.","qs":"Dos resistencias de 20 ohmios se conectan en paralelo; ¿cuál es la resistencia equivalente?","optss":["40 ohmios","10 ohmios","20 ohmios","0.1 ohmios"],"rs":"Para dos resistencias iguales en paralelo, R = R/2 = 20/2 = 10 ohmios."},
  {"id":26,"sec":"Rough Wiring","block":1,"q":"Compared to copper, an aluminum conductor of the same AWG size generally has which characteristic?","opts":["Higher ampacity","No listed ampacity","Identical ampacity","Lower ampacity"],"correct":3,"re":"Aluminum has higher resistivity than copper, so an equal-size aluminum conductor has a lower ampacity. See NEC Table 310.16.","qr":"По сравнению с медью, алюминиевый проводник того же размера AWG, как правило, имеет какую характеристику?","optsr":["Большую допустимую нагрузку (ampacity)","Не имеет указанной нагрузки","Одинаковую допустимую нагрузку","Меньшую допустимую нагрузку (ampacity)"],"rr":"Алюминий имеет большее удельное сопротивление, чем медь, поэтому алюминиевый проводник того же размера имеет меньшую ampacity. См. NEC Table 310.16.","qs":"En comparación con el cobre, un conductor de aluminio del mismo tamaño AWG generalmente tiene ¿cuál característica?","optss":["Mayor ampacidad","Sin ampacidad especificada","Ampacidad idéntica","Menor ampacidad"],"rs":"El aluminio tiene mayor resistividad que el cobre, por lo que un conductor de aluminio del mismo tamaño tiene una ampacidad menor. Véase NEC Table 310.16."},
  {"id":27,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"A motor nameplate lists 16 amps full-load current and a service factor of 1.25; what is the maximum overload protection setting permitted by NEC 430.32?","opts":["16 amps","20 amps","18.4 amps","24 amps"],"correct":1,"re":"With a service factor of 1.15 or more, NEC 430.32(A)(1) allows 125% of nameplate FLA: 16 A x 1.25 = 20 A.","qr":"На табличке двигателя указан ток полной нагрузки 16 ампер и сервис-фактор 1.25; какая максимальная уставка защиты от перегрузки разрешена по NEC 430.32?","optsr":["16 ампер","20 ампер","18.4 ампера","24 ампера"],"rr":"При сервис-факторе 1.15 или более NEC 430.32(A)(1) допускает 125% от FLA с таблички: 16 А x 1.25 = 20 А.","qs":"La placa de identificación de un motor indica 16 amperios de corriente a plena carga y un factor de servicio de 1.25; ¿cuál es el ajuste máximo de protección de sobrecarga permitido por NEC 430.32?","optss":["16 amperios","20 amperios","18.4 amperios","24 amperios"],"rs":"Con un factor de servicio de 1.15 o más, NEC 430.32(A)(1) permite el 125% de la FLA de la placa de identificación: 16 A x 1.25 = 20 A."},
  {"id":28,"sec":"Safety","block":1,"q":"How does NFPA 70E define a qualified person?","opts":["Any worker who has been employed by the company for at least five years","Any person holding a valid driver's license and first-aid card","Only a licensed professional engineer","One who has demonstrated skills and knowledge related to the construction and operation of electrical equipment and has received safety training to recognize and avoid the hazards involved"],"correct":3,"re":"NFPA 70E defines a qualified person as one who has demonstrated skills and knowledge related to the construction and operation of the electrical equipment and installations and has received safety training to identify and avoid the hazards involved.","qr":"Как NFPA 70E определяет квалифицированного специалиста (qualified person)?","optsr":["Любой работник, проработавший в компании не менее пяти лет","Любой человек с действующими водительскими правами и сертификатом первой помощи","Только лицензированный профессиональный инженер","Тот, кто продемонстрировал навыки и знания, связанные с конструкцией и эксплуатацией электрооборудования, и прошёл обучение по технике безопасности для распознавания и предотвращения соответствующих опасностей"],"rr":"NFPA 70E определяет квалифицированного специалиста как того, кто продемонстрировал навыки и знания, связанные с конструкцией и эксплуатацией электрооборудования и установок, и прошёл обучение по технике безопасности для выявления и предотвращения соответствующих опасностей.","qs":"¿Cómo define NFPA 70E a una persona calificada?","optss":["Cualquier trabajador que haya estado empleado por la empresa durante al menos cinco años","Cualquier persona que tenga una licencia de conducir válida y una tarjeta de primeros auxilios","Únicamente un ingeniero profesional con licencia","Alguien que ha demostrado destrezas y conocimientos relacionados con la construcción y operación de equipos eléctricos y ha recibido capacitación en seguridad para reconocer y evitar los peligros involucrados"],"rs":"NFPA 70E define a una persona calificada como alguien que ha demostrado destrezas y conocimientos relacionados con la construcción y operación de los equipos e instalaciones eléctricas y ha recibido capacitación en seguridad para identificar y evitar los peligros involucrados."},
  {"id":29,"sec":"Planning & Estimation","block":1,"q":"A 6 ohm and a 12 ohm resistor are connected in parallel; what is the total resistance?","opts":["18 ohms","4 ohms","9 ohms","0.25 ohms"],"correct":1,"re":"Parallel: R = (6 x 12)/(6 + 12) = 72/18 = 4 ohms.","qr":"Резисторы 6 Ом и 12 Ом соединены параллельно; каково общее сопротивление?","optsr":["18 Ом","4 Ом","9 Ом","0,25 Ом"],"rr":"Параллельно: R = (6 x 12)/(6 + 12) = 72/18 = 4 Ом.","qs":"Una resistencia de 6 ohmios y una de 12 ohmios se conectan en paralelo; ¿cuál es la resistencia total?","optss":["18 ohmios","4 ohmios","9 ohmios","0.25 ohmios"],"rs":"En paralelo: R = (6 x 12)/(6 + 12) = 72/18 = 4 ohmios."},
  {"id":30,"sec":"Rough Wiring","block":1,"q":"Per NEC Table 310.16, what is the ampacity of a 14 AWG copper conductor in the 60°C column?","opts":["25 A","20 A","15 A","30 A"],"correct":2,"re":"In the 60°C column of Table 310.16, 14 AWG copper is rated 15 A.","qr":"Согласно NEC Table 310.16, какова ampacity медного проводника 14 AWG в колонке 60°C?","optsr":["25 A","20 A","15 A","30 A"],"rr":"В колонке 60°C таблицы 310.16 проводник 14 AWG из меди рассчитан на 15 A.","qs":"Según NEC Table 310.16, ¿cuál es la ampacidad de un conductor de cobre 14 AWG en la columna de 60°C?","optss":["25 A","20 A","15 A","30 A"],"rs":"En la columna de 60°C de la Table 310.16, el cobre 14 AWG está clasificado para 15 A."},
  {"id":31,"sec":"Finish Wiring & Trim","block":1,"q":"Along a kitchen countertop, receptacles serving the counter must be installed so that no point along the wall countertop is more than what distance from a receptacle?","opts":["24 inches","20 inches","12 inches","30 inches"],"correct":0,"re":"NEC 210.52(C) requires that receptacles be placed so no point along the wall line of the countertop is more than 24 in. from a receptacle, supporting the 'no point more than 24 in.' rule for a 2-ft cord reach.","qr":"Вдоль кухонной столешницы розетки, обслуживающие стойку, должны быть установлены так, чтобы ни одна точка вдоль настенной столешницы не находилась дальше какого расстояния от розетки?","optsr":["24 дюйма","20 дюймов","12 дюймов","30 дюймов"],"rr":"NEC 210.52(C) требует размещать розетки так, чтобы ни одна точка вдоль линии стены столешницы не находилась далее 24 дюймов от розетки, что соответствует правилу 'не далее 24 дюймов' для шнура длиной 2 фута.","qs":"A lo largo de la encimera (countertop) de una cocina, los tomacorrientes que sirven la encimera deben instalarse de modo que ningún punto a lo largo de la línea de pared de la encimera esté a más de qué distancia de un tomacorriente?","optss":["24 pulgadas","20 pulgadas","12 pulgadas","30 pulgadas"],"rs":"NEC 210.52(C) requiere que los tomacorrientes se coloquen de modo que ningún punto a lo largo de la línea de pared de la encimera esté a más de 24 in. de un tomacorriente, respaldando la regla de 'ningún punto a más de 24 in.' para un alcance de cordón de 2 ft."},
  {"id":32,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"What is the primary purpose of the motor overload protection device required by NEC 430 Part III?","opts":["To protect against short circuits between conductors","To protect the motor and conductors from sustained overcurrent due to motor overload","To provide instantaneous disconnection during a ground fault","To limit voltage spikes during motor starting"],"correct":1,"re":"NEC 430.32 overload devices protect the motor, motor-control apparatus, and branch-circuit conductors against excessive heating from running overcurrents (overloads), not short circuits or ground faults.","qr":"Какова основная цель устройства защиты двигателя от перегрузки, требуемого NEC 430 Часть III?","optsr":["Защита от коротких замыканий между проводниками","Защита двигателя и проводников от длительного сверхтока из-за перегрузки двигателя","Обеспечение мгновенного отключения при замыкании на землю","Ограничение скачков напряжения при пуске двигателя"],"rr":"Устройства защиты от перегрузки NEC 430.32 защищают двигатель, аппаратуру управления и проводники ответвления от чрезмерного нагрева рабочими сверхтоками (перегрузками), а не от коротких замыканий или замыканий на землю.","qs":"¿Cuál es el propósito principal del dispositivo de protección de sobrecarga del motor requerido por NEC 430 Part III?","optss":["Proteger contra cortocircuitos entre conductores","Proteger el motor y los conductores contra la sobrecorriente sostenida debida a una sobrecarga del motor","Proporcionar desconexión instantánea durante una falla a tierra","Limitar los picos de voltaje durante el arranque del motor"],"rs":"Los dispositivos de sobrecarga de NEC 430.32 protegen el motor, el aparato de control del motor y los conductores del circuito ramal contra el calentamiento excesivo debido a sobrecorrientes de funcionamiento (sobrecargas), no contra cortocircuitos ni fallas a tierra."},
  {"id":33,"sec":"Safety","block":1,"q":"What is the purpose of the arc-flash boundary established under NFPA 70E?","opts":["It marks where the incident energy equals 1.2 cal/cm2, the onset of a second-degree burn to bare skin","It indicates the maximum length of an extension cord allowed","It defines the minimum bending radius for conductors","It sets the distance for required emergency lighting"],"correct":0,"re":"The arc-flash boundary is the distance at which the incident energy is 1.2 cal/cm2; at this point an unprotected person could receive a second-degree burn if an arc-flash occurred.","qr":"Какова цель границы дугового разряда (arc-flash boundary), устанавливаемой согласно NFPA 70E?","optsr":["Она отмечает место, где падающая энергия равна 1,2 кал/см2 — порог ожога второй степени для незащищённой кожи","Она указывает максимально допустимую длину удлинителя","Она определяет минимальный радиус изгиба проводников","Она задаёт расстояние для требуемого аварийного освещения"],"rr":"Граница дугового разряда — это расстояние, на котором падающая энергия составляет 1,2 кал/см2; в этой точке незащищённый человек может получить ожог второй степени при возникновении дугового разряда.","qs":"¿Cuál es el propósito del límite de arco eléctrico establecido según NFPA 70E?","optss":["Marca dónde la energía incidente equivale a 1.2 cal/cm2, el inicio de una quemadura de segundo grado en la piel descubierta","Indica la longitud máxima de un cordón de extensión permitido","Define el radio de curvatura mínimo para los conductores","Establece la distancia para la iluminación de emergencia requerida"],"rs":"El límite de arco eléctrico es la distancia a la cual la energía incidente es de 1.2 cal/cm2; en este punto una persona desprotegida podría recibir una quemadura de segundo grado si ocurriera un arco eléctrico."},
  {"id":34,"sec":"Planning & Estimation","block":1,"q":"Four 100 ohm resistors are connected in parallel; what is the equivalent resistance?","opts":["400 ohms","100 ohms","25 ohms","50 ohms"],"correct":2,"re":"For equal parallel resistors, R = R/n = 100/4 = 25 ohms.","qr":"Четыре резистора по 100 Ом соединены параллельно; каково эквивалентное сопротивление?","optsr":["400 Ом","100 Ом","25 Ом","50 Ом"],"rr":"Для равных параллельных резисторов R = R/n = 100/4 = 25 Ом.","qs":"Cuatro resistencias de 100 ohmios se conectan en paralelo; ¿cuál es la resistencia equivalente?","optss":["400 ohmios","100 ohmios","25 ohmios","50 ohmios"],"rs":"Para resistencias iguales en paralelo, R = R/n = 100/4 = 25 ohmios."},
  {"id":35,"sec":"Rough Wiring","block":1,"q":"The three temperature columns in NEC Table 310.16 represent which conductor property?","opts":["Insulation temperature ratings","Ambient temperature ranges","Conduit fill percentages","Voltage class ratings"],"correct":0,"re":"The 60°C, 75°C, and 90°C columns correspond to the temperature rating of the conductor insulation. See NEC Table 310.16.","qr":"Три температурные колонки в NEC Table 310.16 отражают какое свойство проводника?","optsr":["Температурные классы изоляции","Диапазоны температуры окружающей среды","Проценты заполнения трубы","Классы напряжения"],"rr":"Колонки 60°C, 75°C и 90°C соответствуют температурному классу изоляции проводника. См. NEC Table 310.16.","qs":"Las tres columnas de temperatura en NEC Table 310.16 representan ¿cuál propiedad del conductor?","optss":["Clasificaciones de temperatura del aislamiento","Rangos de temperatura ambiente","Porcentajes de llenado del conduit","Clasificaciones de clase de voltaje"],"rs":"Las columnas de 60°C, 75°C y 90°C corresponden a la clasificación de temperatura del aislamiento del conductor. Véase NEC Table 310.16."},
  {"id":36,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"Which device in a motor branch circuit is designed to protect against short circuits and ground faults rather than running overloads?","opts":["The thermal overload relay","The control transformer","The motor holding contact","The branch-circuit short-circuit and ground-fault protective device (fuse or breaker)"],"correct":3,"re":"NEC 430 Part IV requires a branch-circuit short-circuit and ground-fault protective device (typically a fuse or inverse-time circuit breaker) that is separate from the running-overload device in Part III.","qr":"Какое устройство в ответвлении двигателя предназначено для защиты от коротких замыканий и замыканий на землю, а не от рабочих перегрузок?","optsr":["Тепловое реле перегрузки","Управляющий трансформатор","Удерживающий контакт двигателя","Устройство защиты ответвления от короткого замыкания и замыкания на землю (предохранитель или автомат)"],"rr":"NEC 430 Часть IV требует устройство защиты ответвления от короткого замыкания и замыкания на землю (обычно предохранитель или автомат с обратнозависимой характеристикой), отдельное от устройства защиты от рабочей перегрузки в Части III.","qs":"¿Qué dispositivo en un circuito ramal de motor está diseñado para proteger contra cortocircuitos y fallas a tierra en lugar de sobrecargas de funcionamiento?","optss":["El relé de sobrecarga térmica","El transformador de control","El contacto de retención del motor","El dispositivo de protección contra cortocircuito y falla a tierra del circuito ramal (fusible o interruptor)"],"rs":"NEC 430 Part IV requiere un dispositivo de protección contra cortocircuito y falla a tierra del circuito ramal (típicamente un fusible o un interruptor automático de tiempo inverso) que es independiente del dispositivo de sobrecarga de funcionamiento de Part III."},
  {"id":37,"sec":"Planning & Estimation","block":1,"q":"In a series circuit with a 30 ohm and a 60 ohm resistor across 90 V, what is the circuit current?","opts":["3 A","0.5 A","1 A","90 A"],"correct":2,"re":"Total R = 30 + 60 = 90 ohms; I = V/R = 90/90 = 1 A.","qr":"В последовательной цепи с резисторами 30 Ом и 60 Ом под напряжением 90 В, каков ток цепи?","optsr":["3 А","0,5 А","1 А","90 А"],"rr":"Общее R = 30 + 60 = 90 Ом; I = V/R = 90/90 = 1 А.","qs":"En un circuito en serie con una resistencia de 30 ohmios y una de 60 ohmios a través de 90 V, ¿cuál es la corriente del circuito?","optss":["3 A","0.5 A","1 A","90 A"],"rs":"R total = 30 + 60 = 90 ohmios; I = V/R = 90/90 = 1 A."},
  {"id":38,"sec":"Rough Wiring","block":1,"q":"When a conductor with 90°C insulation terminates on equipment rated for 75°C, which column's ampacity must be used for the final termination rating?","opts":["60°C","90°C","75°C","Average of 75°C and 90°C"],"correct":2,"re":"Per NEC 110.14(C), the lowest temperature rating of any connected termination or conductor governs; here the 75°C column applies.","qr":"Когда проводник с изоляцией 90°C подключается к оборудованию, рассчитанному на 75°C, ampacity какой колонки нужно использовать для итоговой нагрузки на зажимах?","optsr":["60°C","90°C","75°C","Среднее между 75°C и 90°C"],"rr":"Согласно NEC 110.14(C), действует наименьший температурный класс зажима или проводника; здесь применяется колонка 75°C.","qs":"Cuando un conductor con aislamiento de 90°C termina en un equipo clasificado para 75°C, ¿qué columna de ampacidad debe usarse para la clasificación final de la terminación?","optss":["60°C","90°C","75°C","Promedio de 75°C y 90°C"],"rs":"Según NEC 110.14(C), rige la clasificación de temperatura más baja de cualquier terminación o conductor conectado; aquí aplica la columna de 75°C."},
  {"id":39,"sec":"Safety","block":1,"q":"When applying lockout/tagout under Cal/OSHA T8 Section 3314, who is permitted to remove a lock that an authorized employee placed on a disconnect?","opts":["Any electrician on the next shift who needs the circuit","Generally only the authorized employee who applied that lock, except under a documented procedure when that employee is unavailable","The site security guard at the end of the day","Any apprentice working in the same area"],"correct":1,"re":"Cal/OSHA T8 Section 3314 requires that each lock be removed by the employee who applied it; removal by others is allowed only through a specific documented procedure when that employee is absent and the employer verifies it is safe.","qr":"При применении lockout/tagout согласно разделу 3314 Title 8 Cal/OSHA, кому разрешено снимать замок, установленный уполномоченным работником на разъединитель?","optsr":["Любому электрику следующей смены, которому нужна цепь","Как правило, только уполномоченному работнику, установившему этот замок, за исключением документированной процедуры, когда этот работник недоступен","Охраннику объекта в конце рабочего дня","Любому ученику, работающему в той же зоне"],"rr":"Раздел 3314 Title 8 Cal/OSHA требует, чтобы каждый замок снимал работник, который его установил; снятие другими допускается только по специальной документированной процедуре, когда этот работник отсутствует и работодатель убедился, что это безопасно.","qs":"Al aplicar el bloqueo/etiquetado según Cal/OSHA T8 Section 3314, ¿quién está autorizado a retirar un candado que un empleado autorizado colocó en un medio de desconexión?","optss":["Cualquier electricista del siguiente turno que necesite el circuito","Generalmente solo el empleado autorizado que aplicó ese candado, excepto mediante un procedimiento documentado cuando ese empleado no está disponible","El guardia de seguridad del sitio al final del día","Cualquier aprendiz que trabaje en la misma área"],"rs":"Cal/OSHA T8 Section 3314 requiere que cada candado sea retirado por el empleado que lo aplicó; el retiro por otros solo se permite mediante un procedimiento documentado específico cuando ese empleado está ausente y el empleador verifica que es seguro."},
  {"id":40,"sec":"Finish Wiring & Trim","block":1,"q":"A kitchen wall countertop space is at least how wide before a receptacle outlet is required to serve it?","opts":["12 inches","6 inches","18 inches","24 inches"],"correct":0,"re":"NEC 210.52(C)(1) requires a receptacle for each wall countertop space that is 12 in. (300 mm) or wider.","qr":"Какой минимальной ширины должно быть пространство кухонной настенной столешницы, прежде чем потребуется обслуживающая его розетка?","optsr":["12 дюймов","6 дюймов","18 дюймов","24 дюйма"],"rr":"NEC 210.52(C)(1) требует розетку для каждого настенного пространства столешницы шириной 12 дюймов (300 мм) или более.","qs":"¿De qué ancho mínimo debe ser un espacio de encimera de pared en una cocina antes de que se requiera una salida de tomacorriente para servirlo?","optss":["12 pulgadas","6 pulgadas","18 pulgadas","24 pulgadas"],"rs":"NEC 210.52(C)(1) requiere un tomacorriente para cada espacio de encimera de pared que tenga 12 in. (300 mm) o más de ancho."},
  {"id":41,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"Why is the branch-circuit short-circuit and ground-fault protective device for a motor typically rated higher than the motor's full-load current?","opts":["Because it must also serve as the overload device","Because conductors are always oversized","Because it must allow the high inrush (locked-rotor) current during motor starting without tripping","Because the nameplate current is inaccurate"],"correct":2,"re":"Motors draw a large inrush/locked-rotor current at startup, so NEC 430.52 permits the short-circuit/ground-fault device to be set well above FLC so it does not nuisance-trip while still protecting against faults.","qr":"Почему устройство защиты ответвления двигателя от короткого замыкания и замыкания на землю обычно рассчитано на ток выше тока полной нагрузки двигателя?","optsr":["Потому что оно должно также служить устройством защиты от перегрузки","Потому что проводники всегда завышены по сечению","Потому что оно должно пропускать высокий пусковой ток (ток заторможенного ротора) при пуске двигателя без срабатывания","Потому что ток с таблички неточен"],"rr":"Двигатели потребляют большой пусковой ток / ток заторможенного ротора при запуске, поэтому NEC 430.52 допускает уставку устройства защиты от короткого замыкания / замыкания на землю значительно выше тока полной нагрузки, чтобы оно не срабатывало ложно, при этом защищая от повреждений.","qs":"¿Por qué el dispositivo de protección contra cortocircuito y falla a tierra del circuito ramal de un motor típicamente está clasificado más alto que la corriente a plena carga del motor?","optss":["Porque también debe servir como el dispositivo de sobrecarga","Porque los conductores siempre están sobredimensionados","Porque debe permitir la alta corriente de irrupción (rotor bloqueado) durante el arranque del motor sin dispararse","Porque la corriente de la placa de identificación es inexacta"],"rs":"Los motores consumen una gran corriente de irrupción/rotor bloqueado al arrancar, por lo que NEC 430.52 permite que el dispositivo de cortocircuito/falla a tierra se ajuste muy por encima de la FLC para que no se dispare por molestia, sin dejar de proteger contra fallas."},
  {"id":42,"sec":"Rough Wiring","block":1,"q":"The 90°C column of an ampacity table is primarily used for which purpose?","opts":["The final allowable load on terminals","Determining conduit size","Applying derating/correction factors as a starting point","Selecting overcurrent device size directly"],"correct":2,"re":"The 90°C ampacity is commonly used as the starting value for adjustment and correction factors, provided terminations are not exceeded. See NEC 110.14(C) and 310.15.","qr":"Колонка 90°C в таблице ampacity в основном используется для какой цели?","optsr":["Итоговая допустимая нагрузка на зажимах","Для определения размера трубы","Как исходное значение для применения коэффициентов снижения/коррекции","Для прямого выбора аппарата защиты"],"rr":"Ampacity 90°C обычно используется как исходное значение для применения коэффициентов снижения и коррекции, при условии что зажимы не перегружаются. См. NEC 110.14(C) и 310.15.","qs":"La columna de 90°C de una tabla de ampacidad se usa principalmente para ¿cuál propósito?","optss":["La carga final permitida en las terminales","Determinar el tamaño del conduit","Aplicar factores de reducción/corrección como punto de partida","Seleccionar directamente el tamaño del dispositivo de sobrecorriente"],"rs":"La ampacidad de 90°C se usa comúnmente como valor de partida para los factores de ajuste y corrección, siempre que no se excedan las terminaciones. Véase NEC 110.14(C) y 310.15."},
  {"id":43,"sec":"Planning & Estimation","block":1,"q":"A single-phase load draws 16 A at 240 V; what is the apparent power in volt-amperes?","opts":["3840 VA","15 VA","256 VA","1920 VA"],"correct":0,"re":"Apparent power S = V x I = 240 x 16 = 3840 VA.","qr":"Однофазная нагрузка потребляет 16 А при 240 В; какова полная мощность в вольт-амперах?","optsr":["3840 ВА","15 ВА","256 ВА","1920 ВА"],"rr":"Полная мощность S = V x I = 240 x 16 = 3840 ВА.","qs":"Una carga monofásica consume 16 A a 240 V; ¿cuál es la potencia aparente en voltio-amperios?","optss":["3840 VA","15 VA","256 VA","1920 VA"],"rs":"Potencia aparente S = V x I = 240 x 16 = 3840 VA."},
  {"id":44,"sec":"Safety","block":1,"q":"What does establishing an electrically safe work condition require after the disconnecting means is opened?","opts":["Immediately beginning work since the switch is off","Waiting 24 hours before any testing","Visually verifying the disconnect is open, applying lockout/tagout, testing for absence of voltage, and grounding where induced or stored energy may be present","Calling the utility to confirm the meter reading"],"correct":2,"re":"NFPA 70E lists the steps to establish an electrically safe work condition, including verifying the disconnect is open, applying LOTO, testing for absence of voltage with an adequately rated device, and applying grounds where stored or induced voltage could exist.","qr":"Что требуется для создания электробезопасного рабочего состояния после размыкания отключающего устройства?","optsr":["Немедленно начать работу, поскольку выключатель отключён","Подождать 24 часа перед любой проверкой","Визуально убедиться, что разъединитель разомкнут, применить lockout/tagout, проверить отсутствие напряжения и заземлить там, где может присутствовать наведённая или накопленная энергия","Позвонить в коммунальную службу для подтверждения показаний счётчика"],"rr":"NFPA 70E перечисляет шаги для создания электробезопасного рабочего состояния, включая проверку разомкнутого состояния разъединителя, применение LOTO, проверку отсутствия напряжения прибором соответствующего класса и установку заземления там, где может существовать накопленное или наведённое напряжение.","qs":"¿Qué requiere establecer una condición de trabajo eléctricamente segura después de que se abre el medio de desconexión?","optss":["Comenzar el trabajo de inmediato ya que el interruptor está apagado","Esperar 24 horas antes de cualquier prueba","Verificar visualmente que la desconexión esté abierta, aplicar bloqueo/etiquetado, probar la ausencia de voltaje y poner a tierra donde pueda haber energía inducida o almacenada","Llamar a la empresa de servicios para confirmar la lectura del medidor"],"rs":"NFPA 70E enumera los pasos para establecer una condición de trabajo eléctricamente segura, incluido verificar que la desconexión esté abierta, aplicar LOTO, probar la ausencia de voltaje con un dispositivo de clasificación adecuada y aplicar conexiones a tierra donde pudiera existir voltaje almacenado o inducido."},
  {"id":45,"sec":"Rough Wiring","block":1,"q":"When the ambient temperature exceeds 30°C (86°F), the conductor ampacity from Table 310.16 must be:","opts":["Multiplied by a correction factor less than 1.0","Increased by the correction factor","Left unchanged","Multiplied by 1.25"],"correct":0,"re":"Higher ambient temperatures reduce ampacity, so a correction factor below 1.0 from Table 310.15(B)(1) is applied.","qr":"Когда температура окружающей среды превышает 30°C (86°F), ampacity из Table 310.16 нужно:","optsr":["Умножить на коэффициент коррекции меньше 1.0","Увеличить на коэффициент коррекции","Оставить без изменений","Умножить на 1.25"],"rr":"Более высокая температура окружающей среды снижает ampacity, поэтому применяется коэффициент коррекции меньше 1.0 из Table 310.15(B)(1).","qs":"Cuando la temperatura ambiente excede los 30°C (86°F), la ampacidad del conductor de la Table 310.16 debe ser:","optss":["Multiplicada por un factor de corrección menor que 1.0","Aumentada por el factor de corrección","Dejada sin cambios","Multiplicada por 1.25"],"rs":"Las temperaturas ambiente más altas reducen la ampacidad, por lo que se aplica un factor de corrección menor que 1.0 de la Table 310.15(B)(1)."},
  {"id":46,"sec":"Planning & Estimation","block":1,"q":"What current does a 1500 W single-phase resistive heater draw on a 120 V circuit?","opts":["12.5 A","180000 A","0.08 A","8 A"],"correct":0,"re":"I = P/V = 1500/120 = 12.5 A (resistive, PF = 1).","qr":"Какой ток потребляет однофазный резистивный нагреватель 1500 Вт в цепи 120 В?","optsr":["12,5 А","180000 А","0,08 А","8 А"],"rr":"I = P/V = 1500/120 = 12,5 А (резистивная нагрузка, PF = 1).","qs":"¿Qué corriente consume un calefactor resistivo monofásico de 1500 W en un circuito de 120 V?","optss":["12.5 A","180000 A","0.08 A","8 A"],"rs":"I = P/V = 1500/120 = 12.5 A (resistivo, PF = 1)."},
  {"id":47,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a standard three-phase induction motor, how is the direction of rotation reversed?","opts":["By reversing all three line leads","By reversing the connection of the equipment grounding conductor","By interchanging any two of the three line leads","By increasing the supply voltage"],"correct":2,"re":"Swapping any two of the three line conductors reverses the phase sequence, which reverses the direction of the rotating magnetic field and thus the motor rotation.","qr":"В стандартном трёхфазном асинхронном двигателе как изменяется направление вращения?","optsr":["Изменением подключения всех трёх линейных вводов","Изменением подключения заземляющего проводника оборудования","Меняя местами любые два из трёх линейных вводов","Увеличением напряжения питания"],"rr":"Перестановка любых двух из трёх линейных проводников меняет порядок чередования фаз, что изменяет направление вращающегося магнитного поля и, следовательно, вращение двигателя.","qs":"En un motor de inducción trifásico estándar, ¿cómo se invierte la dirección de rotación?","optss":["Invirtiendo los tres conductores de línea","Invirtiendo la conexión del conductor de puesta a tierra del equipo","Intercambiando dos cualesquiera de los tres conductores de línea","Aumentando el voltaje de alimentación"],"rs":"Intercambiar dos cualesquiera de los tres conductores de línea invierte la secuencia de fases, lo que invierte la dirección del campo magnético giratorio y, por tanto, la rotación del motor."},
  {"id":48,"sec":"Safety","block":1,"q":"Which of the following tasks is an unqualified person permitted to perform near energized electrical equipment?","opts":["Opening an energized motor control center to troubleshoot","Work outside the limited approach boundary, where exposure to energized parts is not present","Crossing the restricted approach boundary to take measurements","Replacing energized bus connections during an outage"],"correct":1,"re":"Under NFPA 70E, an unqualified person may work outside the limited approach boundary; they are not permitted to cross it toward exposed energized parts unless continuously escorted by a qualified person and even then cannot perform the qualified work.","qr":"Какую из следующих задач разрешено выполнять неквалифицированному специалисту вблизи электрооборудования под напряжением?","optsr":["Открывать находящийся под напряжением центр управления двигателями для поиска неисправностей","Работу за пределами limited approach boundary, где нет контакта с частями под напряжением","Пересекать restricted approach boundary для выполнения измерений","Заменять находящиеся под напряжением шинные соединения во время отключения"],"rr":"Согласно NFPA 70E, неквалифицированный специалист может работать за пределами limited approach boundary; ему не разрешается пересекать её в сторону открытых частей под напряжением, кроме как под постоянным сопровождением квалифицированного специалиста, и даже тогда он не может выполнять квалифицированную работу.","qs":"¿Cuál de las siguientes tareas puede realizar una persona no calificada cerca de equipos eléctricos energizados?","optss":["Abrir un centro de control de motores energizado para diagnosticar fallas","Trabajo fuera del límite de aproximación limitada, donde no hay exposición a partes energizadas","Cruzar el límite de aproximación restringida para tomar mediciones","Reemplazar conexiones de barra energizadas durante un corte"],"rs":"Según NFPA 70E, una persona no calificada puede trabajar fuera del límite de aproximación limitada; no se le permite cruzarlo hacia partes energizadas expuestas a menos que sea escoltada continuamente por una persona calificada, e incluso entonces no puede realizar el trabajo calificado."},
  {"id":49,"sec":"Finish Wiring & Trim","block":1,"q":"A kitchen island countertop with a long dimension of 24 in. or greater and a short dimension of 12 in. or greater generally requires at least how many receptacle outlets?","opts":["Zero","Three","Two","One"],"correct":3,"re":"NEC 210.52(C) requires at least one receptacle outlet for an island countertop space meeting the minimum dimensions of 24 in. by 12 in.","qr":"Кухонный остров со столешницей с длинной стороной 24 дюйма или более и короткой стороной 12 дюймов или более, как правило, требует как минимум сколько розеток?","optsr":["Ноль","Три","Две","Одну"],"rr":"NEC 210.52(C) требует как минимум одну розетку для пространства столешницы острова, отвечающего минимальным размерам 24 на 12 дюймов.","qs":"Una encimera de isla de cocina con una dimensión larga de 24 in. o mayor y una dimensión corta de 12 in. o mayor generalmente requiere al menos cuántas salidas de tomacorriente?","optss":["Cero","Tres","Dos","Una"],"rs":"NEC 210.52(C) requiere al menos una salida de tomacorriente para un espacio de encimera de isla que cumpla con las dimensiones mínimas de 24 in. por 12 in."},
  {"id":50,"sec":"Rough Wiring","block":1,"q":"Ampacity tables such as Table 310.16 are based on an assumed ambient temperature of:","opts":["30°C (86°F)","20°C (68°F)","40°C (104°F)","60°C (140°F)"],"correct":0,"re":"Table 310.16 is based on an ambient temperature of 30°C (86°F); other ambients require correction factors. See NEC 310.15(B).","qr":"Таблицы ampacity, такие как Table 310.16, основаны на расчётной температуре окружающей среды:","optsr":["30°C (86°F)","20°C (68°F)","40°C (104°F)","60°C (140°F)"],"rr":"Table 310.16 основана на температуре окружающей среды 30°C (86°F); для других температур нужны коэффициенты коррекции. См. NEC 310.15(B).","qs":"Las tablas de ampacidad como la Table 310.16 se basan en una temperatura ambiente supuesta de:","optss":["30°C (86°F)","20°C (68°F)","40°C (104°F)","60°C (140°F)"],"rs":"La Table 310.16 se basa en una temperatura ambiente de 30°C (86°F); otras temperaturas ambiente requieren factores de corrección. Véase NEC 310.15(B)."},
  {"id":51,"sec":"Planning & Estimation","block":1,"q":"A resistor dissipates 600 W at a current of 5 A; what is its resistance?","opts":["120 ohms","24 ohms","3000 ohms","0.042 ohms"],"correct":1,"re":"From P = I squared x R, R = P / I squared = 600 / 25 = 24 ohms.","qr":"Резистор рассеивает 600 Вт при токе 5 А; каково его сопротивление?","optsr":["120 Ом","24 Ом","3000 Ом","0,042 Ом"],"rr":"Из P = I в квадрате x R, R = P / I в квадрате = 600 / 25 = 24 Ом.","qs":"Una resistencia disipa 600 W con una corriente de 5 A; ¿cuál es su resistencia?","optss":["120 ohmios","24 ohmios","3000 ohmios","0.042 ohmios"],"rs":"A partir de P = I al cuadrado x R, R = P / I al cuadrado = 600 / 25 = 24 ohmios."},
  {"id":52,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"A three-phase motor connected to lines L1-T1, L2-T2, L3-T3 is rotating in the wrong direction; which change will correct the rotation?","opts":["Swap L1 and L2 only","Swap all three leads simultaneously","Reconnect the neutral","Add a phase-shifting capacitor"],"correct":0,"re":"Reversing any two leads reverses rotation; swapping L1 and L2 (or any single pair) reverses the phase sequence and corrects the direction.","qr":"Трёхфазный двигатель, подключённый к линиям L1-T1, L2-T2, L3-T3, вращается в неправильном направлении; какое изменение исправит вращение?","optsr":["Поменять местами только L1 и L2","Поменять местами все три ввода одновременно","Переподключить нейтраль","Добавить фазосдвигающий конденсатор"],"rr":"Изменение любых двух вводов меняет вращение; перестановка L1 и L2 (или любой одной пары) изменяет порядок чередования фаз и исправляет направление.","qs":"Un motor trifásico conectado a las líneas L1-T1, L2-T2, L3-T3 está girando en la dirección incorrecta; ¿qué cambio corregirá la rotación?","optss":["Intercambiar solo L1 y L2","Intercambiar los tres conductores simultáneamente","Reconectar el neutro","Agregar un capacitor de desfase"],"rs":"Invertir dos conductores cualesquiera invierte la rotación; intercambiar L1 y L2 (o cualquier par único) invierte la secuencia de fases y corrige la dirección."},
  {"id":53,"sec":"Rough Wiring","block":1,"q":"If a 90°C conductor is installed in a 50°C ambient, why is starting from the 90°C column advantageous?","opts":["Its higher base ampacity better absorbs the temperature correction","It avoids any derating","It eliminates the need for correction factors","It allows a smaller overcurrent device"],"correct":0,"re":"Using the higher 90°C base ampacity gives more margin when the ambient correction factor reduces the value, as permitted by NEC 310.15(B) and 110.14(C).","qr":"Если проводник на 90°C установлен при температуре окружающей среды 50°C, почему выгодно начинать с колонки 90°C?","optsr":["Его более высокая базовая ampacity лучше выдерживает температурную коррекцию","Это исключает любое снижение","Это устраняет необходимость в коэффициентах коррекции","Это позволяет использовать меньший аппарат защиты"],"rr":"Использование более высокой базовой ampacity 90°C даёт больший запас, когда коэффициент коррекции по температуре уменьшает значение, что разрешено NEC 310.15(B) и 110.14(C).","qs":"Si un conductor de 90°C se instala en una temperatura ambiente de 50°C, ¿por qué es ventajoso partir de la columna de 90°C?","optss":["Su mayor ampacidad base absorbe mejor la corrección por temperatura","Evita cualquier reducción","Elimina la necesidad de factores de corrección","Permite un dispositivo de sobrecorriente más pequeño"],"rs":"Usar la mayor ampacidad base de 90°C da más margen cuando el factor de corrección por temperatura ambiente reduce el valor, según lo permitido por NEC 310.15(B) y 110.14(C)."},
  {"id":54,"sec":"Safety","block":1,"q":"What is the primary hazard that arc-flash PPE is designed to protect against?","opts":["Falls from elevated work platforms","Thermal burns from the radiant and convective heat of an electric arc","Hearing loss from rotating machinery","Chemical splashes from battery electrolyte"],"correct":1,"re":"Arc-rated PPE is selected based on incident energy to protect the worker from the intense thermal energy of an arc flash; it is rated in cal/cm2 to match or exceed the calculated incident energy.","qr":"От какой основной опасности предназначены защищать СИЗ от дугового разряда?","optsr":["Падений с высотных рабочих площадок","Термических ожогов от лучистого и конвективного тепла электрической дуги","Потери слуха от вращающихся механизмов","Химических брызг электролита аккумулятора"],"rr":"СИЗ с дуговой защитой (arc-rated) выбираются на основе падающей энергии для защиты работника от интенсивной тепловой энергии дугового разряда; они классифицируются в кал/см2, чтобы соответствовать или превышать расчётную падающую энергию.","qs":"¿Cuál es el peligro principal contra el que está diseñado el EPP de arco eléctrico?","optss":["Caídas desde plataformas de trabajo elevadas","Quemaduras térmicas por el calor radiante y convectivo de un arco eléctrico","Pérdida auditiva por maquinaria giratoria","Salpicaduras químicas del electrolito de baterías"],"rs":"El EPP con clasificación de arco se selecciona en función de la energía incidente para proteger al trabajador de la intensa energía térmica de un arco eléctrico; se clasifica en cal/cm2 para igualar o exceder la energía incidente calculada."},
  {"id":55,"sec":"Planning & Estimation","block":1,"q":"What voltage is required to push 4 A through a 35 ohm resistor?","opts":["140 V","8.75 V","0.114 V","39 V"],"correct":0,"re":"By Ohm's law, V = I x R = 4 x 35 = 140 V.","qr":"Какое напряжение нужно, чтобы пропустить 4 А через резистор 35 Ом?","optsr":["140 В","8,75 В","0,114 В","39 В"],"rr":"По закону Ома, V = I x R = 4 x 35 = 140 В.","qs":"¿Qué voltaje se requiere para hacer pasar 4 A a través de una resistencia de 35 ohmios?","optss":["140 V","8.75 V","0.114 V","39 V"],"rs":"Por la ley de Ohm, V = I x R = 4 x 35 = 140 V."},
  {"id":56,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a magnetic motor starter, what is the function of the holding (maintaining) contact in the control circuit?","opts":["To open the circuit during an overload condition","To keep the starter coil energized after the momentary start button is released","To step down the control voltage","To reverse the motor rotation"],"correct":1,"re":"The holding contact is an auxiliary contact wired in parallel with the start button; once the coil energizes, it closes and maintains coil power so the motor keeps running after the start button is released.","qr":"В магнитном пускателе двигателя какова функция удерживающего (фиксирующего) контакта в цепи управления?","optsr":["Размыкать цепь при перегрузке","Удерживать катушку пускателя под напряжением после отпускания кнопки пуска кратковременного действия","Понижать управляющее напряжение","Изменять направление вращения двигателя"],"rr":"Удерживающий контакт — это вспомогательный контакт, подключённый параллельно кнопке пуска; как только катушка получает питание, он замыкается и поддерживает питание катушки, чтобы двигатель продолжал работать после отпускания кнопки пуска.","qs":"En un arrancador magnético de motor, ¿cuál es la función del contacto de retención (de sostenimiento) en el circuito de control?","optss":["Abrir el circuito durante una condición de sobrecarga","Mantener energizada la bobina del arrancador después de soltar el botón momentáneo de arranque","Reducir el voltaje de control","Invertir la rotación del motor"],"rs":"El contacto de retención es un contacto auxiliar cableado en paralelo con el botón de arranque; una vez que la bobina se energiza, se cierra y mantiene la alimentación de la bobina para que el motor siga funcionando después de soltar el botón de arranque."},
  {"id":57,"sec":"Rough Wiring","block":1,"q":"According to Table 310.15(C)(1), what adjustment factor applies when 4 to 6 current-carrying conductors are bundled in a raceway?","opts":["100%","80%","70%","50%"],"correct":1,"re":"For 4-6 current-carrying conductors, the adjustment factor is 80%. See NEC Table 310.15(C)(1).","qr":"Согласно Table 310.15(C)(1), какой коэффициент снижения применяется при наличии от 4 до 6 токоведущих проводников в трубе?","optsr":["100%","80%","70%","50%"],"rr":"Для 4-6 токоведущих проводников коэффициент снижения составляет 80%. См. NEC Table 310.15(C)(1).","qs":"De acuerdo con la Table 310.15(C)(1), ¿qué factor de ajuste aplica cuando se agrupan de 4 a 6 conductores portadores de corriente en una canalización?","optss":["100%","80%","70%","50%"],"rs":"Para 4 a 6 conductores portadores de corriente, el factor de ajuste es 80%. Véase NEC Table 310.15(C)(1)."},
  {"id":58,"sec":"Finish Wiring & Trim","block":1,"q":"Receptacles installed to serve dwelling kitchen countertop surfaces must be supplied by at least how many small-appliance branch circuits?","opts":["One 15-amp circuit","Two 20-amp circuits","One 30-amp circuit","Three 15-amp circuits"],"correct":1,"re":"NEC 210.11(C)(1) and 210.52(B) require at least two 20-amp small-appliance branch circuits to serve countertop and other receptacles in the kitchen, pantry, and dining areas.","qr":"Розетки, установленные для обслуживания кухонных столешниц в жилье, должны питаться как минимум от скольких ответвлённых цепей для мелких приборов?","optsr":["Одной цепи 15 А","Двух цепей 20 А","Одной цепи 30 А","Трёх цепей 15 А"],"rr":"NEC 210.11(C)(1) и 210.52(B) требуют как минимум две ответвлённые цепи 20 А для мелких приборов для обслуживания розеток столешниц и других розеток на кухне, в кладовой и обеденных зонах.","qs":"Los tomacorrientes instalados para servir las superficies de encimera de cocina de una vivienda deben ser alimentados por al menos cuántos circuitos ramales para electrodomésticos pequeños?","optss":["Un circuito de 15 amperios","Dos circuitos de 20 amperios","Un circuito de 30 amperios","Tres circuitos de 15 amperios"],"rs":"NEC 210.11(C)(1) y 210.52(B) requieren al menos dos circuitos ramales de 20 amperios para electrodomésticos pequeños que sirvan los tomacorrientes de la encimera y otros en la cocina, despensa y áreas de comedor."},
  {"id":59,"sec":"Safety","block":1,"q":"Under the NFPA 70E PPE category method, what determines which arc-flash PPE category applies to a task?","opts":["The color of the equipment enclosure","The specific equipment and task parameters listed in the arc-flash PPE category tables, including voltage and available fault current","The total horsepower of all connected motors","The age of the electrical panel"],"correct":1,"re":"NFPA 70E PPE category tables assign a category (1 through 4) based on the specific equipment type, available short-circuit current, and fault clearing time, which together estimate the arc-flash exposure.","qr":"Согласно методу категорий СИЗ по NFPA 70E, что определяет, какая категория СИЗ от дугового разряда применяется к задаче?","optsr":["Цвет корпуса оборудования","Конкретное оборудование и параметры задачи, указанные в таблицах категорий СИЗ от дугового разряда, включая напряжение и доступный ток короткого замыкания","Суммарная мощность всех подключённых двигателей в л.с.","Возраст электрического щита"],"rr":"Таблицы категорий СИЗ NFPA 70E присваивают категорию (от 1 до 4) на основе конкретного типа оборудования, доступного тока короткого замыкания и времени отключения при коротком замыкании, что вместе оценивает воздействие дугового разряда.","qs":"Según el método de categoría de EPP de NFPA 70E, ¿qué determina cuál categoría de EPP de arco eléctrico aplica a una tarea?","optss":["El color del gabinete del equipo","Los parámetros específicos del equipo y de la tarea enumerados en las tablas de categoría de EPP de arco eléctrico, incluidos el voltaje y la corriente de falla disponible","La potencia total en caballos de fuerza de todos los motores conectados","La antigüedad del tablero eléctrico"],"rs":"Las tablas de categoría de EPP de NFPA 70E asignan una categoría (1 a 4) según el tipo específico de equipo, la corriente de cortocircuito disponible y el tiempo de despeje de falla, que en conjunto estiman la exposición al arco eléctrico."},
  {"id":60,"sec":"Planning & Estimation","block":1,"q":"A 2000 W appliance operates for 3 hours; how much energy does it consume?","opts":["0.67 kWh","667 Wh","6 kWh","6000 kWh"],"correct":2,"re":"Energy = power x time = 2000 W x 3 h = 6000 Wh = 6 kWh.","qr":"Прибор мощностью 2000 Вт работает 3 часа; сколько энергии он потребляет?","optsr":["0,67 kWh","667 Вт·ч","6 kWh","6000 kWh"],"rr":"Энергия = мощность x время = 2000 Вт x 3 ч = 6000 Вт·ч = 6 kWh.","qs":"Un electrodoméstico de 2000 W opera durante 3 horas; ¿cuánta energía consume?","optss":["0.67 kWh","667 Wh","6 kWh","6000 kWh"],"rs":"Energía = potencia x tiempo = 2000 W x 3 h = 6000 Wh = 6 kWh."},
  {"id":61,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a standard three-wire start/stop control circuit, how are the start and stop pushbuttons typically wired?","opts":["Start is normally closed and stop is normally open","Both buttons are normally closed and in parallel","Start (normally open) is in parallel with the holding contact, and stop (normally closed) is in series","Both buttons are normally open and in series"],"correct":2,"re":"A standard start/stop station uses a normally open start button (parallel with the holding contact to seal in) and a normally closed stop button in series, so pressing stop de-energizes the coil.","qr":"В стандартной трёхпроводной цепи управления пуск/стоп как обычно подключаются кнопки пуска и стоп?","optsr":["Пуск нормально замкнут, а стоп нормально разомкнут","Обе кнопки нормально замкнуты и параллельны","Пуск (нормально разомкнутый) параллельно удерживающему контакту, а стоп (нормально замкнутый) последовательно","Обе кнопки нормально разомкнуты и последовательны"],"rr":"Стандартный пост пуск/стоп использует нормально разомкнутую кнопку пуска (параллельно удерживающему контакту для самоблокировки) и нормально замкнутую кнопку стоп последовательно, поэтому нажатие стоп обесточивает катушку.","qs":"En un circuito de control estándar de arranque/paro de tres hilos, ¿cómo se cablean típicamente los botones de arranque y paro?","optss":["El de arranque es normalmente cerrado y el de paro es normalmente abierto","Ambos botones son normalmente cerrados y en paralelo","El de arranque (normalmente abierto) está en paralelo con el contacto de retención, y el de paro (normalmente cerrado) está en serie","Ambos botones son normalmente abiertos y en serie"],"rs":"Una estación estándar de arranque/paro usa un botón de arranque normalmente abierto (en paralelo con el contacto de retención para sellarse) y un botón de paro normalmente cerrado en serie, de modo que al presionar paro se desenergiza la bobina."},
  {"id":62,"sec":"Rough Wiring","block":1,"q":"Per Table 310.15(C)(1), what adjustment factor applies when 7 to 9 current-carrying conductors are run together in a raceway?","opts":["60%","80%","70%","50%"],"correct":2,"re":"For 7-9 current-carrying conductors, the adjustment factor is 70%. See NEC Table 310.15(C)(1).","qr":"Согласно Table 310.15(C)(1), какой коэффициент снижения применяется при наличии от 7 до 9 токоведущих проводников, проложенных вместе в трубе?","optsr":["60%","80%","70%","50%"],"rr":"Для 7-9 токоведущих проводников коэффициент снижения составляет 70%. См. NEC Table 310.15(C)(1).","qs":"Según la Table 310.15(C)(1), ¿qué factor de ajuste aplica cuando se tienden juntos de 7 a 9 conductores portadores de corriente en una canalización?","optss":["60%","80%","70%","50%"],"rs":"Para 7 a 9 conductores portadores de corriente, el factor de ajuste es 70%. Véase NEC Table 310.15(C)(1)."},
  {"id":63,"sec":"Safety","block":1,"q":"When performing the live-dead-live test, why must the voltage tester be checked on a known energized source both before and after testing the de-energized circuit?","opts":["To charge the tester's internal battery","To confirm the tester is functioning properly so a false 'dead' reading is not relied upon","To calibrate the tester to the local utility frequency","To discharge stored capacitance in the conductors"],"correct":1,"re":"Re-verifying the tester on a known live source after the dead test confirms the instrument did not fail during the test, ensuring the absence-of-voltage reading was valid before touching conductors.","qr":"При выполнении теста live-dead-live, почему детектор напряжения должен проверяться на заведомо живом источнике как до, так и после проверки обесточенной цепи?","optsr":["Чтобы зарядить внутреннюю батарею прибора","Чтобы подтвердить исправность прибора и не полагаться на ложное показание «отсутствия напряжения»","Чтобы откалибровать прибор под частоту местной коммунальной сети","Чтобы разрядить накопленную ёмкость в проводниках"],"rr":"Повторная проверка прибора на заведомо живом источнике после теста на отсутствие напряжения подтверждает, что прибор не вышел из строя во время проверки, гарантируя, что показание отсутствия напряжения было достоверным до прикосновения к проводникам.","qs":"Al realizar la prueba vivo-muerto-vivo, ¿por qué debe verificarse el comprobador de voltaje en una fuente energizada conocida tanto antes como después de probar el circuito desenergizado?","optss":["Para cargar la batería interna del comprobador","Para confirmar que el comprobador funciona correctamente y no se confíe en una lectura falsa de 'muerto'","Para calibrar el comprobador a la frecuencia de la empresa de servicios local","Para descargar la capacitancia almacenada en los conductores"],"rs":"Volver a verificar el comprobador en una fuente viva conocida después de la prueba de 'muerto' confirma que el instrumento no falló durante la prueba, asegurando que la lectura de ausencia de voltaje era válida antes de tocar los conductores."},
  {"id":64,"sec":"Planning & Estimation","block":1,"q":"If electricity costs 0.20 dollars per kWh, what does it cost to run a 5 kW load for 8 hours?","opts":["40.00 dollars","1.60 dollars","8.00 dollars","0.20 dollars"],"correct":2,"re":"Energy = 5 kW x 8 h = 40 kWh; cost = 40 x 0.20 = 8.00 dollars.","qr":"Если электроэнергия стоит 0,20 доллара за kWh, сколько стоит работа нагрузки 5 кВт в течение 8 часов?","optsr":["40,00 долларов","1,60 доллара","8,00 долларов","0,20 доллара"],"rr":"Энергия = 5 кВт x 8 ч = 40 kWh; стоимость = 40 x 0,20 = 8,00 долларов.","qs":"Si la electricidad cuesta 0.20 dólares por kWh, ¿cuánto cuesta operar una carga de 5 kW durante 8 horas?","optss":["40.00 dólares","1.60 dólares","8.00 dólares","0.20 dólares"],"rs":"Energía = 5 kW x 8 h = 40 kWh; costo = 40 x 0.20 = 8.00 dólares."},
  {"id":65,"sec":"Rough Wiring","block":1,"q":"At what number of current-carrying conductors in a single raceway do the Table 310.15(C)(1) adjustment factors first apply?","opts":["2 or more","More than 3 (4 or more)","3 or more","More than 9"],"correct":1,"re":"Adjustment factors begin when there are more than three current-carrying conductors (i.e., 4 or more). See NEC 310.15(C)(1).","qr":"При каком количестве токоведущих проводников в одной трубе впервые применяются коэффициенты снижения из Table 310.15(C)(1)?","optsr":["2 или больше","Более 3 (4 или больше)","3 или больше","Более 9"],"rr":"Коэффициенты снижения начинают применяться, когда токоведущих проводников более трёх (то есть 4 или больше). См. NEC 310.15(C)(1).","qs":"¿A partir de qué número de conductores portadores de corriente en una sola canalización comienzan a aplicar los factores de ajuste de la Table 310.15(C)(1)?","optss":["2 o más","Más de 3 (4 o más)","3 o más","Más de 9"],"rs":"Los factores de ajuste comienzan cuando hay más de tres conductores portadores de corriente (es decir, 4 o más). Véase NEC 310.15(C)(1)."},
  {"id":66,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"What is the main difference between a contactor and a magnetic motor starter?","opts":["A contactor includes built-in overload protection, but a starter does not","A contactor can only switch DC loads","A starter is essentially a contactor with integral overload protection added","A starter has no electromagnetic coil"],"correct":2,"re":"A magnetic motor starter is a contactor combined with an overload relay; a plain contactor switches the load but provides no running-overload protection.","qr":"В чём основное различие между контактором и магнитным пускателем двигателя?","optsr":["Контактор включает встроенную защиту от перегрузки, а пускатель нет","Контактор может коммутировать только нагрузки постоянного тока","Пускатель — это, по существу, контактор с добавленной встроенной защитой от перегрузки","У пускателя нет электромагнитной катушки"],"rr":"Магнитный пускатель двигателя — это контактор, объединённый с реле перегрузки; обычный контактор коммутирует нагрузку, но не обеспечивает защиту от рабочей перегрузки.","qs":"¿Cuál es la diferencia principal entre un contactor y un arrancador magnético de motor?","optss":["Un contactor incluye protección de sobrecarga integrada, pero un arrancador no","Un contactor solo puede conmutar cargas de CC","Un arrancador es esencialmente un contactor con protección de sobrecarga integral añadida","Un arrancador no tiene bobina electromagnética"],"rs":"Un arrancador magnético de motor es un contactor combinado con un relé de sobrecarga; un contactor simple conmuta la carga pero no proporciona protección de sobrecarga de funcionamiento."},
  {"id":67,"sec":"Finish Wiring & Trim","block":1,"q":"In a dwelling, hallways of at least what length require a minimum of one receptacle outlet?","opts":["15 feet","5 feet","12 feet","10 feet"],"correct":3,"re":"NEC 210.52(H) requires that hallways 10 ft (3.0 m) or more in length have at least one receptacle outlet.","qr":"В жилье коридоры какой минимальной длины требуют как минимум одну розетку?","optsr":["15 футов","5 футов","12 футов","10 футов"],"rr":"NEC 210.52(H) требует, чтобы коридоры длиной 10 футов (3,0 м) или более имели как минимум одну розетку.","qs":"En una vivienda, los pasillos de al menos qué longitud requieren un mínimo de una salida de tomacorriente?","optss":["15 pies","5 pies","12 pies","10 pies"],"rs":"NEC 210.52(H) requiere que los pasillos de 10 ft (3.0 m) o más de longitud tengan al menos una salida de tomacorriente."},
  {"id":68,"sec":"Planning & Estimation","block":1,"q":"A motor delivers 10 HP of mechanical output; approximately how many watts is this?","opts":["746 W","7460 W","1340 W","74.6 W"],"correct":1,"re":"Using 1 HP = 746 W, 10 HP = 10 x 746 = 7460 W.","qr":"Двигатель выдаёт 10 HP механической мощности; сколько это примерно ватт?","optsr":["746 Вт","7460 Вт","1340 Вт","74,6 Вт"],"rr":"Используя 1 HP = 746 Вт, 10 HP = 10 x 746 = 7460 Вт.","qs":"Un motor entrega 10 HP de salida mecánica; ¿aproximadamente cuántos watts son?","optss":["746 W","7460 W","1340 W","74.6 W"],"rs":"Usando 1 HP = 746 W, 10 HP = 10 x 746 = 7460 W."},
  {"id":69,"sec":"Safety","block":1,"q":"Per NFPA 70E, which condition justifies performing work on energized electrical conductors instead of de-energizing them?","opts":["The crew wants to finish the job faster","The supervisor verbally prefers energized work","De-energizing would introduce additional or increased hazards, or is infeasible due to equipment design or operational limitations","The equipment is rated above 600 volts"],"correct":2,"re":"NFPA 70E permits energized work only when de-energizing introduces additional or increased hazards (such as life-support shutdown) or is infeasible due to equipment design or operational limitations; convenience or saving time does not qualify.","qr":"Согласно NFPA 70E, какое условие оправдывает выполнение работы на проводниках под напряжением вместо их обесточивания?","optsr":["Бригада хочет закончить работу быстрее","Руководитель устно предпочитает работу под напряжением","Обесточивание создало бы дополнительные или повышенные опасности либо невыполнимо из-за конструкции оборудования или эксплуатационных ограничений","Оборудование рассчитано на напряжение выше 600 вольт"],"rr":"NFPA 70E допускает работу под напряжением только когда обесточивание создаёт дополнительные или повышенные опасности (например, отключение систем жизнеобеспечения) или невыполнимо из-за конструкции оборудования или эксплуатационных ограничений; удобство или экономия времени не подходят.","qs":"Según NFPA 70E, ¿qué condición justifica realizar trabajo en conductores eléctricos energizados en lugar de desenergizarlos?","optss":["La cuadrilla quiere terminar el trabajo más rápido","El supervisor prefiere verbalmente el trabajo energizado","Desenergizar introduciría peligros adicionales o mayores, o es inviable debido al diseño del equipo o a limitaciones operativas","El equipo está clasificado por encima de 600 voltios"],"rs":"NFPA 70E permite el trabajo energizado solo cuando desenergizar introduce peligros adicionales o mayores (como apagar un soporte vital) o es inviable debido al diseño del equipo o a limitaciones operativas; la conveniencia o el ahorro de tiempo no califican."},
  {"id":70,"sec":"Rough Wiring","block":1,"q":"Six current-carrying THHN copper 12 AWG conductors (90°C value 30 A) share one conduit; after applying the bundling adjustment, the adjusted ampacity is approximately:","opts":["30 A","27 A","21 A","24 A"],"correct":3,"re":"Starting from the 90°C value of 30 A and applying the 80% factor for 4-6 conductors gives 30 × 0.80 = 24 A. See NEC Table 310.15(C)(1).","qr":"Шесть токоведущих медных проводников THHN 12 AWG (значение 90°C = 30 A) проложены в одной трубе; после применения коэффициента за пучкование скорректированная ampacity составляет примерно:","optsr":["30 A","27 A","21 A","24 A"],"rr":"Начиная со значения 90°C = 30 A и применяя коэффициент 80% для 4-6 проводников, получаем 30 × 0.80 = 24 A. См. NEC Table 310.15(C)(1).","qs":"Seis conductores de cobre THHN 12 AWG portadores de corriente (valor de 90°C de 30 A) comparten un conduit; después de aplicar el ajuste por agrupamiento, la ampacidad ajustada es aproximadamente:","optss":["30 A","27 A","21 A","24 A"],"rs":"Partiendo del valor de 90°C de 30 A y aplicando el factor del 80% para 4 a 6 conductores se obtiene 30 × 0.80 = 24 A. Véase NEC Table 310.15(C)(1)."},
  {"id":71,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"When the overload relay of a magnetic motor starter trips, which circuit does it directly open to stop the motor?","opts":["The control circuit, de-energizing the starter coil","The main power (line) conductors to the motor","The equipment grounding conductor","The branch-circuit feeder"],"correct":0,"re":"Overload relay contacts are wired into the control circuit; when they trip open, the starter coil de-energizes, dropping out the main contacts and disconnecting the motor.","qr":"Когда реле перегрузки магнитного пускателя двигателя срабатывает, какую цепь оно непосредственно размыкает для остановки двигателя?","optsr":["Цепь управления, обесточивая катушку пускателя","Основные силовые (линейные) проводники к двигателю","Заземляющий проводник оборудования","Питающую линию ответвления"],"rr":"Контакты реле перегрузки включены в цепь управления; при их размыкании катушка пускателя обесточивается, отключая главные контакты и двигатель.","qs":"Cuando el relé de sobrecarga de un arrancador magnético de motor se dispara, ¿qué circuito abre directamente para detener el motor?","optss":["El circuito de control, desenergizando la bobina del arrancador","Los conductores principales de potencia (línea) hacia el motor","El conductor de puesta a tierra del equipo","El alimentador del circuito ramal"],"rs":"Los contactos del relé de sobrecarga están cableados en el circuito de control; cuando se disparan y abren, la bobina del arrancador se desenergiza, liberando los contactos principales y desconectando el motor."},
  {"id":72,"sec":"Planning & Estimation","block":1,"q":"A 5 HP motor is 100 percent efficient and runs on 240 V single-phase at PF 1; what current does it draw?","opts":["3730 A","15.5 A","0.064 A","31 A"],"correct":1,"re":"P = 5 x 746 = 3730 W; I = P/V = 3730/240 = 15.5 A.","qr":"Двигатель 5 HP со 100-процентным КПД работает от 240 В однофазной сети при PF 1; какой ток он потребляет?","optsr":["3730 А","15,5 А","0,064 А","31 А"],"rr":"P = 5 x 746 = 3730 Вт; I = P/V = 3730/240 = 15,5 А.","qs":"Un motor de 5 HP es 100 por ciento eficiente y funciona a 240 V monofásico con PF 1; ¿qué corriente consume?","optss":["3730 A","15.5 A","0.064 A","31 A"],"rs":"P = 5 x 746 = 3730 W; I = P/V = 3730/240 = 15.5 A."},
  {"id":73,"sec":"Rough Wiring","block":1,"q":"Eight current-carrying conductors with a 90°C base ampacity of 40 A each are bundled in a raceway; the adjusted ampacity is:","opts":["40 A","36 A","28 A","32 A"],"correct":2,"re":"For 7-9 conductors the factor is 70%, so 40 × 0.70 = 28 A. See NEC Table 310.15(C)(1).","qr":"Восемь токоведущих проводников с базовой ampacity 90°C по 40 A каждый собраны в пучок в трубе; скорректированная ampacity равна:","optsr":["40 A","36 A","28 A","32 A"],"rr":"Для 7-9 проводников коэффициент 70%, поэтому 40 × 0.70 = 28 A. См. NEC Table 310.15(C)(1).","qs":"Ocho conductores portadores de corriente con una ampacidad base de 90°C de 40 A cada uno se agrupan en una canalización; la ampacidad ajustada es:","optss":["40 A","36 A","28 A","32 A"],"rs":"Para 7 a 9 conductores el factor es 70%, así que 40 × 0.70 = 28 A. Véase NEC Table 310.15(C)(1)."},
  {"id":74,"sec":"Safety","block":1,"q":"What is the function of the limited approach boundary under NFPA 70E?","opts":["It is the distance from an exposed energized part within which a shock hazard exists","It is the maximum reach of a bucket truck","It marks the edge of the equipment grounding electrode system","It is the boundary for fire-sprinkler coverage"],"correct":0,"re":"The limited approach boundary is the distance from an exposed energized conductor or circuit part within which a shock hazard exists; unqualified persons must not cross it without a qualified escort.","qr":"Какова функция limited approach boundary согласно NFPA 70E?","optsr":["Это расстояние от открытой части под напряжением, в пределах которого существует опасность поражения током","Это максимальный вылет автовышки","Она отмечает край системы заземляющих электродов оборудования","Это граница зоны покрытия пожарными спринклерами"],"rr":"Limited approach boundary — это расстояние от открытого проводника или части цепи под напряжением, в пределах которого существует опасность поражения током; неквалифицированные лица не должны пересекать её без квалифицированного сопровождающего.","qs":"¿Cuál es la función del límite de aproximación limitada según NFPA 70E?","optss":["Es la distancia desde una parte energizada expuesta dentro de la cual existe un peligro de descarga","Es el alcance máximo de un camión con canastilla","Marca el borde del sistema de electrodos de puesta a tierra del equipo","Es el límite para la cobertura de rociadores contra incendios"],"rs":"El límite de aproximación limitada es la distancia desde un conductor o parte de circuito energizada expuesta dentro de la cual existe un peligro de descarga; las personas no calificadas no deben cruzarlo sin un escolta calificado."},
  {"id":75,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a typical motor control circuit using a control transformer, what voltage is most commonly supplied to the control circuit?","opts":["480 volts","240 volts","24 volts","120 volts"],"correct":3,"re":"Control transformers commonly step the line voltage down to 120 volts for the control circuit, providing safer and standardized voltage for pilot devices and coils.","qr":"В типичной цепи управления двигателем с управляющим трансформатором какое напряжение чаще всего подаётся в цепь управления?","optsr":["480 вольт","240 вольт","24 вольта","120 вольт"],"rr":"Управляющие трансформаторы обычно понижают линейное напряжение до 120 вольт для цепи управления, обеспечивая более безопасное и стандартизированное напряжение для пилотных устройств и катушек.","qs":"En un circuito de control de motor típico que usa un transformador de control, ¿qué voltaje se suministra más comúnmente al circuito de control?","optss":["480 voltios","240 voltios","24 voltios","120 voltios"],"rs":"Los transformadores de control comúnmente reducen el voltaje de línea a 120 voltios para el circuito de control, proporcionando un voltaje más seguro y estandarizado para los dispositivos piloto y las bobinas."},
  {"id":76,"sec":"Finish Wiring & Trim","block":1,"q":"A dwelling unit must have at least how many receptacle outlets installed for each bathroom, located adjacent to each basin?","opts":["None are required","At least two per bathroom","One only if the room exceeds 50 sq ft","At least one within 36 in. of the outside edge of each basin"],"correct":3,"re":"NEC 210.52(D) requires at least one receptacle outlet installed within 36 in. of the outside edge of each bathroom basin (lavatory).","qr":"В жилом помещении должно быть установлено как минимум сколько розеток для каждой ванной комнаты, расположенных рядом с каждой раковиной?","optsr":["Не требуется","Как минимум две на ванную комнату","Только одну, если площадь комнаты превышает 50 кв. футов","Как минимум одну в пределах 36 дюймов от внешнего края каждой раковины"],"rr":"NEC 210.52(D) требует как минимум одну розетку, установленную в пределах 36 дюймов от внешнего края каждой раковины (умывальника) ванной комнаты.","qs":"Una unidad de vivienda debe tener al menos cuántas salidas de tomacorriente instaladas por cada baño, ubicadas adyacentes a cada lavabo?","optss":["No se requiere ninguna","Al menos dos por baño","Una solo si la habitación excede 50 sq ft","Al menos una dentro de 36 in. del borde exterior de cada lavabo"],"rs":"NEC 210.52(D) requiere al menos una salida de tomacorriente instalada dentro de 36 in. del borde exterior de cada lavabo (lavamanos) de baño."},
  {"id":77,"sec":"Planning & Estimation","block":1,"q":"A motor has an input of 5000 W and an output of 4000 W; what is its efficiency?","opts":["125 percent","80 percent","20 percent","90 percent"],"correct":1,"re":"Efficiency = output/input = 4000/5000 = 0.80 = 80 percent.","qr":"Двигатель имеет входную мощность 5000 Вт и выходную 4000 Вт; каков его КПД?","optsr":["125 процентов","80 процентов","20 процентов","90 процентов"],"rr":"КПД = выход/вход = 4000/5000 = 0,80 = 80 процентов.","qs":"Un motor tiene una entrada de 5000 W y una salida de 4000 W; ¿cuál es su eficiencia?","optss":["125 por ciento","80 por ciento","20 por ciento","90 por ciento"],"rs":"Eficiencia = salida/entrada = 4000/5000 = 0.80 = 80 por ciento."},
  {"id":78,"sec":"Rough Wiring","block":1,"q":"In a normally balanced 3-wire, single-phase, 120/240-volt circuit, the neutral conductor is:","opts":["Always counted as a current-carrying conductor","Counted only if the load is over 50 amps","Not counted as a current-carrying conductor","Counted as two conductors"],"correct":2,"re":"The neutral of a balanced single-phase 3-wire circuit carries only unbalanced current and is not counted as current-carrying. See NEC 310.15(E).","qr":"В нормально сбалансированной 3-проводной однофазной цепи 120/240 В нейтральный проводник:","optsr":["Всегда считается токоведущим проводником","Считается только если нагрузка превышает 50 ампер","Не считается токоведущим проводником","Считается за два проводника"],"rr":"Нейтраль сбалансированной однофазной 3-проводной цепи несёт только небалансный ток и не считается токоведущей. См. NEC 310.15(E).","qs":"En un circuito monofásico de 3 hilos, 120/240 voltios, normalmente balanceado, el conductor neutro es:","optss":["Siempre contado como conductor portador de corriente","Contado solo si la carga supera los 50 amperios","No contado como conductor portador de corriente","Contado como dos conductores"],"rs":"El neutro de un circuito monofásico balanceado de 3 hilos solo conduce la corriente desbalanceada y no se cuenta como portador de corriente. Véase NEC 310.15(E)."},
  {"id":79,"sec":"Safety","block":1,"q":"Before energizing newly installed equipment after maintenance under Cal/OSHA T8 Section 3314, what must be verified?","opts":["That the warranty paperwork is filed","That the paint on the enclosure has dried","That all employees are clear, tools removed, guards reinstalled, and each worker has removed their own lock before re-energizing","That the utility bill has been paid"],"correct":2,"re":"Cal/OSHA T8 Section 3314 requires that before re-energizing, the work area is inspected to ensure nonessential items are removed, components are intact, employees are clear, and each authorized employee removes their own lockout device.","qr":"Перед подачей напряжения на вновь установленное оборудование после обслуживания согласно разделу 3314 Title 8 Cal/OSHA, что должно быть проверено?","optsr":["Что гарантийные документы поданы","Что краска на корпусе высохла","Что все работники удалены, инструменты убраны, ограждения установлены на место, и каждый работник снял свой собственный замок перед повторной подачей напряжения","Что счёт за электроэнергию оплачен"],"rr":"Раздел 3314 Title 8 Cal/OSHA требует, чтобы перед повторной подачей напряжения рабочая зона была проверена для удаления несущественных предметов, целостности компонентов, удаления работников, и каждый уполномоченный работник снял своё собственное блокирующее устройство.","qs":"Antes de energizar equipo recién instalado después del mantenimiento según Cal/OSHA T8 Section 3314, ¿qué debe verificarse?","optss":["Que el papeleo de la garantía esté archivado","Que la pintura del gabinete se haya secado","Que todos los empleados estén despejados, las herramientas retiradas, las guardas reinstaladas y que cada trabajador haya retirado su propio candado antes de reenergizar","Que la factura de servicios se haya pagado"],"rs":"Cal/OSHA T8 Section 3314 requiere que antes de reenergizar, se inspeccione el área de trabajo para asegurar que se hayan retirado los elementos no esenciales, los componentes estén intactos, los empleados estén despejados y cada empleado autorizado retire su propio dispositivo de bloqueo."},
  {"id":80,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"What does a reversing magnetic starter use to change the direction of a three-phase motor?","opts":["A single contactor with a reversing coil","Two contactors (forward and reverse) that interchange two of the line leads","A variable resistor in the rotor circuit","A capacitor bank switched into the line"],"correct":1,"re":"A reversing starter uses two mechanically and electrically interlocked contactors; the reverse contactor is wired to swap two of the three line leads, reversing rotation.","qr":"Что использует реверсивный магнитный пускатель для изменения направления трёхфазного двигателя?","optsr":["Один контактор с реверсивной катушкой","Два контактора (вперёд и назад), которые меняют местами два из линейных вводов","Переменный резистор в цепи ротора","Конденсаторную батарею, подключаемую к линии"],"rr":"Реверсивный пускатель использует два механически и электрически взаимоблокированных контактора; контактор реверса подключён так, чтобы менять местами два из трёх линейных вводов, изменяя направление вращения.","qs":"¿Qué utiliza un arrancador magnético reversible para cambiar la dirección de un motor trifásico?","optss":["Un solo contactor con una bobina reversible","Dos contactores (avance y retroceso) que intercambian dos de los conductores de línea","Una resistencia variable en el circuito del rotor","Un banco de capacitores conmutado en la línea"],"rs":"Un arrancador reversible usa dos contactores enclavados mecánica y eléctricamente; el contactor de retroceso está cableado para intercambiar dos de los tres conductores de línea, invirtiendo la rotación."},
  {"id":81,"sec":"Rough Wiring","block":1,"q":"When is the neutral conductor of a 4-wire, 3-phase wye circuit required to be counted as a current-carrying conductor?","opts":["Never","Only when it carries unbalanced current of a linear load","When the major portion of the load consists of nonlinear loads","Only on 480Y/277-volt systems"],"correct":2,"re":"Per NEC 310.15(E), the neutral is counted when the major portion of the load is nonlinear (harmonic) because it then carries significant current.","qr":"Когда нейтральный проводник 4-проводной трёхфазной цепи звезда обязан учитываться как токоведущий?","optsr":["Никогда","Только когда он несёт небалансный ток линейной нагрузки","Когда большую часть нагрузки составляют нелинейные нагрузки","Только в системах 480Y/277 В"],"rr":"Согласно NEC 310.15(E), нейтраль учитывается, когда большую часть нагрузки составляют нелинейные (гармонические) нагрузки, так как тогда она несёт значительный ток.","qs":"¿Cuándo se requiere contar el conductor neutro de un circuito en estrella (wye) trifásico de 4 hilos como conductor portador de corriente?","optss":["Nunca","Solo cuando conduce corriente desbalanceada de una carga lineal","Cuando la mayor parte de la carga consiste en cargas no lineales","Solo en sistemas de 480Y/277 voltios"],"rs":"Según NEC 310.15(E), el neutro se cuenta cuando la mayor parte de la carga es no lineal (armónica), porque entonces conduce corriente significativa."},
  {"id":82,"sec":"Planning & Estimation","block":1,"q":"A motor delivers 3 HP at the shaft with an efficiency of 75 percent; what is the electrical input power?","opts":["2984 W","1678 W","2238 W","1119 W"],"correct":0,"re":"Output = 3 x 746 = 2238 W; input = output/eff = 2238/0.75 = 2984 W.","qr":"Двигатель выдаёт 3 HP на валу при КПД 75 процентов; какова входная электрическая мощность?","optsr":["2984 Вт","1678 Вт","2238 Вт","1119 Вт"],"rr":"Выход = 3 x 746 = 2238 Вт; вход = выход/КПД = 2238/0,75 = 2984 Вт.","qs":"Un motor entrega 3 HP en el eje con una eficiencia del 75 por ciento; ¿cuál es la potencia eléctrica de entrada?","optss":["2984 W","1678 W","2238 W","1119 W"],"rs":"Salida = 3 x 746 = 2238 W; entrada = salida/eficiencia = 2238/0.75 = 2984 W."},
  {"id":83,"sec":"Safety","block":1,"q":"An arc-flash hazard analysis primarily determines which two key items for a piece of equipment?","opts":["The conductor insulation color and conduit size","The breaker manufacturer and catalog number","The ambient temperature and humidity","The incident energy (or PPE category) and the arc-flash boundary"],"correct":3,"re":"An arc-flash risk assessment establishes the incident energy (or assigns a PPE category) and the arc-flash boundary so the correct arc-rated PPE can be selected and the protection distance known.","qr":"Анализ опасности дугового разряда главным образом определяет какие два ключевых параметра для единицы оборудования?","optsr":["Цвет изоляции проводника и размер кабелепровода","Производителя автоматического выключателя и каталожный номер","Температуру и влажность окружающей среды","Падающую энергию (или категорию СИЗ) и границу дугового разряда"],"rr":"Оценка риска дугового разряда устанавливает падающую энергию (или присваивает категорию СИЗ) и границу дугового разряда, чтобы можно было выбрать правильные СИЗ с дуговой защитой и знать защитное расстояние.","qs":"Un análisis de peligro de arco eléctrico determina principalmente cuáles dos elementos clave para una pieza de equipo?","optss":["El color del aislamiento del conductor y el tamaño del conduit","El fabricante del interruptor y el número de catálogo","La temperatura ambiente y la humedad","La energía incidente (o categoría de EPP) y el límite de arco eléctrico"],"rs":"Una evaluación de riesgo de arco eléctrico establece la energía incidente (o asigna una categoría de EPP) y el límite de arco eléctrico para poder seleccionar el EPP con clasificación de arco correcto y conocer la distancia de protección."},
  {"id":84,"sec":"Rough Wiring","block":1,"q":"In a 3-wire circuit taken from two phases and the neutral of a 3-phase, 4-wire wye system, the neutral is:","opts":["Not counted as current-carrying","Counted as a current-carrying conductor","Counted as half a conductor","Allowed to be smaller than the phases"],"correct":1,"re":"Per NEC 310.15(E), the neutral of such a 3-wire wye circuit carries approximately the same current as the phase conductors and is counted as current-carrying.","qr":"В 3-проводной цепи, взятой от двух фаз и нейтрали трёхфазной 4-проводной системы звезда, нейтраль:","optsr":["Не считается токоведущей","Считается токоведущим проводником","Считается за половину проводника","Может быть меньше фазных"],"rr":"Согласно NEC 310.15(E), нейтраль такой 3-проводной цепи звезда несёт примерно такой же ток, как и фазные проводники, и считается токоведущей.","qs":"En un circuito de 3 hilos tomado de dos fases y el neutro de un sistema trifásico en estrella (wye) de 4 hilos, el neutro es:","optss":["No contado como portador de corriente","Contado como conductor portador de corriente","Contado como medio conductor","Permitido ser más pequeño que las fases"],"rs":"Según NEC 310.15(E), el neutro de tal circuito en estrella de 3 hilos conduce aproximadamente la misma corriente que los conductores de fase y se cuenta como portador de corriente."},
  {"id":85,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"Why are the forward and reverse contactors in a reversing starter mechanically and electrically interlocked?","opts":["To prevent both contactors from closing at the same time, which would cause a line-to-line short","To increase the motor torque","To reduce the control voltage","To allow simultaneous two-direction operation"],"correct":0,"re":"Interlocking ensures only one direction contactor can be energized at a time; closing both would connect two phases together through the swapped leads, creating a phase-to-phase short circuit.","qr":"Почему контакторы прямого и обратного хода в реверсивном пускателе механически и электрически взаимоблокированы?","optsr":["Чтобы предотвратить одновременное замыкание обоих контакторов, которое вызвало бы межфазное короткое замыкание","Чтобы увеличить крутящий момент двигателя","Чтобы снизить управляющее напряжение","Чтобы обеспечить одновременную работу в двух направлениях"],"rr":"Взаимоблокировка гарантирует, что одновременно может быть включён только один контактор направления; замыкание обоих соединило бы две фазы через переставленные вводы, создав межфазное короткое замыкание.","qs":"¿Por qué los contactores de avance y retroceso en un arrancador reversible están enclavados mecánica y eléctricamente?","optss":["Para evitar que ambos contactores se cierren al mismo tiempo, lo que causaría un cortocircuito de línea a línea","Para aumentar el par del motor","Para reducir el voltaje de control","Para permitir la operación simultánea en dos direcciones"],"rs":"El enclavamiento asegura que solo un contactor de dirección pueda energizarse a la vez; cerrar ambos conectaría dos fases entre sí a través de los conductores intercambiados, creando un cortocircuito de fase a fase."},
  {"id":86,"sec":"Finish Wiring & Trim","block":1,"q":"A dwelling unit foyer that is not part of a hallway and has an area greater than 60 sq ft requires receptacle outlets on any wall space how wide or wider?","opts":["3 ft","2 ft","1 ft","4 ft"],"correct":0,"re":"NEC 210.52(I) requires receptacle outlets in foyers larger than 60 sq ft for each wall space 3 ft (900 mm) or more in width that is unbroken by doorways and similar openings.","qr":"Прихожая жилого помещения, не являющаяся частью коридора и имеющая площадь более 60 кв. футов, требует розеток на любом пространстве стены какой ширины или шире?","optsr":["3 фута","2 фута","1 фут","4 фута"],"rr":"NEC 210.52(I) требует розетки в прихожих площадью более 60 кв. футов для каждого пространства стены шириной 3 фута (900 мм) или более, не прерванного дверными проёмами и подобными отверстиями.","qs":"Un vestíbulo (foyer) de una unidad de vivienda que no es parte de un pasillo y tiene un área mayor a 60 sq ft requiere salidas de tomacorriente en cualquier espacio de pared de qué ancho o mayor?","optss":["3 ft","2 ft","1 ft","4 ft"],"rs":"NEC 210.52(I) requiere salidas de tomacorriente en vestíbulos mayores a 60 sq ft para cada espacio de pared de 3 ft (900 mm) o más de ancho que no esté interrumpido por puertas y aberturas similares."},
  {"id":87,"sec":"Planning & Estimation","block":1,"q":"A single-phase motor draws 10 A at 240 V and delivers 1800 W of real power; what is its power factor?","opts":["0.90","1.33","0.50","0.75"],"correct":3,"re":"PF = P / (V x I) = 1800 / (240 x 10) = 1800/2400 = 0.75.","qr":"Однофазный двигатель потребляет 10 А при 240 В и выдаёт 1800 Вт активной мощности; каков его коэффициент мощности?","optsr":["0,90","1,33","0,50","0,75"],"rr":"PF = P / (V x I) = 1800 / (240 x 10) = 1800/2400 = 0,75.","qs":"Un motor monofásico consume 10 A a 240 V y entrega 1800 W de potencia real; ¿cuál es su factor de potencia?","optss":["0.90","1.33","0.50","0.75"],"rs":"PF = P / (V x I) = 1800 / (240 x 10) = 1800/2400 = 0.75."},
  {"id":88,"sec":"Rough Wiring","block":1,"q":"An equipment grounding conductor (EGC) run in the same raceway as the circuit conductors is counted as how many current-carrying conductors?","opts":["One","Two","Zero","Depends on its size"],"correct":2,"re":"Grounding and bonding conductors are not counted as current-carrying conductors for adjustment purposes. See NEC 310.15(E).","qr":"Заземляющий проводник оборудования (EGC), проложенный в той же трубе, что и проводники цепи, считается за сколько токоведущих проводников?","optsr":["Один","Два","Ноль","Зависит от его сечения"],"rr":"Заземляющие и уравнивающие проводники не считаются токоведущими при расчёте коэффициентов снижения. См. NEC 310.15(E).","qs":"Un conductor de puesta a tierra del equipo (EGC) tendido en la misma canalización que los conductores del circuito se cuenta como cuántos conductores portadores de corriente?","optss":["Uno","Dos","Cero","Depende de su tamaño"],"rs":"Los conductores de puesta a tierra y de unión no se cuentan como conductores portadores de corriente para fines de ajuste. Véase NEC 310.15(E)."},
  {"id":89,"sec":"Safety","block":1,"q":"Which device is appropriate for verifying the absence of voltage during the test-before-touch step?","opts":["A non-contact pen-type detector used by itself as the sole means","A continuity ohmmeter set to the resistance scale","A clamp ammeter reading load current","An adequately rated contact voltage tester confirmed working before and after the test"],"correct":3,"re":"NFPA 70E requires an adequately rated voltage detector or tester to verify absence of voltage, and the device must be tested for proper operation immediately before and after the absence-of-voltage test.","qr":"Какой прибор подходит для проверки отсутствия напряжения на этапе проверки перед прикосновением?","optsr":["Бесконтактный детектор-ручка, используемый сам по себе как единственное средство","Омметр для проверки целостности цепи на шкале сопротивления","Токоизмерительные клещи, измеряющие ток нагрузки","Контактный детектор напряжения соответствующего класса, исправность которого подтверждена до и после проверки"],"rr":"NFPA 70E требует детектора или тестера напряжения соответствующего класса для проверки отсутствия напряжения, и прибор должен быть проверен на правильную работу непосредственно до и после теста на отсутствие напряжения.","qs":"¿Qué dispositivo es apropiado para verificar la ausencia de voltaje durante el paso de probar antes de tocar?","optss":["Un detector tipo pluma sin contacto usado por sí solo como único medio","Un ohmímetro de continuidad ajustado a la escala de resistencia","Un amperímetro de gancho leyendo la corriente de carga","Un comprobador de voltaje de contacto con clasificación adecuada, confirmado en funcionamiento antes y después de la prueba"],"rs":"NFPA 70E requiere un detector o comprobador de voltaje con clasificación adecuada para verificar la ausencia de voltaje, y el dispositivo debe probarse para su correcto funcionamiento inmediatamente antes y después de la prueba de ausencia de voltaje."},
  {"id":90,"sec":"Planning & Estimation","block":1,"q":"What is the real power of a single-phase load drawing 20 A at 120 V with a power factor of 0.85?","opts":["2400 W","102 W","2823 W","2040 W"],"correct":3,"re":"Real power P = V x I x PF = 120 x 20 x 0.85 = 2040 W.","qr":"Какова активная мощность однофазной нагрузки, потребляющей 20 А при 120 В с коэффициентом мощности 0,85?","optsr":["2400 Вт","102 Вт","2823 Вт","2040 Вт"],"rr":"Активная мощность P = V x I x PF = 120 x 20 x 0,85 = 2040 Вт.","qs":"¿Cuál es la potencia real de una carga monofásica que consume 20 A a 120 V con un factor de potencia de 0.85?","optss":["2400 W","102 W","2823 W","2040 W"],"rs":"Potencia real P = V x I x PF = 120 x 20 x 0.85 = 2040 W."},
  {"id":91,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"How does a single-phase induction motor differ from a three-phase induction motor regarding starting?","opts":["A single-phase motor requires an auxiliary starting method (such as a start winding), while a three-phase motor is self-starting","A single-phase motor is inherently self-starting with no auxiliary means","A three-phase motor cannot start under load","Both require a capacitor to start"],"correct":0,"re":"A three-phase motor produces a rotating magnetic field and is self-starting; a single-phase motor's pulsating field is not, so it needs a start winding (and often a capacitor) to develop starting torque.","qr":"Чем однофазный асинхронный двигатель отличается от трёхфазного асинхронного двигателя в отношении пуска?","optsr":["Однофазному двигателю требуется вспомогательный метод пуска (например, пусковая обмотка), а трёхфазный двигатель самозапускающийся","Однофазный двигатель самозапускающийся без вспомогательных средств","Трёхфазный двигатель не может запускаться под нагрузкой","Оба требуют конденсатор для пуска"],"rr":"Трёхфазный двигатель создаёт вращающееся магнитное поле и самозапускающийся; пульсирующее поле однофазного двигателя — нет, поэтому ему нужна пусковая обмотка (и часто конденсатор) для создания пускового момента.","qs":"¿En qué se diferencia un motor de inducción monofásico de un motor de inducción trifásico respecto al arranque?","optss":["Un motor monofásico requiere un método de arranque auxiliar (como un devanado de arranque), mientras que un motor trifásico es de arranque automático","Un motor monofásico es inherentemente de arranque automático sin medios auxiliares","Un motor trifásico no puede arrancar bajo carga","Ambos requieren un capacitor para arrancar"],"rs":"Un motor trifásico produce un campo magnético giratorio y es de arranque automático; el campo pulsante de un motor monofásico no lo es, por lo que necesita un devanado de arranque (y a menudo un capacitor) para desarrollar par de arranque."},
  {"id":92,"sec":"Rough Wiring","block":1,"q":"What is the minimum conductor size generally permitted for conductors installed in parallel?","opts":["4 AWG","1/0 AWG","1 AWG","2/0 AWG"],"correct":1,"re":"NEC 310.10(G) (parallel conductors) permits paralleling only for sizes 1/0 AWG and larger, with limited exceptions.","qr":"Какой минимальный размер проводника обычно разрешён для проводников, соединяемых параллельно?","optsr":["4 AWG","1/0 AWG","1 AWG","2/0 AWG"],"rr":"NEC 310.10(G) (параллельные проводники) разрешает параллельное соединение только для размеров 1/0 AWG и больше, с ограниченными исключениями.","qs":"¿Cuál es el tamaño mínimo de conductor generalmente permitido para conductores instalados en paralelo?","optss":["4 AWG","1/0 AWG","1 AWG","2/0 AWG"],"rs":"NEC 310.10(G) (conductores en paralelo) permite el paralelaje solo para tamaños 1/0 AWG y mayores, con excepciones limitadas."},
  {"id":93,"sec":"Safety","block":1,"q":"Under Cal/OSHA T8 Section 3314, what must be done with stored energy (such as charged capacitors or spring tension) during lockout?","opts":["It may be ignored if the main disconnect is locked open","It should be increased to test the equipment","It must be relieved, disconnected, restrained, or otherwise rendered safe before work begins","It must be measured but left in place"],"correct":2,"re":"Cal/OSHA T8 Section 3314 requires that stored or residual energy be dissipated or restrained so that it cannot cause injury; locking the disconnect alone does not address stored capacitive or mechanical energy.","qr":"Согласно разделу 3314 Title 8 Cal/OSHA, что необходимо сделать с накопленной энергией (например, заряженными конденсаторами или натяжением пружины) во время блокировки?","optsr":["Её можно игнорировать, если главный разъединитель заблокирован в разомкнутом положении","Её следует увеличить для проверки оборудования","Она должна быть сброшена, отсоединена, ограничена или иным образом сделана безопасной до начала работы","Её необходимо измерить, но оставить на месте"],"rr":"Раздел 3314 Title 8 Cal/OSHA требует, чтобы накопленная или остаточная энергия была рассеяна или ограничена так, чтобы она не могла причинить травму; одна только блокировка разъединителя не устраняет накопленную ёмкостную или механическую энергию.","qs":"Según Cal/OSHA T8 Section 3314, ¿qué debe hacerse con la energía almacenada (como capacitores cargados o tensión de resortes) durante el bloqueo?","optss":["Puede ignorarse si la desconexión principal está bloqueada en posición abierta","Debe aumentarse para probar el equipo","Debe liberarse, desconectarse, restringirse o hacerse segura de otra manera antes de comenzar el trabajo","Debe medirse pero dejarse en su lugar"],"rs":"Cal/OSHA T8 Section 3314 requiere que la energía almacenada o residual sea disipada o restringida de modo que no pueda causar lesiones; bloquear la desconexión por sí solo no aborda la energía capacitiva o mecánica almacenada."},
  {"id":94,"sec":"Planning & Estimation","block":1,"q":"A single-phase circuit carries 25 A over a one-way length where the total conductor resistance for the run is 0.4 ohms; what is the voltage drop?","opts":["10 V","62.5 V","0.016 V","100 V"],"correct":0,"re":"Voltage drop Vd = I x R = 25 x 0.4 = 10 V.","qr":"Однофазная цепь несёт 25 А по трассе, где суммарное сопротивление проводников составляет 0,4 Ом; какова потеря напряжения?","optsr":["10 В","62,5 В","0,016 В","100 В"],"rr":"Потеря напряжения Vd = I x R = 25 x 0,4 = 10 В.","qs":"Un circuito monofásico conduce 25 A a lo largo de un tendido de un solo sentido donde la resistencia total del conductor para el tendido es de 0.4 ohmios; ¿cuál es la caída de voltaje?","optss":["10 V","62.5 V","0.016 V","100 V"],"rs":"Caída de voltaje Vd = I x R = 25 x 0.4 = 10 V."},
  {"id":95,"sec":"Finish Wiring & Trim","block":1,"q":"Which dwelling location requires that 125-volt, 15- and 20-amp receptacles be GFCI-protected?","opts":["A bedroom closet","A bathroom","An attic crawl space with no equipment","A formal dining room"],"correct":1,"re":"NEC 210.8(A) lists bathrooms among the dwelling locations where 125-volt, 15- and 20-amp receptacles must have ground-fault circuit-interrupter protection.","qr":"Какое место в жилье требует, чтобы розетки 125 В, 15 и 20 А были защищены GFCI?","optsr":["Шкаф в спальне","Ванная комната","Чердачное пространство без оборудования","Парадная столовая"],"rr":"NEC 210.8(A) перечисляет ванные комнаты среди мест в жилье, где розетки 125 В, 15 и 20 А должны иметь защиту устройством защитного отключения по току утечки (GFCI).","qs":"¿Qué ubicación de vivienda requiere que los tomacorrientes de 125 voltios, 15 y 20 amperios estén protegidos con GFCI?","optss":["Un clóset de dormitorio","Un baño","Un espacio de gateo en el ático sin equipos","Un comedor formal"],"rs":"NEC 210.8(A) incluye los baños entre las ubicaciones de vivienda donde los tomacorrientes de 125 voltios, 15 y 20 amperios deben tener protección de interruptor de circuito por falla a tierra (GFCI)."},
  {"id":96,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a capacitor-start single-phase motor, what is the purpose of the start capacitor?","opts":["To create a phase shift in the start winding so the motor develops starting torque","To improve the running power factor continuously","To limit the locked-rotor current to the run winding","To convert single-phase power to three-phase"],"correct":0,"re":"The start capacitor shifts the current in the start winding out of phase with the run winding, producing a rotating field that gives high starting torque.","qr":"В однофазном двигателе с конденсаторным пуском какова цель пускового конденсатора?","optsr":["Создавать фазовый сдвиг в пусковой обмотке, чтобы двигатель развивал пусковой момент","Постоянно улучшать рабочий коэффициент мощности","Ограничивать ток заторможенного ротора в рабочей обмотке","Преобразовывать однофазное питание в трёхфазное"],"rr":"Пусковой конденсатор сдвигает ток в пусковой обмотке по фазе относительно рабочей обмотки, создавая вращающееся поле, которое обеспечивает высокий пусковой момент.","qs":"En un motor monofásico de arranque por capacitor, ¿cuál es el propósito del capacitor de arranque?","optss":["Crear un desfase en el devanado de arranque para que el motor desarrolle par de arranque","Mejorar continuamente el factor de potencia de funcionamiento","Limitar la corriente de rotor bloqueado al devanado de funcionamiento","Convertir la potencia monofásica en trifásica"],"rs":"El capacitor de arranque desfasa la corriente en el devanado de arranque respecto al devanado de funcionamiento, produciendo un campo giratorio que proporciona un alto par de arranque."},
  {"id":97,"sec":"Rough Wiring","block":1,"q":"When conductors are installed in parallel, the paralleled conductors of each phase must be:","opts":["Different sizes to balance load","The same length, material, and size","Of different insulation types","Connected with different terminations"],"correct":1,"re":"Per NEC 310.10(G), paralleled conductors of each phase must be identical in length, material, size, and insulation and terminated the same way.","qr":"Когда проводники соединяются параллельно, параллельные проводники каждой фазы должны быть:","optsr":["Разного сечения для балансировки нагрузки","Одинаковой длины, материала и сечения","Разных типов изоляции","Подключены разными способами"],"rr":"Согласно NEC 310.10(G), параллельные проводники каждой фазы должны быть одинаковыми по длине, материалу, сечению и изоляции и одинаково оконцованы.","qs":"Cuando los conductores se instalan en paralelo, los conductores en paralelo de cada fase deben ser:","optss":["De diferentes tamaños para balancear la carga","De la misma longitud, material y tamaño","De diferentes tipos de aislamiento","Conectados con diferentes terminaciones"],"rs":"Según NEC 310.10(G), los conductores en paralelo de cada fase deben ser idénticos en longitud, material, tamaño y aislamiento, y terminados de la misma manera."},
  {"id":98,"sec":"Planning & Estimation","block":1,"q":"A 120 V branch circuit has a measured voltage drop of 6 V; what is the percent voltage drop?","opts":["20 percent","0.5 percent","2 percent","5 percent"],"correct":3,"re":"Percent drop = Vd/Vsource x 100 = 6/120 x 100 = 5 percent.","qr":"Ответвлённая цепь 120 В имеет измеренную потерю напряжения 6 В; каков процент потери напряжения?","optsr":["20 процентов","0,5 процента","2 процента","5 процентов"],"rr":"Процент потери = Vd/Vисточника x 100 = 6/120 x 100 = 5 процентов.","qs":"Un circuito ramal de 120 V tiene una caída de voltaje medida de 6 V; ¿cuál es el porcentaje de caída de voltaje?","optss":["20 por ciento","0.5 por ciento","2 por ciento","5 por ciento"],"rs":"Porcentaje de caída = Vd/Vfuente x 100 = 6/120 x 100 = 5 por ciento."},
  {"id":99,"sec":"Safety","block":1,"q":"When may an unqualified person cross the limited approach boundary toward an exposed energized part?","opts":["Never, under any circumstances whatsoever","Any time, as long as they wear safety glasses","Only during daylight hours","Only when continuously escorted or advised by a qualified person and properly protected"],"correct":3,"re":"NFPA 70E allows an unqualified person to cross the limited approach boundary only when continuously escorted by a qualified person who advises them of the hazards and ensures protection; they still may not perform the qualified work.","qr":"Когда неквалифицированный специалист может пересечь limited approach boundary в сторону открытой части под напряжением?","optsr":["Никогда, ни при каких обстоятельствах","В любое время, пока надеты защитные очки","Только в светлое время суток","Только под постоянным сопровождением или руководством квалифицированного специалиста и при надлежащей защите"],"rr":"NFPA 70E разрешает неквалифицированному специалисту пересекать limited approach boundary только при постоянном сопровождении квалифицированного специалиста, который информирует его об опасностях и обеспечивает защиту; при этом он всё равно не может выполнять квалифицированную работу.","qs":"¿Cuándo puede una persona no calificada cruzar el límite de aproximación limitada hacia una parte energizada expuesta?","optss":["Nunca, bajo ninguna circunstancia","En cualquier momento, siempre que use lentes de seguridad","Solo durante las horas de luz del día","Solo cuando es escoltada o asesorada continuamente por una persona calificada y está debidamente protegida"],"rs":"NFPA 70E permite que una persona no calificada cruce el límite de aproximación limitada solo cuando es escoltada continuamente por una persona calificada que la advierte de los peligros y garantiza su protección; aun así, no puede realizar el trabajo calificado."},
  {"id":100,"sec":"Startup, Troubleshooting & Maintenance","block":1,"q":"In a capacitor-start, induction-run motor, what device disconnects the start winding once the motor reaches about 75% of full speed?","opts":["A thermal overload relay","A centrifugal switch","A magnetic contactor","A control transformer"],"correct":1,"re":"A centrifugal switch (or equivalent relay) opens to remove the start winding and start capacitor from the circuit once the motor approaches running speed.","qr":"В двигателе с конденсаторным пуском и асинхронным режимом работы какое устройство отключает пусковую обмотку, когда двигатель достигает примерно 75% полной скорости?","optsr":["Тепловое реле перегрузки","Центробежный выключатель","Магнитный контактор","Управляющий трансформатор"],"rr":"Центробежный выключатель (или эквивалентное реле) размыкается, чтобы убрать пусковую обмотку и пусковой конденсатор из цепи, когда двигатель приближается к рабочей скорости.","qs":"En un motor de arranque por capacitor e inducción de funcionamiento, ¿qué dispositivo desconecta el devanado de arranque una vez que el motor alcanza aproximadamente el 75% de la velocidad plena?","optss":["Un relé de sobrecarga térmica","Un interruptor centrífugo","Un contactor magnético","Un transformador de control"],"rs":"Un interruptor centrífugo (o relé equivalente) se abre para retirar el devanado de arranque y el capacitor de arranque del circuito una vez que el motor se acerca a la velocidad de funcionamiento."},
  {"id":101,"sec":"Rough Wiring","block":2,"q":"Two 250 kcmil copper conductors per phase are run in parallel; electrically they behave as:","opts":["One 250 kcmil conductor","A conductor with half the ampacity","A single conductor of roughly doubled ampacity","Two separate branch circuits"],"correct":2,"re":"Parallel conductors share the load and are treated as a single conductor of combined (approximately doubled) ampacity. See NEC 310.10(G).","qr":"Два медных проводника 250 kcmil на фазу проложены параллельно; электрически они работают как:","optsr":["Один проводник 250 kcmil","Проводник с половинной ampacity","Один проводник примерно удвоенной ampacity","Две отдельные ответвлённые цепи"],"rr":"Параллельные проводники делят нагрузку и рассматриваются как один проводник суммарной (примерно удвоенной) ampacity. См. NEC 310.10(G).","qs":"Se instalan dos conductores de cobre de 250 kcmil por fase en paralelo; eléctricamente se comportan como:","optss":["Un conductor de 250 kcmil","Un conductor con la mitad de la ampacidad","Un solo conductor con aproximadamente el doble de ampacidad","Dos circuitos ramales separados"],"rs":"Los conductores en paralelo comparten la carga y se tratan como un solo conductor con ampacidad combinada (aproximadamente el doble). Vea NEC 310.10(G)."},
  {"id":102,"sec":"Planning & Estimation","block":2,"q":"On a 240 V feeder, the conductors have a total resistance of 0.15 ohms and carry 40 A; what is the percent voltage drop?","opts":["2.5 percent","6 V","0.6 percent","25 percent"],"correct":0,"re":"Vd = 40 x 0.15 = 6 V; percent = 6/240 x 100 = 2.5 percent.","qr":"На фидере 240 В проводники имеют суммарное сопротивление 0,15 Ом и несут 40 А; каков процент потери напряжения?","optsr":["2,5 процента","6 В","0,6 процента","25 процентов"],"rr":"Vd = 40 x 0,15 = 6 В; процент = 6/240 x 100 = 2,5 процента.","qs":"En un alimentador de 240 V, los conductores tienen una resistencia total de 0.15 ohms y conducen 40 A; ¿cuál es el porcentaje de caída de tensión?","optss":["2.5 por ciento","6 V","0.6 por ciento","25 por ciento"],"rs":"Vd = 40 x 0.15 = 6 V; porcentaje = 6/240 x 100 = 2.5 por ciento."},
  {"id":103,"sec":"Finish Wiring & Trim","block":2,"q":"Dwelling unit receptacles installed to serve the kitchen countertop surfaces must be provided with what protection?","opts":["AFCI only","Surge protection only","GFCI protection","No special protection"],"correct":2,"re":"NEC 210.8(A) requires GFCI protection for receptacles serving dwelling kitchen countertop surfaces.","qr":"Розетки жилого помещения, установленные для обслуживания поверхностей кухонной столешницы, должны быть снабжены какой защитой?","optsr":["Только AFCI","Только защита от перенапряжений","Защита GFCI","Никакой особой защиты"],"rr":"NEC 210.8(A) требует защиту GFCI для розеток, обслуживающих поверхности кухонной столешницы в жилье.","qs":"Los receptáculos de una unidad de vivienda instalados para servir las superficies de mostrador de la cocina deben contar con qué tipo de protección?","optss":["Solo AFCI","Solo protección contra sobretensiones","Protección GFCI","Ninguna protección especial"],"rs":"NEC 210.8(A) exige protección GFCI para los receptáculos que sirven las superficies de mostrador de la cocina en viviendas."},
  {"id":104,"sec":"Rough Wiring","block":2,"q":"What is the minimum size copper branch-circuit conductor generally permitted for a 15-ampere general-purpose branch circuit?","opts":["12 AWG","16 AWG","14 AWG","10 AWG"],"correct":2,"re":"14 AWG copper is the smallest standard branch-circuit conductor (15 A); 12 AWG is required for 20 A circuits. See NEC 210.19 and Table 310.16.","qr":"Какой минимальный размер медного проводника ответвлённой цепи обычно разрешён для бытовой цепи 15 ампер?","optsr":["12 AWG","16 AWG","14 AWG","10 AWG"],"rr":"Медный проводник 14 AWG — наименьший стандартный проводник ответвлённой цепи (15 A); для цепей 20 A требуется 12 AWG. См. NEC 210.19 и Table 310.16.","qs":"¿Cuál es el menor tamaño de conductor de cobre para circuito ramal que generalmente se permite para un circuito ramal de uso general de 15 amperes?","optss":["12 AWG","16 AWG","14 AWG","10 AWG"],"rs":"El 14 AWG de cobre es el conductor de circuito ramal estándar más pequeño (15 A); se requiere 12 AWG para circuitos de 20 A. Vea NEC 210.19 y la Tabla 310.16."},
  {"id":105,"sec":"Safety","block":2,"q":"What information must an energized electrical work permit typically include under NFPA 70E?","opts":["The job-site lunch schedule and parking assignments","The retail price of replacement parts","The names of all past employees who serviced the equipment","A description of the work, justification for energized work, the shock and arc-flash risk assessment results, and required PPE"],"correct":3,"re":"NFPA 70E specifies the energized work permit include the circuit/equipment description, justification for working energized, results of the shock and arc-flash risk assessments, required PPE, and management approval signatures.","qr":"Какую информацию обычно должно содержать разрешение на электрические работы под напряжением согласно NFPA 70E?","optsr":["Расписание обедов на объекте и распределение парковочных мест","Розничную цену запасных частей","Имена всех бывших работников, обслуживавших оборудование","Описание работы, обоснование работы под напряжением, результаты оценки риска поражения током и дугового разряда, и требуемые СИЗ"],"rr":"NFPA 70E указывает, что разрешение на работу под напряжением должно включать описание цепи/оборудования, обоснование работы под напряжением, результаты оценки риска поражения током и дугового разряда, требуемые СИЗ и подписи руководства об одобрении.","qs":"¿Qué información debe incluir típicamente un permiso de trabajo eléctrico energizado según la NFPA 70E?","optss":["El horario de almuerzo en el sitio de trabajo y la asignación de estacionamiento","El precio de venta al público de las piezas de repuesto","Los nombres de todos los empleados anteriores que dieron servicio al equipo","Una descripción del trabajo, la justificación para el trabajo energizado, los resultados de la evaluación de riesgo de descarga y arco eléctrico, y el EPP requerido"],"rs":"La NFPA 70E especifica que el permiso de trabajo energizado incluya la descripción del circuito/equipo, la justificación para trabajar energizado, los resultados de las evaluaciones de riesgo de descarga y arco eléctrico, el EPP requerido y las firmas de aprobación de la gerencia."},
  {"id":106,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A capacitor-start single-phase motor hums but will not start and does not turn; which fault is the most likely cause?","opts":["The run winding is open","The start capacitor or start winding circuit is open (e.g., failed capacitor or centrifugal switch)","The supply voltage is too high","The motor bearings are over-greased"],"correct":1,"re":"Humming without starting typically indicates the run winding is energized but the start circuit (capacitor, start winding, or centrifugal switch) is open, so no starting torque is produced.","qr":"Однофазный двигатель с конденсаторным пуском гудит, но не запускается и не вращается; какая неисправность является наиболее вероятной причиной?","optsr":["Обрыв рабочей обмотки","Обрыв цепи пускового конденсатора или пусковой обмотки (например, неисправный конденсатор или центробежный выключатель)","Слишком высокое напряжение питания","Подшипники двигателя переполнены смазкой"],"rr":"Гудение без запуска обычно указывает на то, что рабочая обмотка под напряжением, но пусковая цепь (конденсатор, пусковая обмотка или центробежный выключатель) разомкнута, поэтому пусковой момент не создаётся.","qs":"Un motor monofásico de arranque por capacitor zumba pero no arranca y no gira; ¿cuál falla es la causa más probable?","optss":["El devanado de marcha está abierto","El capacitor de arranque o el circuito del devanado de arranque está abierto (por ejemplo, un capacitor o un interruptor centrífugo defectuoso)","La tensión de alimentación es demasiado alta","Los cojinetes del motor tienen exceso de grasa"],"rs":"El zumbido sin arrancar típicamente indica que el devanado de marcha está energizado pero el circuito de arranque (capacitor, devanado de arranque o interruptor centrífugo) está abierto, por lo que no se produce par de arranque."},
  {"id":107,"sec":"Planning & Estimation","block":2,"q":"Using the single-phase voltage-drop formula Vd = 2 x K x I x L / CM, with K = 12.9, I = 20 A, L = 100 ft, and CM = 10380, what is the approximate voltage drop?","opts":["2.48 V","4.97 V","9.94 V","0.50 V"],"correct":1,"re":"Vd = (2 x 12.9 x 20 x 100)/10380 = 51600/10380 = 4.97 V.","qr":"Используя однофазную формулу потери напряжения Vd = 2 x K x I x L / CM, при K = 12,9, I = 20 А, L = 100 футов и CM = 10380, какова приблизительная потеря напряжения?","optsr":["2,48 В","4,97 В","9,94 В","0,50 В"],"rr":"Vd = (2 x 12,9 x 20 x 100)/10380 = 51600/10380 = 4,97 В.","qs":"Usando la fórmula monofásica de caída de tensión Vd = 2 x K x I x L / CM, con K = 12.9, I = 20 A, L = 100 ft y CM = 10380, ¿cuál es la caída de tensión aproximada?","optss":["2.48 V","4.97 V","9.94 V","0.50 V"],"rs":"Vd = (2 x 12.9 x 20 x 100)/10380 = 51600/10380 = 4.97 V."},
  {"id":108,"sec":"Rough Wiring","block":2,"q":"What is the smallest copper conductor size permitted for a 20-ampere branch circuit?","opts":["16 AWG","12 AWG","14 AWG","10 AWG"],"correct":1,"re":"A 20-ampere branch circuit requires a minimum 12 AWG copper conductor per NEC 240.4(D) and Table 310.16.","qr":"Какой наименьший размер медного проводника разрешён для ответвлённой цепи 20 ампер?","optsr":["16 AWG","12 AWG","14 AWG","10 AWG"],"rr":"Ответвлённая цепь 20 ампер требует минимум медный проводник 12 AWG согласно NEC 240.4(D) и Table 310.16.","qs":"¿Cuál es el menor tamaño de conductor de cobre permitido para un circuito ramal de 20 amperes?","optss":["16 AWG","12 AWG","14 AWG","10 AWG"],"rs":"Un circuito ramal de 20 amperes requiere un conductor de cobre mínimo de 12 AWG según NEC 240.4(D) y la Tabla 310.16."},
  {"id":109,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"What is the primary function of a variable frequency drive (VFD) connected to an AC induction motor?","opts":["To control motor speed by varying the frequency (and voltage) supplied to the motor","To convert AC to DC for the motor","To provide overload protection only","To correct power factor on the utility side"],"correct":0,"re":"A VFD adjusts the output frequency, and proportionally the voltage, to the motor; since synchronous speed is proportional to frequency, this controls the motor speed.","qr":"Какова основная функция частотно-регулируемого привода (VFD), подключённого к асинхронному двигателю переменного тока?","optsr":["Управлять скоростью двигателя путём изменения частоты (и напряжения), подаваемой на двигатель","Преобразовывать переменный ток в постоянный для двигателя","Обеспечивать только защиту от перегрузки","Корректировать коэффициент мощности со стороны сети"],"rr":"VFD регулирует выходную частоту и пропорционально напряжение, подаваемое на двигатель; поскольку синхронная скорость пропорциональна частоте, это управляет скоростью двигателя.","qs":"¿Cuál es la función principal de un variador de frecuencia (VFD) conectado a un motor de inducción de CA?","optss":["Controlar la velocidad del motor variando la frecuencia (y la tensión) suministrada al motor","Convertir CA a CC para el motor","Proporcionar únicamente protección contra sobrecarga","Corregir el factor de potencia del lado de la empresa de servicios"],"rs":"Un VFD ajusta la frecuencia de salida y, proporcionalmente, la tensión hacia el motor; dado que la velocidad sincrónica es proporcional a la frecuencia, esto controla la velocidad del motor."},
  {"id":110,"sec":"Safety","block":2,"q":"Why does NFPA 70E emphasize de-energizing equipment rather than relying solely on PPE?","opts":["PPE is more expensive than de-energizing","Eliminating the hazard by de-energizing is more effective than PPE, which only mitigates the consequences if an incident occurs","PPE cannot be cleaned after use","De-energizing is required only for cosmetic reasons"],"correct":1,"re":"NFPA 70E follows the hierarchy of risk controls, where elimination (de-energizing) is the most effective control and PPE is the last line of defense that only reduces the severity of injury if an arc or shock occurs.","qr":"Почему NFPA 70E подчёркивает обесточивание оборудования, а не опору исключительно на СИЗ?","optsr":["СИЗ дороже, чем обесточивание","Устранение опасности путём обесточивания эффективнее СИЗ, которые лишь смягчают последствия в случае инцидента","СИЗ нельзя очистить после использования","Обесточивание требуется только из косметических соображений"],"rr":"NFPA 70E следует иерархии управления рисками, где устранение (обесточивание) является наиболее эффективным средством, а СИЗ — последней линией защиты, которая лишь снижает тяжесть травмы при возникновении дуги или поражения током.","qs":"¿Por qué la NFPA 70E enfatiza desenergizar el equipo en lugar de depender únicamente del EPP?","optss":["El EPP es más costoso que desenergizar","Eliminar el peligro al desenergizar es más eficaz que el EPP, el cual solo mitiga las consecuencias si ocurre un incidente","El EPP no se puede limpiar después de usarlo","Desenergizar se requiere únicamente por razones estéticas"],"rs":"La NFPA 70E sigue la jerarquía de controles de riesgo, donde la eliminación (desenergizar) es el control más eficaz y el EPP es la última línea de defensa que solo reduce la gravedad de la lesión si ocurre un arco o una descarga."},
  {"id":111,"sec":"Planning & Estimation","block":2,"q":"A 240 V single-phase resistive load consumes 4800 W; what is its resistance?","opts":["12 ohms","20 ohms","0.05 ohms","50 ohms"],"correct":0,"re":"From P = V squared / R, R = V squared / P = 57600 / 4800 = 12 ohms.","qr":"Однофазная резистивная нагрузка 240 В потребляет 4800 Вт; каково её сопротивление?","optsr":["12 Ом","20 Ом","0,05 Ом","50 Ом"],"rr":"Из P = V в квадрате / R, R = V в квадрате / P = 57600 / 4800 = 12 Ом.","qs":"Una carga resistiva monofásica de 240 V consume 4800 W; ¿cuál es su resistencia?","optss":["12 ohms","20 ohms","0.05 ohms","50 ohms"],"rs":"A partir de P = V al cuadrado / R, R = V al cuadrado / P = 57600 / 4800 = 12 ohms."},
  {"id":112,"sec":"Rough Wiring","block":2,"q":"Under NEC 240.4(D), what is the maximum overcurrent protection generally permitted for 14 AWG copper conductors?","opts":["10 A","20 A","15 A","25 A"],"correct":2,"re":"NEC 240.4(D) limits 14 AWG copper to a maximum 15-ampere overcurrent device regardless of its higher tabulated ampacity.","qr":"Согласно NEC 240.4(D), какова максимальная защита от сверхтока, обычно разрешённая для медных проводников 14 AWG?","optsr":["10 A","20 A","15 A","25 A"],"rr":"NEC 240.4(D) ограничивает медный проводник 14 AWG максимальным аппаратом защиты на 15 ампер, независимо от его более высокой табличной ampacity.","qs":"Según NEC 240.4(D), ¿cuál es la máxima protección contra sobrecorriente que generalmente se permite para conductores de cobre de 14 AWG?","optss":["10 A","20 A","15 A","25 A"],"rs":"NEC 240.4(D) limita el 14 AWG de cobre a un dispositivo de sobrecorriente máximo de 15 amperes, sin importar su ampacidad tabulada mayor."},
  {"id":113,"sec":"Finish Wiring & Trim","block":2,"q":"Which of the following dwelling receptacle locations is generally required to be GFCI-protected?","opts":["A living room wall","Outdoors","A bedroom wall","A central hallway"],"correct":1,"re":"NEC 210.8(A) requires GFCI protection for outdoor 125-volt, 15- and 20-amp receptacles at dwellings.","qr":"Какое из следующих мест размещения розеток в жилье обычно требует защиты GFCI?","optsr":["Стена гостиной","На улице","Стена спальни","Центральный коридор"],"rr":"NEC 210.8(A) требует защиту GFCI для наружных розеток 125 В, 15 и 20 А в жилых домах.","qs":"¿Cuál de las siguientes ubicaciones de receptáculos en una vivienda generalmente requiere protección GFCI?","optss":["Una pared de la sala de estar","Exteriores","Una pared del dormitorio","Un pasillo central"],"rs":"NEC 210.8(A) exige protección GFCI para los receptáculos de 125 voltios, 15 y 20 amperes ubicados en exteriores de las viviendas."},
  {"id":114,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A VFD generally controls the speed of an AC induction motor by maintaining what relationship between voltage and frequency?","opts":["Zero voltage at low frequency","A constant current regardless of frequency","Maximum voltage at all frequencies","A constant volts-per-hertz (V/Hz) ratio"],"correct":3,"re":"To maintain constant magnetic flux and torque capability across the speed range, a VFD typically holds a constant volts-per-hertz ratio as it varies the output frequency.","qr":"VFD обычно управляет скоростью асинхронного двигателя переменного тока, поддерживая какое соотношение между напряжением и частотой?","optsr":["Нулевое напряжение на низкой частоте","Постоянный ток независимо от частоты","Максимальное напряжение на всех частотах","Постоянное соотношение вольт на герц (V/Hz)"],"rr":"Чтобы поддерживать постоянный магнитный поток и способность создавать момент во всём диапазоне скоростей, VFD обычно удерживает постоянное соотношение вольт на герц при изменении выходной частоты.","qs":"Un VFD generalmente controla la velocidad de un motor de inducción de CA manteniendo qué relación entre la tensión y la frecuencia?","optss":["Tensión cero a baja frecuencia","Una corriente constante sin importar la frecuencia","Tensión máxima en todas las frecuencias","Una relación constante de volts por hertz (V/Hz)"],"rs":"Para mantener un flujo magnético y una capacidad de par constantes en todo el rango de velocidad, un VFD típicamente mantiene una relación constante de volts por hertz mientras varía la frecuencia de salida."},
  {"id":115,"sec":"Safety","block":2,"q":"Which of the following best describes the restricted approach boundary compared with the limited approach boundary?","opts":["The restricted approach boundary is closer to the energized part and accounts for increased risk due to electrical arc-over plus inadvertent movement","The restricted approach boundary is farther from the energized part than the limited approach boundary","The two boundaries are always at the same distance","The restricted approach boundary applies only to mechanical hazards"],"correct":0,"re":"The restricted approach boundary is closer to the exposed energized part than the limited approach boundary; crossing it requires a qualified person with appropriate PPE because of the increased likelihood of arc-over combined with inadvertent movement.","qr":"Что из следующего лучше всего описывает restricted approach boundary по сравнению с limited approach boundary?","optsr":["Restricted approach boundary находится ближе к части под напряжением и учитывает повышенный риск из-за электрической дуги в сочетании с непреднамеренным движением","Restricted approach boundary находится дальше от части под напряжением, чем limited approach boundary","Обе границы всегда находятся на одинаковом расстоянии","Restricted approach boundary применяется только к механическим опасностям"],"rr":"Restricted approach boundary находится ближе к открытой части под напряжением, чем limited approach boundary; её пересечение требует квалифицированного специалиста с соответствующими СИЗ из-за повышенной вероятности дугового перекрытия в сочетании с непреднамеренным движением.","qs":"¿Cuál de las siguientes describe mejor la frontera de aproximación restringida en comparación con la frontera de aproximación limitada?","optss":["La frontera de aproximación restringida está más cerca de la parte energizada y considera el mayor riesgo debido al arco eléctrico más el movimiento involuntario","La frontera de aproximación restringida está más lejos de la parte energizada que la frontera de aproximación limitada","Las dos fronteras siempre están a la misma distancia","La frontera de aproximación restringida se aplica únicamente a peligros mecánicos"],"rs":"La frontera de aproximación restringida está más cerca de la parte energizada expuesta que la frontera de aproximación limitada; cruzarla requiere una persona calificada con el EPP apropiado debido a la mayor probabilidad de arco combinada con el movimiento involuntario."},
  {"id":116,"sec":"Rough Wiring","block":2,"q":"Under NEC 240.4(D), the maximum overcurrent device for 12 AWG copper conductors is generally:","opts":["30 A","25 A","15 A","20 A"],"correct":3,"re":"NEC 240.4(D) limits 12 AWG copper to a maximum 20-ampere overcurrent device.","qr":"Согласно NEC 240.4(D), максимальный аппарат защиты для медных проводников 12 AWG обычно составляет:","optsr":["30 A","25 A","15 A","20 A"],"rr":"NEC 240.4(D) ограничивает медный проводник 12 AWG максимальным аппаратом защиты на 20 ампер.","qs":"Según NEC 240.4(D), el dispositivo de sobrecorriente máximo para conductores de cobre de 12 AWG generalmente es:","optss":["30 A","25 A","15 A","20 A"],"rs":"NEC 240.4(D) limita el 12 AWG de cobre a un dispositivo de sobrecorriente máximo de 20 amperes."},
  {"id":117,"sec":"Planning & Estimation","block":2,"q":"Three lamps rated 60 W each at 120 V are connected in parallel; what is the total current drawn?","opts":["0.5 A","180 A","4.5 A","1.5 A"],"correct":3,"re":"Total P = 3 x 60 = 180 W; I = P/V = 180/120 = 1.5 A.","qr":"Три лампы по 60 Вт каждая при 120 В соединены параллельно; какой суммарный ток потребляется?","optsr":["0,5 А","180 А","4,5 А","1,5 А"],"rr":"Суммарная P = 3 x 60 = 180 Вт; I = P/V = 180/120 = 1,5 А.","qs":"Tres lámparas de 60 W cada una a 120 V se conectan en paralelo; ¿cuál es la corriente total consumida?","optss":["0.5 A","180 A","4.5 A","1.5 A"],"rs":"P total = 3 x 60 = 180 W; I = P/V = 180/120 = 1.5 A."},
  {"id":118,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"Which is a common benefit of starting an AC motor with a VFD instead of across-the-line starting?","opts":["It increases the locked-rotor inrush current","It provides a soft start with reduced inrush current and mechanical stress","It eliminates the need for any overload protection","It requires the motor to be a synchronous type"],"correct":1,"re":"A VFD ramps frequency and voltage up gradually, providing a soft start that greatly reduces inrush current and mechanical/electrical stress compared to across-the-line starting.","qr":"Что является распространённым преимуществом пуска двигателя переменного тока с VFD вместо прямого пуска от сети?","optsr":["Увеличивает пусковой ток заторможенного ротора","Обеспечивает плавный пуск со сниженным пусковым током и механической нагрузкой","Устраняет необходимость в любой защите от перегрузки","Требует, чтобы двигатель был синхронного типа"],"rr":"VFD постепенно повышает частоту и напряжение, обеспечивая плавный пуск, который значительно снижает пусковой ток и механическую/электрическую нагрузку по сравнению с прямым пуском от сети.","qs":"¿Cuál es un beneficio común de arrancar un motor de CA con un VFD en lugar de un arranque directo a la línea?","optss":["Aumenta la corriente de irrupción a rotor bloqueado","Proporciona un arranque suave con reducción de la corriente de irrupción y del esfuerzo mecánico","Elimina la necesidad de cualquier protección contra sobrecarga","Requiere que el motor sea de tipo sincrónico"],"rs":"Un VFD aumenta gradualmente la frecuencia y la tensión, proporcionando un arranque suave que reduce considerablemente la corriente de irrupción y el esfuerzo mecánico/eléctrico en comparación con el arranque directo a la línea."},
  {"id":119,"sec":"Safety","block":2,"q":"Under Cal/OSHA T8 Section 3314, when is a tagout device alone (without a lock) considered acceptable?","opts":["Whenever the worker prefers tags over locks","Anytime the equipment is over 480 volts","Only when the energy-isolating device is not capable of being locked out, and additional safety measures provide protection equivalent to lockout","Only on weekends"],"correct":2,"re":"Cal/OSHA T8 Section 3314 permits tagout alone only when the energy-isolating device cannot accept a lock, and then the employer must provide full employee protection equivalent to that of a lockout program.","qr":"Согласно разделу 3314 Title 8 Cal/OSHA, когда только устройство tagout (без замка) считается приемлемым?","optsr":["Всякий раз, когда работник предпочитает бирки замкам","В любое время, когда оборудование выше 480 вольт","Только когда устройство изоляции энергии не может быть заблокировано замком, и дополнительные меры безопасности обеспечивают защиту, эквивалентную блокировке","Только по выходным"],"rr":"Раздел 3314 Title 8 Cal/OSHA допускает только tagout, когда устройство изоляции энергии не может принять замок, и тогда работодатель должен обеспечить полную защиту работников, эквивалентную программе блокировки.","qs":"Según Cal/OSHA T8 Sección 3314, ¿cuándo se considera aceptable un dispositivo de etiquetado solo (sin un candado)?","optss":["Cuando el trabajador prefiera etiquetas en lugar de candados","En cualquier momento en que el equipo supere los 480 voltios","Solo cuando el dispositivo de aislamiento de energía no se pueda bloquear, y medidas de seguridad adicionales proporcionen una protección equivalente al bloqueo","Solo los fines de semana"],"rs":"Cal/OSHA T8 Sección 3314 permite el etiquetado solo únicamente cuando el dispositivo de aislamiento de energía no puede aceptar un candado, y entonces el empleador debe proporcionar protección total al empleado equivalente a la de un programa de bloqueo."},
  {"id":120,"sec":"Rough Wiring","block":2,"q":"Under NEC 240.4(D), the maximum overcurrent device for 10 AWG copper conductors is generally:","opts":["20 A","30 A","25 A","40 A"],"correct":1,"re":"NEC 240.4(D) limits 10 AWG copper to a maximum 30-ampere overcurrent device.","qr":"Согласно NEC 240.4(D), максимальный аппарат защиты для медных проводников 10 AWG обычно составляет:","optsr":["20 A","30 A","25 A","40 A"],"rr":"NEC 240.4(D) ограничивает медный проводник 10 AWG максимальным аппаратом защиты на 30 ампер.","qs":"Según NEC 240.4(D), el dispositivo de sobrecorriente máximo para conductores de cobre de 10 AWG generalmente es:","optss":["20 A","30 A","25 A","40 A"],"rs":"NEC 240.4(D) limita el 10 AWG de cobre a un dispositivo de sobrecorriente máximo de 30 amperes."},
  {"id":121,"sec":"Planning & Estimation","block":2,"q":"A water heater element has a resistance of 12.8 ohms on a 240 V circuit; what is its power consumption?","opts":["3072 W","18.75 W","4500 W","737280 W"],"correct":2,"re":"P = V squared / R = 57600 / 12.8 = 4500 W.","qr":"Элемент водонагревателя имеет сопротивление 12,8 Ом в цепи 240 В; каково его энергопотребление?","optsr":["3072 Вт","18,75 Вт","4500 Вт","737280 Вт"],"rr":"P = V в квадрате / R = 57600 / 12,8 = 4500 Вт.","qs":"Un elemento de calentador de agua tiene una resistencia de 12.8 ohms en un circuito de 240 V; ¿cuál es su consumo de potencia?","optss":["3072 W","18.75 W","4500 W","737280 W"],"rs":"P = V al cuadrado / R = 57600 / 12.8 = 4500 W."},
  {"id":122,"sec":"Finish Wiring & Trim","block":2,"q":"A 125-volt receptacle in an unfinished basement of a dwelling generally requires what protection?","opts":["No protection","AFCI only","GFCI protection","Isolated ground only"],"correct":2,"re":"NEC 210.8(A) requires GFCI protection for 125-volt, 15- and 20-amp receptacles installed in unfinished basements of dwellings.","qr":"Розетка 125 В в неотделанном подвале жилья обычно требует какой защиты?","optsr":["Никакой защиты","Только AFCI","Защита GFCI","Только изолированное заземление"],"rr":"NEC 210.8(A) требует защиту GFCI для розеток 125 В, 15 и 20 А, установленных в неотделанных подвалах жилых домов.","qs":"Un receptáculo de 125 voltios en un sótano sin terminar de una vivienda generalmente requiere qué tipo de protección?","optss":["Ninguna protección","Solo AFCI","Protección GFCI","Solo tierra aislada"],"rs":"NEC 210.8(A) exige protección GFCI para los receptáculos de 125 voltios, 15 y 20 amperes instalados en sótanos sin terminar de las viviendas."},
  {"id":123,"sec":"Rough Wiring","block":2,"q":"For aluminum conductors under NEC 240.4(D), what is the maximum overcurrent protection for 12 AWG aluminum?","opts":["20 A","10 A","15 A","25 A"],"correct":2,"re":"NEC 240.4(D) limits 12 AWG aluminum/copper-clad aluminum to a maximum 15-ampere overcurrent device.","qr":"Для алюминиевых проводников согласно NEC 240.4(D), какова максимальная защита от сверхтока для алюминия 12 AWG?","optsr":["20 A","10 A","15 A","25 A"],"rr":"NEC 240.4(D) ограничивает алюминий/алюминий в медной оболочке 12 AWG максимальным аппаратом защиты на 15 ампер.","qs":"Para conductores de aluminio según NEC 240.4(D), ¿cuál es la máxima protección contra sobrecorriente para el 12 AWG de aluminio?","optss":["20 A","10 A","15 A","25 A"],"rs":"NEC 240.4(D) limita el 12 AWG de aluminio/aluminio revestido de cobre a un dispositivo de sobrecorriente máximo de 15 amperes."},
  {"id":124,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"When reading a motor nameplate, what does the listed RPM value represent?","opts":["The synchronous speed of the magnetic field","The speed only at no load","The maximum permissible overspeed","The approximate full-load operating speed of the motor shaft"],"correct":3,"re":"The nameplate RPM is the full-load (rated) speed of the motor, which for an induction motor is slightly less than synchronous speed due to slip.","qr":"При чтении заводской таблички двигателя что представляет указанное значение оборотов в минуту (RPM)?","optsr":["Синхронную скорость магнитного поля","Скорость только на холостом ходу","Максимально допустимую скорость превышения","Приблизительную рабочую скорость вала двигателя при полной нагрузке"],"rr":"RPM на табличке — это скорость двигателя при полной (номинальной) нагрузке, которая для асинхронного двигателя немного меньше синхронной скорости из-за скольжения.","qs":"Al leer la placa de datos de un motor, ¿qué representa el valor de RPM indicado?","optss":["La velocidad sincrónica del campo magnético","La velocidad únicamente sin carga","La sobrevelocidad máxima permisible","La velocidad de operación aproximada a plena carga del eje del motor"],"rs":"Las RPM de la placa de datos son la velocidad a plena carga (nominal) del motor, que en un motor de inducción es ligeramente menor que la velocidad sincrónica debido al deslizamiento."},
  {"id":125,"sec":"Safety","block":2,"q":"What is the correct sequence of the live-dead-live verification procedure?","opts":["Test a known live source, test the circuit to be worked on for absence of voltage, then re-test the known live source","Test the dead circuit, then touch it, then test a live source","Touch the circuit first, then test a live source twice","Test resistance, test continuity, then test current"],"correct":0,"re":"The live-dead-live method verifies the tester on a known energized source, then confirms the target circuit is dead, then re-verifies the tester on a known live source to prove it still functions, confirming a valid absence-of-voltage result.","qr":"Какова правильная последовательность процедуры проверки live-dead-live?","optsr":["Проверить заведомо живой источник, проверить рабочую цепь на отсутствие напряжения, затем повторно проверить заведомо живой источник","Проверить обесточенную цепь, затем прикоснуться к ней, затем проверить живой источник","Сначала прикоснуться к цепи, затем дважды проверить живой источник","Проверить сопротивление, проверить целостность, затем проверить ток"],"rr":"Метод live-dead-live проверяет прибор на заведомо живом источнике, затем подтверждает, что целевая цепь обесточена, затем повторно проверяет прибор на заведомо живом источнике, чтобы доказать его работоспособность, подтверждая достоверный результат отсутствия напряжения.","qs":"¿Cuál es la secuencia correcta del procedimiento de verificación vivo-muerto-vivo?","optss":["Probar una fuente viva conocida, probar el circuito en el que se va a trabajar para verificar la ausencia de tensión, y luego volver a probar la fuente viva conocida","Probar el circuito muerto, luego tocarlo, y luego probar una fuente viva","Tocar el circuito primero, luego probar una fuente viva dos veces","Probar resistencia, probar continuidad, y luego probar corriente"],"rs":"El método vivo-muerto-vivo verifica el probador en una fuente energizada conocida, luego confirma que el circuito objetivo está muerto, y luego vuelve a verificar el probador en una fuente viva conocida para comprobar que aún funciona, confirmando un resultado válido de ausencia de tensión."},
  {"id":126,"sec":"Planning & Estimation","block":2,"q":"In a series circuit, a 5 ohm and a 5 ohm resistor are followed by a 10 ohm resistor; what is the total resistance?","opts":["2 ohms","250 ohms","20 ohms","10 ohms"],"correct":2,"re":"Series adds: 5 + 5 + 10 = 20 ohms.","qr":"В последовательной цепи за резисторами 5 Ом и 5 Ом следует резистор 10 Ом; каково общее сопротивление?","optsr":["2 Ом","250 Ом","20 Ом","10 Ом"],"rr":"Последовательно складывается: 5 + 5 + 10 = 20 Ом.","qs":"En un circuito en serie, un resistor de 5 ohms y uno de 5 ohms son seguidos por un resistor de 10 ohms; ¿cuál es la resistencia total?","optss":["2 ohms","250 ohms","20 ohms","10 ohms"],"rs":"En serie se suma: 5 + 5 + 10 = 20 ohms."},
  {"id":127,"sec":"Rough Wiring","block":2,"q":"Why does aluminum wiring typically require a larger conductor size than copper for the same ampacity?","opts":["Aluminum melts at a lower temperature","Aluminum cannot be insulated as well","Aluminum is heavier than copper","Aluminum has higher electrical resistivity"],"correct":3,"re":"Aluminum's higher resistivity means a larger cross-section is needed to carry the same current. See NEC Table 310.16 ampacity comparisons.","qr":"Почему алюминиевая проводка обычно требует большего сечения, чем медь, для той же ampacity?","optsr":["Алюминий плавится при более низкой температуре","Алюминий хуже изолируется","Алюминий тяжелее меди","Алюминий имеет большее удельное электрическое сопротивление"],"rr":"Большее удельное сопротивление алюминия означает, что для передачи того же тока нужно большее сечение. См. сравнения ampacity в NEC Table 310.16.","qs":"¿Por qué el cableado de aluminio típicamente requiere un tamaño de conductor mayor que el de cobre para la misma ampacidad?","optss":["El aluminio se funde a una temperatura más baja","El aluminio no se puede aislar tan bien","El aluminio es más pesado que el cobre","El aluminio tiene mayor resistividad eléctrica"],"rs":"La mayor resistividad del aluminio significa que se necesita una sección transversal mayor para conducir la misma corriente. Vea las comparaciones de ampacidad de la Tabla 310.16 del NEC."},
  {"id":128,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"On a motor nameplate, what does the code letter (NEMA code letter) primarily indicate?","opts":["The locked-rotor kVA per horsepower (starting inrush characteristic)","The full-load efficiency","The maximum ambient temperature","The insulation class"],"correct":0,"re":"The NEMA code letter on the nameplate indicates the locked-rotor kVA per horsepower, which is used to determine the motor's starting (inrush) current.","qr":"На заводской табличке двигателя что в основном указывает кодовая буква (кодовая буква NEMA)?","optsr":["КВА заторможенного ротора на лошадиную силу (пусковую характеристику)","КПД при полной нагрузке","Максимальную температуру окружающей среды","Класс изоляции"],"rr":"Кодовая буква NEMA на табличке указывает кВА заторможенного ротора на лошадиную силу, что используется для определения пускового тока двигателя.","qs":"En la placa de datos de un motor, ¿qué indica principalmente la letra de código (letra de código NEMA)?","optss":["Los kVA a rotor bloqueado por caballo de fuerza (característica de irrupción de arranque)","La eficiencia a plena carga","La temperatura ambiente máxima","La clase de aislamiento"],"rs":"La letra de código NEMA en la placa de datos indica los kVA a rotor bloqueado por caballo de fuerza, que se usa para determinar la corriente de arranque (irrupción) del motor."},
  {"id":129,"sec":"Planning & Estimation","block":2,"q":"What is the equivalent resistance of a 10 ohm, 20 ohm, and 30 ohm resistor connected in parallel?","opts":["60 ohms","0.183 ohms","20 ohms","5.45 ohms"],"correct":3,"re":"1/R = 1/10 + 1/20 + 1/30 = 6/60 + 3/60 + 2/60 = 11/60; R = 60/11 = 5.45 ohms.","qr":"Каково эквивалентное сопротивление резисторов 10 Ом, 20 Ом и 30 Ом, соединённых параллельно?","optsr":["60 Ом","0,183 Ом","20 Ом","5,45 Ом"],"rr":"1/R = 1/10 + 1/20 + 1/30 = 6/60 + 3/60 + 2/60 = 11/60; R = 60/11 = 5,45 Ом.","qs":"¿Cuál es la resistencia equivalente de un resistor de 10 ohms, uno de 20 ohms y uno de 30 ohms conectados en paralelo?","optss":["60 ohms","0.183 ohms","20 ohms","5.45 ohms"],"rs":"1/R = 1/10 + 1/20 + 1/30 = 6/60 + 3/60 + 2/60 = 11/60; R = 60/11 = 5.45 ohms."},
  {"id":130,"sec":"Safety","block":2,"q":"Which statement about arc-rated clothing under NFPA 70E is correct?","opts":["Ordinary cotton T-shirts provide adequate arc protection","Any flame-retardant clothing is automatically arc-rated","Arc-rated garments must have an arc rating equal to or greater than the estimated incident energy at the working distance","Arc-rated clothing only needs to cover the hands"],"correct":2,"re":"NFPA 70E requires that arc-rated PPE have an arc rating (in cal/cm2) at least equal to the available incident energy; non-rated clothing, even cotton, can ignite or melt and does not provide certified protection.","qr":"Какое утверждение об одежде с дуговой защитой (arc-rated) согласно NFPA 70E является верным?","optsr":["Обычные хлопковые футболки обеспечивают достаточную дуговую защиту","Любая огнестойкая одежда автоматически имеет дуговую защиту","Одежда с дуговой защитой должна иметь дуговой рейтинг, равный или превышающий расчётную падающую энергию на рабочем расстоянии","Одежда с дуговой защитой должна закрывать только руки"],"rr":"NFPA 70E требует, чтобы СИЗ с дуговой защитой имели дуговой рейтинг (в кал/см2) не менее доступной падающей энергии; одежда без рейтинга, даже хлопковая, может воспламениться или расплавиться и не обеспечивает сертифицированной защиты.","qs":"¿Cuál afirmación sobre la ropa con clasificación de arco según la NFPA 70E es correcta?","optss":["Las camisetas comunes de algodón proporcionan protección adecuada contra arco","Cualquier ropa retardante de llama está automáticamente clasificada para arco","Las prendas con clasificación de arco deben tener una clasificación de arco igual o mayor que la energía incidente estimada a la distancia de trabajo","La ropa con clasificación de arco solo necesita cubrir las manos"],"rs":"La NFPA 70E exige que el EPP con clasificación de arco tenga una clasificación de arco (en cal/cm2) al menos igual a la energía incidente disponible; la ropa sin clasificación, incluso de algodón, puede encenderse o fundirse y no proporciona protección certificada."},
  {"id":131,"sec":"Finish Wiring & Trim","block":2,"q":"A receptacle installed in a dwelling garage must be provided with which of the following?","opts":["A locking-type configuration","GFCI protection","AFCI protection only","An isolated neutral"],"correct":1,"re":"NEC 210.8(A) requires GFCI protection for 125-volt, 15- and 20-amp receptacles installed in dwelling garages.","qr":"Розетка, установленная в гараже жилья, должна быть снабжена чем из следующего?","optsr":["Конфигурация с фиксацией","Защита GFCI","Только защита AFCI","Изолированный нейтральный провод"],"rr":"NEC 210.8(A) требует защиту GFCI для розеток 125 В, 15 и 20 А, установленных в гаражах жилых домов.","qs":"Un receptáculo instalado en el garaje de una vivienda debe contar con cuál de los siguientes?","optss":["Una configuración de tipo con seguro","Protección GFCI","Solo protección AFCI","Un neutro aislado"],"rs":"NEC 210.8(A) exige protección GFCI para los receptáculos de 125 voltios, 15 y 20 amperes instalados en los garajes de las viviendas."},
  {"id":132,"sec":"Rough Wiring","block":2,"q":"Terminals listed and marked 'CU-AL' or 'AL-CU' are required when connecting:","opts":["Conductors larger than 1/0 only","Copper conductors only","Grounding conductors only","Aluminum or copper conductors at that termination"],"correct":3,"re":"Terminations marked CU-AL/AL-CU are tested and listed for use with aluminum and copper conductors. See NEC 110.14(A).","qr":"Зажимы с маркировкой 'CU-AL' или 'AL-CU' требуются при подключении:","optsr":["Только проводников больше 1/0","Только медных проводников","Только заземляющих проводников","Алюминиевых или медных проводников на этом зажиме"],"rr":"Зажимы с маркировкой CU-AL/AL-CU испытаны и сертифицированы для применения с алюминиевыми и медными проводниками. См. NEC 110.14(A).","qs":"Las terminales listadas y marcadas como 'CU-AL' o 'AL-CU' se requieren al conectar:","optss":["Únicamente conductores mayores de 1/0","Únicamente conductores de cobre","Únicamente conductores de puesta a tierra","Conductores de aluminio o de cobre en esa terminación"],"rs":"Las terminaciones marcadas CU-AL/AL-CU están probadas y listadas para usarse con conductores de aluminio y de cobre. Vea NEC 110.14(A)."},
  {"id":133,"sec":"Planning & Estimation","block":2,"q":"A single-phase 240 V motor circuit delivers 7200 W of real power at a power factor of 0.80; what is the line current?","opts":["37.5 A","30 A","24 A","60 A"],"correct":0,"re":"I = P / (V x PF) = 7200 / (240 x 0.80) = 7200/192 = 37.5 A.","qr":"Однофазная цепь двигателя 240 В выдаёт 7200 Вт активной мощности при коэффициенте мощности 0,80; каков линейный ток?","optsr":["37,5 А","30 А","24 А","60 А"],"rr":"I = P / (V x PF) = 7200 / (240 x 0,80) = 7200/192 = 37,5 А.","qs":"Un circuito de motor monofásico de 240 V entrega 7200 W de potencia real con un factor de potencia de 0.80; ¿cuál es la corriente de línea?","optss":["37.5 A","30 A","24 A","60 A"],"rs":"I = P / (V x FP) = 7200 / (240 x 0.80) = 7200/192 = 37.5 A."},
  {"id":134,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"On a motor nameplate, what does a service factor (SF) of 1.15 indicate?","opts":["The motor must always run at 115% of rated voltage","The motor can be operated continuously at up to 115% of its rated horsepower without immediate damage","The starting current is 115% of full-load current","The insulation is rated for 115°C"],"correct":1,"re":"A service factor of 1.15 means the motor can carry a continuous overload of 15% above its rated horsepower under specified conditions; it also affects the allowable overload sizing per NEC 430.32.","qr":"На заводской табличке двигателя что указывает сервис-фактор (SF) 1.15?","optsr":["Двигатель должен всегда работать при 115% номинального напряжения","Двигатель может непрерывно работать при нагрузке до 115% от его номинальной мощности без немедленного повреждения","Пусковой ток составляет 115% от тока полной нагрузки","Изоляция рассчитана на 115°C"],"rr":"Сервис-фактор 1.15 означает, что двигатель может нести непрерывную перегрузку 15% сверх номинальной мощности при указанных условиях; он также влияет на допустимый выбор защиты от перегрузки по NEC 430.32.","qs":"En la placa de datos de un motor, ¿qué indica un factor de servicio (SF) de 1.15?","optss":["El motor siempre debe funcionar al 115% de la tensión nominal","El motor puede operarse continuamente hasta el 115% de su potencia nominal en caballos de fuerza sin daño inmediato","La corriente de arranque es el 115% de la corriente a plena carga","El aislamiento está clasificado para 115°C"],"rs":"Un factor de servicio de 1.15 significa que el motor puede soportar una sobrecarga continua del 15% por encima de su potencia nominal en caballos de fuerza bajo condiciones especificadas; también afecta el dimensionamiento permitido de la sobrecarga según NEC 430.32."},
  {"id":135,"sec":"Safety","block":2,"q":"What is the role of an electrically safe work condition in eliminating electrical hazards?","opts":["It removes the shock and arc-flash hazards because the equipment is verified de-energized, isolated, and incapable of being re-energized","It reduces the hazard by half but still requires full PPE","It only protects against arc flash, not shock","It applies only to low-voltage control circuits"],"correct":0,"re":"Once an electrically safe work condition is established and verified, the source of electrical energy is removed, eliminating both shock and arc-flash hazards so the work is no longer considered energized work.","qr":"Какова роль электробезопасного рабочего состояния в устранении электрических опасностей?","optsr":["Оно устраняет опасности поражения током и дугового разряда, поскольку оборудование проверено как обесточенное, изолированное и неспособное снова получить питание","Оно снижает опасность вдвое, но всё равно требует полного комплекта СИЗ","Оно защищает только от дугового разряда, но не от поражения током","Оно применяется только к низковольтным цепям управления"],"rr":"После создания и проверки электробезопасного рабочего состояния источник электрической энергии удаляется, устраняя опасности как поражения током, так и дугового разряда, поэтому работа больше не считается работой под напряжением.","qs":"¿Cuál es la función de una condición de trabajo eléctricamente segura para eliminar los peligros eléctricos?","optss":["Elimina los peligros de descarga y arco eléctrico porque se verifica que el equipo está desenergizado, aislado e incapaz de ser reenergizado","Reduce el peligro a la mitad pero aún requiere EPP completo","Solo protege contra arco eléctrico, no contra descarga","Se aplica únicamente a circuitos de control de baja tensión"],"rs":"Una vez que se establece y verifica una condición de trabajo eléctricamente segura, se elimina la fuente de energía eléctrica, eliminando tanto el peligro de descarga como el de arco eléctrico, de modo que el trabajo ya no se considera trabajo energizado."},
  {"id":136,"sec":"Rough Wiring","block":2,"q":"When both ambient correction and bundling adjustment factors apply to a conductor, they must be:","opts":["Multiplied together with the base ampacity","Added together","Ignored if conductors are 90°C rated","Used separately, choosing the smaller"],"correct":0,"re":"Correction and adjustment factors are multiplied together and applied to the base ampacity. See NEC 310.15(B) and (C).","qr":"Когда к проводнику применяются и температурная коррекция, и коэффициент за пучкование, их нужно:","optsr":["Перемножить вместе с базовой ampacity","Сложить вместе","Игнорировать, если проводники рассчитаны на 90°C","Применять раздельно, выбирая меньший"],"rr":"Коэффициенты коррекции и снижения перемножаются и применяются к базовой ampacity. См. NEC 310.15(B) и (C).","qs":"Cuando se aplican a un conductor tanto los factores de corrección por temperatura ambiente como los de ajuste por agrupamiento, deben:","optss":["Multiplicarse juntos con la ampacidad base","Sumarse juntos","Ignorarse si los conductores están clasificados a 90°C","Usarse por separado, eligiendo el menor"],"rs":"Los factores de corrección y de ajuste se multiplican juntos y se aplican a la ampacidad base. Vea NEC 310.15(B) y (C)."},
  {"id":137,"sec":"Planning & Estimation","block":2,"q":"A 3 kW load runs continuously for one full day; how much energy is consumed?","opts":["24 kWh","3 kWh","72 kWh","125 kWh"],"correct":2,"re":"Energy = 3 kW x 24 h = 72 kWh.","qr":"Нагрузка 3 кВт работает непрерывно полные сутки; сколько энергии потребляется?","optsr":["24 kWh","3 kWh","72 kWh","125 kWh"],"rr":"Энергия = 3 кВт x 24 ч = 72 kWh.","qs":"Una carga de 3 kW funciona continuamente durante un día completo; ¿cuánta energía se consume?","optss":["24 kWh","3 kWh","72 kWh","125 kWh"],"rs":"Energía = 3 kW x 24 h = 72 kWh."},
  {"id":138,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A motor nameplate shows a dual voltage rating of 230/460 V; what generally happens to the full-load current when the motor is wired for the higher voltage (460 V)?","opts":["It approximately doubles","It stays exactly the same","It becomes zero","It is approximately one-half of the 230 V value"],"correct":3,"re":"For a given horsepower, current is inversely proportional to voltage, so wiring for 460 V draws about half the full-load current required at 230 V.","qr":"На заводской табличке двигателя указано двойное напряжение 230/460 В; что обычно происходит с током полной нагрузки, когда двигатель подключён на более высокое напряжение (460 В)?","optsr":["Он примерно удваивается","Он остаётся точно таким же","Он становится нулевым","Он составляет примерно половину значения при 230 В"],"rr":"Для данной мощности ток обратно пропорционален напряжению, поэтому подключение на 460 В потребляет примерно половину тока полной нагрузки, требуемого при 230 В.","qs":"La placa de datos de un motor muestra una clasificación de doble tensión de 230/460 V; ¿qué le ocurre generalmente a la corriente a plena carga cuando el motor se conecta para la tensión más alta (460 V)?","optss":["Se duplica aproximadamente","Permanece exactamente igual","Se vuelve cero","Es aproximadamente la mitad del valor de 230 V"],"rs":"Para una potencia dada en caballos de fuerza, la corriente es inversamente proporcional a la tensión, por lo que conectar para 460 V consume aproximadamente la mitad de la corriente a plena carga requerida a 230 V."},
  {"id":139,"sec":"Rough Wiring","block":2,"q":"A conductor rated USE-2 carries which temperature rating?","opts":["60°C","75°C","105°C","90°C"],"correct":3,"re":"The '-2' suffix indicates a 90°C wet and dry rating, so USE-2 is rated 90°C. See NEC Table 310.4(A).","qr":"Проводник с маркировкой USE-2 имеет какой температурный класс?","optsr":["60°C","75°C","105°C","90°C"],"rr":"Суффикс '-2' означает рейтинг 90°C для влажных и сухих мест, поэтому USE-2 рассчитан на 90°C. См. NEC Table 310.4(A).","qs":"Un conductor clasificado USE-2 tiene qué clasificación de temperatura?","optss":["60°C","75°C","105°C","90°C"],"rs":"El sufijo '-2' indica una clasificación de 90°C en mojado y en seco, por lo que el USE-2 está clasificado a 90°C. Vea la Tabla 310.4(A) del NEC."},
  {"id":140,"sec":"Safety","block":2,"q":"Who is authorized to determine that energized work is justified and to approve an energized electrical work permit?","opts":["Any worker on the crew by majority vote","The first person to arrive on site","The equipment manufacturer's sales representative","Authorized management personnel, after the justification and risk assessment are documented"],"correct":3,"re":"NFPA 70E requires that the energized electrical work permit be reviewed and signed by authorized management, confirming the justification for energized work and the completed risk assessments.","qr":"Кто уполномочен определять, что работа под напряжением обоснована, и одобрять разрешение на электрические работы под напряжением?","optsr":["Любой работник бригады большинством голосов","Первый человек, прибывший на объект","Торговый представитель производителя оборудования","Уполномоченный руководящий персонал после документирования обоснования и оценки риска"],"rr":"NFPA 70E требует, чтобы разрешение на электрические работы под напряжением было рассмотрено и подписано уполномоченным руководством, подтверждающим обоснование работы под напряжением и завершённые оценки риска.","qs":"¿Quién está autorizado para determinar que el trabajo energizado está justificado y para aprobar un permiso de trabajo eléctrico energizado?","optss":["Cualquier trabajador de la cuadrilla por voto mayoritario","La primera persona en llegar al sitio","El representante de ventas del fabricante del equipo","El personal gerencial autorizado, después de que la justificación y la evaluación de riesgo estén documentadas"],"rs":"La NFPA 70E exige que el permiso de trabajo eléctrico energizado sea revisado y firmado por la gerencia autorizada, confirmando la justificación para el trabajo energizado y las evaluaciones de riesgo completadas."},
  {"id":141,"sec":"Finish Wiring & Trim","block":2,"q":"Receptacles installed within what distance of the outside edge of a sink generally require GFCI protection in a dwelling?","opts":["3 feet","4 feet","10 feet","6 feet"],"correct":3,"re":"NEC 210.8(A) requires GFCI protection for receptacles located within 6 ft of the outside edge of a sink.","qr":"Розетки, установленные в пределах какого расстояния от внешнего края раковины, обычно требуют защиты GFCI в жилье?","optsr":["3 фута","4 фута","10 футов","6 футов"],"rr":"NEC 210.8(A) требует защиту GFCI для розеток, расположенных в пределах 6 футов от внешнего края раковины.","qs":"Los receptáculos instalados dentro de qué distancia del borde exterior de un fregadero generalmente requieren protección GFCI en una vivienda?","optss":["3 feet","4 feet","10 feet","6 feet"],"rs":"NEC 210.8(A) exige protección GFCI para los receptáculos ubicados dentro de 6 ft del borde exterior de un fregadero."},
  {"id":142,"sec":"Planning & Estimation","block":2,"q":"A pump motor draws 4 kW input and produces 5 HP of useful output; what is its efficiency?","opts":["125 percent","80 percent","93 percent","75 percent"],"correct":2,"re":"Output = 5 x 746 = 3730 W; eff = 3730/4000 = 0.93 = 93 percent.","qr":"Насосный двигатель потребляет 4 кВт и выдаёт полезную мощность 5 HP; каков его КПД?","optsr":["125 процентов","80 процентов","93 процента","75 процентов"],"rr":"Выход = 5 x 746 = 3730 Вт; КПД = 3730/4000 = 0,93 = 93 процента.","qs":"Un motor de bomba consume 4 kW de entrada y produce 5 HP de salida útil; ¿cuál es su eficiencia?","optss":["125 por ciento","80 por ciento","93 por ciento","75 por ciento"],"rs":"Salida = 5 x 746 = 3730 W; ef = 3730/4000 = 0.93 = 93 por ciento."},
  {"id":143,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A 5 hp single-phase 230 V motor and a 5 hp three-phase 230 V motor are compared; which statement about their full-load currents is generally true?","opts":["The single-phase motor draws less current than the three-phase motor","Both draw exactly the same current","The single-phase motor draws more current than the three-phase motor for the same horsepower and voltage","The three-phase motor cannot operate at 230 V"],"correct":2,"re":"For the same horsepower and voltage, a single-phase motor draws substantially more current than a three-phase motor because three-phase power is delivered more efficiently across three conductors.","qr":"Сравниваются однофазный двигатель 5 л.с. 230 В и трёхфазный двигатель 5 л.с. 230 В; какое утверждение об их токах полной нагрузки обычно верно?","optsr":["Однофазный двигатель потребляет меньше тока, чем трёхфазный двигатель","Оба потребляют точно одинаковый ток","Однофазный двигатель потребляет больше тока, чем трёхфазный двигатель при той же мощности и напряжении","Трёхфазный двигатель не может работать при 230 В"],"rr":"При той же мощности и напряжении однофазный двигатель потребляет существенно больший ток, чем трёхфазный двигатель, поскольку трёхфазная мощность передаётся более эффективно по трём проводникам.","qs":"Se comparan un motor monofásico de 5 hp a 230 V y un motor trifásico de 5 hp a 230 V; ¿cuál afirmación sobre sus corrientes a plena carga es generalmente verdadera?","optss":["El motor monofásico consume menos corriente que el motor trifásico","Ambos consumen exactamente la misma corriente","El motor monofásico consume más corriente que el motor trifásico para la misma potencia en caballos de fuerza y tensión","El motor trifásico no puede operar a 230 V"],"rs":"Para la misma potencia en caballos de fuerza y tensión, un motor monofásico consume considerablemente más corriente que un motor trifásico porque la potencia trifásica se entrega de manera más eficiente a través de tres conductores."},
  {"id":144,"sec":"Rough Wiring","block":2,"q":"Plain USE conductor without an outer covering rated for the purpose is generally NOT permitted to be used as:","opts":["Underground feeder","Direct-burial service entrance","Underground service lateral","Interior branch-circuit wiring inside premises"],"correct":3,"re":"USE is intended for underground/service use; it is not listed for general interior wiring within buildings. See NEC Table 310.4(A) notes.","qr":"Обычный проводник USE без надлежащей наружной оболочки, как правило, НЕ разрешён для использования в качестве:","optsr":["Подземного фидера","Ввода с прямой укладкой в грунт","Подземного ответвления ввода","Внутренней проводки ответвлённых цепей внутри здания"],"rr":"USE предназначен для подземного/вводного применения; он не сертифицирован для общей внутренней проводки внутри зданий. См. примечания к NEC Table 310.4(A).","qs":"El conductor USE simple sin una cubierta exterior clasificada para ese propósito generalmente NO se permite usar como:","optss":["Alimentador subterráneo","Acometida de entrada enterrada directamente","Acometida lateral subterránea","Cableado de circuito ramal interior dentro de las instalaciones"],"rs":"El USE está destinado para uso subterráneo/de acometida; no está listado para cableado interior general dentro de los edificios. Vea las notas de la Tabla 310.4(A) del NEC."},
  {"id":145,"sec":"Safety","block":2,"q":"During lockout/tagout, where must each authorized employee place their lockout device?","opts":["On the equipment nameplate","On the door of the electrical room only","On the energy-isolating device, so each worker controls the isolation with their own lock","In their personal toolbox for safekeeping"],"correct":2,"re":"Cal/OSHA T8 Section 3314 requires the lockout device be applied to the energy-isolating means; when multiple workers are involved, each applies their own lock (often via a group lockout hasp) so isolation cannot be removed until every worker is done.","qr":"Во время lockout/tagout, где каждый уполномоченный работник должен разместить своё блокирующее устройство?","optsr":["На заводской табличке оборудования","Только на двери электрощитовой","На устройстве изоляции энергии, чтобы каждый работник контролировал изоляцию своим собственным замком","В своём личном ящике для инструментов на хранении"],"rr":"Раздел 3314 Title 8 Cal/OSHA требует, чтобы блокирующее устройство устанавливалось на средство изоляции энергии; при участии нескольких работников каждый ставит свой собственный замок (часто через групповую блокировочную скобу), чтобы изоляцию нельзя было снять, пока не закончит каждый работник.","qs":"Durante el bloqueo/etiquetado, ¿dónde debe colocar su dispositivo de bloqueo cada empleado autorizado?","optss":["En la placa de datos del equipo","Únicamente en la puerta del cuarto eléctrico","En el dispositivo de aislamiento de energía, para que cada trabajador controle el aislamiento con su propio candado","En su caja de herramientas personal para resguardarlo"],"rs":"Cal/OSHA T8 Sección 3314 exige que el dispositivo de bloqueo se aplique al medio de aislamiento de energía; cuando hay varios trabajadores involucrados, cada uno aplica su propio candado (a menudo mediante una mordaza de bloqueo grupal) para que el aislamiento no pueda retirarse hasta que cada trabajador haya terminado."},
  {"id":146,"sec":"Planning & Estimation","block":2,"q":"A single-phase load of 8 kVA operates at a power factor of 0.90; what is the real power in kW?","opts":["7.2 kW","8.89 kW","8 kW","0.9 kW"],"correct":0,"re":"Real power = kVA x PF = 8 x 0.90 = 7.2 kW.","qr":"Однофазная нагрузка 8 кВА работает при коэффициенте мощности 0,90; какова активная мощность в кВт?","optsr":["7,2 кВт","8,89 кВт","8 кВт","0,9 кВт"],"rr":"Активная мощность = кВА x PF = 8 x 0,90 = 7,2 кВт.","qs":"Una carga monofásica de 8 kVA opera con un factor de potencia de 0.90; ¿cuál es la potencia real en kW?","optss":["7.2 kW","8.89 kW","8 kW","0.9 kW"],"rs":"Potencia real = kVA x FP = 8 x 0.90 = 7.2 kW."},
  {"id":147,"sec":"Rough Wiring","block":2,"q":"A dual-rated conductor marked 'THHN/THWN-2' may be used in a wet location at what temperature rating?","opts":["60°C","90°C","75°C","It cannot be used in wet locations"],"correct":1,"re":"The THWN-2 rating provides 90°C in both wet and dry locations for the dual-rated conductor. See NEC Table 310.4(A).","qr":"Проводник с двойной маркировкой 'THHN/THWN-2' может использоваться во влажном месте при каком температурном классе?","optsr":["60°C","90°C","75°C","Не может использоваться во влажных местах"],"rr":"Маркировка THWN-2 обеспечивает 90°C как во влажных, так и в сухих местах для проводника с двойной маркировкой. См. NEC Table 310.4(A).","qs":"Un conductor de doble clasificación marcado 'THHN/THWN-2' puede usarse en una ubicación mojada a qué clasificación de temperatura?","optss":["60°C","90°C","75°C","No puede usarse en ubicaciones mojadas"],"rs":"La clasificación THWN-2 proporciona 90°C tanto en ubicaciones mojadas como secas para el conductor de doble clasificación. Vea la Tabla 310.4(A) del NEC."},
  {"id":148,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A three-phase motor running on a 480 V system suddenly draws high current, runs hot, and hums loudly; which condition should be checked first?","opts":["Excessive control-circuit voltage","An open phase (single-phasing) on the supply","A reversed grounding conductor","Too large a branch-circuit conductor"],"correct":1,"re":"Loss of one phase (single-phasing) causes a three-phase motor to overheat and draw high current on the remaining phases; checking for an open phase or blown fuse is the first step.","qr":"Трёхфазный двигатель, работающий в системе 480 В, внезапно потребляет большой ток, перегревается и громко гудит; какое условие следует проверить в первую очередь?","optsr":["Чрезмерное напряжение цепи управления","Обрыв фазы (однофазный режим) на питании","Перепутанный заземляющий проводник","Слишком большое сечение проводника ответвления"],"rr":"Потеря одной фазы (однофазный режим) приводит к перегреву трёхфазного двигателя и потреблению большого тока по оставшимся фазам; проверка обрыва фазы или перегоревшего предохранителя — первый шаг.","qs":"Un motor trifásico que funciona en un sistema de 480 V de repente consume corriente alta, se calienta y zumba fuertemente; ¿cuál condición debe revisarse primero?","optss":["Tensión excesiva en el circuito de control","Una fase abierta (monofaseo) en la alimentación","Un conductor de puesta a tierra invertido","Un conductor de circuito ramal demasiado grande"],"rs":"La pérdida de una fase (monofaseo) hace que un motor trifásico se sobrecaliente y consuma corriente alta en las fases restantes; revisar si hay una fase abierta o un fusible fundido es el primer paso."},
  {"id":149,"sec":"Finish Wiring & Trim","block":2,"q":"A dwelling laundry area receptacle that serves the laundry equipment generally requires what protection?","opts":["GFCI protection","Tamper-resistant only","AFCI only","No protection"],"correct":0,"re":"NEC 210.8(A) requires GFCI protection for 125-volt, 15- and 20-amp receptacles installed in dwelling laundry areas.","qr":"Розетка в прачечной зоне жилья, обслуживающая прачечное оборудование, обычно требует какой защиты?","optsr":["Защита GFCI","Только защита от вскрытия","Только AFCI","Никакой защиты"],"rr":"NEC 210.8(A) требует защиту GFCI для розеток 125 В, 15 и 20 А, установленных в прачечных зонах жилья.","qs":"Un receptáculo del área de lavandería de una vivienda que sirve el equipo de lavandería generalmente requiere qué tipo de protección?","optss":["Protección GFCI","Solo resistente a manipulación","Solo AFCI","Ninguna protección"],"rs":"NEC 210.8(A) exige protección GFCI para los receptáculos de 125 voltios, 15 y 20 amperes instalados en las áreas de lavandería de las viviendas."},
  {"id":150,"sec":"Safety","block":2,"q":"Which factor increases the available incident energy at a given piece of equipment during an arc flash?","opts":["A shorter fault clearing time of the upstream protective device","A longer arc duration before the protective device clears the fault","A larger working distance from the arc source","A lower available short-circuit current"],"correct":1,"re":"Incident energy increases with longer arc duration; the longer the upstream protective device takes to clear the fault, the more thermal energy is delivered, which is why fast-clearing protection lowers the arc-flash hazard.","qr":"Какой фактор увеличивает доступную падающую энергию на данной единице оборудования во время дугового разряда?","optsr":["Более короткое время отключения вышестоящего защитного устройства при коротком замыкании","Более длительная продолжительность дуги до того, как защитное устройство отключит короткое замыкание","Большее рабочее расстояние от источника дуги","Меньший доступный ток короткого замыкания"],"rr":"Падающая энергия увеличивается при большей продолжительности дуги; чем дольше вышестоящее защитное устройство отключает короткое замыкание, тем больше тепловой энергии выделяется, поэтому быстродействующая защита снижает опасность дугового разряда.","qs":"¿Cuál factor aumenta la energía incidente disponible en una pieza de equipo dada durante un arco eléctrico?","optss":["Un tiempo de despeje de falla más corto del dispositivo de protección aguas arriba","Una duración del arco más larga antes de que el dispositivo de protección despeje la falla","Una distancia de trabajo mayor desde la fuente del arco","Una corriente de cortocircuito disponible menor"],"rs":"La energía incidente aumenta con una duración del arco más larga; mientras más tarde el dispositivo de protección aguas arriba en despejar la falla, más energía térmica se entrega, razón por la cual una protección de despeje rápido reduce el peligro de arco eléctrico."},
  {"id":151,"sec":"Planning & Estimation","block":2,"q":"If a 277 V circuit has a 3 percent maximum allowable voltage drop, what is the maximum permitted drop in volts?","opts":["0.83 V","8.31 V","83.1 V","9.23 V"],"correct":1,"re":"Max drop = 0.03 x 277 = 8.31 V.","qr":"Если цепь 277 В имеет максимально допустимую потерю напряжения 3 процента, какова максимально допустимая потеря в вольтах?","optsr":["0,83 В","8,31 В","83,1 В","9,23 В"],"rr":"Максимальная потеря = 0,03 x 277 = 8,31 В.","qs":"Si un circuito de 277 V tiene una caída de tensión máxima permitida del 3 por ciento, ¿cuál es la caída máxima permitida en volts?","optss":["0.83 V","8.31 V","83.1 V","9.23 V"],"rs":"Caída máxima = 0.03 x 277 = 8.31 V."},
  {"id":152,"sec":"Rough Wiring","block":2,"q":"Ten current-carrying conductors are installed in a single raceway; which Table 310.15(C)(1) adjustment factor applies?","opts":["50%","70%","80%","45%"],"correct":0,"re":"For 10 to 20 current-carrying conductors the adjustment factor is 50%. See NEC Table 310.15(C)(1).","qr":"Десять токоведущих проводников проложены в одной трубе; какой коэффициент снижения из Table 310.15(C)(1) применяется?","optsr":["50%","70%","80%","45%"],"rr":"Для 10-20 токоведущих проводников коэффициент снижения составляет 50%. См. NEC Table 310.15(C)(1).","qs":"Se instalan diez conductores portadores de corriente en una sola canalización; ¿cuál factor de ajuste de la Tabla 310.15(C)(1) se aplica?","optss":["50%","70%","80%","45%"],"rs":"Para 10 a 20 conductores portadores de corriente el factor de ajuste es 50%. Vea la Tabla 310.15(C)(1) del NEC."},
  {"id":153,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"If a magnetic motor starter's coil will not energize when the start button is pressed, which is a logical first item to check in the control circuit?","opts":["The motor bearings","The direction of motor rotation","The horsepower rating on the nameplate","Continuity of the control circuit, including the stop button, overload contacts, and control fuse"],"correct":3,"re":"A coil that will not pick up points to an open control circuit; check the stop button (NC), overload (NC) contacts, control fuse, and coil continuity before suspecting mechanical issues.","qr":"Если катушка магнитного пускателя двигателя не получает питание при нажатии кнопки пуска, какой логичный первый пункт для проверки в цепи управления?","optsr":["Подшипники двигателя","Направление вращения двигателя","Номинальную мощность на табличке","Целостность цепи управления, включая кнопку стоп, контакты перегрузки и управляющий предохранитель"],"rr":"Катушка, которая не срабатывает, указывает на разомкнутую цепь управления; проверьте кнопку стоп (НЗ), контакты перегрузки (НЗ), управляющий предохранитель и целостность катушки, прежде чем подозревать механические проблемы.","qs":"Si la bobina de un arrancador magnético de motor no se energiza cuando se presiona el botón de arranque, ¿cuál es un primer elemento lógico que revisar en el circuito de control?","optss":["Los cojinetes del motor","La dirección de rotación del motor","La potencia nominal en caballos de fuerza de la placa de datos","La continuidad del circuito de control, incluyendo el botón de paro, los contactos de sobrecarga y el fusible de control"],"rs":"Una bobina que no se activa indica un circuito de control abierto; revise el botón de paro (NC), los contactos de sobrecarga (NC), el fusible de control y la continuidad de la bobina antes de sospechar de problemas mecánicos."},
  {"id":154,"sec":"Rough Wiring","block":2,"q":"Which statement about counting current-carrying conductors for derating is correct?","opts":["The grounded neutral is always counted","Equipment grounding conductors are counted","Only ungrounded (hot) conductors and qualifying neutrals are counted","All conductors in the raceway are counted"],"correct":2,"re":"Only ungrounded conductors plus neutrals that actually carry current count; EGCs and non-current-carrying neutrals are excluded. See NEC 310.15(E).","qr":"Какое утверждение о подсчёте токоведущих проводников для снижения нагрузки верно?","optsr":["Заземлённая нейтраль всегда учитывается","Заземляющие проводники оборудования учитываются","Учитываются только незаземлённые (фазные) проводники и квалифицирующиеся нейтрали","Учитываются все проводники в трубе"],"rr":"Учитываются только незаземлённые проводники плюс нейтрали, реально несущие ток; EGC и нетоковедущие нейтрали исключаются. См. NEC 310.15(E).","qs":"¿Cuál afirmación sobre el conteo de conductores portadores de corriente para reducción es correcta?","optss":["El neutro puesto a tierra siempre se cuenta","Los conductores de puesta a tierra de equipos se cuentan","Solo se cuentan los conductores no puestos a tierra (vivos) y los neutros que califican","Todos los conductores de la canalización se cuentan"],"rs":"Solo se cuentan los conductores no puestos a tierra más los neutros que realmente conducen corriente; los EGC y los neutros no portadores de corriente se excluyen. Vea NEC 310.15(E)."},
  {"id":155,"sec":"Safety","block":2,"q":"What must a qualified person do before crossing the arc-flash boundary to perform a task?","opts":["Wait until the incident energy drops on its own","Remove all metal jewelry and proceed in street clothes","Wear arc-rated PPE rated equal to or greater than the incident energy at the working distance","Notify the local fire department in writing"],"correct":2,"re":"NFPA 70E requires that anyone crossing the arc-flash boundary wear arc-rated PPE with an arc rating at least equal to the estimated incident energy at the working distance to prevent a second-degree burn.","qr":"Что должен сделать квалифицированный специалист перед пересечением границы дугового разряда для выполнения задачи?","optsr":["Подождать, пока падающая энергия снизится сама по себе","Снять все металлические украшения и работать в обычной одежде","Надеть СИЗ с дуговой защитой, рейтинг которых равен или превышает падающую энергию на рабочем расстоянии","Письменно уведомить местную пожарную службу"],"rr":"NFPA 70E требует, чтобы любой, пересекающий границу дугового разряда, носил СИЗ с дуговой защитой, дуговой рейтинг которых не менее расчётной падающей энергии на рабочем расстоянии, чтобы предотвратить ожог второй степени.","qs":"¿Qué debe hacer una persona calificada antes de cruzar la frontera de arco eléctrico para realizar una tarea?","optss":["Esperar hasta que la energía incidente disminuya por sí sola","Quitarse todas las joyas metálicas y proceder con ropa de calle","Usar EPP con clasificación de arco igual o mayor que la energía incidente a la distancia de trabajo","Notificar por escrito al departamento de bomberos local"],"rs":"La NFPA 70E exige que cualquiera que cruce la frontera de arco eléctrico use EPP con clasificación de arco con una clasificación de arco al menos igual a la energía incidente estimada a la distancia de trabajo para prevenir una quemadura de segundo grado."},
  {"id":156,"sec":"Planning & Estimation","block":2,"q":"A conductor run drops 7.2 V on a 120 V circuit supplying a load; what is the voltage delivered at the load?","opts":["112.8 V","127.2 V","6 V","120 V"],"correct":0,"re":"Load voltage = source minus drop = 120 - 7.2 = 112.8 V.","qr":"Трасса проводника теряет 7,2 В в цепи 120 В, питающей нагрузку; какое напряжение подаётся на нагрузку?","optsr":["112,8 В","127,2 В","6 В","120 В"],"rr":"Напряжение на нагрузке = источник минус потеря = 120 - 7,2 = 112,8 В.","qs":"Un tramo de conductor cae 7.2 V en un circuito de 120 V que alimenta una carga; ¿cuál es la tensión entregada en la carga?","optss":["112.8 V","127.2 V","6 V","120 V"],"rs":"Tensión en la carga = fuente menos caída = 120 - 7.2 = 112.8 V."},
  {"id":157,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A continuous-duty motor's branch-circuit conductors are sized at 125% of full-load current; the overload device for the same motor (SF 1.15) is sized at 125% of nameplate FLA. Why can these two percentages reference different current values?","opts":["Conductors use the NEC table FLC, while the overload device uses the actual nameplate full-load amperes","Both must always use the exact same current value","The overload device uses locked-rotor current","Conductors use nameplate amperes and overloads use table values"],"correct":0,"re":"Per NEC 430.6(A), conductor and short-circuit device sizing use the table FLC values, while overload protection per 430.32 is based on the motor's actual nameplate full-load current.","qr":"Проводники ответвления двигателя длительного режима выбраны на уровне 125% от тока полной нагрузки; устройство защиты от перегрузки для того же двигателя (SF 1.15) выбрано на уровне 125% от FLA с таблички. Почему эти два процента могут ссылаться на разные значения тока?","optsr":["Проводники используют табличный ток FLC из NEC, а устройство защиты от перегрузки использует фактический ток полной нагрузки с таблички","Оба всегда должны использовать точно одно и то же значение тока","Устройство защиты от перегрузки использует ток заторможенного ротора","Проводники используют ток с таблички, а защита от перегрузки — табличные значения"],"rr":"Согласно NEC 430.6(A), выбор проводника и устройства защиты от короткого замыкания использует табличные значения FLC, тогда как защита от перегрузки по 430.32 основана на фактическом токе полной нагрузки с таблички двигателя.","qs":"Los conductores del circuito ramal de un motor de servicio continuo se dimensionan al 125% de la corriente a plena carga; el dispositivo de sobrecarga para el mismo motor (SF 1.15) se dimensiona al 125% de la FLA de la placa de datos. ¿Por qué estos dos porcentajes pueden referirse a valores de corriente diferentes?","optss":["Los conductores usan la FLC de la tabla del NEC, mientras que el dispositivo de sobrecarga usa los amperes reales a plena carga de la placa de datos","Ambos siempre deben usar exactamente el mismo valor de corriente","El dispositivo de sobrecarga usa la corriente a rotor bloqueado","Los conductores usan los amperes de la placa de datos y las sobrecargas usan los valores de la tabla"],"rs":"Según NEC 430.6(A), el dimensionamiento de los conductores y del dispositivo de cortocircuito usa los valores de FLC de la tabla, mientras que la protección contra sobrecarga según 430.32 se basa en la corriente real a plena carga de la placa de datos del motor."},
  {"id":158,"sec":"Finish Wiring & Trim","block":2,"q":"When a single GFCI receptacle is wired to protect downstream receptacles, the protected outlets must be connected to which set of terminals on the GFCI device?","opts":["The LINE terminals","The grounding terminal only","The LOAD terminals","Either set works the same"],"correct":2,"re":"Downstream (protected) receptacles must connect to the LOAD terminals of the GFCI; the incoming supply connects to the LINE terminals.","qr":"Когда одна розетка GFCI подключена для защиты последующих розеток, защищаемые выходы должны быть подключены к какому набору клемм на устройстве GFCI?","optsr":["Клеммы LINE","Только клемма заземления","Клеммы LOAD","Любой набор работает одинаково"],"rr":"Последующие (защищаемые) розетки должны подключаться к клеммам LOAD устройства GFCI; входящее питание подключается к клеммам LINE.","qs":"Cuando un solo receptáculo GFCI se conecta para proteger receptáculos aguas abajo, las salidas protegidas deben conectarse a cuál conjunto de terminales del dispositivo GFCI?","optss":["Las terminales LINE","Únicamente la terminal de puesta a tierra","Las terminales LOAD","Cualquier conjunto funciona igual"],"rs":"Los receptáculos aguas abajo (protegidos) deben conectarse a las terminales LOAD del GFCI; la alimentación entrante se conecta a las terminales LINE."},
  {"id":159,"sec":"Rough Wiring","block":2,"q":"For a continuous load, branch-circuit conductors must have an allowable ampacity of not less than what percentage of the continuous load?","opts":["100%","125%","150%","115%"],"correct":1,"re":"Per NEC 210.19(A) and 215.2, conductors supplying continuous loads must be sized at not less than 125% of the continuous load.","qr":"Для длительной нагрузки проводники ответвлённой цепи должны иметь допустимую ampacity не менее какого процента длительной нагрузки?","optsr":["100%","125%","150%","115%"],"rr":"Согласно NEC 210.19(A) и 215.2, проводники, питающие длительные нагрузки, должны быть рассчитаны не менее чем на 125% длительной нагрузки.","qs":"Para una carga continua, los conductores del circuito ramal deben tener una ampacidad permisible no menor a qué porcentaje de la carga continua?","optss":["100%","125%","150%","115%"],"rs":"Según NEC 210.19(A) y 215.2, los conductores que alimentan cargas continuas deben dimensionarse no menor al 125% de la carga continua."},
  {"id":160,"sec":"Planning & Estimation","block":2,"q":"A current of 0.25 A flows through a 480 ohm resistor; how much power is dissipated?","opts":["30 W","120 W","7680 W","1920 W"],"correct":0,"re":"P = I squared x R = 0.0625 x 480 = 30 W.","qr":"Ток 0,25 А течёт через резистор 480 Ом; какая мощность рассеивается?","optsr":["30 Вт","120 Вт","7680 Вт","1920 Вт"],"rr":"P = I в квадрате x R = 0,0625 x 480 = 30 Вт.","qs":"Una corriente de 0.25 A fluye a través de un resistor de 480 ohms; ¿cuánta potencia se disipa?","optss":["30 W","120 W","7680 W","1920 W"],"rs":"P = I al cuadrado x R = 0.0625 x 480 = 30 W."},
  {"id":161,"sec":"Safety","block":2,"q":"Under Cal/OSHA T8 Section 3314, how often must lockout/tagout procedures be inspected or reviewed?","opts":["Only once when the employee is first hired","Every ten years","Periodically, at least annually, to ensure the procedures and employee performance remain effective","Never, once the written program is created"],"correct":2,"re":"Cal/OSHA T8 Section 3314 requires a periodic inspection, at least annually, of the energy-control procedures to correct deficiencies and verify that authorized employees follow them correctly.","qr":"Согласно разделу 3314 Title 8 Cal/OSHA, как часто должны проверяться или пересматриваться процедуры lockout/tagout?","optsr":["Только один раз при первичном приёме работника на работу","Каждые десять лет","Периодически, не реже одного раза в год, чтобы убедиться, что процедуры и работа сотрудников остаются эффективными","Никогда, после создания письменной программы"],"rr":"Раздел 3314 Title 8 Cal/OSHA требует периодической проверки, не реже одного раза в год, процедур управления энергией для устранения недостатков и подтверждения того, что уполномоченные работники следуют им правильно.","qs":"Según Cal/OSHA T8 Sección 3314, ¿con qué frecuencia deben inspeccionarse o revisarse los procedimientos de bloqueo/etiquetado?","optss":["Solo una vez cuando el empleado es contratado por primera vez","Cada diez años","Periódicamente, al menos anualmente, para asegurar que los procedimientos y el desempeño del empleado sigan siendo eficaces","Nunca, una vez que el programa escrito está creado"],"rs":"Cal/OSHA T8 Sección 3314 exige una inspección periódica, al menos anual, de los procedimientos de control de energía para corregir deficiencias y verificar que los empleados autorizados los sigan correctamente."},
  {"id":162,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A single-phase 240 V continuous-duty motor has a table full-load current of 20 amps; what minimum branch-circuit conductor ampacity is required by NEC 430.22?","opts":["20 amps","25 amps","23 amps","30 amps"],"correct":1,"re":"NEC 430.22 requires 125% of the FLC for a single motor: 20 A x 1.25 = 25 A minimum conductor ampacity.","qr":"Однофазный двигатель 240 В длительного режима имеет табличный ток полной нагрузки 20 ампер; какая минимальная допустимая токовая нагрузка проводника ответвления требуется по NEC 430.22?","optsr":["20 ампер","25 ампер","23 ампера","30 ампер"],"rr":"NEC 430.22 требует 125% от тока полной нагрузки для одного двигателя: 20 А x 1.25 = 25 А минимальная допустимая токовая нагрузка проводника.","qs":"Un motor monofásico de servicio continuo de 240 V tiene una corriente a plena carga de tabla de 20 amperes; ¿qué ampacidad mínima de conductor de circuito ramal requiere NEC 430.22?","optss":["20 amperes","25 amperes","23 amperes","30 amperes"],"rs":"NEC 430.22 exige el 125% de la FLC para un solo motor: 20 A x 1.25 = 25 A de ampacidad mínima del conductor."},
  {"id":163,"sec":"Rough Wiring","block":2,"q":"Six current-carrying conductors are in one conduit and the ambient is 40°C; both the 0.91 ambient correction and the 80% adjustment apply to a 90°C base ampacity of 40 A, giving approximately:","opts":["40 A","36 A","32 A","29 A"],"correct":3,"re":"40 A × 0.91 × 0.80 ≈ 29 A; correction and adjustment factors are multiplied per NEC 310.15(B) and (C).","qr":"Шесть токоведущих проводников в одной трубе при температуре окружающей среды 40°C; и коэффициент коррекции 0.91, и коэффициент снижения 80% применяются к базовой ampacity 90°C = 40 A, давая примерно:","optsr":["40 A","36 A","32 A","29 A"],"rr":"40 A × 0.91 × 0.80 ≈ 29 A; коэффициенты коррекции и снижения перемножаются согласно NEC 310.15(B) и (C).","qs":"Seis conductores portadores de corriente están en un conduit y el ambiente es de 40°C; tanto la corrección por ambiente de 0.91 como el ajuste del 80% se aplican a una ampacidad base de 90°C de 40 A, dando aproximadamente:","optss":["40 A","36 A","32 A","29 A"],"rs":"40 A × 0.91 × 0.80 ≈ 29 A; los factores de corrección y de ajuste se multiplican según NEC 310.15(B) y (C)."},
  {"id":164,"sec":"Planning & Estimation","block":2,"q":"Two resistors in series carry the same 2 A; if one is 15 ohms and the other 25 ohms, what is the total voltage across the pair?","opts":["20 V","8 V","40 V","80 V"],"correct":3,"re":"Total R = 15 + 25 = 40 ohms; V = I x R = 2 x 40 = 80 V.","qr":"Два резистора последовательно несут одинаковый ток 2 А; если один 15 Ом, а другой 25 Ом, каково суммарное напряжение на паре?","optsr":["20 В","8 В","40 В","80 В"],"rr":"Общее R = 15 + 25 = 40 Ом; V = I x R = 2 x 40 = 80 В.","qs":"Dos resistores en serie conducen los mismos 2 A; si uno es de 15 ohms y el otro de 25 ohms, ¿cuál es la tensión total a través del par?","optss":["20 V","8 V","40 V","80 V"],"rs":"R total = 15 + 25 = 40 ohms; V = I x R = 2 x 40 = 80 V."},
  {"id":165,"sec":"Safety","block":2,"q":"What distinguishes a qualified person from an unqualified person when it comes to shock approach boundaries?","opts":["Unqualified persons may freely cross any boundary if they wear gloves","Only a qualified person may cross the restricted approach boundary toward exposed energized parts using appropriate PPE and a plan","Both may cross all boundaries equally","Only the unqualified person may cross the restricted approach boundary"],"correct":1,"re":"NFPA 70E permits only a qualified person, using appropriate shock PPE and a documented approach plan, to cross the restricted approach boundary; unqualified persons are kept outside the limited approach boundary except under qualified escort.","qr":"Что отличает квалифицированного специалиста от неквалифицированного в отношении границ приближения по поражению током?","optsr":["Неквалифицированные лица могут свободно пересекать любую границу, если носят перчатки","Только квалифицированный специалист может пересекать restricted approach boundary в сторону открытых частей под напряжением, используя соответствующие СИЗ и план","Оба могут пересекать все границы одинаково","Только неквалифицированный специалист может пересекать restricted approach boundary"],"rr":"NFPA 70E разрешает только квалифицированному специалисту, использующему соответствующие СИЗ от поражения током и документированный план приближения, пересекать restricted approach boundary; неквалифицированные лица удерживаются за пределами limited approach boundary, кроме как под квалифицированным сопровождением.","qs":"¿Qué distingue a una persona calificada de una persona no calificada cuando se trata de las fronteras de aproximación por descarga?","optss":["Las personas no calificadas pueden cruzar libremente cualquier frontera si usan guantes","Solo una persona calificada puede cruzar la frontera de aproximación restringida hacia partes energizadas expuestas usando el EPP apropiado y un plan","Ambas pueden cruzar todas las fronteras por igual","Solo la persona no calificada puede cruzar la frontera de aproximación restringida"],"rs":"La NFPA 70E permite que solo una persona calificada, usando el EPP de descarga apropiado y un plan de aproximación documentado, cruce la frontera de aproximación restringida; las personas no calificadas se mantienen fuera de la frontera de aproximación limitada salvo bajo escolta calificada."},
  {"id":166,"sec":"Rough Wiring","block":2,"q":"Which conductor material is lighter in weight and lower in cost, making it common for large service-entrance and feeder runs despite needing upsizing?","opts":["Silver-coated copper","Copper","Tinned copper","Aluminum"],"correct":3,"re":"Aluminum is lighter and cheaper than copper, which is why it is widely used for larger feeders and services even though it must be upsized for equal ampacity. See NEC Table 310.16.","qr":"Какой материал проводника легче по весу и дешевле, что делает его распространённым для крупных вводов и фидеров, несмотря на необходимость увеличения сечения?","optsr":["Медь с серебряным покрытием","Медь","Лужёная медь","Алюминий"],"rr":"Алюминий легче и дешевле меди, поэтому он широко используется для крупных фидеров и вводов, хотя его сечение приходится увеличивать для равной ampacity. См. NEC Table 310.16.","qs":"¿Cuál material conductor es más ligero en peso y más bajo en costo, lo que lo hace común para grandes tramos de acometida y alimentadores a pesar de necesitar sobredimensionamiento?","optss":["Cobre recubierto de plata","Cobre","Cobre estañado","Aluminio"],"rs":"El aluminio es más ligero y más barato que el cobre, razón por la cual se usa ampliamente para alimentadores y acometidas más grandes aunque deba sobredimensionarse para igual ampacidad. Vea la Tabla 310.16 del NEC."},
  {"id":167,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"If the initial overload protection sized at 125% of nameplate FLA trips during the motor's normal starting cycle, what does NEC 430.32 permit as a remedy?","opts":["Removing the overload protection entirely","Replacing the motor with a larger horsepower unit","Reducing the branch-circuit conductor size","Increasing the overload trip setting up to a higher permitted maximum (such as 140% of FLA)"],"correct":3,"re":"NEC 430.32(C) allows the overload size to be increased to a higher maximum (e.g., up to 140% for SF 1.15+ motors) when the initial value is not sufficient to allow the motor to start.","qr":"Если начальная защита от перегрузки, выбранная на уровне 125% от FLA с таблички, срабатывает во время нормального пускового цикла двигателя, что разрешает NEC 430.32 в качестве решения?","optsr":["Полностью убрать защиту от перегрузки","Заменить двигатель на блок большей мощности","Уменьшить сечение проводника ответвления","Увеличить уставку срабатывания защиты от перегрузки до более высокого разрешённого максимума (например, до 140% от FLA)"],"rr":"NEC 430.32(C) допускает увеличение размера защиты от перегрузки до более высокого максимума (например, до 140% для двигателей с SF 1.15+), когда начального значения недостаточно для запуска двигателя.","qs":"Si la protección contra sobrecarga inicial dimensionada al 125% de la FLA de la placa de datos se dispara durante el ciclo normal de arranque del motor, ¿qué permite NEC 430.32 como solución?","optss":["Eliminar por completo la protección contra sobrecarga","Reemplazar el motor por una unidad de mayor potencia en caballos de fuerza","Reducir el tamaño del conductor del circuito ramal","Aumentar el ajuste de disparo de la sobrecarga hasta un máximo permitido mayor (como el 140% de la FLA)"],"rs":"NEC 430.32(C) permite aumentar el tamaño de la sobrecarga a un máximo mayor (por ejemplo, hasta el 140% para motores con SF 1.15 o más) cuando el valor inicial no es suficiente para permitir que el motor arranque."},
  {"id":168,"sec":"Finish Wiring & Trim","block":2,"q":"A GFCI device is designed to open the circuit when it detects a current imbalance of approximately what value between the hot and neutral conductors?","opts":["0.5 ampere","20 milliamperes","4 to 6 milliamperes","5 amperes"],"correct":2,"re":"A Class A GFCI is designed to trip when the difference between the hot and grounded conductor currents reaches approximately 4 to 6 milliamperes, protecting against shock.","qr":"Устройство GFCI предназначено для размыкания цепи при обнаружении дисбаланса тока примерно какой величины между фазным и нейтральным проводниками?","optsr":["0,5 ампера","20 миллиампер","4–6 миллиампер","5 ампер"],"rr":"GFCI класса A предназначен для срабатывания, когда разница между токами фазного и заземлённого проводников достигает примерно 4–6 миллиампер, защищая от поражения током.","qs":"Un dispositivo GFCI está diseñado para abrir el circuito cuando detecta un desbalance de corriente de aproximadamente qué valor entre los conductores vivo y neutro?","optss":["0.5 ampere","20 miliamperes","4 a 6 miliamperes","5 amperes"],"rs":"Un GFCI Clase A está diseñado para dispararse cuando la diferencia entre las corrientes del conductor vivo y del conductor puesto a tierra alcanza aproximadamente 4 a 6 miliamperes, protegiendo contra descargas."},
  {"id":169,"sec":"Planning & Estimation","block":2,"q":"A 7.5 HP single-phase motor at 90 percent efficiency operates on 240 V; what is the approximate input power?","opts":["6217 W","5036 W","5595 W","4500 W"],"correct":0,"re":"Output = 7.5 x 746 = 5595 W; input = 5595/0.90 = 6217 W.","qr":"Однофазный двигатель 7,5 HP с КПД 90 процентов работает от 240 В; какова приблизительная входная мощность?","optsr":["6217 Вт","5036 Вт","5595 Вт","4500 Вт"],"rr":"Выход = 7,5 x 746 = 5595 Вт; вход = 5595/0,90 = 6217 Вт.","qs":"Un motor monofásico de 7.5 HP con 90 por ciento de eficiencia opera a 240 V; ¿cuál es la potencia de entrada aproximada?","optss":["6217 W","5036 W","5595 W","4500 W"],"rs":"Salida = 7.5 x 746 = 5595 W; entrada = 5595/0.90 = 6217 W."},
  {"id":170,"sec":"Safety","block":2,"q":"After an electrical incident or whenever a circuit's status is uncertain, what is the safest assumption a worker should make?","opts":["Assume the circuit is de-energized to save time on testing","Assume the breaker tripped and cleared the fault","Treat all conductors and parts as energized until verified de-energized by an electrically safe work condition","Assume another worker already locked it out"],"correct":2,"re":"Cal/OSHA and NFPA 70E require conductors and circuit parts to be treated as energized until an electrically safe work condition is established and verified, because unverified assumptions about de-energization cause many electrical injuries.","qr":"После электрического инцидента или всякий раз, когда статус цепи неясен, какое предположение работнику безопаснее всего сделать?","optsr":["Предположить, что цепь обесточена, чтобы сэкономить время на проверке","Предположить, что автомат сработал и отключил короткое замыкание","Рассматривать все проводники и части как находящиеся под напряжением, пока обесточивание не подтверждено электробезопасным рабочим состоянием","Предположить, что другой работник уже заблокировал её"],"rr":"Cal/OSHA и NFPA 70E требуют рассматривать проводники и части цепи как находящиеся под напряжением, пока не создано и не проверено электробезопасное рабочее состояние, поскольку непроверенные предположения об обесточивании вызывают многие электротравмы.","qs":"Después de un incidente eléctrico o cuando el estado de un circuito es incierto, ¿cuál es la suposición más segura que debe hacer un trabajador?","optss":["Suponer que el circuito está desenergizado para ahorrar tiempo en las pruebas","Suponer que el interruptor se disparó y despejó la falla","Tratar todos los conductores y partes como energizados hasta que se verifique que están desenergizados mediante una condición de trabajo eléctricamente segura","Suponer que otro trabajador ya lo bloqueó"],"rs":"Cal/OSHA y la NFPA 70E exigen que los conductores y las partes del circuito se traten como energizados hasta que se establezca y verifique una condición de trabajo eléctricamente segura, porque las suposiciones no verificadas sobre la desenergización causan muchas lesiones eléctricas."},
  {"id":171,"sec":"Rough Wiring","block":2,"q":"Four current-carrying conductors with a 90°C base ampacity of 55 A each are bundled in a raceway; what is the adjusted ampacity?","opts":["55 A","49.5 A","44 A","38.5 A"],"correct":2,"re":"For 4-6 conductors the adjustment factor is 80%, so 55 × 0.80 = 44 A. See NEC Table 310.15(C)(1).","qr":"Четыре токоведущих проводника с базовой ampacity 90°C по 55 A каждый собраны в пучок в трубе; какова скорректированная ampacity?","optsr":["55 A","49.5 A","44 A","38.5 A"],"rr":"Для 4-6 проводников коэффициент снижения 80%, поэтому 55 × 0.80 = 44 A. См. NEC Table 310.15(C)(1).","qs":"Cuatro conductores portadores de corriente con una ampacidad base de 90°C de 55 A cada uno están agrupados en una canalización; ¿cuál es la ampacidad ajustada?","optss":["55 A","49.5 A","44 A","38.5 A"],"rs":"Para 4-6 conductores el factor de ajuste es 80%, por lo que 55 × 0.80 = 44 A. Vea la Tabla 310.15(C)(1) del NEC."},
  {"id":172,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"A single-phase transformer has a primary voltage of 480 V and a secondary voltage of 120 V, so what is its turns ratio?","opts":["1:4","1:2","2:1","4:1"],"correct":3,"re":"Turns ratio equals primary voltage divided by secondary voltage, so 480 V divided by 120 V equals a 4:1 ratio.","qr":"Однофазный трансформатор имеет первичное напряжение 480 В и вторичное 120 В, каков его коэффициент трансформации?","optsr":["1:4","1:2","2:1","4:1"],"rr":"Коэффициент трансформации равен первичному напряжению, делённому на вторичное: 480 В / 120 В = 4:1.","qs":"Un transformador monofásico tiene una tensión primaria de 480 V y una tensión secundaria de 120 V, entonces ¿cuál es su relación de vueltas?","optss":["1:4","1:2","2:1","4:1"],"rs":"La relación de vueltas es igual a la tensión primaria dividida entre la tensión secundaria, por lo que 480 V dividido entre 120 V es igual a una relación de 4:1."},
  {"id":173,"sec":"Planning & Estimation","block":2,"q":"A 120 V circuit feeds a load 150 ft away; if the two-way voltage drop is 3.6 V, what percent of the source voltage is lost?","opts":["0.3 percent","1 percent","6 percent","3 percent"],"correct":3,"re":"Percent drop = 3.6/120 x 100 = 3 percent.","qr":"Цепь 120 В питает нагрузку на расстоянии 150 футов; если потеря напряжения в обе стороны составляет 3,6 В, какой процент напряжения источника теряется?","optsr":["0,3 процента","1 процент","6 процентов","3 процента"],"rr":"Процент потери = 3,6/120 x 100 = 3 процента.","qs":"Un circuito de 120 V alimenta una carga a 150 ft de distancia; si la caída de tensión de ida y vuelta es de 3.6 V, ¿qué porcentaje de la tensión de la fuente se pierde?","optss":["0.3 por ciento","1 por ciento","6 por ciento","3 por ciento"],"rs":"Porcentaje de caída = 3.6/120 x 100 = 3 por ciento."},
  {"id":174,"sec":"Rough Wiring","block":2,"q":"When installing electrical metallic tubing (EMT) on a wall, what is the maximum distance the raceway must be securely fastened from each outlet box, junction box, or other conduit termination?","opts":["18 inches","10 feet","3 feet","5 feet"],"correct":2,"re":"Per NEC 358.30, EMT must be securely fastened within 3 ft of each outlet box, junction box, cabinet, or fitting.","qr":"При установке электрической металлической трубки (EMT) на стене, на каком максимальном расстоянии от каждой распределительной коробки, соединительной коробки или другого окончания кабелепровода должен быть надёжно закреплён raceway?","optsr":["18 дюймов","10 футов","3 фута","5 футов"],"rr":"Согласно NEC 358.30, EMT должна быть надёжно закреплена в пределах 3 футов от каждой распределительной коробки, соединительной коробки, шкафа или фитинга.","qs":"Al instalar tubería metálica eléctrica (EMT) en una pared, ¿cuál es la distancia máxima a la que la canalización debe estar sujetada de forma segura desde cada caja de salida, caja de empalme u otra terminación de conduit?","optss":["18 inches","10 feet","3 feet","5 feet"],"rs":"Según NEC 358.30, el EMT debe estar sujetado de forma segura dentro de 3 ft de cada caja de salida, caja de empalme, gabinete o accesorio."},
  {"id":175,"sec":"Safety","block":2,"q":"At what approximate level of 60 Hz alternating current passing through the human body does a person typically lose the ability to release a conductor due to muscular contraction?","opts":["About 1 mA","About 500 mA","About 100 mA","About 10 to 16 mA"],"correct":3,"re":"The let-go threshold for most adults is roughly 10 to 16 mA; above this the muscles contract and the victim cannot release the energized conductor.","qr":"При каком приблизительно уровне переменного тока частотой 60 Гц, проходящего через тело человека, человек обычно теряет способность отпустить проводник из-за сокращения мышц?","optsr":["Около 1 мА","Около 500 мА","Около 100 мА","Около 10–16 мА"],"rr":"Порог отпускания для большинства взрослых составляет примерно 10–16 мА; выше этого мышцы сокращаются, и пострадавший не может отпустить проводник под напряжением.","qs":"¿A qué nivel aproximado de corriente alterna de 60 Hz que pasa a través del cuerpo humano una persona típicamente pierde la capacidad de soltar un conductor debido a la contracción muscular?","optss":["Aproximadamente 1 mA","Aproximadamente 500 mA","Aproximadamente 100 mA","Aproximadamente 10 a 16 mA"],"rs":"El umbral de soltar para la mayoría de los adultos es de aproximadamente 10 a 16 mA; por encima de esto los músculos se contraen y la víctima no puede soltar el conductor energizado."},
  {"id":176,"sec":"Planning & Estimation","block":2,"q":"In a balanced three-phase wye-connected system, what is the relationship between the line voltage and the phase voltage?","opts":["Line voltage equals phase voltage","Line voltage equals phase voltage times 3","Line voltage equals phase voltage divided by 1.732","Line voltage equals phase voltage times 1.732"],"correct":3,"re":"In a wye configuration, line voltage = phase voltage × √3 (1.732), while line current equals phase current.","qr":"В сбалансированной трёхфазной системе, соединённой звездой, какова связь между линейным напряжением и фазным напряжением?","optsr":["Линейное напряжение равно фазному напряжению","Линейное напряжение равно фазному напряжению, умноженному на 3","Линейное напряжение равно фазному напряжению, делённому на 1.732","Линейное напряжение равно фазному напряжению, умноженному на 1.732"],"rr":"При соединении звездой линейное напряжение = фазное напряжение × √3 (1.732), а линейный ток равен фазному току.","qs":"En un sistema trifásico balanceado conectado en estrella, ¿cuál es la relación entre la tensión de línea y la tensión de fase?","optss":["La tensión de línea es igual a la tensión de fase","La tensión de línea es igual a la tensión de fase por 3","La tensión de línea es igual a la tensión de fase dividida entre 1.732","La tensión de línea es igual a la tensión de fase por 1.732"],"rs":"En una configuración en estrella, la tensión de línea = tensión de fase × √3 (1.732), mientras que la corriente de línea es igual a la corriente de fase."},
  {"id":177,"sec":"Finish Wiring & Trim","block":2,"q":"Which device is designed to detect dangerous arcing conditions in branch-circuit wiring and is required for dwelling unit bedrooms?","opts":["GFCI","Surge protective device","Isolated ground receptacle","AFCI"],"correct":3,"re":"NEC 210.12 requires arc-fault circuit-interrupter (AFCI) protection for branch circuits supplying outlets in dwelling bedrooms, which detect arcing faults.","qr":"Какое устройство предназначено для обнаружения опасных дуговых условий в проводке ответвлённой цепи и требуется для спален жилого помещения?","optsr":["GFCI","Устройство защиты от перенапряжений","Розетка с изолированным заземлением","AFCI"],"rr":"NEC 210.12 требует защиту от дугового пробоя (AFCI) для ответвлённых цепей, питающих выходы в спальнях жилья, которые обнаруживают дуговые замыкания.","qs":"¿Cuál dispositivo está diseñado para detectar condiciones peligrosas de arqueo en el cableado de circuitos ramales y se requiere para los dormitorios de unidades de vivienda?","optss":["GFCI","Dispositivo de protección contra sobretensiones","Receptáculo de tierra aislada","AFCI"],"rs":"NEC 210.12 exige protección con interruptor de circuito por falla de arco (AFCI) para los circuitos ramales que alimentan salidas en los dormitorios de las viviendas, los cuales detectan fallas de arqueo."},
  {"id":178,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"Which test instrument measures the insulation resistance of a conductor by applying a high DC voltage?","opts":["Clamp-on ammeter","Phase-rotation meter","Megohmmeter (megger)","Non-contact voltage tester"],"correct":2,"re":"A megohmmeter, or megger, applies a high DC test voltage (such as 500 V or 1000 V) to measure insulation resistance in megohms.","qr":"Какой измерительный прибор измеряет сопротивление изоляции проводника, прикладывая высокое постоянное напряжение?","optsr":["Токоизмерительные клещи","Прибор для проверки чередования фаз","Мегомметр (megger)","Бесконтактный индикатор напряжения"],"rr":"Мегомметр (megger) прикладывает высокое испытательное постоянное напряжение (например, 500 В или 1000 В) для измерения сопротивления изоляции в мегомах.","qs":"¿Cuál instrumento de prueba mide la resistencia de aislamiento de un conductor aplicando una alta tensión de CC?","optss":["Amperímetro de gancho","Medidor de rotación de fase","Megóhmetro (megger)","Detector de tensión sin contacto"],"rs":"Un megóhmetro, o megger, aplica una alta tensión de prueba de CC (como 500 V o 1000 V) para medir la resistencia de aislamiento en megaohmios."},
  {"id":179,"sec":"Rough Wiring","block":2,"q":"What is the maximum total degrees of bends permitted in a run of conduit between pull points such as boxes or conduit bodies?","opts":["180 degrees","540 degrees","270 degrees","360 degrees"],"correct":3,"re":"NEC limits the total bends between pull points to a maximum of 360 degrees (the equivalent of four quarter bends) for raceways such as EMT, RMC, IMC, and PVC.","qr":"Какое максимальное суммарное число градусов изгибов допускается на участке кабелепровода между точками протяжки, такими как коробки или соединительные корпуса?","optsr":["180 градусов","540 градусов","270 градусов","360 градусов"],"rr":"NEC ограничивает суммарное число изгибов между точками протяжки максимум 360 градусами (эквивалент четырёх изгибов по 90 градусов) для кабелепроводов, таких как EMT, RMC, IMC и PVC.","qs":"¿Cuál es el máximo total de grados de curvas permitido en un tramo de conduit entre puntos de tiro tales como cajas o cuerpos de conduit?","optss":["180 grados","540 grados","270 grados","360 grados"],"rs":"El NEC limita el total de curvas entre puntos de tiro a un máximo de 360 grados (el equivalente a cuatro curvas de un cuarto) para canalizaciones como EMT, RMC, IMC y PVC."},
  {"id":180,"sec":"Safety","block":2,"q":"Approximately what level of current through the body is generally considered the threshold of perception, where a person can just barely feel a tingle?","opts":["About 1 mA","About 50 mA","About 200 mA","About 1,000 mA"],"correct":0,"re":"The threshold of perception for most people is around 1 mA, producing a faint tingling sensation.","qr":"Какой приблизительно уровень тока через тело обычно считается порогом восприятия, когда человек едва ощущает покалывание?","optsr":["Около 1 мА","Около 50 мА","Около 200 мА","Около 1000 мА"],"rr":"Порог восприятия для большинства людей составляет около 1 мА и вызывает слабое ощущение покалывания.","qs":"¿Aproximadamente qué nivel de corriente a través del cuerpo se considera generalmente el umbral de percepción, donde una persona apenas puede sentir un hormigueo?","optss":["Aproximadamente 1 mA","Aproximadamente 50 mA","Aproximadamente 200 mA","Aproximadamente 1,000 mA"],"rs":"El umbral de percepción para la mayoría de las personas es de alrededor de 1 mA, produciendo una leve sensación de hormigueo."},
  {"id":181,"sec":"Planning & Estimation","block":2,"q":"What is the total apparent power of a three-phase load operating at 480 V line-to-line drawing 50 A per line?","opts":["72,000 VA","24,000 VA","41,569 VA","13,856 VA"],"correct":2,"re":"Three-phase apparent power S = √3 × VL × IL = 1.732 × 480 × 50 = 41,569 VA.","qr":"Какова полная мощность трёхфазной нагрузки, работающей при линейном напряжении 480 В и потребляющей 50 А на линию?","optsr":["72 000 ВА","24 000 ВА","41 569 ВА","13 856 ВА"],"rr":"Трёхфазная полная мощность S = √3 × VL × IL = 1.732 × 480 × 50 = 41 569 ВА.","qs":"¿Cuál es la potencia aparente total de una carga trifásica que opera a 480 V de línea a línea consumiendo 50 A por línea?","optss":["72,000 VA","24,000 VA","41,569 VA","13,856 VA"],"rs":"La potencia aparente trifásica S = √3 × VL × IL = 1.732 × 480 × 50 = 41,569 VA."},
  {"id":182,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"Which instrument allows you to read the current in a conductor without breaking the circuit or disconnecting any wires?","opts":["Megohmmeter","Clamp-on ammeter","Insulation tester","Continuity tester"],"correct":1,"re":"A clamp-on ammeter measures current by sensing the magnetic field around a conductor, so the circuit does not need to be opened.","qr":"Какой прибор позволяет считывать ток в проводнике без разрыва цепи и отсоединения проводов?","optsr":["Мегомметр","Токоизмерительные клещи","Прибор для проверки изоляции","Прибор для проверки целостности цепи"],"rr":"Токоизмерительные клещи измеряют ток, считывая магнитное поле вокруг проводника, поэтому цепь не нужно размыкать.","qs":"¿Cuál instrumento permite leer la corriente en un conductor sin abrir el circuito ni desconectar ningún cable?","optss":["Megóhmetro","Amperímetro de gancho","Probador de aislamiento","Probador de continuidad"],"rs":"Un amperímetro de gancho mide la corriente al detectar el campo magnético alrededor de un conductor, por lo que no es necesario abrir el circuito."},
  {"id":183,"sec":"Rough Wiring","block":2,"q":"Nonmetallic-sheathed cable (Type NM) run on the surface of framing members must be secured at intervals not exceeding which distance?","opts":["4 1/2 feet","3 feet","6 feet","10 feet"],"correct":0,"re":"Per NEC 334.30, Type NM cable must be secured at intervals not exceeding 4 1/2 ft.","qr":"Кабель в неметаллической оболочке (тип NM), проложенный по поверхности элементов каркаса, должен быть закреплён с интервалами, не превышающими какое расстояние?","optsr":["4 1/2 фута","3 фута","6 футов","10 футов"],"rr":"Согласно NEC 334.30, кабель типа NM должен быть закреплён с интервалами, не превышающими 4 1/2 фута.","qs":"El cable con cubierta no metálica (Tipo NM) instalado sobre la superficie de los miembros estructurales debe asegurarse a intervalos que no excedan qué distancia?","optss":["4 1/2 feet","3 feet","6 feet","10 feet"],"rs":"Según NEC 334.30, el cable Tipo NM debe asegurarse a intervalos que no excedan 4 1/2 ft."},
  {"id":184,"sec":"Safety","block":2,"q":"Currents in the range of roughly 100 to 200 mA through the chest are especially dangerous primarily because they can cause which life-threatening condition?","opts":["Minor skin burns only","Muscle cramps that resolve quickly","Temporary loss of hearing","Ventricular fibrillation of the heart"],"correct":3,"re":"Currents of about 100 to 200 mA across the chest can throw the heart into ventricular fibrillation, which is frequently fatal without immediate intervention.","qr":"Токи в диапазоне примерно 100–200 мА через грудную клетку особенно опасны главным образом потому, что они могут вызвать какое опасное для жизни состояние?","optsr":["Только лёгкие ожоги кожи","Мышечные судороги, которые быстро проходят","Временную потерю слуха","Фибрилляцию желудочков сердца"],"rr":"Токи около 100–200 мА через грудную клетку могут вызвать фибрилляцию желудочков сердца, которая часто смертельна без немедленного вмешательства.","qs":"Las corrientes en el rango de aproximadamente 100 a 200 mA a través del pecho son especialmente peligrosas principalmente porque pueden causar cuál condición potencialmente mortal?","optss":["Solo quemaduras menores en la piel","Calambres musculares que se resuelven rápidamente","Pérdida temporal de la audición","Fibrilación ventricular del corazón"],"rs":"Las corrientes de aproximadamente 100 a 200 mA a través del pecho pueden llevar el corazón a fibrilación ventricular, que es frecuentemente mortal sin intervención inmediata."},
  {"id":185,"sec":"Planning & Estimation","block":2,"q":"A 240 V three-phase motor delivers 30 kW of real power at a power factor of 0.85; approximately what line current does it draw?","opts":["72 A","85 A","104 A","60 A"],"correct":1,"re":"IL = P / (√3 × VL × PF) = 30,000 / (1.732 × 240 × 0.85) = 84.9 A ≈ 85 A.","qr":"Трёхфазный двигатель на 240 В выдаёт 30 кВт активной мощности при коэффициенте мощности 0.85; какой примерно линейный ток он потребляет?","optsr":["72 А","85 А","104 А","60 А"],"rr":"IL = P / (√3 × VL × PF) = 30 000 / (1.732 × 240 × 0.85) = 84.9 А ≈ 85 А.","qs":"Un motor trifásico de 240 V entrega 30 kW de potencia real con un factor de potencia de 0.85; ¿aproximadamente qué corriente de línea consume?","optss":["72 A","85 A","104 A","60 A"],"rs":"IL = P / (√3 × VL × FP) = 30,000 / (1.732 × 240 × 0.85) = 84.9 A ≈ 85 A."},
  {"id":186,"sec":"Rough Wiring","block":2,"q":"Type NM cable must be secured within what maximum distance of each outlet box, junction box, or cabinet where the cable enters?","opts":["12 inches","24 inches","18 inches","8 inches"],"correct":0,"re":"Per NEC 334.30, NM cable must be secured within 12 in. of every outlet box, junction box, cabinet, or fitting.","qr":"Кабель типа NM должен быть закреплён на каком максимальном расстоянии от каждой распределительной коробки, соединительной коробки или шкафа, где кабель входит?","optsr":["12 дюймов","24 дюйма","18 дюймов","8 дюймов"],"rr":"Согласно NEC 334.30, кабель NM должен быть закреплён в пределах 12 дюймов от каждой распределительной коробки, соединительной коробки, шкафа или фитинга.","qs":"El cable Tipo NM debe asegurarse dentro de qué distancia máxima de cada caja de salida, caja de empalme o gabinete donde entra el cable?","optss":["12 inches","24 inches","18 inches","8 inches"],"rs":"Según NEC 334.30, el cable NM debe asegurarse dentro de 12 in. de cada caja de salida, caja de empalme, gabinete o accesorio."},
  {"id":187,"sec":"Finish Wiring & Trim","block":2,"q":"AFCI protection is generally required for branch circuits supplying outlets in which of the following dwelling areas?","opts":["Bathrooms","Outdoor patios","Detached unheated garages","Bedrooms and living rooms"],"correct":3,"re":"NEC 210.12(A) requires AFCI protection for branch circuits supplying outlets in dwelling living areas such as bedrooms, living rooms, family rooms, and similar rooms.","qr":"Защита AFCI обычно требуется для ответвлённых цепей, питающих выходы в какой из следующих зон жилья?","optsr":["Ванные комнаты","Уличные террасы","Отдельно стоящие неотапливаемые гаражи","Спальни и гостиные"],"rr":"NEC 210.12(A) требует защиту AFCI для ответвлённых цепей, питающих выходы в жилых зонах, таких как спальни, гостиные, семейные комнаты и подобные помещения.","qs":"La protección AFCI generalmente se requiere para los circuitos ramales que alimentan salidas en cuál de las siguientes áreas de una vivienda?","optss":["Baños","Patios exteriores","Garajes separados sin calefacción","Dormitorios y salas de estar"],"rs":"NEC 210.12(A) exige protección AFCI para los circuitos ramales que alimentan salidas en las áreas habitables de las viviendas tales como dormitorios, salas de estar, cuartos familiares y habitaciones similares."},
  {"id":188,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"An ideal step-down transformer with a 10:1 turns ratio carries 5 A in its primary winding, so what is the approximate secondary current?","opts":["0.5 A","50 A","5 A","15 A"],"correct":1,"re":"In an ideal transformer the current ratio is the inverse of the turns ratio, so a 10:1 step-down draws 5 A primary and delivers about 50 A secondary.","qr":"Идеальный понижающий трансформатор с коэффициентом 10:1 несёт 5 А в первичной обмотке, каков приблизительный ток во вторичной обмотке?","optsr":["0,5 А","50 А","5 А","15 А"],"rr":"В идеальном трансформаторе отношение токов обратно коэффициенту трансформации, поэтому при 10:1 первичные 5 А дают около 50 А во вторичной обмотке.","qs":"Un transformador reductor ideal con una relación de vueltas de 10:1 conduce 5 A en su devanado primario, entonces ¿cuál es la corriente secundaria aproximada?","optss":["0.5 A","50 A","5 A","15 A"],"rs":"En un transformador ideal la relación de corriente es la inversa de la relación de vueltas, por lo que un reductor de 10:1 consume 5 A en el primario y entrega aproximadamente 50 A en el secundario."},
  {"id":189,"sec":"Rough Wiring","block":2,"q":"When more than two conductors are installed in a conduit or tubing, the maximum allowable conductor fill is what percentage of the raceway cross-sectional area?","opts":["31 percent","40 percent","53 percent","60 percent"],"correct":1,"re":"Per NEC Chapter 9, Table 1, where over 2 conductors are installed in a raceway, the maximum fill is 40 percent of the cross-sectional area.","qr":"Когда в кабелепроводе или трубке проложено более двух проводников, какой максимально допустимый коэффициент заполнения проводниками в процентах от площади поперечного сечения raceway?","optsr":["31 процент","40 процентов","53 процента","60 процентов"],"rr":"Согласно NEC, Глава 9, Таблица 1, когда в raceway проложено более 2 проводников, максимальное заполнение составляет 40 процентов площади поперечного сечения.","qs":"Cuando se instalan más de dos conductores en un conduit o tubería, ¿el llenado máximo permitido de conductores es qué porcentaje del área de la sección transversal de la canalización?","optss":["31 por ciento","40 por ciento","53 por ciento","60 por ciento"],"rs":"Según el Capítulo 9, Tabla 1 del NEC, donde se instalan más de 2 conductores en una canalización, el llenado máximo es del 40 por ciento del área de la sección transversal."},
  {"id":190,"sec":"Planning & Estimation","block":2,"q":"In a balanced three-phase delta-connected system, what is the relationship between line current and phase (winding) current?","opts":["Line current equals phase current","Line current equals phase current divided by 1.732","Line current equals phase current times 3","Line current equals phase current times 1.732"],"correct":3,"re":"In a delta configuration, line current = phase current × √3 (1.732), while line voltage equals phase voltage.","qr":"В сбалансированной трёхфазной системе, соединённой треугольником, какова связь между линейным током и фазным током обмотки?","optsr":["Линейный ток равен фазному току","Линейный ток равен фазному току, делённому на 1.732","Линейный ток равен фазному току, умноженному на 3","Линейный ток равен фазному току, умноженному на 1.732"],"rr":"При соединении треугольником линейный ток = фазный ток × √3 (1.732), а линейное напряжение равно фазному напряжению.","qs":"En un sistema trifásico balanceado conectado en delta, ¿cuál es la relación entre la corriente de línea y la corriente de fase (devanado)?","optss":["La corriente de línea es igual a la corriente de fase","La corriente de línea es igual a la corriente de fase dividida entre 1.732","La corriente de línea es igual a la corriente de fase por 3","La corriente de línea es igual a la corriente de fase por 1.732"],"rs":"En una configuración en delta, la corriente de línea = corriente de fase × √3 (1.732), mientras que la tensión de línea es igual a la tensión de fase."},
  {"id":191,"sec":"Safety","block":2,"q":"A Class A ground-fault circuit interrupter (GFCI) is designed to trip when the difference in current between the hot and neutral conductors reaches approximately what value?","opts":["500 mA","30 mA","100 mA","5 mA"],"correct":3,"re":"A Class A GFCI trips at a ground-fault current of about 5 mA (nominally 4 to 6 mA), the level chosen to protect people from lethal shock.","qr":"Устройство защитного отключения класса A (GFCI) рассчитано на срабатывание, когда разница тока между фазным и нейтральным проводниками достигает примерно какого значения?","optsr":["500 мА","30 мА","100 мА","5 мА"],"rr":"GFCI класса A срабатывает при токе утечки на землю около 5 мА (номинально 4–6 мА) — уровень, выбранный для защиты людей от смертельного поражения током.","qs":"Un interruptor de circuito por falla a tierra (GFCI) Clase A está diseñado para dispararse cuando la diferencia de corriente entre los conductores vivo y neutro alcanza aproximadamente qué valor?","optss":["500 mA","30 mA","100 mA","5 mA"],"rs":"Un GFCI Clase A se dispara con una corriente de falla a tierra de aproximadamente 5 mA (nominalmente 4 a 6 mA), el nivel elegido para proteger a las personas de descargas letales."},
  {"id":192,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"In a balanced three-phase wye (star) connected transformer, how does the line voltage compare to the phase (winding) voltage?","opts":["Line voltage is the square root of 3 times the phase voltage","Line voltage is half the phase voltage","Line voltage is 3 times the phase voltage","Line voltage equals phase voltage"],"correct":0,"re":"In a wye connection the line voltage equals the phase voltage multiplied by the square root of 3 (about 1.732), while line and phase currents are equal.","qr":"В сбалансированном трёхфазном трансформаторе со схемой звезда, как линейное напряжение соотносится с фазным (обмоточным) напряжением?","optsr":["Линейное напряжение в корень из 3 раз больше фазного напряжения","Линейное напряжение составляет половину фазного напряжения","Линейное напряжение в 3 раза больше фазного напряжения","Линейное напряжение равно фазному напряжению"],"rr":"В схеме звезда линейное напряжение равно фазному напряжению, умноженному на корень из 3 (примерно 1,732), а линейный и фазный токи равны.","qs":"En un transformador trifásico balanceado conectado en estrella, ¿cómo se compara la tensión de línea con la tensión de fase (devanado)?","optss":["La tensión de línea es la raíz cuadrada de 3 veces la tensión de fase","La tensión de línea es la mitad de la tensión de fase","La tensión de línea es 3 veces la tensión de fase","La tensión de línea es igual a la tensión de fase"],"rs":"En una conexión en estrella la tensión de línea es igual a la tensión de fase multiplicada por la raíz cuadrada de 3 (aproximadamente 1.732), mientras que las corrientes de línea y de fase son iguales."},
  {"id":193,"sec":"Rough Wiring","block":2,"q":"A single insulated conductor installed alone in a conduit is permitted to fill a maximum of what percentage of the raceway's cross-sectional area?","opts":["31 percent","40 percent","53 percent","60 percent"],"correct":2,"re":"Per NEC Chapter 9, Table 1, one conductor in a raceway is permitted a maximum fill of 53 percent.","qr":"Одиночный изолированный проводник, проложенный в кабелепроводе один, может заполнять максимум какой процент площади поперечного сечения raceway?","optsr":["31 процент","40 процентов","53 процента","60 процентов"],"rr":"Согласно NEC, Глава 9, Таблица 1, для одного проводника в raceway допускается максимальное заполнение 53 процента.","qs":"Un solo conductor aislado instalado solo en un conduit puede llenar un máximo de qué porcentaje del área de la sección transversal de la canalización?","optss":["31 por ciento","40 por ciento","53 por ciento","60 por ciento"],"rs":"Según el Capítulo 9, Tabla 1 del NEC, se permite que un conductor en una canalización tenga un llenado máximo del 53 por ciento."},
  {"id":194,"sec":"Planning & Estimation","block":2,"q":"A three-phase wye system has a phase voltage of 277 V; what is the approximate line-to-line voltage?","opts":["277 V","480 V","831 V","160 V"],"correct":1,"re":"Wye line voltage = phase voltage × √3 = 277 × 1.732 = 480 V.","qr":"Трёхфазная система звезда имеет фазное напряжение 277 В; каково примерно линейное напряжение?","optsr":["277 В","480 В","831 В","160 В"],"rr":"Линейное напряжение звезды = фазное напряжение × √3 = 277 × 1.732 = 480 В.","qs":"Un sistema trifásico en estrella tiene una tensión de fase de 277 V; ¿cuál es la tensión aproximada de línea a línea?","optss":["277 V","480 V","831 V","160 V"],"rs":"Tensión de línea en estrella = tensión de fase × √3 = 277 × 1.732 = 480 V."},
  {"id":195,"sec":"Finish Wiring & Trim","block":2,"q":"What is the primary hazard that AFCI protection is intended to reduce?","opts":["Fires caused by arcing faults","Electric shock to a person","Voltage drop on long runs","Overloaded neutral conductors"],"correct":0,"re":"AFCI devices are intended to de-energize a circuit when an arcing fault is detected, reducing the risk of fires ignited by arcing in wiring, per NEC 210.12.","qr":"Какую главную опасность призвана уменьшить защита AFCI?","optsr":["Пожары, вызванные дуговыми замыканиями","Поражение человека электрическим током","Падение напряжения на длинных линиях","Перегрузка нейтральных проводников"],"rr":"Устройства AFCI предназначены для обесточивания цепи при обнаружении дугового замыкания, снижая риск пожаров от искрения в проводке, согласно NEC 210.12.","qs":"¿Cuál es el peligro principal que la protección AFCI pretende reducir?","optss":["Incendios causados por fallas de arqueo","Descarga eléctrica a una persona","Caída de tensión en tramos largos","Conductores neutros sobrecargados"],"rs":"Los dispositivos AFCI están destinados a desenergizar un circuito cuando se detecta una falla de arqueo, reduciendo el riesgo de incendios provocados por arqueo en el cableado, según NEC 210.12."},
  {"id":196,"sec":"Safety","block":2,"q":"Under OSHA 1926.404, which of the following best describes the GFCI requirement for 125-volt, single-phase, 15- and 20-ampere receptacle outlets used by employees on a construction site?","opts":["GFCI protection is required only when it rains","GFCI protection is never required outdoors","GFCI protection is required for all such receptacles not part of the permanent wiring","GFCI protection applies only to 240-volt circuits"],"correct":2,"re":"OSHA requires GFCI protection for all 125-V, single-phase, 15-, 20-, and 30-A receptacle outlets that are not part of the permanent wiring and are used by employees.","qr":"Согласно OSHA 1926.404, что из перечисленного лучше всего описывает требование к GFCI для розеток 125 В, однофазных, на 15 и 20 А, используемых работниками на стройплощадке?","optsr":["Защита GFCI требуется только во время дождя","Защита GFCI никогда не требуется на улице","Защита GFCI требуется для всех таких розеток, не являющихся частью постоянной проводки","Защита GFCI применяется только к цепям 240 В"],"rr":"OSHA требует защиту GFCI для всех розеток 125 В, однофазных, на 15, 20 и 30 А, которые не являются частью постоянной проводки и используются работниками.","qs":"Según OSHA 1926.404, ¿cuál de las siguientes describe mejor el requisito de GFCI para las salidas de receptáculos de 125 voltios, monofásicas, de 15 y 20 amperes utilizadas por los empleados en un sitio de construcción?","optss":["La protección GFCI se requiere únicamente cuando llueve","La protección GFCI nunca se requiere en exteriores","La protección GFCI se requiere para todos esos receptáculos que no formen parte del cableado permanente","La protección GFCI se aplica únicamente a circuitos de 240 voltios"],"rs":"OSHA exige protección GFCI para todas las salidas de receptáculos de 125 V, monofásicas, de 15, 20 y 30 A que no formen parte del cableado permanente y que sean utilizadas por los empleados."},
  {"id":197,"sec":"Startup, Troubleshooting & Maintenance","block":2,"q":"What is the primary purpose of using a phase-rotation meter before connecting a three-phase motor?","opts":["To measure insulation resistance","To verify the phase sequence so the motor turns in the correct direction","To measure the ground-electrode resistance","To check conductor continuity"],"correct":1,"re":"A phase-rotation meter confirms the A-B-C phase sequence so a three-phase motor rotates in the intended direction when energized.","qr":"Какова основная цель использования прибора для проверки чередования фаз перед подключением трёхфазного двигателя?","optsr":["Измерить сопротивление изоляции","Проверить последовательность фаз, чтобы двигатель вращался в правильном направлении","Измерить сопротивление заземляющего электрода","Проверить целостность проводника"],"rr":"Прибор для проверки чередования фаз подтверждает последовательность A-B-C, чтобы трёхфазный двигатель вращался в нужном направлении при включении.","qs":"¿Cuál es el propósito principal de usar un medidor de rotación de fase antes de conectar un motor trifásico?","optss":["Medir la resistencia de aislamiento","Verificar la secuencia de fases para que el motor gire en la dirección correcta","Medir la resistencia del electrodo de tierra","Comprobar la continuidad del conductor"],"rs":"Un medidor de rotación de fase confirma la secuencia de fases A-B-C para que un motor trifásico gire en la dirección prevista al energizarse."},
  {"id":198,"sec":"Rough Wiring","block":2,"q":"When exactly two conductors are installed in a conduit, the maximum conductor fill permitted is what percentage of the raceway cross-sectional area?","opts":["60 percent","40 percent","53 percent","31 percent"],"correct":3,"re":"Per NEC Chapter 9, Table 1, two conductors in a raceway are limited to a maximum fill of 31 percent.","qr":"Когда в кабелепроводе проложено ровно два проводника, какое максимальное заполнение проводниками допускается в процентах от площади поперечного сечения raceway?","optsr":["60 процентов","40 процентов","53 процента","31 процент"],"rr":"Согласно NEC, Глава 9, Таблица 1, два проводника в raceway ограничены максимальным заполнением 31 процент.","qs":"Cuando se instalan exactamente dos conductores en un conduit, ¿el llenado máximo de conductores permitido es qué porcentaje del área de la sección transversal de la canalización?","optss":["60 por ciento","40 por ciento","53 por ciento","31 por ciento"],"rs":"Según el Capítulo 9, Tabla 1 del NEC, dos conductores en una canalización están limitados a un llenado máximo del 31 por ciento."},
  {"id":199,"sec":"Planning & Estimation","block":2,"q":"What is the real power consumed by a three-phase load at 208 V drawing 40 A per line with a power factor of 0.9?","opts":["14,400 W","8,320 W","16,000 W","12,973 W"],"correct":3,"re":"P = √3 × VL × IL × PF = 1.732 × 208 × 40 × 0.9 = 12,973 W.","qr":"Какова активная мощность, потребляемая трёхфазной нагрузкой при 208 В, потребляющей 40 А на линию при коэффициенте мощности 0.9?","optsr":["14 400 Вт","8 320 Вт","16 000 Вт","12 973 Вт"],"rr":"P = √3 × VL × IL × PF = 1.732 × 208 × 40 × 0.9 = 12 973 Вт.","qs":"¿Cuál es la potencia real consumida por una carga trifásica a 208 V que consume 40 A por línea con un factor de potencia de 0.9?","optss":["14,400 W","8,320 W","16,000 W","12,973 W"],"rs":"P = √3 × VL × IL × FP = 1.732 × 208 × 40 × 0.9 = 12,973 W."},
  {"id":200,"sec":"Safety","block":2,"q":"On a construction site, OSHA 1926.404 allows an employer to use an assured equipment grounding conductor program as an alternative to which protective measure?","opts":["Lockout/tagout procedures","Hard-hat requirements","Personal fall arrest systems","GFCI protection on temporary receptacles"],"correct":3,"re":"The assured equipment grounding conductor program is the permitted alternative to GFCI protection for receptacles not part of the permanent wiring.","qr":"На стройплощадке OSHA 1926.404 разрешает работодателю использовать программу обеспечения заземляющего проводника как альтернативу какой защитной мере?","optsr":["Процедурам блокировки/маркировки (lockout/tagout)","Требованиям к каскам","Системам индивидуальной защиты от падения","Защите GFCI на временных розетках"],"rr":"Программа обеспечения заземляющего проводника является допустимой альтернативой защите GFCI для розеток, не являющихся частью постоянной проводки.","qs":"En un sitio de construcción, OSHA 1926.404 permite que un empleador use un programa de conductor de puesta a tierra de equipos garantizado como alternativa a cuál medida de protección?","optss":["Procedimientos de bloqueo/etiquetado","Requisitos de casco de seguridad","Sistemas personales de detención de caídas","Protección GFCI en receptáculos temporales"],"rs":"El programa de conductor de puesta a tierra de equipos garantizado es la alternativa permitida a la protección GFCI para receptáculos que no formen parte del cableado permanente."},
  {"id":201,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"When using a digital multimeter set to the resistance (ohms) function, on what condition must the circuit be tested?","opts":["Energized at full load","Under reduced voltage","Energized at no load","De-energized with no voltage present"],"correct":3,"re":"Resistance and continuity measurements must be made on a de-energized circuit, because applied voltage will give false readings and can damage the meter.","qr":"При использовании цифрового мультиметра в режиме измерения сопротивления (ом), при каком условии должна тестироваться цепь?","optsr":["Под полной нагрузкой и напряжением","При пониженном напряжении","Под напряжением без нагрузки","Обесточенной, без напряжения"],"rr":"Измерения сопротивления и целостности выполняются на обесточенной цепи, так как приложенное напряжение даёт ложные показания и может повредить прибор.","qs":"Al usar un multímetro digital configurado en la función de resistencia (ohmios), ¿en qué condición debe probarse el circuito?","optss":["Energizado a plena carga","Bajo voltaje reducido","Energizado sin carga","Desenergizado y sin voltaje presente"],"rs":"Las mediciones de resistencia y continuidad deben hacerse en un circuito desenergizado, porque el voltaje aplicado dará lecturas falsas y puede dañar el medidor."},
  {"id":202,"sec":"Rough Wiring","block":3,"q":"Where a cable or raceway-type wiring method passes through a wood stud and the edge of the bored hole is less than 1 1/4 inches from the nearest edge of the stud, what protection is required?","opts":["A steel plate or bushing at least 1/16 inch thick","No additional protection is required","Wrapping the cable with electrical tape","Doubling the staple spacing"],"correct":0,"re":"Per NEC 300.4(A), where the hole is less than 1 1/4 in. from the nearest edge, a steel plate or bushing at least 1/16 in. thick must protect the wiring from screws and nails.","qr":"Когда кабель или кабелепровод проходит через деревянную стойку и край просверленного отверстия находится менее чем в 1 1/4 дюйма от ближайшего края стойки, какая защита требуется?","optsr":["Стальная пластина или втулка толщиной не менее 1/16 дюйма","Дополнительная защита не требуется","Обмотка кабеля изолентой","Удвоение интервала установки скоб"],"rr":"Согласно NEC 300.4(A), когда отверстие находится менее чем в 1 1/4 дюйма от ближайшего края, стальная пластина или втулка толщиной не менее 1/16 дюйма должна защищать проводку от шурупов и гвоздей.","qs":"Cuando un método de cableado tipo cable o canalización atraviesa un montante de madera y el borde del agujero perforado está a menos de 1 1/4 pulgadas del borde más cercano del montante, ¿qué protección se requiere?","optss":["Una placa o buje de acero de al menos 1/16 de pulgada de espesor","No se requiere protección adicional","Envolver el cable con cinta eléctrica","Duplicar el espaciamiento de las grapas"],"rs":"Según NEC 300.4(A), cuando el agujero está a menos de 1 1/4 pulg. del borde más cercano, una placa o buje de acero de al menos 1/16 pulg. de espesor debe proteger el cableado de tornillos y clavos."},
  {"id":203,"sec":"Planning & Estimation","block":3,"q":"A 480 V line-to-line three-phase system is connected in wye; what is the voltage from any one line to the neutral?","opts":["480 V","277 V","240 V","831 V"],"correct":1,"re":"Line-to-neutral (phase) voltage = line voltage ÷ √3 = 480 ÷ 1.732 = 277 V.","qr":"Трёхфазная система 480 В линейного напряжения соединена звездой; какое напряжение от любой линии до нейтрали?","optsr":["480 В","277 В","240 В","831 В"],"rr":"Напряжение линия-нейтраль (фазное) = линейное напряжение ÷ √3 = 480 ÷ 1.732 = 277 В.","qs":"Un sistema trifásico de 480 V línea a línea está conectado en estrella; ¿cuál es el voltaje de cualquier línea al neutro?","optss":["480 V","277 V","240 V","831 V"],"rs":"Voltaje línea a neutro (de fase) = voltaje de línea ÷ √3 = 480 ÷ 1.732 = 277 V."},
  {"id":204,"sec":"Finish Wiring & Trim","block":3,"q":"In a new dwelling unit, 125-volt, 15- and 20-amp receptacles installed in areas specified by the Code must be of what type to resist insertion of foreign objects by children?","opts":["Weather-resistant","Tamper-resistant","Isolated ground","Hospital grade"],"correct":1,"re":"NEC 406.12 requires listed tamper-resistant (TR) receptacles for 125-volt, 15- and 20-amp receptacles in dwelling units, which have internal shutters preventing object insertion.","qr":"В новом жилом помещении розетки 125 В, 15 и 20 А, установленные в зонах, указанных Кодексом, должны быть какого типа, чтобы препятствовать вставке посторонних предметов детьми?","optsr":["Влагостойкие","Защищённые от вскрытия (tamper-resistant)","С изолированным заземлением","Больничного класса"],"rr":"NEC 406.12 требует сертифицированные защищённые от вскрытия (TR) розетки для розеток 125 В, 15 и 20 А в жилых помещениях, которые имеют внутренние шторки, препятствующие вставке предметов.","qs":"En una unidad de vivienda nueva, los receptáculos de 125 voltios, 15 y 20 amperios instalados en las áreas especificadas por el Código deben ser de qué tipo para resistir la inserción de objetos extraños por parte de los niños?","optss":["Resistentes a la intemperie","Resistentes a la manipulación","De tierra aislada","De grado hospitalario"],"rs":"NEC 406.12 requiere receptáculos resistentes a la manipulación (TR) listados para los receptáculos de 125 voltios, 15 y 20 amperios en unidades de vivienda, los cuales tienen obturadores internos que impiden la inserción de objetos."},
  {"id":205,"sec":"Rough Wiring","block":3,"q":"Which raceway type is most subject to corrosion and is NOT suitable for severe corrosive environments unless provided with supplementary corrosion protection?","opts":["Electrical metallic tubing (EMT)","PVC Schedule 40","Rigid metal conduit (RMC)","Intermediate metal conduit (IMC)"],"correct":0,"re":"Per NEC 358.10, EMT and its fittings are subject to corrosion and require supplementary protection in severe corrosive conditions, unlike PVC.","qr":"Какой тип raceway наиболее подвержен коррозии и НЕ подходит для сильно коррозионной среды без дополнительной защиты от коррозии?","optsr":["Электрическая металлическая трубка (EMT)","PVC Schedule 40","Жёсткий металлический кабелепровод (RMC)","Промежуточный металлический кабелепровод (IMC)"],"rr":"Согласно NEC 358.10, EMT и её фитинги подвержены коррозии и требуют дополнительной защиты в сильно коррозионных условиях, в отличие от PVC.","qs":"¿Qué tipo de canalización es más susceptible a la corrosión y NO es adecuada para ambientes corrosivos severos a menos que se le proporcione protección suplementaria contra la corrosión?","optss":["Tubería metálica eléctrica (EMT)","PVC Cédula 40","Conduit metálico rígido (RMC)","Conduit metálico intermedio (IMC)"],"rs":"Según NEC 358.10, el EMT y sus accesorios son susceptibles a la corrosión y requieren protección suplementaria en condiciones corrosivas severas, a diferencia del PVC."},
  {"id":206,"sec":"Safety","block":3,"q":"Under an assured equipment grounding conductor program, each cord set and receptacle that is not part of the permanent wiring must, at a minimum, be tested for continuity and proper terminal connection of the equipment grounding conductor at what frequency?","opts":["Before first use, after repair, and at least every 3 months","Once per year","Only when a tool fails","Once every 5 years"],"correct":0,"re":"OSHA requires testing before first use, after any repairs, after suspected damage, and at intervals not exceeding 3 months (6 months for fixed receptacles not exposed to damage).","qr":"В рамках программы обеспечения заземляющего проводника каждый удлинитель и розетка, не входящие в постоянную проводку, должны как минимум проверяться на непрерывность и правильность подключения заземляющего проводника с какой периодичностью?","optsr":["Перед первым использованием, после ремонта и не реже одного раза в 3 месяца","Один раз в год","Только когда инструмент выходит из строя","Один раз в 5 лет"],"rr":"OSHA требует проверки перед первым использованием, после ремонта, после подозрения на повреждение и с интервалом не более 3 месяцев (6 месяцев для стационарных розеток, не подверженных повреждению).","qs":"Bajo un programa garantizado de conductor de puesta a tierra de equipos, cada juego de cordón y receptáculo que no forma parte del cableado permanente debe, como mínimo, probarse para verificar la continuidad y la conexión adecuada del terminal del conductor de puesta a tierra de equipos, ¿con qué frecuencia?","optss":["Antes del primer uso, después de una reparación y al menos cada 3 meses","Una vez al año","Solo cuando una herramienta falla","Una vez cada 5 años"],"rs":"OSHA requiere realizar pruebas antes del primer uso, después de cualquier reparación, después de sospecha de daño y a intervalos que no excedan 3 meses (6 meses para receptáculos fijos no expuestos a daño)."},
  {"id":207,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"A buck-boost transformer is most commonly used to do which of the following?","opts":["Make a small voltage correction, such as raising 208 V to about 230 V","Convert single-phase to three-phase power","Provide complete isolation between two large systems","Step a primary down to a separately derived 120/240 V service"],"correct":0,"re":"A buck-boost transformer is connected as an autotransformer to make a small percentage adjustment in voltage, such as bucking down or boosting up a supply by roughly 5 to 20 percent.","qr":"Трансформатор buck-boost чаще всего используется для выполнения какого из следующих действий?","optsr":["Небольшая коррекция напряжения, например повышение 208 В примерно до 230 В","Преобразование однофазного питания в трёхфазное","Полная гальваническая развязка между двумя крупными системами","Понижение первичной обмотки до отдельно выделенного питания 120/240 В"],"rr":"Трансформатор buck-boost подключается как автотрансформатор для небольшой процентной корректировки напряжения, например понижения или повышения примерно на 5–20 процентов.","qs":"Un transformador buck-boost se usa más comúnmente para hacer cuál de las siguientes acciones?","optss":["Hacer una pequeña corrección de voltaje, como elevar 208 V a aproximadamente 230 V","Convertir energía monofásica a trifásica","Proporcionar aislamiento completo entre dos sistemas grandes","Reducir un primario a un servicio de 120/240 V derivado por separado"],"rs":"Un transformador buck-boost se conecta como autotransformador para hacer un pequeño ajuste porcentual en el voltaje, como reducir (buck) o aumentar (boost) un suministro en aproximadamente 5 a 20 por ciento."},
  {"id":208,"sec":"Planning & Estimation","block":3,"q":"A single-phase transformer has a primary voltage of 480 V and a secondary voltage of 120 V; what is the turns ratio?","opts":["4:1","1:4","2:1","6:1"],"correct":0,"re":"Turns ratio = primary voltage ÷ secondary voltage = 480 ÷ 120 = 4, expressed as 4:1.","qr":"Однофазный трансформатор имеет первичное напряжение 480 В и вторичное напряжение 120 В; каков коэффициент трансформации?","optsr":["4:1","1:4","2:1","6:1"],"rr":"Коэффициент трансформации = первичное напряжение ÷ вторичное напряжение = 480 ÷ 120 = 4, то есть 4:1.","qs":"Un transformador monofásico tiene un voltaje primario de 480 V y un voltaje secundario de 120 V; ¿cuál es la relación de vueltas?","optss":["4:1","1:4","2:1","6:1"],"rs":"Relación de vueltas = voltaje primario ÷ voltaje secundario = 480 ÷ 120 = 4, expresada como 4:1."},
  {"id":209,"sec":"Rough Wiring","block":3,"q":"Rigid PVC conduit (Schedule 40) installed on a wall must be securely fastened within what distance of each box, cabinet, or other conduit termination?","opts":["18 inches","8 feet","3 feet","5 feet"],"correct":2,"re":"Per NEC 352.30, rigid PVC conduit must be securely fastened within 3 ft of each box, cabinet, conduit body, or other termination.","qr":"Жёсткий PVC кабелепровод (Schedule 40), установленный на стене, должен быть надёжно закреплён в пределах какого расстояния от каждой коробки, шкафа или другого окончания кабелепровода?","optsr":["18 дюймов","8 футов","3 фута","5 футов"],"rr":"Согласно NEC 352.30, жёсткий PVC кабелепровод должен быть надёжно закреплён в пределах 3 футов от каждой коробки, шкафа, соединительного корпуса или другого окончания.","qs":"El conduit rígido de PVC (Cédula 40) instalado en una pared debe sujetarse firmemente dentro de qué distancia de cada caja, gabinete u otra terminación del conduit?","optss":["18 pulgadas","8 pies","3 pies","5 pies"],"rs":"Según NEC 352.30, el conduit rígido de PVC debe sujetarse firmemente dentro de los 3 pies de cada caja, gabinete, cuerpo de conduit u otra terminación."},
  {"id":210,"sec":"Safety","block":3,"q":"In an assured equipment grounding conductor program, which of the following tests must be performed on each cord set and receptacle?","opts":["A measurement of the conductor's color fade","A test that all equipment grounding conductors are electrically continuous","A test of the cord's tensile strength only","A check of the manufacturer's warranty date"],"correct":1,"re":"Each cord set and receptacle must be tested to verify that the equipment grounding conductor is electrically continuous and correctly connected to its proper terminal.","qr":"В программе обеспечения заземляющего проводника какая из следующих проверок должна выполняться на каждом удлинителе и розетке?","optsr":["Измерение выцветания цвета проводника","Проверка электрической непрерывности всех заземляющих проводников","Проверка только прочности шнура на разрыв","Проверка даты гарантии производителя"],"rr":"Каждый удлинитель и розетка должны проверяться для подтверждения того, что заземляющий проводник электрически непрерывен и правильно подключён к своему контакту.","qs":"En un programa garantizado de conductor de puesta a tierra de equipos, ¿cuál de las siguientes pruebas debe realizarse en cada juego de cordón y receptáculo?","optss":["Una medición de la decoloración del color del conductor","Una prueba de que todos los conductores de puesta a tierra de equipos tienen continuidad eléctrica","Una prueba únicamente de la resistencia a la tracción del cordón","Una verificación de la fecha de garantía del fabricante"],"rs":"Cada juego de cordón y receptáculo debe probarse para verificar que el conductor de puesta a tierra de equipos tiene continuidad eléctrica y está correctamente conectado a su terminal apropiado."},
  {"id":211,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Before energizing a newly installed panelboard, which commissioning check should be performed on all terminations?","opts":["Apply full load current and watch for heat","Energize and read voltage at each breaker","Verify each lug is tightened to the manufacturer's specified torque","Spray contact cleaner on each lug"],"correct":2,"re":"A key pre-energization commissioning step is to torque all terminations to the manufacturer's specified values using a calibrated torque tool to prevent loose, high-resistance connections.","qr":"Перед подачей напряжения на вновь установленный распределительный щит, какую пусконаладочную проверку следует выполнить на всех соединениях?","optsr":["Подать полный ток нагрузки и наблюдать за нагревом","Включить и считать напряжение на каждом автомате","Убедиться, что каждый зажим затянут с моментом, указанным производителем","Распылить очиститель контактов на каждый зажим"],"rr":"Ключевой шаг наладки перед подачей напряжения — затянуть все соединения с моментом, указанным производителем, калиброванным динамометрическим инструментом, чтобы предотвратить слабые соединения с высоким сопротивлением.","qs":"Antes de energizar un tablero recién instalado, ¿qué verificación de puesta en servicio debe realizarse en todas las terminaciones?","optss":["Aplicar corriente a plena carga y observar el calentamiento","Energizar y leer el voltaje en cada interruptor","Verificar que cada lengüeta esté apretada al par de torsión especificado por el fabricante","Rociar limpiador de contactos en cada lengüeta"],"rs":"Un paso clave de puesta en servicio previo a la energización es apretar todas las terminaciones a los valores de par de torsión especificados por el fabricante usando una herramienta de torque calibrada para evitar conexiones flojas de alta resistencia."},
  {"id":212,"sec":"Planning & Estimation","block":3,"q":"A transformer with a 10:1 turns ratio has 240 V applied to its primary; what is the secondary voltage (ignoring losses)?","opts":["24 V","120 V","10 V","2,400 V"],"correct":0,"re":"Secondary voltage = primary voltage ÷ turns ratio = 240 ÷ 10 = 24 V.","qr":"Трансформатор с коэффициентом трансформации 10:1 имеет 240 В на первичной обмотке; каково вторичное напряжение (без учёта потерь)?","optsr":["24 В","120 В","10 В","2 400 В"],"rr":"Вторичное напряжение = первичное напряжение ÷ коэффициент трансформации = 240 ÷ 10 = 24 В.","qs":"Un transformador con una relación de vueltas de 10:1 tiene 240 V aplicados a su primario; ¿cuál es el voltaje secundario (ignorando las pérdidas)?","optss":["24 V","120 V","10 V","2,400 V"],"rs":"Voltaje secundario = voltaje primario ÷ relación de vueltas = 240 ÷ 10 = 24 V."},
  {"id":213,"sec":"Rough Wiring","block":3,"q":"An expansion fitting is required to be installed on a rigid PVC conduit run to compensate for which condition?","opts":["Electromagnetic interference","Voltage drop over long distances","Excessive conductor fill","Thermal expansion and contraction of the conduit"],"correct":3,"re":"Per NEC 352.44, expansion fittings shall be provided to compensate for thermal expansion and contraction where the length change is expected to be 1/4 in. or greater.","qr":"Компенсационный фитинг (expansion fitting) требуется устанавливать на участке жёсткого PVC кабелепровода для компенсации какого условия?","optsr":["Электромагнитных помех","Падения напряжения на больших расстояниях","Избыточного заполнения проводниками","Теплового расширения и сжатия кабелепровода"],"rr":"Согласно NEC 352.44, компенсационные фитинги должны устанавливаться для компенсации теплового расширения и сжатия, когда ожидаемое изменение длины составляет 1/4 дюйма или более.","qs":"Se requiere instalar un accesorio de expansión en un tramo de conduit rígido de PVC para compensar cuál condición?","optss":["Interferencia electromagnética","Caída de voltaje en distancias largas","Relleno excesivo de conductores","Expansión y contracción térmica del conduit"],"rs":"Según NEC 352.44, se deben proporcionar accesorios de expansión para compensar la expansión y contracción térmica cuando se espera que el cambio de longitud sea de 1/4 pulg. o mayor."},
  {"id":214,"sec":"Finish Wiring & Trim","block":3,"q":"What feature distinguishes a tamper-resistant receptacle from a standard receptacle?","opts":["Internal spring-loaded shutters over the slots","A higher amperage rating","A weatherproof gasket","An integral surge suppressor"],"correct":0,"re":"Tamper-resistant receptacles (NEC 406.12) use internal spring-loaded shutters that open only when both blades of a plug are inserted simultaneously, blocking single-object insertion.","qr":"Какая особенность отличает защищённую от вскрытия розетку от стандартной?","optsr":["Внутренние подпружиненные шторки над прорезями","Более высокий номинальный ток","Водонепроницаемая прокладка","Встроенный подавитель перенапряжений"],"rr":"Защищённые от вскрытия розетки (NEC 406.12) используют внутренние подпружиненные шторки, которые открываются только при одновременной вставке обоих контактов вилки, блокируя вставку одного предмета.","qs":"¿Qué característica distingue a un receptáculo resistente a la manipulación de un receptáculo estándar?","optss":["Obturadores internos accionados por resorte sobre las ranuras","Una clasificación de amperaje más alta","Una junta a prueba de intemperie","Un supresor de sobretensiones integrado"],"rs":"Los receptáculos resistentes a la manipulación (NEC 406.12) usan obturadores internos accionados por resorte que se abren solo cuando ambas patas de un enchufe se insertan simultáneamente, bloqueando la inserción de un solo objeto."},
  {"id":215,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Which method is used to measure the resistance of a driven ground rod to earth?","opts":["Continuity test with a multimeter on the ohms range","Three-point fall-of-potential ground-resistance test","Insulation-resistance test with a megger","Clamp-on current measurement of the service conductor"],"correct":1,"re":"Ground-electrode resistance is commonly measured with a three-point fall-of-potential test using auxiliary probes, or with a clamp-on ground-resistance tester.","qr":"Какой метод используется для измерения сопротивления забитого заземляющего стержня относительно земли?","optsr":["Проверка целостности мультиметром в режиме ом","Трёхточечный метод падения потенциала для измерения сопротивления заземления","Проверка сопротивления изоляции мегомметром","Измерение тока клещами на вводном проводнике"],"rr":"Сопротивление заземляющего электрода обычно измеряется трёхточечным методом падения потенциала со вспомогательными электродами или клещевым измерителем сопротивления заземления.","qs":"¿Qué método se usa para medir la resistencia a tierra de una varilla de puesta a tierra hincada?","optss":["Prueba de continuidad con un multímetro en el rango de ohmios","Prueba de resistencia de tierra de caída de potencial de tres puntos","Prueba de resistencia de aislamiento con un megóhmetro","Medición de corriente con pinza del conductor del servicio"],"rs":"La resistencia del electrodo de tierra se mide comúnmente con una prueba de caída de potencial de tres puntos usando sondas auxiliares, o con un probador de resistencia de tierra tipo pinza."},
  {"id":216,"sec":"Safety","block":3,"q":"A portable electric drill marked with the symbol of a square within a square is described as double-insulated; what does this designation indicate about the tool?","opts":["It relies on two independent layers of insulation and does not require an equipment grounding conductor","It must always be connected to a GFCI to be safe","It is rated for use only in wet locations","It contains two internal batteries"],"correct":0,"re":"The square-within-a-square symbol identifies a double-insulated tool, which provides two independent insulation systems and therefore does not need a grounding conductor.","qr":"Портативная электрическая дрель, отмеченная символом квадрата внутри квадрата, называется двойной изоляции; что означает это обозначение в отношении инструмента?","optsr":["Она использует два независимых слоя изоляции и не требует заземляющего проводника","Она всегда должна подключаться к GFCI для безопасности","Она рассчитана только на использование во влажных местах","Она содержит две внутренние батареи"],"rr":"Символ квадрата внутри квадрата обозначает инструмент двойной изоляции, который обеспечивает две независимые системы изоляции и поэтому не требует заземляющего проводника.","qs":"Un taladro eléctrico portátil marcado con el símbolo de un cuadrado dentro de un cuadrado se describe como de doble aislamiento; ¿qué indica esta designación sobre la herramienta?","optss":["Depende de dos capas independientes de aislamiento y no requiere un conductor de puesta a tierra de equipos","Siempre debe conectarse a un GFCI para ser segura","Está clasificada para uso solo en lugares mojados","Contiene dos baterías internas"],"rs":"El símbolo de cuadrado dentro de un cuadrado identifica una herramienta de doble aislamiento, que proporciona dos sistemas de aislamiento independientes y por lo tanto no necesita un conductor de puesta a tierra."},
  {"id":217,"sec":"Planning & Estimation","block":3,"q":"What is the full-load current on the secondary of a 25 kVA single-phase transformer with a 240 V secondary?","opts":["60 A","104 A","208 A","10 A"],"correct":1,"re":"Single-phase secondary current = kVA × 1000 ÷ V = 25,000 ÷ 240 = 104 A.","qr":"Каков ток полной нагрузки на вторичной обмотке однофазного трансформатора 25 кВА с вторичным напряжением 240 В?","optsr":["60 А","104 А","208 А","10 А"],"rr":"Ток вторичной обмотки однофазного трансформатора = кВА × 1000 ÷ В = 25 000 ÷ 240 = 104 А.","qs":"¿Cuál es la corriente a plena carga en el secundario de un transformador monofásico de 25 kVA con un secundario de 240 V?","optss":["60 A","104 A","208 A","10 A"],"rs":"Corriente secundaria monofásica = kVA × 1000 ÷ V = 25,000 ÷ 240 = 104 A."},
  {"id":218,"sec":"Rough Wiring","block":3,"q":"In a standard outlet box, what volume in cubic inches must be allowed for each 14 AWG conductor when performing a box-fill calculation?","opts":["1.5 cubic inches","2.5 cubic inches","2.25 cubic inches","2.0 cubic inches"],"correct":3,"re":"Per NEC Table 314.16(B), each 14 AWG conductor requires a volume allowance of 2.0 cubic inches.","qr":"В стандартной распределительной коробке какой объём в кубических дюймах должен быть выделен на каждый проводник 14 AWG при расчёте заполнения коробки?","optsr":["1.5 кубических дюйма","2.5 кубических дюйма","2.25 кубических дюйма","2.0 кубических дюйма"],"rr":"Согласно NEC Таблица 314.16(B), каждый проводник 14 AWG требует выделения объёма 2.0 кубических дюйма.","qs":"En una caja de salida estándar, ¿qué volumen en pulgadas cúbicas debe asignarse por cada conductor 14 AWG al realizar un cálculo de relleno de caja?","optss":["1.5 pulgadas cúbicas","2.5 pulgadas cúbicas","2.25 pulgadas cúbicas","2.0 pulgadas cúbicas"],"rs":"Según la Tabla 314.16(B) del NEC, cada conductor 14 AWG requiere una asignación de volumen de 2.0 pulgadas cúbicas."},
  {"id":219,"sec":"Planning & Estimation","block":3,"q":"A three-phase transformer is rated 75 kVA with a 208 V secondary; what is the approximate secondary full-load line current?","opts":["208 A","625 A","360 A","104 A"],"correct":0,"re":"Three-phase current = kVA × 1000 ÷ (√3 × V) = 75,000 ÷ (1.732 × 208) = 75,000 ÷ 360.3 = 208 A.","qr":"Трёхфазный трансформатор рассчитан на 75 кВА с вторичным напряжением 208 В; каков примерный ток полной нагрузки вторичной линии?","optsr":["208 А","625 А","360 А","104 А"],"rr":"Трёхфазный ток = кВА × 1000 ÷ (√3 × В) = 75 000 ÷ (1.732 × 208) = 208 А.","qs":"Un transformador trifásico está clasificado en 75 kVA con un secundario de 208 V; ¿cuál es la corriente de línea aproximada a plena carga del secundario?","optss":["208 A","625 A","360 A","104 A"],"rs":"Corriente trifásica = kVA × 1000 ÷ (√3 × V) = 75,000 ÷ (1.732 × 208) = 75,000 ÷ 360.3 = 208 A."},
  {"id":220,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"A non-contact voltage tester is best suited for which task?","opts":["Measuring exact line-to-line voltage","Measuring the turns ratio of a transformer","Measuring current draw on a feeder","Quickly indicating the presence of voltage without touching a conductor"],"correct":3,"re":"A non-contact voltage tester senses the electric field and indicates whether voltage is present, but it does not display an exact value.","qr":"Бесконтактный индикатор напряжения лучше всего подходит для какой задачи?","optsr":["Измерение точного межфазного напряжения","Измерение коэффициента трансформации трансформатора","Измерение потребляемого тока на фидере","Быстрое определение наличия напряжения без касания проводника"],"rr":"Бесконтактный индикатор напряжения считывает электрическое поле и показывает наличие напряжения, но не отображает точное значение.","qs":"Un probador de voltaje sin contacto es más adecuado para cuál tarea?","optss":["Medir el voltaje exacto línea a línea","Medir la relación de vueltas de un transformador","Medir el consumo de corriente en un alimentador","Indicar rápidamente la presencia de voltaje sin tocar un conductor"],"rs":"Un probador de voltaje sin contacto detecta el campo eléctrico e indica si hay voltaje presente, pero no muestra un valor exacto."},
  {"id":221,"sec":"Safety","block":3,"q":"A grounded portable power tool with a three-prong plug is plugged into a two-wire receptacle using an adapter whose grounding pigtail is left unconnected; what is the principal hazard?","opts":["The tool's metal housing has no path to ground if an internal fault occurs","The tool will run in reverse","The tool will draw excessive current and trip the breaker","The tool will overheat the receptacle"],"correct":0,"re":"Without the grounding pigtail connected, a fault to the tool's metal frame leaves the housing energized with no low-resistance path to ground, exposing the user to shock.","qr":"Заземляемый портативный электроинструмент с трёхштырьковой вилкой подключён к двухпроводной розетке через переходник, у которого заземляющий хвостик оставлен неподключённым; в чём основная опасность?","optsr":["Металлический корпус инструмента не имеет пути к земле при внутреннем повреждении","Инструмент будет работать в обратную сторону","Инструмент будет потреблять чрезмерный ток и отключит автомат","Инструмент перегреет розетку"],"rr":"Без подключённого заземляющего хвостика повреждение на металлический корпус инструмента оставляет корпус под напряжением без низкоомного пути к земле, подвергая пользователя поражению током.","qs":"Una herramienta eléctrica portátil puesta a tierra con un enchufe de tres patas se conecta a un receptáculo de dos hilos usando un adaptador cuya coleta de puesta a tierra se deja sin conectar; ¿cuál es el principal peligro?","optss":["La carcasa metálica de la herramienta no tiene una ruta a tierra si ocurre una falla interna","La herramienta funcionará en reversa","La herramienta consumirá corriente excesiva y disparará el interruptor","La herramienta sobrecalentará el receptáculo"],"rs":"Sin la coleta de puesta a tierra conectada, una falla al bastidor metálico de la herramienta deja la carcasa energizada sin una ruta de baja resistencia a tierra, exponiendo al usuario a una descarga."},
  {"id":222,"sec":"Rough Wiring","block":3,"q":"In a box-fill calculation, what volume in cubic inches must be allowed for each 12 AWG conductor?","opts":["2.25 cubic inches","2.0 cubic inches","2.5 cubic inches","3.0 cubic inches"],"correct":0,"re":"Per NEC Table 314.16(B), each 12 AWG conductor requires a volume allowance of 2.25 cubic inches.","qr":"При расчёте заполнения коробки какой объём в кубических дюймах должен быть выделен на каждый проводник 12 AWG?","optsr":["2.25 кубических дюйма","2.0 кубических дюйма","2.5 кубических дюйма","3.0 кубических дюйма"],"rr":"Согласно NEC Таблица 314.16(B), каждый проводник 12 AWG требует выделения объёма 2.25 кубических дюйма.","qs":"En un cálculo de relleno de caja, ¿qué volumen en pulgadas cúbicas debe asignarse por cada conductor 12 AWG?","optss":["2.25 pulgadas cúbicas","2.0 pulgadas cúbicas","2.5 pulgadas cúbicas","3.0 pulgadas cúbicas"],"rs":"Según la Tabla 314.16(B) del NEC, cada conductor 12 AWG requiere una asignación de volumen de 2.25 pulgadas cúbicas."},
  {"id":223,"sec":"Finish Wiring & Trim","block":3,"q":"A 15- or 20-amp, 125-volt receptacle installed outdoors in a damp or wet location must be listed as which type?","opts":["Tamper-resistant only","Self-grounding","Hospital grade","Weather-resistant (WR)"],"correct":3,"re":"NEC 406.9(A) and (B) require receptacles in damp or wet locations to be of the weather-resistant (WR) type, listed for those conditions.","qr":"Розетка 15 или 20 А, 125 В, установленная на улице во влажном или мокром месте, должна быть сертифицирована как какой тип?","optsr":["Только защищённая от вскрытия","Самозаземляющаяся","Больничного класса","Влагостойкая (WR)"],"rr":"NEC 406.9(A) и (B) требуют, чтобы розетки во влажных или мокрых местах были влагостойкого типа (WR), сертифицированного для таких условий.","qs":"Un receptáculo de 15 o 20 amperios, 125 voltios instalado en exteriores en un lugar húmedo o mojado debe estar listado como cuál tipo?","optss":["Solo resistente a la manipulación","De autopuesta a tierra","De grado hospitalario","Resistente a la intemperie (WR)"],"rs":"NEC 406.9(A) y (B) requieren que los receptáculos en lugares húmedos o mojados sean del tipo resistente a la intemperie (WR), listados para esas condiciones."},
  {"id":224,"sec":"Planning & Estimation","block":3,"q":"If a step-down transformer has a secondary current of 100 A and a turns ratio of 5:1, what is the approximate primary current (ignoring losses)?","opts":["500 A","20 A","100 A","25 A"],"correct":1,"re":"Primary current = secondary current ÷ turns ratio = 100 ÷ 5 = 20 A (current is inversely proportional to the voltage ratio).","qr":"Если понижающий трансформатор имеет вторичный ток 100 А и коэффициент трансформации 5:1, каков примерный первичный ток (без учёта потерь)?","optsr":["500 А","20 А","100 А","25 А"],"rr":"Первичный ток = вторичный ток ÷ коэффициент трансформации = 100 ÷ 5 = 20 А (ток обратно пропорционален коэффициенту напряжения).","qs":"Si un transformador reductor tiene una corriente secundaria de 100 A y una relación de vueltas de 5:1, ¿cuál es la corriente primaria aproximada (ignorando las pérdidas)?","optss":["500 A","20 A","100 A","25 A"],"rs":"Corriente primaria = corriente secundaria ÷ relación de vueltas = 100 ÷ 5 = 20 A (la corriente es inversamente proporcional a la relación de voltaje)."},
  {"id":225,"sec":"Rough Wiring","block":3,"q":"When calculating box fill, how are all of the equipment grounding conductors that enter a box counted, regardless of how many there are?","opts":["Each grounding conductor counts as one separate conductor","They are not counted at all","All grounding conductors together count as a single conductor volume allowance based on the largest one","They count double because of the bonding requirement"],"correct":2,"re":"Per NEC 314.16(B)(5), all equipment grounding conductors count collectively as a single conductor volume allowance, based on the largest grounding conductor present.","qr":"При расчёте заполнения коробки как учитываются все заземляющие проводники оборудования, входящие в коробку, независимо от их количества?","optsr":["Каждый заземляющий проводник считается как один отдельный проводник","Они вообще не учитываются","Все заземляющие проводники вместе считаются как объём одного проводника на основе самого большого из них","Они считаются вдвойне из-за требования к соединению"],"rr":"Согласно NEC 314.16(B)(5), все заземляющие проводники оборудования вместе считаются как объём одного проводника на основе самого большого из присутствующих заземляющих проводников.","qs":"Al calcular el relleno de caja, ¿cómo se cuentan todos los conductores de puesta a tierra de equipos que entran a una caja, sin importar cuántos haya?","optss":["Cada conductor de puesta a tierra cuenta como un conductor separado","No se cuentan en absoluto","Todos los conductores de puesta a tierra juntos cuentan como una sola asignación de volumen de conductor basada en el más grande","Cuentan doble debido al requisito de unión"],"rs":"Según NEC 314.16(B)(5), todos los conductores de puesta a tierra de equipos cuentan colectivamente como una sola asignación de volumen de conductor, basada en el conductor de puesta a tierra más grande presente."},
  {"id":226,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"For a 25 kVA single-phase transformer with a 240 V secondary, what is the approximate full-load secondary current?","opts":["About 60 A","About 208 A","About 104 A","About 25 A"],"correct":2,"re":"Secondary current equals VA divided by voltage, so 25,000 VA divided by 240 V is about 104 A.","qr":"Для однофазного трансформатора 25 кВА с вторичным напряжением 240 В, каков приблизительный ток полной нагрузки вторичной обмотки?","optsr":["Около 60 А","Около 208 А","Около 104 А","Около 25 А"],"rr":"Вторичный ток равен ВА, делённым на напряжение: 25 000 ВА / 240 В ≈ 104 А.","qs":"Para un transformador monofásico de 25 kVA con un secundario de 240 V, ¿cuál es la corriente secundaria aproximada a plena carga?","optss":["Aproximadamente 60 A","Aproximadamente 208 A","Aproximadamente 104 A","Aproximadamente 25 A"],"rs":"La corriente secundaria es igual a los VA divididos por el voltaje, entonces 25,000 VA divididos por 240 V es aproximadamente 104 A."},
  {"id":227,"sec":"Safety","block":3,"q":"When working on or near exposed energized electrical parts, which type of portable ladder is recommended to reduce the risk of electric shock?","opts":["Aluminum ladder","Steel ladder","Magnesium ladder","Fiberglass (nonconductive) ladder"],"correct":3,"re":"A fiberglass ladder has nonconductive side rails, making it the proper choice near energized parts where a metal ladder could become an electrical path.","qr":"При работе на или рядом с открытыми токоведущими частями под напряжением какой тип переносной лестницы рекомендуется для снижения риска поражения током?","optsr":["Алюминиевая лестница","Стальная лестница","Магниевая лестница","Лестница из стеклопластика (непроводящая)"],"rr":"Лестница из стеклопластика имеет непроводящие боковые стойки, что делает её правильным выбором рядом с токоведущими частями, где металлическая лестница могла бы стать электрическим путём.","qs":"Al trabajar sobre o cerca de partes eléctricas energizadas expuestas, ¿qué tipo de escalera portátil se recomienda para reducir el riesgo de descarga eléctrica?","optss":["Escalera de aluminio","Escalera de acero","Escalera de magnesio","Escalera de fibra de vidrio (no conductora)"],"rs":"Una escalera de fibra de vidrio tiene rieles laterales no conductores, lo que la hace la elección adecuada cerca de partes energizadas donde una escalera metálica podría convertirse en una ruta eléctrica."},
  {"id":228,"sec":"Rough Wiring","block":3,"q":"In a box-fill calculation, how many conductor volume allowances are counted for a single device such as a receptacle or switch mounted on a yoke or strap?","opts":["One based on the largest conductor connected to the device","Two based on the largest conductor connected to the device","Three regardless of conductor size","Zero because devices are not counted"],"correct":1,"re":"Per NEC 314.16(B)(4), each yoke or strap containing one or more devices is counted as two conductor volume allowances based on the largest conductor connected to it.","qr":"При расчёте заполнения коробки сколько объёмов проводников учитывается для одного устройства, такого как розетка или выключатель, установленного на ярме или скобе?","optsr":["Один на основе самого большого проводника, подключённого к устройству","Два на основе самого большого проводника, подключённого к устройству","Три независимо от сечения проводника","Ноль, так как устройства не учитываются"],"rr":"Согласно NEC 314.16(B)(4), каждое ярмо или скоба, содержащая одно или несколько устройств, учитывается как два объёма проводников на основе самого большого подключённого к ней проводника.","qs":"En un cálculo de relleno de caja, ¿cuántas asignaciones de volumen de conductor se cuentan por un solo dispositivo como un receptáculo o interruptor montado en un yugo o tira?","optss":["Una basada en el conductor más grande conectado al dispositivo","Dos basadas en el conductor más grande conectado al dispositivo","Tres sin importar el tamaño del conductor","Cero porque los dispositivos no se cuentan"],"rs":"Según NEC 314.16(B)(4), cada yugo o tira que contiene uno o más dispositivos se cuenta como dos asignaciones de volumen de conductor basadas en el conductor más grande conectado a él."},
  {"id":229,"sec":"Planning & Estimation","block":3,"q":"What size transformer, in kVA, is minimally required to supply a single-phase 240 V load drawing 80 A?","opts":["10 kVA","19.2 kVA","33.3 kVA","15 kVA"],"correct":1,"re":"kVA = V × A ÷ 1000 = 240 × 80 ÷ 1000 = 19.2 kVA.","qr":"Трансформатор какой мощности в кВА минимально требуется для питания однофазной нагрузки 240 В, потребляющей 80 А?","optsr":["10 кВА","19.2 кВА","33.3 кВА","15 кВА"],"rr":"кВА = В × А ÷ 1000 = 240 × 80 ÷ 1000 = 19.2 кВА.","qs":"¿Qué tamaño de transformador, en kVA, se requiere como mínimo para alimentar una carga monofásica de 240 V que consume 80 A?","optss":["10 kVA","19.2 kVA","33.3 kVA","15 kVA"],"rs":"kVA = V × A ÷ 1000 = 240 × 80 ÷ 1000 = 19.2 kVA."},
  {"id":230,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"When commissioning a separately derived system from a dry-type transformer, where must the system grounding (bonding) connection be made?","opts":["At the load end of every branch circuit","Only at the utility transformer","At the source, bonding the secondary neutral to a grounding electrode","At each individual receptacle"],"correct":2,"re":"A separately derived system must have its grounded (neutral) conductor bonded to a grounding electrode at or near the source, typically with a system bonding jumper at the transformer.","qr":"При наладке отдельно выделенной системы от сухого трансформатора, где должно выполняться заземление (соединение) системы?","optsr":["На конце нагрузки каждой ответвлённой цепи","Только на трансформаторе энергокомпании","У источника, соединяя вторичный нейтраль с заземляющим электродом","На каждой отдельной розетке"],"rr":"Отдельно выделенная система должна иметь заземлённый (нейтральный) проводник, соединённый с заземляющим электродом у источника, обычно системной соединительной перемычкой на трансформаторе.","qs":"Al poner en servicio un sistema derivado por separado de un transformador de tipo seco, ¿dónde debe hacerse la conexión de puesta a tierra (unión) del sistema?","optss":["En el extremo de carga de cada circuito ramal","Solo en el transformador de la empresa de servicios","En la fuente, uniendo el neutro secundario a un electrodo de puesta a tierra","En cada receptáculo individual"],"rs":"Un sistema derivado por separado debe tener su conductor puesto a tierra (neutro) unido a un electrodo de puesta a tierra en o cerca de la fuente, normalmente con un puente de unión del sistema en el transformador."},
  {"id":231,"sec":"Safety","block":3,"q":"An electrician must change a light fixture located near energized overhead conductors and chooses a ladder; which of the following is the least appropriate choice?","opts":["A dry wood ladder","An aluminum extension ladder","A fiberglass ladder","A nonconductive step ladder"],"correct":1,"re":"An aluminum ladder is conductive and the least appropriate near energized conductors; fiberglass or other nonconductive ladders should be used instead.","qr":"Электрик должен заменить светильник, расположенный рядом с токоведущими воздушными проводниками под напряжением, и выбирает лестницу; какой из следующих вариантов наименее подходящий?","optsr":["Сухая деревянная лестница","Алюминиевая раздвижная лестница","Лестница из стеклопластика","Непроводящая стремянка"],"rr":"Алюминиевая лестница проводит ток и наименее подходит рядом с токоведущими проводниками; вместо неё следует использовать стеклопластиковые или другие непроводящие лестницы.","qs":"Un electricista debe cambiar una luminaria ubicada cerca de conductores aéreos energizados y elige una escalera; ¿cuál de las siguientes es la opción menos apropiada?","optss":["Una escalera de madera seca","Una escalera de extensión de aluminio","Una escalera de fibra de vidrio","Una escalera de tijera no conductora"],"rs":"Una escalera de aluminio es conductora y la menos apropiada cerca de conductores energizados; en su lugar deben usarse escaleras de fibra de vidrio u otras no conductoras."},
  {"id":232,"sec":"Finish Wiring & Trim","block":3,"q":"A 15- or 20-amp, 125-volt receptacle in a wet location must have an enclosure that is weatherproof under what condition?","opts":["Only when the cover is closed","Whether or not an attachment plug cap is inserted","Only when no plug is inserted","Only during dry weather"],"correct":1,"re":"NEC 406.9(B)(1) requires receptacles in wet locations to have a weatherproof enclosure (an in-use/while-in-use cover) that remains weatherproof whether or not an attachment plug is inserted.","qr":"Розетка 15 или 20 А, 125 В в мокром месте должна иметь корпус, который является водонепроницаемым при каком условии?","optsr":["Только когда крышка закрыта","Независимо от того, вставлена вилка или нет","Только когда вилка не вставлена","Только в сухую погоду"],"rr":"NEC 406.9(B)(1) требует, чтобы розетки в мокрых местах имели водонепроницаемый корпус (крышку 'in-use'/'while-in-use'), который остаётся водонепроницаемым независимо от того, вставлена вилка или нет.","qs":"Un receptáculo de 15 o 20 amperios, 125 voltios en un lugar mojado debe tener un encerramiento que sea a prueba de intemperie ¿bajo qué condición?","optss":["Solo cuando la cubierta está cerrada","Esté o no insertada una clavija de enchufe","Solo cuando no hay un enchufe insertado","Solo durante clima seco"],"rs":"NEC 406.9(B)(1) requiere que los receptáculos en lugares mojados tengan un encerramiento a prueba de intemperie (una cubierta de uso/mientras está en uso) que permanezca a prueba de intemperie esté o no insertado un enchufe."},
  {"id":233,"sec":"Rough Wiring","block":3,"q":"Which of the following wiring methods is flexible and commonly used for the final connection to a motor to reduce the transmission of vibration and noise?","opts":["Rigid metal conduit (RMC)","PVC Schedule 80","Electrical metallic tubing (EMT)","Flexible metal conduit (FMC)"],"correct":3,"re":"Per NEC Article 348, flexible metal conduit (FMC) is used where flexibility is needed, such as motor connections, to dampen vibration.","qr":"Какой из следующих методов прокладки является гибким и обычно используется для окончательного подключения к двигателю с целью уменьшения передачи вибрации и шума?","optsr":["Жёсткий металлический кабелепровод (RMC)","PVC Schedule 80","Электрическая металлическая трубка (EMT)","Гибкий металлический кабелепровод (FMC)"],"rr":"Согласно NEC Статья 348, гибкий металлический кабелепровод (FMC) используется там, где требуется гибкость, например для подключения двигателей, для гашения вибрации.","qs":"¿Cuál de los siguientes métodos de cableado es flexible y se usa comúnmente para la conexión final a un motor a fin de reducir la transmisión de vibración y ruido?","optss":["Conduit metálico rígido (RMC)","PVC Cédula 80","Tubería metálica eléctrica (EMT)","Conduit metálico flexible (FMC)"],"rs":"Según el Artículo 348 del NEC, el conduit metálico flexible (FMC) se usa donde se necesita flexibilidad, como en las conexiones de motores, para amortiguar la vibración."},
  {"id":234,"sec":"Planning & Estimation","block":3,"q":"A single-phase transformer steps 7,200 V down to 240 V; if the primary draws 5 A, what is the approximate secondary current (ignoring losses)?","opts":["0.17 A","30 A","150 A","300 A"],"correct":2,"re":"Secondary current = primary current × (primary V ÷ secondary V) = 5 × (7200 ÷ 240) = 5 × 30 = 150 A.","qr":"Однофазный трансформатор понижает 7 200 В до 240 В; если первичная обмотка потребляет 5 А, каков примерный вторичный ток (без учёта потерь)?","optsr":["0.17 А","30 А","150 А","300 А"],"rr":"Вторичный ток = первичный ток × (первичное В ÷ вторичное В) = 5 × (7200 ÷ 240) = 5 × 30 = 150 А.","qs":"Un transformador monofásico reduce 7,200 V a 240 V; si el primario consume 5 A, ¿cuál es la corriente secundaria aproximada (ignorando las pérdidas)?","optss":["0.17 A","30 A","150 A","300 A"],"rs":"Corriente secundaria = corriente primaria × (V primario ÷ V secundario) = 5 × (7200 ÷ 240) = 5 × 30 = 150 A."},
  {"id":235,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"If a megohmmeter reads a very low or near-zero insulation resistance between a conductor and ground, what does this most likely indicate?","opts":["Excellent insulation","A correctly grounded system that needs no further action","An open circuit","Insulation breakdown or a fault to ground"],"correct":3,"re":"A very low insulation-resistance reading indicates deteriorated or damaged insulation or a fault path to ground, which must be corrected before energizing.","qr":"Если мегомметр показывает очень низкое или близкое к нулю сопротивление изоляции между проводником и землёй, что это, скорее всего, означает?","optsr":["Отличную изоляцию","Правильно заземлённую систему, не требующую действий","Обрыв цепи","Пробой изоляции или замыкание на землю"],"rr":"Очень низкое показание сопротивления изоляции указывает на повреждённую или ухудшившуюся изоляцию либо путь утечки на землю, что необходимо устранить до подачи напряжения.","qs":"Si un megóhmetro lee una resistencia de aislamiento muy baja o cercana a cero entre un conductor y tierra, ¿qué indica esto con mayor probabilidad?","optss":["Aislamiento excelente","Un sistema correctamente puesto a tierra que no requiere más acción","Un circuito abierto","Ruptura del aislamiento o una falla a tierra"],"rs":"Una lectura muy baja de resistencia de aislamiento indica un aislamiento deteriorado o dañado o una ruta de falla a tierra, que debe corregirse antes de energizar."},
  {"id":236,"sec":"Safety","block":3,"q":"If you discover a coworker who is still in contact with an energized conductor and cannot let go, what is the correct first action?","opts":["Immediately grab the victim and pull them away with your bare hands","Pour water on the victim to cool the burns","De-energize the circuit or use a nonconductive object to separate the victim from the source","Begin chest compressions while the victim is still energized"],"correct":2,"re":"You must first remove the source of electricity, either by shutting off the power or using a nonconductive means to free the victim, before touching them or starting CPR.","qr":"Если вы обнаружили коллегу, который всё ещё контактирует с проводником под напряжением и не может отпустить его, какое первое действие правильное?","optsr":["Немедленно схватить пострадавшего и оттащить голыми руками","Облить пострадавшего водой, чтобы охладить ожоги","Обесточить цепь или использовать непроводящий предмет, чтобы отделить пострадавшего от источника","Начать компрессии грудной клетки, пока пострадавший под напряжением"],"rr":"Сначала необходимо устранить источник электричества, отключив питание или используя непроводящее средство для освобождения пострадавшего, прежде чем прикасаться к нему или начинать СЛР.","qs":"Si descubre a un compañero de trabajo que todavía está en contacto con un conductor energizado y no puede soltarse, ¿cuál es la primera acción correcta?","optss":["Agarrar inmediatamente a la víctima y jalarla con las manos desnudas","Echar agua a la víctima para enfriar las quemaduras","Desenergizar el circuito o usar un objeto no conductor para separar a la víctima de la fuente","Comenzar compresiones torácicas mientras la víctima todavía está energizada"],"rs":"Primero debe eliminar la fuente de electricidad, ya sea cortando la energía o usando un medio no conductor para liberar a la víctima, antes de tocarla o comenzar la RCP."},
  {"id":237,"sec":"Rough Wiring","block":3,"q":"Which flexible raceway is specifically listed and suitable for use in wet locations and damp environments where liquids may be present?","opts":["Flexible metal conduit (FMC)","Liquidtight flexible metal conduit (LFMC)","Electrical nonmetallic tubing (ENT) without fittings","Standard EMT without weatherproof fittings"],"correct":1,"re":"Per NEC Article 350, liquidtight flexible metal conduit (LFMC) has a liquidtight outer jacket making it suitable for wet locations; standard FMC is not.","qr":"Какой гибкий raceway специально сертифицирован и подходит для использования во влажных местах и сырой среде, где могут присутствовать жидкости?","optsr":["Гибкий металлический кабелепровод (FMC)","Жидконепроницаемый гибкий металлический кабелепровод (LFMC)","Электрическая неметаллическая трубка (ENT) без фитингов","Стандартная EMT без водонепроницаемых фитингов"],"rr":"Согласно NEC Статья 350, жидконепроницаемый гибкий металлический кабелепровод (LFMC) имеет жидконепроницаемую внешнюю оболочку, что делает его пригодным для влажных мест; стандартный FMC не подходит.","qs":"¿Qué canalización flexible está específicamente listada y es adecuada para uso en lugares mojados y ambientes húmedos donde pueden estar presentes líquidos?","optss":["Conduit metálico flexible (FMC)","Conduit metálico flexible hermético a líquidos (LFMC)","Tubería no metálica eléctrica (ENT) sin accesorios","EMT estándar sin accesorios a prueba de intemperie"],"rs":"Según el Artículo 350 del NEC, el conduit metálico flexible hermético a líquidos (LFMC) tiene una cubierta exterior hermética a líquidos que lo hace adecuado para lugares mojados; el FMC estándar no lo es."},
  {"id":238,"sec":"Planning & Estimation","block":3,"q":"Per NEC Table 430.248, the full-load current of a single-phase 240 V, 5 HP motor is approximately:","opts":["28 A","15 A","56 A","8 A"],"correct":0,"re":"NEC Table 430.248 lists a 5 HP single-phase 230 V (used for 240 V) motor at 28 A full-load current.","qr":"Согласно таблице NEC 430.248, ток полной нагрузки однофазного двигателя 240 В, 5 л.с. составляет примерно:","optsr":["28 А","15 А","56 А","8 А"],"rr":"Таблица NEC 430.248 указывает для двигателя 5 л.с. однофазного 230 В (применяется для 240 В) ток полной нагрузки 28 А.","qs":"Según la Tabla 430.248 del NEC, la corriente a plena carga de un motor monofásico de 240 V, 5 HP es aproximadamente:","optss":["28 A","15 A","56 A","8 A"],"rs":"La Tabla 430.248 del NEC indica un motor monofásico de 5 HP a 230 V (usado para 240 V) con 28 A de corriente a plena carga."},
  {"id":239,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"In a delta-connected three-phase transformer winding, how does the line current relate to the phase (winding) current?","opts":["Line current equals 3 times the phase current","Line current equals phase current","Line current is one-third of the phase current","Line current equals the square root of 3 times the phase current"],"correct":3,"re":"In a delta connection the line current equals the phase current multiplied by the square root of 3, while line and phase voltages are equal.","qr":"В трёхфазной обмотке трансформатора со схемой треугольник, как линейный ток связан с фазным (обмоточным) током?","optsr":["Линейный ток в 3 раза больше фазного тока","Линейный ток равен фазному току","Линейный ток составляет одну треть фазного тока","Линейный ток в корень из 3 раз больше фазного тока"],"rr":"В схеме треугольник линейный ток равен фазному току, умноженному на корень из 3, а линейное и фазное напряжения равны.","qs":"En un devanado de transformador trifásico conectado en delta, ¿cómo se relaciona la corriente de línea con la corriente de fase (devanado)?","optss":["La corriente de línea es igual a 3 veces la corriente de fase","La corriente de línea es igual a la corriente de fase","La corriente de línea es un tercio de la corriente de fase","La corriente de línea es igual a la raíz cuadrada de 3 por la corriente de fase"],"rs":"En una conexión delta la corriente de línea es igual a la corriente de fase multiplicada por la raíz cuadrada de 3, mientras que los voltajes de línea y de fase son iguales."},
  {"id":240,"sec":"Rough Wiring","block":3,"q":"Electrical nonmetallic tubing (ENT) is generally NOT permitted to be installed in which of the following locations?","opts":["Exposed where subject to physical damage","Concealed within walls, floors, and ceilings","Above a suspended ceiling in a one-story building","Encased in a concrete slab"],"correct":0,"re":"Per NEC 362.12, ENT is not permitted where subject to physical damage because its nonmetallic material offers limited mechanical protection.","qr":"Электрическую неметаллическую трубку (ENT) обычно НЕ разрешается устанавливать в каком из следующих мест?","optsr":["Открыто там, где подвержено механическим повреждениям","Скрыто внутри стен, полов и потолков","Над подвесным потолком в одноэтажном здании","Заделанной в бетонную плиту"],"rr":"Согласно NEC 362.12, ENT не разрешается там, где она подвержена механическим повреждениям, поскольку её неметаллический материал обеспечивает ограниченную механическую защиту.","qs":"La tubería no metálica eléctrica (ENT) generalmente NO se permite instalar en cuál de los siguientes lugares?","optss":["Expuesta donde está sujeta a daño físico","Oculta dentro de paredes, pisos y techos","Sobre un techo suspendido en un edificio de un piso","Embebida en una losa de concreto"],"rs":"Según NEC 362.12, el ENT no se permite donde esté sujeto a daño físico porque su material no metálico ofrece protección mecánica limitada."},
  {"id":241,"sec":"Finish Wiring & Trim","block":3,"q":"The cover that keeps an outdoor receptacle weatherproof even while a cord is plugged in is commonly called what?","opts":["A flush cover plate","A blank cover","A faceplate gasket","An in-use (while-in-use) cover"],"correct":3,"re":"An in-use or while-in-use cover (NEC 406.9(B)(1)) is a bubble-type enclosure that maintains weatherproof integrity while a plug and cord remain inserted in a wet location.","qr":"Крышка, которая сохраняет наружную розетку водонепроницаемой даже когда шнур вставлен, обычно называется как?","optsr":["Заподлицо установленная крышка","Глухая крышка","Прокладка лицевой панели","Крышка 'in-use' (while-in-use)"],"rr":"Крышка 'in-use' или 'while-in-use' (NEC 406.9(B)(1)) — это корпус пузырькового типа, который сохраняет водонепроницаемость, пока вилка и шнур остаются вставленными в мокром месте.","qs":"La cubierta que mantiene un receptáculo exterior a prueba de intemperie incluso mientras un cordón está enchufado se llama comúnmente ¿cómo?","optss":["Una placa de cubierta empotrada","Una cubierta ciega","Una junta de placa frontal","Una cubierta de uso (mientras está en uso)"],"rs":"Una cubierta de uso o mientras está en uso (NEC 406.9(B)(1)) es un encerramiento tipo burbuja que mantiene la integridad a prueba de intemperie mientras un enchufe y cordón permanecen insertados en un lugar mojado."},
  {"id":242,"sec":"Safety","block":3,"q":"After a shock victim has been safely separated from the electrical source and is found to have no pulse and is not breathing, what is the appropriate next step?","opts":["Wait for the burns to heal before acting","Begin CPR and have someone call emergency services","Give the victim water to drink","Move the victim to a vehicle and drive to the hospital without further aid"],"correct":1,"re":"Once the victim is clear of the source and shows no pulse or breathing, begin CPR immediately and ensure emergency medical services are summoned.","qr":"После того как пострадавший от удара током безопасно отделён от источника электричества и у него отсутствуют пульс и дыхание, какой следующий шаг правильный?","optsr":["Подождать, пока заживут ожоги, прежде чем действовать","Начать СЛР и поручить кому-либо вызвать экстренные службы","Дать пострадавшему воды попить","Перенести пострадавшего в машину и ехать в больницу без дальнейшей помощи"],"rr":"Как только пострадавший освобождён от источника и у него нет пульса или дыхания, немедленно начинайте СЛР и обеспечьте вызов экстренной медицинской помощи.","qs":"Después de que una víctima de descarga ha sido separada con seguridad de la fuente eléctrica y se encuentra sin pulso y sin respiración, ¿cuál es el paso apropiado a seguir?","optss":["Esperar a que sanen las quemaduras antes de actuar","Comenzar la RCP y hacer que alguien llame a los servicios de emergencia","Darle agua a la víctima para beber","Llevar a la víctima a un vehículo y conducir al hospital sin más ayuda"],"rs":"Una vez que la víctima está libre de la fuente y no muestra pulso ni respiración, comience la RCP de inmediato y asegúrese de que se llame a los servicios médicos de emergencia."},
  {"id":243,"sec":"Planning & Estimation","block":3,"q":"When sizing branch-circuit conductors for a single continuously-running motor, which current value does the NEC require you to use?","opts":["The motor's actual measured current","The locked-rotor current","The full-load current value from the NEC motor tables","The nameplate current divided by 1.25"],"correct":2,"re":"NEC 430.6(A) requires using the full-load current values from Tables 430.247 through 430.250 rather than the nameplate current for conductor sizing.","qr":"При выборе проводников ответвления для одного непрерывно работающего двигателя, какое значение тока требует использовать NEC?","optsr":["Фактически измеренный ток двигателя","Ток заторможенного ротора","Значение тока полной нагрузки из таблиц двигателей NEC","Ток с шильдика, делённый на 1.25"],"rr":"NEC 430.6(A) требует использовать значения тока полной нагрузки из таблиц 430.247–430.250, а не ток с шильдика, для выбора проводников.","qs":"Al dimensionar los conductores del circuito ramal para un solo motor de funcionamiento continuo, ¿qué valor de corriente requiere usar el NEC?","optss":["La corriente real medida del motor","La corriente de rotor bloqueado","El valor de corriente a plena carga de las tablas de motores del NEC","La corriente de placa dividida por 1.25"],"rs":"NEC 430.6(A) requiere usar los valores de corriente a plena carga de las Tablas 430.247 a 430.250 en lugar de la corriente de placa para el dimensionamiento de conductores."},
  {"id":244,"sec":"Rough Wiring","block":3,"q":"Type AC (armored) cable must be secured at intervals not exceeding what distance when installed along framing members?","opts":["3 feet","8 feet","4 1/2 feet","6 feet"],"correct":2,"re":"Per NEC 320.30, Type AC cable must be secured at intervals not exceeding 4 1/2 ft.","qr":"Кабель типа AC (бронированный) должен быть закреплён с интервалами, не превышающими какое расстояние, при установке вдоль элементов каркаса?","optsr":["3 фута","8 футов","4 1/2 фута","6 футов"],"rr":"Согласно NEC 320.30, кабель типа AC должен быть закреплён с интервалами, не превышающими 4 1/2 фута.","qs":"El cable tipo AC (blindado) debe sujetarse a intervalos que no excedan qué distancia cuando se instala a lo largo de los miembros estructurales?","optss":["3 pies","8 pies","4 1/2 pies","6 pies"],"rs":"Según NEC 320.30, el cable tipo AC debe sujetarse a intervalos que no excedan 4 1/2 pies."},
  {"id":245,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Which instrument function is the correct choice to verify that a fuse is good without removing it from a de-energized holder?","opts":["AC voltage","Clamp-on current","Continuity (ohms)","Insulation resistance"],"correct":2,"re":"On a de-energized circuit, the continuity (ohms) function shows a low resistance through a good fuse and an open (no continuity) through a blown fuse.","qr":"Какая функция прибора правильна для проверки исправности предохранителя без извлечения его из обесточенного держателя?","optsr":["Переменное напряжение","Измерение тока клещами","Целостность (ом)","Сопротивление изоляции"],"rr":"На обесточенной цепи функция целостности (ом) показывает низкое сопротивление через исправный предохранитель и обрыв через перегоревший.","qs":"¿Qué función del instrumento es la elección correcta para verificar que un fusible está bueno sin retirarlo de un portafusibles desenergizado?","optss":["Voltaje de CA","Corriente con pinza","Continuidad (ohmios)","Resistencia de aislamiento"],"rs":"En un circuito desenergizado, la función de continuidad (ohmios) muestra una resistencia baja a través de un fusible bueno y un circuito abierto (sin continuidad) a través de un fusible fundido."},
  {"id":246,"sec":"Safety","block":3,"q":"Why is it dangerous to touch an electric-shock victim who is still in contact with the energized source before the power is removed?","opts":["The victim may be carrying a contagious disease","The victim's clothing may be flammable","The current can pass through the victim and into the rescuer, creating a second casualty","The rescuer might damage the electrical equipment"],"correct":2,"re":"If the source is still energized, current can flow through the victim into the rescuer, making the rescuer a second shock victim.","qr":"Почему опасно прикасаться к пострадавшему от удара током, который всё ещё контактирует с источником под напряжением, до того как питание отключено?","optsr":["Пострадавший может быть носителем заразного заболевания","Одежда пострадавшего может быть легковоспламеняющейся","Ток может пройти через пострадавшего и в спасателя, создав второго пострадавшего","Спасатель может повредить электрооборудование"],"rr":"Если источник всё ещё под напряжением, ток может пройти через пострадавшего в спасателя, делая спасателя вторым пострадавшим от удара током.","qs":"¿Por qué es peligroso tocar a una víctima de descarga eléctrica que todavía está en contacto con la fuente energizada antes de que se retire la energía?","optss":["La víctima puede portar una enfermedad contagiosa","La ropa de la víctima puede ser inflamable","La corriente puede pasar a través de la víctima y hacia el rescatista, creando una segunda víctima","El rescatista podría dañar el equipo eléctrico"],"rs":"Si la fuente todavía está energizada, la corriente puede fluir a través de la víctima hacia el rescatista, convirtiéndolo en una segunda víctima de descarga."},
  {"id":247,"sec":"Planning & Estimation","block":3,"q":"A 230 V single-phase motor is rated at 1 HP and operates at roughly 80% efficiency with unity power factor; approximately what current does it draw?","opts":["3.2 A","4.1 A","2.0 A","6.5 A"],"correct":1,"re":"Input watts = 746 ÷ 0.80 = 932.5 W; I = 932.5 ÷ 230 = 4.1 A (1 HP = 746 W).","qr":"Однофазный двигатель 230 В рассчитан на 1 л.с. и работает с КПД около 80% при единичном коэффициенте мощности; какой примерно ток он потребляет?","optsr":["3.2 А","4.1 А","2.0 А","6.5 А"],"rr":"Входная мощность = 746 ÷ 0.80 = 932.5 Вт; I = 932.5 ÷ 230 = 4.1 А (1 л.с. = 746 Вт).","qs":"Un motor monofásico de 230 V está clasificado en 1 HP y opera a aproximadamente 80% de eficiencia con factor de potencia unitario; ¿aproximadamente qué corriente consume?","optss":["3.2 A","4.1 A","2.0 A","6.5 A"],"rs":"Vatios de entrada = 746 ÷ 0.80 = 932.5 W; I = 932.5 ÷ 230 = 4.1 A (1 HP = 746 W)."},
  {"id":248,"sec":"Rough Wiring","block":3,"q":"Which cable type is specifically listed for direct burial in the earth without requiring a protective raceway?","opts":["Type NM cable","Type AC cable","Type MC cable not marked for direct burial","Type UF cable"],"correct":3,"re":"Per NEC Article 340, Type UF (underground feeder) cable is listed and suitable for direct burial in the earth.","qr":"Какой тип кабеля специально сертифицирован для прямой укладки в землю без необходимости защитного raceway?","optsr":["Кабель типа NM","Кабель типа AC","Кабель типа MC без маркировки для прямой укладки","Кабель типа UF"],"rr":"Согласно NEC Статья 340, кабель типа UF (подземный фидер) сертифицирован и подходит для прямой укладки в землю.","qs":"¿Qué tipo de cable está específicamente listado para enterramiento directo en la tierra sin requerir una canalización protectora?","optss":["Cable tipo NM","Cable tipo AC","Cable tipo MC no marcado para enterramiento directo","Cable tipo UF"],"rs":"Según el Artículo 340 del NEC, el cable tipo UF (alimentador subterráneo) está listado y es adecuado para enterramiento directo en la tierra."},
  {"id":249,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"What is the main reason a torque screwdriver or torque wrench is preferred over hand-tight tightening for electrical terminations?","opts":["It applies the manufacturer's specified torque to ensure a reliable, low-resistance connection","It increases the conductor ampacity","It eliminates the need for a wire stripper","It is faster than a regular tool"],"correct":0,"re":"A calibrated torque tool applies the exact manufacturer-specified value, preventing connections that are too loose (overheating) or too tight (damage), which is required for many listed terminations.","qr":"Какова основная причина, по которой динамометрическая отвёртка или ключ предпочтительнее затяжки вручную для электрических соединений?","optsr":["Прикладывает указанный производителем момент для надёжного соединения с низким сопротивлением","Увеличивает допустимую токовую нагрузку проводника","Устраняет необходимость в инструменте для зачистки","Это быстрее обычного инструмента"],"rr":"Калиброванный динамометрический инструмент прикладывает точное значение, указанное производителем, предотвращая слишком слабые (перегрев) или слишком тугие (повреждение) соединения, что требуется для многих сертифицированных зажимов.","qs":"¿Cuál es la razón principal por la que se prefiere un destornillador o llave de torque sobre el apriete manual para las terminaciones eléctricas?","optss":["Aplica el par de torsión especificado por el fabricante para asegurar una conexión confiable de baja resistencia","Aumenta la capacidad de corriente del conductor","Elimina la necesidad de un pelacables","Es más rápido que una herramienta común"],"rs":"Una herramienta de torque calibrada aplica el valor exacto especificado por el fabricante, evitando conexiones demasiado flojas (sobrecalentamiento) o demasiado apretadas (daño), lo cual se requiere para muchas terminaciones listadas."},
  {"id":250,"sec":"Finish Wiring & Trim","block":3,"q":"An insulated grounded (neutral) conductor of 6 AWG or smaller must be identified by which color?","opts":["Green","Blue","Red","White or gray"],"correct":3,"re":"NEC 200.6(A) requires that grounded (neutral) conductors 6 AWG or smaller be identified by a continuous white or gray outer finish, or three continuous white/gray stripes.","qr":"Изолированный заземлённый (нейтральный) проводник сечением 6 AWG или меньше должен идентифицироваться каким цветом?","optsr":["Зелёный","Синий","Красный","Белый или серый"],"rr":"NEC 200.6(A) требует, чтобы заземлённые (нейтральные) проводники сечением 6 AWG или меньше идентифицировались сплошным белым или серым внешним покрытием, либо тремя сплошными белыми/серыми полосами.","qs":"Un conductor puesto a tierra (neutro) aislado de 6 AWG o menor debe identificarse con cuál color?","optss":["Verde","Azul","Rojo","Blanco o gris"],"rs":"NEC 200.6(A) requiere que los conductores puestos a tierra (neutros) de 6 AWG o menores se identifiquen con un acabado exterior continuo blanco o gris, o tres franjas continuas blancas/grises."},
  {"id":251,"sec":"Planning & Estimation","block":3,"q":"How many watts are equal to one horsepower for electrical motor calculations?","opts":["550 W","1,000 W","746 W","1,200 W"],"correct":2,"re":"One horsepower equals 746 watts, the standard conversion used in motor load calculations.","qr":"Сколько ватт равно одной лошадиной силе для расчётов электродвигателей?","optsr":["550 Вт","1 000 Вт","746 Вт","1 200 Вт"],"rr":"Одна лошадиная сила равна 746 ваттам, это стандартное преобразование, используемое в расчётах нагрузки двигателей.","qs":"¿Cuántos vatios equivalen a un caballo de fuerza para los cálculos de motores eléctricos?","optss":["550 W","1,000 W","746 W","1,200 W"],"rs":"Un caballo de fuerza equivale a 746 vatios, la conversión estándar usada en los cálculos de carga de motores."},
  {"id":252,"sec":"Safety","block":3,"q":"Under OSHA temporary wiring rules for construction, flexible cords and cables used for temporary power must be protected from damage; which condition would make a cord unacceptable for continued use?","opts":["The outer jacket is cut or split, exposing the inner conductors","The cord is rated for hard or extra-hard usage","The cord is colored orange","The cord is longer than 25 feet"],"correct":0,"re":"A cord with a damaged outer jacket that exposes the conductors must be removed from service; length or color alone does not make a cord unacceptable.","qr":"Согласно правилам OSHA по временной проводке на стройке, гибкие шнуры и кабели для временного питания должны быть защищены от повреждений; какое состояние сделает шнур непригодным для дальнейшего использования?","optsr":["Внешняя оболочка порезана или расщеплена, обнажая внутренние проводники","Шнур рассчитан на тяжёлую или особо тяжёлую эксплуатацию","Шнур окрашен в оранжевый цвет","Шнур длиннее 25 футов"],"rr":"Шнур с повреждённой внешней оболочкой, обнажающей проводники, должен быть выведен из эксплуатации; одна лишь длина или цвет не делают шнур непригодным.","qs":"Según las reglas de OSHA para cableado temporal en construcción, los cordones y cables flexibles usados para energía temporal deben protegerse contra daños; ¿qué condición haría que un cordón sea inaceptable para uso continuado?","optss":["La cubierta exterior está cortada o partida, exponiendo los conductores internos","El cordón está clasificado para uso rudo o extra rudo","El cordón es de color naranja","El cordón mide más de 25 pies"],"rs":"Un cordón con una cubierta exterior dañada que expone los conductores debe retirarse del servicio; la longitud o el color por sí solos no hacen que un cordón sea inaceptable."},
  {"id":253,"sec":"Rough Wiring","block":3,"q":"Type NM (nonmetallic-sheathed) cable is permitted to be used in which of the following locations?","opts":["Wet locations such as direct burial","Embedded in poured concrete","Exposed to oils and other deteriorating agents","Dry locations of normally dry, non-corrosive interiors"],"correct":3,"re":"Per NEC 334.10 and 334.12, Type NM cable is permitted in normally dry locations and is not permitted in wet locations, embedded in concrete, or where exposed to corrosive conditions.","qr":"Кабель типа NM (в неметаллической оболочке) разрешается использовать в каком из следующих мест?","optsr":["Влажные места, например прямая укладка в землю","Заделанный в залитый бетон","Подверженный воздействию масел и других разрушающих агентов","Сухие места обычно сухих, некоррозионных помещений"],"rr":"Согласно NEC 334.10 и 334.12, кабель типа NM разрешается в обычно сухих местах и не разрешается во влажных местах, заделанным в бетон или там, где подвержен коррозионным условиям.","qs":"El cable tipo NM (con cubierta no metálica) se permite usar en cuál de los siguientes lugares?","optss":["Lugares mojados como enterramiento directo","Embebido en concreto vertido","Expuesto a aceites y otros agentes deteriorantes","Lugares secos de interiores normalmente secos y no corrosivos"],"rs":"Según NEC 334.10 y 334.12, el cable tipo NM se permite en lugares normalmente secos y no se permite en lugares mojados, embebido en concreto ni donde esté expuesto a condiciones corrosivas."},
  {"id":254,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"A transformer enclosure and core must be connected to which conductor for safety?","opts":["The ungrounded (hot) conductor","The equipment grounding conductor","The secondary neutral only on the load side","No connection is required"],"correct":1,"re":"The non-current-carrying metal parts of a transformer, such as its enclosure and core, must be bonded to the equipment grounding conductor to provide a safe fault-clearing path.","qr":"Корпус и сердечник трансформатора должны быть подключены к какому проводнику для безопасности?","optsr":["К незаземлённому (фазному) проводнику","К защитному проводнику заземления оборудования","Только к вторичному нейтрали на стороне нагрузки","Подключение не требуется"],"rr":"Нетоковедущие металлические части трансформатора, такие как корпус и сердечник, должны быть соединены с защитным проводником заземления оборудования для безопасного отвода тока КЗ.","qs":"El encerramiento y el núcleo de un transformador deben conectarse a cuál conductor por seguridad?","optss":["El conductor no puesto a tierra (vivo)","El conductor de puesta a tierra de equipos","El neutro secundario solo en el lado de la carga","No se requiere conexión"],"rs":"Las partes metálicas no conductoras de corriente de un transformador, como su encerramiento y núcleo, deben unirse al conductor de puesta a tierra de equipos para proporcionar una ruta segura de despeje de fallas."},
  {"id":255,"sec":"Planning & Estimation","block":3,"q":"Per NEC Table 430.250, a three-phase 460 V, 10 HP motor has a full-load current of approximately:","opts":["28 A","14 A","21 A","9 A"],"correct":1,"re":"NEC Table 430.250 lists a 10 HP, 460 V three-phase motor at 14 A full-load current.","qr":"Согласно таблице NEC 430.250, трёхфазный двигатель 460 В, 10 л.с. имеет ток полной нагрузки примерно:","optsr":["28 А","14 А","21 А","9 А"],"rr":"Таблица NEC 430.250 указывает для трёхфазного двигателя 10 л.с., 460 В ток полной нагрузки 14 А.","qs":"Según la Tabla 430.250 del NEC, un motor trifásico de 460 V, 10 HP tiene una corriente a plena carga de aproximadamente:","optss":["28 A","14 A","21 A","9 A"],"rs":"La Tabla 430.250 del NEC indica un motor trifásico de 10 HP, 460 V con 14 A de corriente a plena carga."},
  {"id":256,"sec":"Rough Wiring","block":3,"q":"When fittings are installed on a conduit entering an enclosure in a wet location, which type of fitting must be used?","opts":["A standard indoor connector","A reducing washer","A raintight or wet-location-rated fitting","A set-screw fitting"],"correct":2,"re":"Per NEC 314.15 and 300.5, fittings and enclosures used in wet locations must be listed for wet locations to prevent moisture entry.","qr":"Когда фитинги устанавливаются на кабелепроводе, входящем в корпус во влажном месте, какой тип фитинга должен использоваться?","optsr":["Стандартный внутренний соединитель","Уменьшающая шайба","Дождезащищённый фитинг или фитинг для влажных мест","Фитинг с установочным винтом"],"rr":"Согласно NEC 314.15 и 300.5, фитинги и корпуса, используемые во влажных местах, должны быть сертифицированы для влажных мест, чтобы предотвратить проникновение влаги.","qs":"Cuando se instalan accesorios en un conduit que entra a un encerramiento en un lugar mojado, ¿qué tipo de accesorio debe usarse?","optss":["Un conector estándar para interiores","Una arandela reductora","Un accesorio hermético a la lluvia o clasificado para lugares mojados","Un accesorio de tornillo prisionero"],"rs":"Según NEC 314.15 y 300.5, los accesorios y encerramientos usados en lugares mojados deben estar listados para lugares mojados para prevenir la entrada de humedad."},
  {"id":257,"sec":"Safety","block":3,"q":"For temporary wiring on a construction site, flexible cords are generally required to be of which type to withstand job-site conditions?","opts":["Light-duty lamp cord","Untwisted bare conductors","Single-conductor bell wire","Listed for hard usage or extra-hard usage"],"correct":3,"re":"Job-site temporary cords must be listed for hard or extra-hard usage so the jacket can resist the abuse found on construction sites.","qr":"Для временной проводки на стройплощадке гибкие шнуры обычно должны быть какого типа, чтобы выдерживать условия объекта?","optsr":["Лёгкий шнур для ламп","Нескрученные оголённые проводники","Однопроводный звонковый провод","Сертифицированные для тяжёлой или особо тяжёлой эксплуатации"],"rr":"Временные шнуры на объекте должны быть сертифицированы для тяжёлой или особо тяжёлой эксплуатации, чтобы оболочка выдерживала нагрузки, характерные для стройплощадок.","qs":"Para el cableado temporal en una obra de construcción, los cordones flexibles generalmente deben ser de qué tipo para soportar las condiciones de la obra?","optss":["Cordón de lámpara de servicio ligero","Conductores desnudos no trenzados","Alambre de campana de un solo conductor","Listado para uso rudo o extra rudo"],"rs":"Los cordones temporales de obra deben estar listados para uso rudo o extra rudo para que la cubierta pueda resistir el maltrato que se encuentra en las obras de construcción."},
  {"id":258,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"During startup, an electrician uses a clamp-on ammeter on each phase of a three-phase motor feeder; what does a large imbalance between the phase currents most likely suggest?","opts":["The motor is operating normally","The clamp meter is reading insulation resistance","A possible winding fault, loose connection, or voltage imbalance","The phase rotation is reversed"],"correct":2,"re":"Significant current imbalance between phases often indicates a developing winding fault, a high-resistance (loose) connection, or a supply voltage imbalance that should be investigated.","qr":"При запуске электрик использует токоизмерительные клещи на каждой фазе фидера трёхфазного двигателя; на что, скорее всего, указывает большой дисбаланс между фазными токами?","optsr":["Двигатель работает нормально","Клещи измеряют сопротивление изоляции","Возможный дефект обмотки, слабое соединение или дисбаланс напряжения","Чередование фаз перевёрнуто"],"rr":"Значительный дисбаланс тока между фазами часто указывает на развивающийся дефект обмотки, соединение с высоким сопротивлением (слабое) или дисбаланс питающего напряжения, что требует проверки.","qs":"Durante el arranque, un electricista usa un amperímetro de pinza en cada fase de un alimentador de motor trifásico; ¿qué sugiere con mayor probabilidad un gran desequilibrio entre las corrientes de fase?","optss":["El motor está operando normalmente","El medidor de pinza está leyendo la resistencia de aislamiento","Una posible falla en el devanado, conexión floja o desequilibrio de voltaje","La rotación de fase está invertida"],"rs":"Un desequilibrio significativo de corriente entre fases a menudo indica una falla en desarrollo en el devanado, una conexión de alta resistencia (floja) o un desequilibrio de voltaje de suministro que debe investigarse."},
  {"id":259,"sec":"Finish Wiring & Trim","block":3,"q":"An equipment grounding conductor (EGC), when insulated, is identified by which of the following?","opts":["White or gray","Solid black","Green, or green with one or more yellow stripes","Solid red"],"correct":2,"re":"NEC 250.119 permits an insulated EGC to be green, or green with one or more yellow stripes; it may also be bare.","qr":"Заземляющий проводник оборудования (EGC), когда он изолирован, идентифицируется чем из следующего?","optsr":["Белый или серый","Сплошной чёрный","Зелёный, или зелёный с одной или несколькими жёлтыми полосами","Сплошной красный"],"rr":"NEC 250.119 разрешает изолированному EGC быть зелёным или зелёным с одной или несколькими жёлтыми полосами; он также может быть голым.","qs":"Un conductor de puesta a tierra de equipos (EGC), cuando está aislado, se identifica por cuál de los siguientes?","optss":["Blanco o gris","Negro sólido","Verde, o verde con una o más franjas amarillas","Rojo sólido"],"rs":"NEC 250.119 permite que un EGC aislado sea verde, o verde con una o más franjas amarillas; también puede ser desnudo."},
  {"id":260,"sec":"Planning & Estimation","block":3,"q":"When sizing the branch-circuit conductors for a single continuous-duty motor, the conductor ampacity must be at least what percent of the motor full-load current?","opts":["100%","115%","125%","150%"],"correct":2,"re":"NEC 430.22 requires motor branch-circuit conductors to have an ampacity of at least 125% of the motor full-load current.","qr":"При выборе проводников ответвления для одного двигателя длительного режима, допустимая нагрузка проводника должна составлять не менее какого процента от тока полной нагрузки двигателя?","optsr":["100%","115%","125%","150%"],"rr":"NEC 430.22 требует, чтобы проводники ответвления двигателя имели допустимую нагрузку не менее 125% от тока полной нагрузки двигателя.","qs":"Al dimensionar los conductores del circuito ramal para un solo motor de servicio continuo, la capacidad de corriente del conductor debe ser al menos qué porcentaje de la corriente a plena carga del motor?","optss":["100%","115%","125%","150%"],"rs":"NEC 430.22 requiere que los conductores del circuito ramal del motor tengan una capacidad de corriente de al menos 125% de la corriente a plena carga del motor."},
  {"id":261,"sec":"Rough Wiring","block":3,"q":"Cables or raceways installed parallel to framing members must be set back from the nearest edge of the framing member by at least what distance to avoid the need for a protective plate?","opts":["3/4 inch","1 1/4 inches","1 inch","1 1/2 inches"],"correct":1,"re":"Per NEC 300.4(D), cables run parallel to framing members must be at least 1 1/4 in. from the nearest edge, or be protected by a steel plate.","qr":"Кабели или кабелепроводы, проложенные параллельно элементам каркаса, должны быть отодвинуты от ближайшего края элемента каркаса не менее чем на какое расстояние, чтобы избежать необходимости в защитной пластине?","optsr":["3/4 дюйма","1 1/4 дюйма","1 дюйм","1 1/2 дюйма"],"rr":"Согласно NEC 300.4(D), кабели, проложенные параллельно элементам каркаса, должны находиться не менее чем в 1 1/4 дюйма от ближайшего края или быть защищены стальной пластиной.","qs":"Los cables o canalizaciones instalados paralelos a los miembros estructurales deben retraerse del borde más cercano del miembro estructural por al menos qué distancia para evitar la necesidad de una placa protectora?","optss":["3/4 de pulgada","1 1/4 pulgadas","1 pulgada","1 1/2 pulgadas"],"rs":"Según NEC 300.4(D), los cables tendidos paralelos a los miembros estructurales deben estar al menos a 1 1/4 pulg. del borde más cercano, o estar protegidos por una placa de acero."},
  {"id":262,"sec":"Safety","block":3,"q":"Which practice involving an extension cord on a job site is a recognized safety hazard?","opts":["Removing the grounding prong from the cord's plug to fit a two-slot receptacle","Using a cord listed for outdoor use","Using a cord with an intact molded plug","Coiling unused cord neatly out of walkways"],"correct":0,"re":"Cutting or removing the grounding prong defeats the equipment grounding path and is a serious hazard; the other practices are acceptable.","qr":"Какая практика с удлинителем на объекте является признанной угрозой безопасности?","optsr":["Удаление заземляющего штыря с вилки шнура для подключения к двухконтактной розетке","Использование шнура, сертифицированного для уличного применения","Использование шнура с целой литой вилкой","Аккуратная укладка неиспользуемого шнура вне проходов"],"rr":"Срезание или удаление заземляющего штыря нарушает путь заземления оборудования и является серьёзной опасностью; остальные практики допустимы.","qs":"¿Qué práctica que involucra un cordón de extensión en una obra es un peligro de seguridad reconocido?","optss":["Retirar la pata de puesta a tierra del enchufe del cordón para que entre en un receptáculo de dos ranuras","Usar un cordón listado para uso en exteriores","Usar un cordón con un enchufe moldeado intacto","Enrollar ordenadamente el cordón no usado fuera de las áreas de paso"],"rs":"Cortar o retirar la pata de puesta a tierra anula la ruta de puesta a tierra de equipos y es un peligro grave; las otras prácticas son aceptables."},
  {"id":263,"sec":"Planning & Estimation","block":3,"q":"A demand factor is best described as:","opts":["The ratio of the maximum demand to the total connected load","The sum of all connected loads","The ratio of nameplate voltage to operating voltage","The product of voltage and current"],"correct":0,"re":"Per NEC Article 100, the demand factor is the ratio of the maximum demand of a system to the total connected load, allowing realistic sizing below 100% of connected load.","qr":"Коэффициент спроса лучше всего описывается как:","optsr":["Отношение максимального спроса к общей подключённой нагрузке","Сумма всех подключённых нагрузок","Отношение номинального напряжения к рабочему напряжению","Произведение напряжения и тока"],"rr":"Согласно статье NEC 100, коэффициент спроса — это отношение максимального спроса системы к общей подключённой нагрузке, что позволяет реалистично рассчитывать размер ниже 100% подключённой нагрузки.","qs":"Un factor de demanda se describe mejor como:","optss":["La relación entre la demanda máxima y la carga conectada total","La suma de todas las cargas conectadas","La relación entre el voltaje de placa y el voltaje de operación","El producto del voltaje y la corriente"],"rs":"Según el Artículo 100 del NEC, el factor de demanda es la relación entre la demanda máxima de un sistema y la carga conectada total, lo que permite un dimensionamiento realista por debajo del 100% de la carga conectada."},
  {"id":264,"sec":"Rough Wiring","block":3,"q":"Which raceway has the thickest, heaviest wall and provides the greatest physical protection for conductors?","opts":["Electrical nonmetallic tubing (ENT)","Electrical metallic tubing (EMT)","Rigid metal conduit (RMC)","Flexible metal conduit (FMC)"],"correct":2,"re":"Per NEC Article 344, rigid metal conduit (RMC) is the heaviest-wall steel raceway and offers the greatest physical protection compared to IMC and EMT.","qr":"Какой raceway имеет самую толстую, тяжёлую стенку и обеспечивает наибольшую физическую защиту проводников?","optsr":["Электрическая неметаллическая трубка (ENT)","Электрическая металлическая трубка (EMT)","Жёсткий металлический кабелепровод (RMC)","Гибкий металлический кабелепровод (FMC)"],"rr":"Согласно NEC Статья 344, жёсткий металлический кабелепровод (RMC) является стальным raceway с самой толстой стенкой и обеспечивает наибольшую физическую защиту по сравнению с IMC и EMT.","qs":"¿Qué canalización tiene la pared más gruesa y pesada y proporciona la mayor protección física para los conductores?","optss":["Tubería no metálica eléctrica (ENT)","Tubería metálica eléctrica (EMT)","Conduit metálico rígido (RMC)","Conduit metálico flexible (FMC)"],"rs":"Según el Artículo 344 del NEC, el conduit metálico rígido (RMC) es la canalización de acero de pared más pesada y ofrece la mayor protección física en comparación con el IMC y el EMT."},
  {"id":265,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Before applying a high-voltage megohmmeter test to a circuit, what must be confirmed first?","opts":["The circuit is fully energized","The circuit is de-energized and isolated, and sensitive electronics are disconnected","A load is connected to the far end","The phase rotation is correct"],"correct":1,"re":"Insulation-resistance testing applies high DC voltage, so the circuit must be de-energized, isolated, and any sensitive electronic equipment disconnected to avoid damage and ensure safety.","qr":"Перед подачей высоковольтного теста мегомметром на цепь, что должно быть подтверждено в первую очередь?","optsr":["Цепь полностью под напряжением","Цепь обесточена и изолирована, чувствительная электроника отключена","К дальнему концу подключена нагрузка","Чередование фаз правильное"],"rr":"Проверка сопротивления изоляции прикладывает высокое постоянное напряжение, поэтому цепь должна быть обесточена, изолирована, а чувствительное электронное оборудование отключено для безопасности.","qs":"Antes de aplicar una prueba de megóhmetro de alto voltaje a un circuito, ¿qué debe confirmarse primero?","optss":["El circuito está completamente energizado","El circuito está desenergizado y aislado, y los componentes electrónicos sensibles están desconectados","Hay una carga conectada en el extremo lejano","La rotación de fase es correcta"],"rs":"La prueba de resistencia de aislamiento aplica alto voltaje de CC, por lo que el circuito debe estar desenergizado, aislado y cualquier equipo electrónico sensible debe estar desconectado para evitar daños y garantizar la seguridad."},
  {"id":266,"sec":"Safety","block":3,"q":"An extension cord used to supply a portable tool runs across a doorway where it could be pinched by the door; what does OSHA generally require regarding flexible cords?","opts":["Flexible cords must not be run through doorways, windows, or similar openings where they can be damaged","Cords may be run through doorways if the door is kept open with the cord","Cords through doorways are fine if taped to the floor","Only metal-jacketed cords may pass through doorways"],"correct":0,"re":"OSHA prohibits running flexible cords through doorways, windows, holes in walls, or similar openings where they are subject to damage.","qr":"Удлинитель, питающий портативный инструмент, проложен через дверной проём, где его может зажать дверью; что обычно требует OSHA в отношении гибких шнуров?","optsr":["Гибкие шнуры нельзя прокладывать через дверные проёмы, окна или подобные отверстия, где они могут быть повреждены","Шнуры можно прокладывать через дверные проёмы, если дверь удерживается открытой шнуром","Шнуры через дверные проёмы допустимы, если приклеены к полу","Через дверные проёмы можно прокладывать только шнуры с металлической оболочкой"],"rr":"OSHA запрещает прокладку гибких шнуров через дверные проёмы, окна, отверстия в стенах или подобные проёмы, где они подвержены повреждению.","qs":"Un cordón de extensión usado para alimentar una herramienta portátil pasa a través de una puerta donde podría ser pellizcado por la puerta; ¿qué requiere generalmente OSHA respecto a los cordones flexibles?","optss":["Los cordones flexibles no deben pasarse a través de puertas, ventanas o aberturas similares donde puedan dañarse","Los cordones pueden pasarse a través de puertas si la puerta se mantiene abierta con el cordón","Los cordones a través de puertas están bien si se pegan con cinta al piso","Solo los cordones con cubierta metálica pueden pasar a través de puertas"],"rs":"OSHA prohíbe pasar cordones flexibles a través de puertas, ventanas, agujeros en paredes o aberturas similares donde estén sujetos a daño."},
  {"id":267,"sec":"Rough Wiring","block":3,"q":"PVC Schedule 80 conduit is preferred over PVC Schedule 40 in which application?","opts":["Underground in non-traffic areas","Inside dry interior walls","Inside a finished attic with no access","Where exposed to physical damage"],"correct":3,"re":"Per NEC 352.10, PVC Schedule 80 has a thicker wall and is permitted where the conduit is exposed to physical damage, whereas Schedule 40 is not.","qr":"PVC Schedule 80 кабелепровод предпочтительнее PVC Schedule 40 в каком применении?","optsr":["Под землёй в местах без движения транспорта","Внутри сухих внутренних стен","Внутри отделанного чердака без доступа","Там, где подвержен механическим повреждениям"],"rr":"Согласно NEC 352.10, PVC Schedule 80 имеет более толстую стенку и разрешён там, где кабелепровод подвержен механическим повреждениям, тогда как Schedule 40 не разрешён.","qs":"El conduit de PVC Cédula 80 se prefiere sobre el PVC Cédula 40 en cuál aplicación?","optss":["Bajo tierra en áreas sin tráfico","Dentro de paredes interiores secas","Dentro de un ático terminado sin acceso","Donde esté expuesto a daño físico"],"rs":"Según NEC 352.10, el PVC Cédula 80 tiene una pared más gruesa y se permite donde el conduit esté expuesto a daño físico, mientras que la Cédula 40 no lo está."},
  {"id":268,"sec":"Planning & Estimation","block":3,"q":"A panel has 60 kVA of connected load with an applicable demand factor of 70%; what is the calculated demand load?","opts":["60 kVA","86 kVA","18 kVA","42 kVA"],"correct":3,"re":"Demand load = connected load × demand factor = 60 × 0.70 = 42 kVA.","qr":"Панель имеет 60 кВА подключённой нагрузки с применимым коэффициентом спроса 70%; какова расчётная нагрузка спроса?","optsr":["60 кВА","86 кВА","18 кВА","42 кВА"],"rr":"Нагрузка спроса = подключённая нагрузка × коэффициент спроса = 60 × 0.70 = 42 кВА.","qs":"Un tablero tiene 60 kVA de carga conectada con un factor de demanda aplicable de 70%; ¿cuál es la carga de demanda calculada?","optss":["60 kVA","86 kVA","18 kVA","42 kVA"],"rs":"Carga de demanda = carga conectada × factor de demanda = 60 × 0.70 = 42 kVA."},
  {"id":269,"sec":"Finish Wiring & Trim","block":3,"q":"An equipment grounding conductor may also be installed as which of the following?","opts":["A white insulated conductor","A gray insulated conductor","A bare conductor","A blue insulated conductor"],"correct":2,"re":"NEC 250.118 and 250.119 permit an equipment grounding conductor to be a bare conductor, in addition to the green/green-yellow insulated identification.","qr":"Заземляющий проводник оборудования также может быть установлен как что из следующего?","optsr":["Белый изолированный проводник","Серый изолированный проводник","Голый проводник","Синий изолированный проводник"],"rr":"NEC 250.118 и 250.119 разрешают заземляющему проводнику оборудования быть голым проводником, в дополнение к зелёной/зелёно-жёлтой изолированной идентификации.","qs":"Un conductor de puesta a tierra de equipos también puede instalarse como cuál de los siguientes?","optss":["Un conductor aislado blanco","Un conductor aislado gris","Un conductor desnudo","Un conductor aislado azul"],"rs":"NEC 250.118 y 250.119 permiten que un conductor de puesta a tierra de equipos sea un conductor desnudo, además de la identificación aislada verde/verde-amarillo."},
  {"id":270,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Two 120 V buck-boost transformer windings are connected to boost a 208 V supply; what is the main advantage of using a buck-boost connection instead of an isolation transformer for this small correction?","opts":["It provides complete isolation from the source","It is smaller and less costly because it only handles the boosted portion of the load","It converts the supply to three-phase","It eliminates the need for overcurrent protection"],"correct":1,"re":"Because a buck-boost is wired as an autotransformer that only processes the small voltage difference, it is physically smaller and less expensive than a full isolation transformer of the same load.","qr":"Две обмотки трансформатора buck-boost на 120 В подключены для повышения питания 208 В; в чём основное преимущество использования buck-boost вместо разделительного трансформатора для такой малой коррекции?","optsr":["Обеспечивает полную развязку от источника","Он меньше и дешевле, так как обрабатывает только повышаемую часть нагрузки","Преобразует питание в трёхфазное","Устраняет необходимость в защите от сверхтока"],"rr":"Поскольку buck-boost подключён как автотрансформатор, обрабатывающий только небольшую разницу напряжений, он физически меньше и дешевле полноценного разделительного трансформатора той же мощности.","qs":"Dos devanados de transformador buck-boost de 120 V se conectan para aumentar un suministro de 208 V; ¿cuál es la principal ventaja de usar una conexión buck-boost en lugar de un transformador de aislamiento para esta pequeña corrección?","optss":["Proporciona aislamiento completo de la fuente","Es más pequeño y menos costoso porque solo maneja la porción aumentada de la carga","Convierte el suministro a trifásico","Elimina la necesidad de protección contra sobrecorriente"],"rs":"Debido a que un buck-boost se conecta como un autotransformador que solo procesa la pequeña diferencia de voltaje, es físicamente más pequeño y menos costoso que un transformador de aislamiento completo de la misma carga."},
  {"id":271,"sec":"Safety","block":3,"q":"Why should flexible cords used as temporary wiring on a construction site not be used as a substitute for the fixed (permanent) wiring of a structure?","opts":["Flexible cords are more expensive than permanent wiring","Flexible cords are not intended for permanent installation and are more prone to damage and overheating in that role","Flexible cords carry too little current for any tool","Flexible cords are illegal to manufacture"],"correct":1,"re":"Flexible cords are not a substitute for fixed wiring because they are subject to mechanical damage, are not protected within the building structure, and can overheat when used permanently.","qr":"Почему гибкие шнуры, используемые как временная проводка на стройплощадке, не должны заменять стационарную (постоянную) проводку конструкции?","optsr":["Гибкие шнуры дороже постоянной проводки","Гибкие шнуры не предназначены для постоянной установки и в этой роли более подвержены повреждению и перегреву","Гибкие шнуры пропускают слишком мало тока для любого инструмента","Гибкие шнуры запрещено производить"],"rr":"Гибкие шнуры не заменяют стационарную проводку, потому что они подвержены механическим повреждениям, не защищены внутри конструкции здания и могут перегреваться при постоянном использовании.","qs":"¿Por qué los cordones flexibles usados como cableado temporal en una obra de construcción no deben usarse como sustituto del cableado fijo (permanente) de una estructura?","optss":["Los cordones flexibles son más costosos que el cableado permanente","Los cordones flexibles no están destinados a instalación permanente y son más propensos a daños y sobrecalentamiento en ese papel","Los cordones flexibles transportan muy poca corriente para cualquier herramienta","Los cordones flexibles son ilegales de fabricar"],"rs":"Los cordones flexibles no son un sustituto del cableado fijo porque están sujetos a daño mecánico, no están protegidos dentro de la estructura del edificio y pueden sobrecalentarse cuando se usan permanentemente."},
  {"id":272,"sec":"Rough Wiring","block":3,"q":"A conductor or cable installed through a metal framing member must be protected by a bushing or grommet where required because the metal edge can cause what type of damage?","opts":["Voltage drop","Electromagnetic interference","Excessive heat buildup","Abrasion or cutting of the conductor insulation"],"correct":3,"re":"Per NEC 300.4(B), where cables pass through factory or field punched holes in metal framing, listed bushings or grommets protect the cable from abrasion against sharp metal edges.","qr":"Проводник или кабель, проложенный через металлический элемент каркаса, должен быть защищён втулкой или прокладкой там, где это требуется, потому что металлический край может вызвать какой тип повреждения?","optsr":["Падение напряжения","Электромагнитные помехи","Избыточный нагрев","Истирание или порез изоляции проводника"],"rr":"Согласно NEC 300.4(B), когда кабели проходят через заводские или просверленные на месте отверстия в металлическом каркасе, сертифицированные втулки или прокладки защищают кабель от истирания об острые металлические края.","qs":"Un conductor o cable instalado a través de un miembro estructural metálico debe protegerse con un buje o ojal donde se requiera porque el borde metálico puede causar qué tipo de daño?","optss":["Caída de voltaje","Interferencia electromagnética","Acumulación excesiva de calor","Abrasión o corte del aislamiento del conductor"],"rs":"Según NEC 300.4(B), donde los cables pasan a través de agujeros perforados de fábrica o en campo en miembros estructurales metálicos, los bujes u ojales listados protegen el cable de la abrasión contra los bordes metálicos afilados."},
  {"id":273,"sec":"Planning & Estimation","block":3,"q":"Under the standard method of NEC Article 220, what is the general lighting load value assigned per square foot of a dwelling unit?","opts":["1 VA per square foot","2 VA per square foot","3 VA per square foot","5 VA per square foot"],"correct":2,"re":"NEC Table 220.12 assigns 3 VA per square foot for general lighting in dwelling units.","qr":"По стандартному методу статьи NEC 220, какое значение нагрузки общего освещения назначается на квадратный фут жилого помещения?","optsr":["1 ВА на квадратный фут","2 ВА на квадратный фут","3 ВА на квадратный фут","5 ВА на квадратный фут"],"rr":"Таблица NEC 220.12 назначает 3 ВА на квадратный фут для общего освещения в жилых помещениях.","qs":"Bajo el método estándar del Artículo 220 del NEC, ¿cuál es el valor de carga de iluminación general asignado por pie cuadrado de una unidad de vivienda?","optss":["1 VA por pie cuadrado","2 VA por pie cuadrado","3 VA por pie cuadrado","5 VA por pie cuadrado"],"rs":"La Tabla 220.12 del NEC asigna 3 VA por pie cuadrado para iluminación general en unidades de vivienda."},
  {"id":274,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"What does a continuity test of an equipment grounding conductor verify during commissioning?","opts":["That there is a complete, low-resistance metallic path back to the source","The exact resistance to earth in ohms","The insulation quality of the conductor","The phase sequence of the supply"],"correct":0,"re":"A continuity test on the equipment grounding conductor verifies an unbroken low-resistance path for fault current to return to the source and operate the overcurrent device.","qr":"Что подтверждает проверка целостности защитного проводника заземления при наладке?","optsr":["Наличие непрерывного металлического пути с низким сопротивлением к источнику","Точное сопротивление относительно земли в омах","Качество изоляции проводника","Последовательность фаз питания"],"rr":"Проверка целостности защитного проводника заземления подтверждает непрерывный путь с низким сопротивлением для возврата тока КЗ к источнику и срабатывания защиты от сверхтока.","qs":"¿Qué verifica una prueba de continuidad de un conductor de puesta a tierra de equipos durante la puesta en servicio?","optss":["Que hay una ruta metálica completa de baja resistencia de regreso a la fuente","La resistencia exacta a tierra en ohmios","La calidad del aislamiento del conductor","La secuencia de fase del suministro"],"rs":"Una prueba de continuidad en el conductor de puesta a tierra de equipos verifica una ruta ininterrumpida de baja resistencia para que la corriente de falla regrese a la fuente y opere el dispositivo de sobrecorriente."},
  {"id":275,"sec":"Rough Wiring","block":3,"q":"When Type NM cable is run through bored holes in wood studs or joists, additional securing along that portion of the run is considered satisfied because the holes provide what?","opts":["Grounding continuity","Support and protection at each penetration","Required derating","Expansion compensation"],"correct":1,"re":"Per NEC 334.30, NM cable installed through bored holes in framing members is considered supported and secured by the framing where intervals do not exceed code limits.","qr":"Когда кабель типа NM проложен через просверленные отверстия в деревянных стойках или балках, дополнительное крепление вдоль этого участка считается выполненным, потому что отверстия обеспечивают что?","optsr":["Непрерывность заземления","Опору и защиту в каждом месте прохода","Требуемое снижение нагрузки","Компенсацию расширения"],"rr":"Согласно NEC 334.30, кабель NM, проложенный через просверленные отверстия в элементах каркаса, считается опираемым и закреплённым каркасом, когда интервалы не превышают пределов норм.","qs":"Cuando el cable tipo NM se tiende a través de agujeros perforados en montantes o viguetas de madera, la sujeción adicional a lo largo de esa porción del tramo se considera satisfecha porque los agujeros proporcionan qué?","optss":["Continuidad de puesta a tierra","Soporte y protección en cada penetración","Reducción de capacidad requerida","Compensación de expansión"],"rs":"Según NEC 334.30, el cable NM instalado a través de agujeros perforados en miembros estructurales se considera soportado y sujetado por la estructura donde los intervalos no exceden los límites del código."},
  {"id":276,"sec":"Safety","block":3,"q":"Live parts of electrical equipment operating at 50 volts or more must generally be guarded against accidental contact; which of the following is an acceptable method of guarding?","opts":["Placing the equipment in a room or enclosure accessible only to qualified persons","Painting the live parts a bright color","Posting a warning sign with no physical barrier","Coating the parts with a thin layer of oil"],"correct":0,"re":"Guarding live parts by location in a controlled room, vault, or enclosure accessible only to qualified persons is an accepted method; a sign or paint alone is not sufficient.","qr":"Токоведущие части электрооборудования, работающего при 50 В и более, обычно должны быть ограждены от случайного прикосновения; какой из следующих способов ограждения допустим?","optsr":["Размещение оборудования в помещении или корпусе, доступном только квалифицированным лицам","Покраска токоведущих частей в яркий цвет","Размещение предупреждающего знака без физического барьера","Покрытие частей тонким слоем масла"],"rr":"Ограждение токоведущих частей по расположению в контролируемом помещении, камере или корпусе, доступном только квалифицированным лицам, является принятым методом; одного знака или краски недостаточно.","qs":"Las partes vivas de equipos eléctricos que operan a 50 voltios o más generalmente deben protegerse contra el contacto accidental; ¿cuál de los siguientes es un método aceptable de protección?","optss":["Colocar el equipo en una habitación o encerramiento accesible solo a personas calificadas","Pintar las partes vivas de un color brillante","Colocar un letrero de advertencia sin barrera física","Recubrir las partes con una capa delgada de aceite"],"rs":"Proteger las partes vivas por ubicación en una habitación, bóveda o encerramiento controlado accesible solo a personas calificadas es un método aceptado; un letrero o pintura por sí solos no son suficientes."},
  {"id":277,"sec":"Planning & Estimation","block":3,"q":"What is the general lighting load for a dwelling with 2,000 square feet of habitable space using the standard calculation?","opts":["6,000 VA","4,000 VA","2,000 VA","10,000 VA"],"correct":0,"re":"General lighting = area × 3 VA/ft² = 2,000 × 3 = 6,000 VA.","qr":"Какова нагрузка общего освещения для жилья площадью 2 000 квадратных футов жилого пространства по стандартному расчёту?","optsr":["6 000 ВА","4 000 ВА","2 000 ВА","10 000 ВА"],"rr":"Общее освещение = площадь × 3 ВА/фут² = 2 000 × 3 = 6 000 ВА.","qs":"¿Cuál es la carga de iluminación general para una vivienda con 2,000 pies cuadrados de espacio habitable usando el cálculo estándar?","optss":["6,000 VA","4,000 VA","2,000 VA","10,000 VA"],"rs":"Iluminación general = área × 3 VA/pie² = 2,000 × 3 = 6,000 VA."},
  {"id":278,"sec":"Finish Wiring & Trim","block":3,"q":"Which color is NOT permitted to be used to identify an ungrounded (hot) conductor?","opts":["White","Red","Black","Blue"],"correct":0,"re":"Ungrounded conductors may be any color other than white, gray, or green (which are reserved for grounded and grounding conductors); white is reserved for the grounded conductor per NEC 200.6/200.7.","qr":"Какой цвет НЕ разрешается использовать для идентификации незаземлённого (фазного) проводника?","optsr":["Белый","Красный","Чёрный","Синий"],"rr":"Незаземлённые проводники могут быть любого цвета, кроме белого, серого или зелёного (которые зарезервированы для заземлённых и заземляющих проводников); белый зарезервирован для заземлённого проводника согласно NEC 200.6/200.7.","qs":"¿Qué color NO se permite usar para identificar un conductor no puesto a tierra (vivo)?","optss":["Blanco","Rojo","Negro","Azul"],"rs":"Los conductores no puestos a tierra pueden ser de cualquier color excepto blanco, gris o verde (que están reservados para los conductores puestos a tierra y de puesta a tierra); el blanco está reservado para el conductor puesto a tierra según NEC 200.6/200.7."},
  {"id":279,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"An ideal transformer steps 240 V up to 480 V; if the load on the 480 V side draws 10 A, what is the approximate primary current (neglecting losses)?","opts":["20 A","10 A","5 A","40 A"],"correct":0,"re":"Power in equals power out for an ideal transformer, so primary current equals secondary VA divided by primary voltage: (480 V x 10 A) / 240 V equals 20 A.","qr":"Идеальный трансформатор повышает 240 В до 480 В; если нагрузка на стороне 480 В потребляет 10 А, каков приблизительный первичный ток (без учёта потерь)?","optsr":["20 А","10 А","5 А","40 А"],"rr":"Для идеального трансформатора входная мощность равна выходной, поэтому первичный ток = вторичные ВА / первичное напряжение: (480 В × 10 А) / 240 В = 20 А.","qs":"Un transformador ideal eleva 240 V a 480 V; si la carga en el lado de 480 V consume 10 A, ¿cuál es la corriente primaria aproximada (despreciando las pérdidas)?","optss":["20 A","10 A","5 A","40 A"],"rs":"La potencia de entrada es igual a la potencia de salida para un transformador ideal, entonces la corriente primaria es igual a los VA secundarios divididos por el voltaje primario: (480 V x 10 A) / 240 V es igual a 20 A."},
  {"id":280,"sec":"Rough Wiring","block":3,"q":"What is the maximum spacing for supports of rigid metal conduit (RMC) trade size 1/2 through 3/4 installed exposed in a straight horizontal run?","opts":["6 feet","16 feet","10 feet","12 feet"],"correct":2,"re":"Per NEC Table 344.30(B)(2), RMC of trade size 1/2 and 3/4 requires support spacing not exceeding 10 ft.","qr":"Какое максимальное расстояние между опорами жёсткого металлического кабелепровода (RMC) типоразмера 1/2 - 3/4, установленного открыто прямым горизонтальным участком?","optsr":["6 футов","16 футов","10 футов","12 футов"],"rr":"Согласно NEC Таблица 344.30(B)(2), RMC типоразмера 1/2 и 3/4 требует расстояния между опорами не более 10 футов.","qs":"¿Cuál es el espaciamiento máximo para los soportes del conduit metálico rígido (RMC) de tamaño comercial 1/2 a 3/4 instalado expuesto en un tramo horizontal recto?","optss":["6 pies","16 pies","10 pies","12 pies"],"rs":"Según la Tabla 344.30(B)(2) del NEC, el RMC de tamaño comercial 1/2 y 3/4 requiere un espaciamiento de soporte que no exceda 10 pies."},
  {"id":281,"sec":"Planning & Estimation","block":3,"q":"How many volt-amperes does the NEC require for each of the two minimum small-appliance branch circuits in a dwelling load calculation?","opts":["1,000 VA each","1,500 VA each","2,000 VA each","3,000 VA each"],"correct":1,"re":"NEC 220.52(A) requires each small-appliance branch circuit to be calculated at 1,500 VA.","qr":"Сколько вольт-ампер требует NEC для каждой из двух минимальных цепей мелких бытовых приборов в расчёте нагрузки жилья?","optsr":["1 000 ВА каждая","1 500 ВА каждая","2 000 ВА каждая","3 000 ВА каждая"],"rr":"NEC 220.52(A) требует рассчитывать каждую цепь мелких бытовых приборов на 1 500 ВА.","qs":"¿Cuántos voltamperios requiere el NEC por cada uno de los dos circuitos ramales mínimos de pequeños electrodomésticos en un cálculo de carga de vivienda?","optss":["1,000 VA cada uno","1,500 VA cada uno","2,000 VA cada uno","3,000 VA cada uno"],"rs":"NEC 220.52(A) requiere que cada circuito ramal de pequeños electrodomésticos se calcule a 1,500 VA."},
  {"id":282,"sec":"Safety","block":3,"q":"The primary purpose of guarding live parts in electrical equipment is to do which of the following?","opts":["Improve the appearance of the installation","Increase the voltage rating of the conductors","Reduce the cost of the equipment","Prevent accidental contact by persons and protect against electric shock"],"correct":3,"re":"Guarding live parts is intended to prevent inadvertent contact by people, thereby protecting against electric shock and burns.","qr":"Основная цель ограждения токоведущих частей в электрооборудовании заключается в чём из следующего?","optsr":["Улучшить внешний вид установки","Повысить номинальное напряжение проводников","Снизить стоимость оборудования","Предотвратить случайное прикосновение людей и защитить от поражения током"],"rr":"Ограждение токоведущих частей предназначено для предотвращения непреднамеренного прикосновения людей, тем самым защищая от поражения током и ожогов.","qs":"El propósito principal de proteger las partes vivas en equipos eléctricos es hacer cuál de los siguientes?","optss":["Mejorar la apariencia de la instalación","Aumentar la clasificación de voltaje de los conductores","Reducir el costo del equipo","Prevenir el contacto accidental de personas y proteger contra descarga eléctrica"],"rs":"Proteger las partes vivas tiene como objetivo prevenir el contacto inadvertido de personas, protegiendo así contra descargas eléctricas y quemaduras."},
  {"id":283,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"When troubleshooting with a multimeter, you read 0 volts across a closed switch that should be passing current to a working load; what does this reading indicate about the switch?","opts":["The switch is good, since a closed switch should have little or no voltage drop across it","The switch is open and faulty","The load is short-circuited","The supply voltage is too high"],"correct":0,"re":"A properly closed switch has nearly zero voltage drop across it, so reading 0 V across it while the load operates indicates the switch contacts are good.","qr":"При поиске неисправности мультиметром вы измеряете 0 вольт на замкнутом выключателе, который должен пропускать ток к работающей нагрузке; что это показание говорит о выключателе?","optsr":["Выключатель исправен, так как на замкнутом выключателе должно быть малое или нулевое падение напряжения","Выключатель разомкнут и неисправен","Нагрузка закорочена","Напряжение питания слишком высокое"],"rr":"На правильно замкнутом выключателе падение напряжения почти нулевое, поэтому показание 0 В при работающей нагрузке означает, что контакты выключателя исправны.","qs":"Al diagnosticar con un multímetro, lee 0 voltios a través de un interruptor cerrado que debería estar pasando corriente a una carga en funcionamiento; ¿qué indica esta lectura sobre el interruptor?","optss":["El interruptor está bueno, ya que un interruptor cerrado debería tener poca o ninguna caída de voltaje a través de él","El interruptor está abierto y defectuoso","La carga está en cortocircuito","El voltaje de suministro es demasiado alto"],"rs":"Un interruptor correctamente cerrado tiene una caída de voltaje de casi cero a través de él, por lo que leer 0 V a través de él mientras la carga opera indica que los contactos del interruptor están buenos."},
  {"id":284,"sec":"Rough Wiring","block":3,"q":"A junction box must have its volume marked or be of sufficient size so that the total box fill does not exceed which of the following?","opts":["Half the number of cable clamps","Exactly 75 percent of the box volume","Twice the smallest conductor area","The marked or calculated volume of the box"],"correct":3,"re":"Per NEC 314.16(A) and (B), the total calculated volume of all contents must not exceed the marked or calculated volume of the box.","qr":"Соединительная коробка должна иметь маркированный объём или быть достаточного размера, чтобы общее заполнение коробки не превышало что из следующего?","optsr":["Половину количества кабельных зажимов","Ровно 75 процентов объёма коробки","Удвоенную площадь наименьшего проводника","Маркированный или расчётный объём коробки"],"rr":"Согласно NEC 314.16(A) и (B), общий расчётный объём всего содержимого не должен превышать маркированный или расчётный объём коробки.","qs":"Una caja de empalmes debe tener su volumen marcado o ser de tamaño suficiente para que el relleno total de la caja no exceda cuál de los siguientes?","optss":["La mitad del número de abrazaderas de cable","Exactamente el 75 por ciento del volumen de la caja","Dos veces el área del conductor más pequeño","El volumen marcado o calculado de la caja"],"rs":"Según NEC 314.16(A) y (B), el volumen total calculado de todo el contenido no debe exceder el volumen marcado o calculado de la caja."},
  {"id":285,"sec":"Planning & Estimation","block":3,"q":"In a dwelling unit standard load calculation, the laundry branch circuit is computed at what value?","opts":["1,000 VA","1,500 VA","2,000 VA","1,200 VA"],"correct":1,"re":"NEC 220.52(B) requires the laundry branch circuit to be calculated at 1,500 VA.","qr":"В стандартном расчёте нагрузки жилого помещения цепь прачечной рассчитывается по какому значению?","optsr":["1 000 ВА","1 500 ВА","2 000 ВА","1 200 ВА"],"rr":"NEC 220.52(B) требует рассчитывать цепь прачечной на 1 500 ВА.","qs":"En un cálculo de carga estándar de una unidad de vivienda, el circuito ramal de lavandería se calcula en qué valor?","optss":["1,000 VA","1,500 VA","2,000 VA","1,200 VA"],"rs":"NEC 220.52(B) requiere que el circuito ramal de lavandería se calcule a 1,500 VA."},
  {"id":286,"sec":"Safety","block":3,"q":"A GFCI provides protection against which specific hazard?","opts":["Overcurrent from a short circuit between hot conductors","Line-to-ground fault current flowing through a person to ground","Overvoltage from a lightning strike","Voltage drop on a long feeder"],"correct":1,"re":"A GFCI senses small imbalances caused by current leaking to ground (such as through a person) and trips to prevent fatal shock; it is not primarily an overcurrent or surge device.","qr":"GFCI обеспечивает защиту от какой конкретной опасности?","optsr":["Сверхтока от короткого замыкания между фазными проводниками","Тока замыкания на землю, протекающего через человека на землю","Перенапряжения от удара молнии","Падения напряжения на длинном фидере"],"rr":"GFCI обнаруживает небольшие дисбалансы, вызванные утечкой тока на землю (например, через человека), и срабатывает, предотвращая смертельное поражение; это в первую очередь не устройство защиты от сверхтока или перенапряжения.","qs":"Un GFCI proporciona protección contra cuál peligro específico?","optss":["Sobrecorriente de un cortocircuito entre conductores vivos","Corriente de falla línea a tierra que fluye a través de una persona hacia tierra","Sobrevoltaje de un rayo","Caída de voltaje en un alimentador largo"],"rs":"Un GFCI detecta pequeños desequilibrios causados por corriente que se fuga a tierra (como a través de una persona) y se dispara para prevenir una descarga fatal; no es principalmente un dispositivo de sobrecorriente o de sobretensión."},
  {"id":287,"sec":"Finish Wiring & Trim","block":3,"q":"When a white conductor in a cable is used as an ungrounded conductor in a switch loop, what must the electrician do at terminations?","opts":["Leave it white since it is in a cable","Connect it only to the neutral bar","Reidentify it with a color other than white, gray, or green","Cut and cap it"],"correct":2,"re":"NEC 200.7(C) permits a white conductor in a cable to serve as an ungrounded conductor only if it is permanently reidentified to indicate its use, by marking it with a color other than white, gray, or green.","qr":"Когда белый проводник в кабеле используется как незаземлённый проводник в петле выключателя, что должен сделать электрик на концах?","optsr":["Оставить его белым, так как он в кабеле","Подключить его только к нейтральной шине","Переидентифицировать его цветом, отличным от белого, серого или зелёного","Обрезать и заглушить его"],"rr":"NEC 200.7(C) разрешает белому проводнику в кабеле служить незаземлённым проводником только если он постоянно переидентифицирован для обозначения его использования путём маркировки цветом, отличным от белого, серого или зелёного.","qs":"Cuando un conductor blanco en un cable se usa como conductor no puesto a tierra en un lazo de interruptor, ¿qué debe hacer el electricista en las terminaciones?","optss":["Dejarlo blanco ya que está en un cable","Conectarlo solo a la barra de neutro","Reidentificarlo con un color que no sea blanco, gris o verde","Cortarlo y taparlo"],"rs":"NEC 200.7(C) permite que un conductor blanco en un cable sirva como conductor no puesto a tierra solo si se reidentifica permanentemente para indicar su uso, marcándolo con un color que no sea blanco, gris o verde."},
  {"id":288,"sec":"Rough Wiring","block":3,"q":"In a box-fill calculation, conductors that originate outside the box and pass through without splice or termination are counted how?","opts":["Each is counted once based on its size","Each is counted as two conductors","They are not counted","Only the largest one is counted"],"correct":0,"re":"Per NEC 314.16(B)(1), each conductor that runs through the box without splice or termination is counted once as a single conductor volume allowance.","qr":"При расчёте заполнения коробки проводники, которые начинаются за пределами коробки и проходят через неё без сращивания или окончания, учитываются как?","optsr":["Каждый учитывается один раз на основе своего сечения","Каждый учитывается как два проводника","Они не учитываются","Учитывается только самый большой"],"rr":"Согласно NEC 314.16(B)(1), каждый проводник, который проходит через коробку без сращивания или окончания, учитывается один раз как объём одного проводника.","qs":"En un cálculo de relleno de caja, ¿cómo se cuentan los conductores que se originan fuera de la caja y pasan a través de ella sin empalme ni terminación?","optss":["Cada uno se cuenta una vez según su tamaño","Cada uno se cuenta como dos conductores","No se cuentan","Solo se cuenta el más grande"],"rs":"Según NEC 314.16(B)(1), cada conductor que pasa a través de la caja sin empalme ni terminación se cuenta una vez como una sola asignación de volumen de conductor."},
  {"id":289,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"Which of the following is a correct safety practice when using a multimeter to measure voltage in a live panel?","opts":["Select a CAT rating and meter rated for the circuit, and inspect the leads before use","Set the meter to the ohms function first","Hold both probes in one hand for stability","Use a meter and leads rated below the system voltage"],"correct":0,"re":"Measuring live voltage safely requires a properly CAT-rated meter and leads suited to the circuit and inspecting the leads for damage before use.","qr":"Что из перечисленного является правильной практикой безопасности при использовании мультиметра для измерения напряжения в щите под напряжением?","optsr":["Выбрать прибор с подходящей категорией CAT для цепи и осмотреть щупы перед использованием","Сначала установить прибор в режим ом","Держать оба щупа в одной руке для устойчивости","Использовать прибор и щупы с номиналом ниже напряжения системы"],"rr":"Безопасное измерение напряжения под нагрузкой требует прибора и щупов с подходящей категорией CAT для цепи и осмотра щупов на повреждения перед использованием.","qs":"¿Cuál de las siguientes es una práctica de seguridad correcta al usar un multímetro para medir voltaje en un tablero energizado?","optss":["Seleccionar una clasificación CAT y un medidor clasificados para el circuito, e inspeccionar las puntas antes de usarlas","Configurar primero el medidor en la función de ohmios","Sostener ambas puntas en una mano para estabilidad","Usar un medidor y puntas clasificados por debajo del voltaje del sistema"],"rs":"Medir voltaje energizado de manera segura requiere un medidor y puntas con la clasificación CAT adecuada apropiados para el circuito e inspeccionar las puntas en busca de daños antes de usarlas."},
  {"id":290,"sec":"Planning & Estimation","block":3,"q":"Using the standard method, the combined general lighting, small-appliance, and laundry load of a dwelling totals 12,000 VA; what is the demand after applying NEC Table 220.42 (first 3,000 VA at 100%, remainder at 35%)?","opts":["12,000 VA","4,200 VA","6,150 VA","9,000 VA"],"correct":2,"re":"First 3,000 VA at 100% = 3,000; remaining 9,000 VA at 35% = 3,150; total = 6,150 VA per Table 220.42.","qr":"По стандартному методу суммарная нагрузка общего освещения, мелких приборов и прачечной жилья составляет 12 000 ВА; каков спрос после применения таблицы NEC 220.42 (первые 3 000 ВА по 100%, остаток по 35%)?","optsr":["12 000 ВА","4 200 ВА","6 150 ВА","9 000 ВА"],"rr":"Первые 3 000 ВА по 100% = 3 000; остальные 9 000 ВА по 35% = 3 150; итого = 6 150 ВА согласно таблице 220.42.","qs":"Usando el método estándar, la carga combinada de iluminación general, pequeños electrodomésticos y lavandería de una vivienda totaliza 12,000 VA; ¿cuál es la demanda después de aplicar la Tabla 220.42 del NEC (los primeros 3,000 VA al 100%, el resto al 35%)?","optss":["12,000 VA","4,200 VA","6,150 VA","9,000 VA"],"rs":"Los primeros 3,000 VA al 100% = 3,000; los 9,000 VA restantes al 35% = 3,150; total = 6,150 VA según la Tabla 220.42."},
  {"id":291,"sec":"Rough Wiring","block":3,"q":"When one or more internal cable clamps are present in a box, how many conductor volume allowances are added for all the clamps?","opts":["None, clamps are not counted","Two regardless of conductor size","One for each clamp present","A single volume allowance based on the largest conductor in the box"],"correct":3,"re":"Per NEC 314.16(B)(2), one or more internal cable clamps count collectively as a single conductor volume allowance based on the largest conductor entering the box.","qr":"Когда в коробке присутствует один или несколько внутренних кабельных зажимов, сколько объёмов проводников добавляется на все зажимы?","optsr":["Ни одного, зажимы не учитываются","Два независимо от сечения проводника","По одному на каждый присутствующий зажим","Один объём на основе самого большого проводника в коробке"],"rr":"Согласно NEC 314.16(B)(2), один или несколько внутренних кабельных зажимов вместе считаются как объём одного проводника на основе самого большого проводника, входящего в коробку.","qs":"Cuando hay una o más abrazaderas de cable internas presentes en una caja, ¿cuántas asignaciones de volumen de conductor se agregan por todas las abrazaderas?","optss":["Ninguna, las abrazaderas no se cuentan","Dos sin importar el tamaño del conductor","Una por cada abrazadera presente","Una sola asignación de volumen basada en el conductor más grande en la caja"],"rs":"Según NEC 314.16(B)(2), una o más abrazaderas de cable internas cuentan colectivamente como una sola asignación de volumen de conductor basada en el conductor más grande que entra a la caja."},
  {"id":292,"sec":"Safety","block":3,"q":"Does a standard GFCI protect a person against a shock received by contacting both the hot and neutral (line-to-line) conductors simultaneously?","opts":["Yes, it always prevents all shocks","Yes, but only on 240-volt circuits","No, because the current is balanced and no imbalance to ground is detected","No, because GFCIs only work on direct current"],"correct":2,"re":"If a person contacts both hot and neutral, the current returns through the neutral and remains balanced, so the GFCI sees no ground-fault imbalance and will not trip.","qr":"Защищает ли стандартный GFCI человека от удара током при одновременном прикосновении к фазному и нейтральному (фаза-фаза) проводникам?","optsr":["Да, он всегда предотвращает все удары током","Да, но только на цепях 240 В","Нет, потому что ток сбалансирован и дисбаланс на землю не обнаруживается","Нет, потому что GFCI работают только на постоянном токе"],"rr":"Если человек касается и фазы, и нейтрали, ток возвращается через нейтраль и остаётся сбалансированным, поэтому GFCI не видит дисбаланса замыкания на землю и не срабатывает.","qs":"¿Protege un GFCI estándar a una persona contra una descarga recibida al contactar simultáneamente los conductores vivo y neutro (línea a línea)?","optss":["Sí, siempre previene todas las descargas","Sí, pero solo en circuitos de 240 voltios","No, porque la corriente está balanceada y no se detecta desequilibrio a tierra","No, porque los GFCI solo funcionan con corriente continua"],"rs":"Si una persona contacta tanto el vivo como el neutro, la corriente regresa a través del neutro y permanece balanceada, por lo que el GFCI no ve desequilibrio de falla a tierra y no se disparará."},
  {"id":293,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"A three-phase delta primary, wye secondary transformer is energized; on the wye secondary the phase voltage measures 277 V, so what is the expected line-to-line voltage?","opts":["About 480 V","About 831 V","About 160 V","277 V"],"correct":0,"re":"On a wye secondary the line-to-line voltage equals phase voltage times the square root of 3, so 277 V times 1.732 is about 480 V.","qr":"Трёхфазный трансформатор с первичной обмоткой треугольник и вторичной звезда включён; на вторичной звезде фазное напряжение составляет 277 В, каково ожидаемое межфазное напряжение?","optsr":["Около 480 В","Около 831 В","Около 160 В","277 В"],"rr":"На вторичной обмотке звезда межфазное напряжение равно фазному, умноженному на корень из 3: 277 В × 1,732 ≈ 480 В.","qs":"Un transformador trifásico de primario en delta, secundario en estrella está energizado; en el secundario en estrella el voltaje de fase mide 277 V, entonces ¿cuál es el voltaje línea a línea esperado?","optss":["Aproximadamente 480 V","Aproximadamente 831 V","Aproximadamente 160 V","277 V"],"rs":"En un secundario en estrella el voltaje línea a línea es igual al voltaje de fase por la raíz cuadrada de 3, entonces 277 V por 1.732 es aproximadamente 480 V."},
  {"id":294,"sec":"Planning & Estimation","block":3,"q":"A dwelling has two small-appliance circuits and one laundry circuit; what total VA do these three circuits contribute before applying the demand factor?","opts":["3,000 VA","1,500 VA","6,000 VA","4,500 VA"],"correct":3,"re":"Two small-appliance circuits (2 × 1,500) + one laundry circuit (1,500) = 3,000 + 1,500 = 4,500 VA.","qr":"Жильё имеет две цепи мелких приборов и одну цепь прачечной; какую общую мощность в ВА дают эти три цепи до применения коэффициента спроса?","optsr":["3 000 ВА","1 500 ВА","6 000 ВА","4 500 ВА"],"rr":"Две цепи мелких приборов (2 × 1 500) + одна цепь прачечной (1 500) = 3 000 + 1 500 = 4 500 ВА.","qs":"Una vivienda tiene dos circuitos de pequeños electrodomésticos y un circuito de lavandería; ¿qué VA total aportan estos tres circuitos antes de aplicar el factor de demanda?","optss":["3,000 VA","1,500 VA","6,000 VA","4,500 VA"],"rs":"Dos circuitos de pequeños electrodomésticos (2 × 1,500) + un circuito de lavandería (1,500) = 3,000 + 1,500 = 4,500 VA."},
  {"id":295,"sec":"Rough Wiring","block":3,"q":"Which raceway is a corrugated, pliable nonmetallic tubing, often colored, that is intended for concealed installation in residential and light commercial work?","opts":["Intermediate metal conduit (IMC)","Liquidtight flexible nonmetallic conduit (LFNC)","Rigid PVC conduit","Electrical nonmetallic tubing (ENT)"],"correct":3,"re":"Per NEC Article 362, electrical nonmetallic tubing (ENT) is a pliable corrugated raceway, often colored, used in concealed locations.","qr":"Какой raceway представляет собой гофрированную гибкую неметаллическую трубку, часто цветную, предназначенную для скрытой установки в жилых и лёгких коммерческих работах?","optsr":["Промежуточный металлический кабелепровод (IMC)","Жидконепроницаемый гибкий неметаллический кабелепровод (LFNC)","Жёсткий PVC кабелепровод","Электрическая неметаллическая трубка (ENT)"],"rr":"Согласно NEC Статья 362, электрическая неметаллическая трубка (ENT) представляет собой гибкий гофрированный raceway, часто цветной, используемый в скрытых местах.","qs":"¿Qué canalización es una tubería no metálica corrugada y flexible, a menudo de color, que está destinada a instalación oculta en trabajos residenciales y comerciales ligeros?","optss":["Conduit metálico intermedio (IMC)","Conduit no metálico flexible hermético a líquidos (LFNC)","Conduit rígido de PVC","Tubería no metálica eléctrica (ENT)"],"rs":"Según el Artículo 362 del NEC, la tubería no metálica eléctrica (ENT) es una canalización corrugada flexible, a menudo de color, usada en lugares ocultos."},
  {"id":296,"sec":"Finish Wiring & Trim","block":3,"q":"Which conductor in a standard duplex receptacle must be connected to the terminal identified by the silver or light-colored screws?","opts":["The grounded (neutral) conductor","The ungrounded (hot) conductor","The equipment grounding conductor","The traveler conductor"],"correct":0,"re":"On a receptacle, the silver/light-colored screws are the grounded (neutral) terminals; the brass screws are the ungrounded terminals and the green screw is for the EGC, per NEC 200.10 and 250.126.","qr":"Какой проводник в стандартной сдвоенной розетке должен подключаться к клемме, обозначенной серебристыми или светлыми винтами?","optsr":["Заземлённый (нейтральный) проводник","Незаземлённый (фазный) проводник","Заземляющий проводник оборудования","Транзитный проводник"],"rr":"На розетке серебристые/светлые винты — это заземлённые (нейтральные) клеммы; латунные винты — незаземлённые клеммы, а зелёный винт — для EGC, согласно NEC 200.10 и 250.126.","qs":"¿Qué conductor en un receptáculo dúplex estándar debe conectarse al terminal identificado por los tornillos plateados o de color claro?","optss":["El conductor puesto a tierra (neutro)","El conductor no puesto a tierra (vivo)","El conductor de puesta a tierra de equipos","El conductor viajero"],"rs":"En un receptáculo, los tornillos plateados/de color claro son los terminales puestos a tierra (neutro); los tornillos de latón son los terminales no puestos a tierra y el tornillo verde es para el EGC, según NEC 200.10 y 250.126."},
  {"id":297,"sec":"Safety","block":3,"q":"After installing a GFCI receptacle on a job site, what should the electrician do to verify it is functioning correctly?","opts":["Measure the cord length","Leave it untested until an inspector arrives","Check the color of the faceplate","Press the TEST button and confirm the device trips, then press RESET"],"correct":3,"re":"Pressing the TEST button should trip the GFCI, confirming the protective mechanism works; RESET then restores power.","qr":"После установки розетки GFCI на объекте что должен сделать электрик, чтобы убедиться, что она работает правильно?","optsr":["Измерить длину шнура","Оставить её непроверенной до прибытия инспектора","Проверить цвет лицевой панели","Нажать кнопку TEST и убедиться, что устройство срабатывает, затем нажать RESET"],"rr":"Нажатие кнопки TEST должно вызвать срабатывание GFCI, подтверждая работу защитного механизма; затем RESET восстанавливает питание.","qs":"Después de instalar un receptáculo GFCI en una obra, ¿qué debe hacer el electricista para verificar que funciona correctamente?","optss":["Medir la longitud del cordón","Dejarlo sin probar hasta que llegue un inspector","Verificar el color de la placa frontal","Presionar el botón TEST y confirmar que el dispositivo se dispara, luego presionar RESET"],"rs":"Presionar el botón TEST debería disparar el GFCI, confirmando que el mecanismo de protección funciona; luego RESET restaura la energía."},
  {"id":298,"sec":"Startup, Troubleshooting & Maintenance","block":3,"q":"During a pre-energization inspection, what is the purpose of verifying that the main bonding jumper is installed at the service?","opts":["To connect the grounded conductor to the equipment grounding system so fault current can clear","To isolate the neutral from ground","To increase voltage to the loads","To balance the phase currents"],"correct":0,"re":"The main bonding jumper connects the grounded (neutral) conductor to the equipment grounding system at the service, establishing the path that lets fault current operate the overcurrent device.","qr":"При осмотре перед подачей напряжения, какова цель проверки установки главной соединительной перемычки на вводе?","optsr":["Соединить заземлённый проводник с системой заземления оборудования для отвода тока КЗ","Изолировать нейтраль от земли","Повысить напряжение на нагрузках","Сбалансировать фазные токи"],"rr":"Главная соединительная перемычка соединяет заземлённый (нейтральный) проводник с системой заземления оборудования на вводе, создавая путь, позволяющий току КЗ привести в действие защиту от сверхтока.","qs":"Durante una inspección previa a la energización, ¿cuál es el propósito de verificar que el puente de unión principal esté instalado en el servicio?","optss":["Conectar el conductor puesto a tierra al sistema de puesta a tierra de equipos para que la corriente de falla pueda despejarse","Aislar el neutro de tierra","Aumentar el voltaje a las cargas","Balancear las corrientes de fase"],"rs":"El puente de unión principal conecta el conductor puesto a tierra (neutro) al sistema de puesta a tierra de equipos en el servicio, estableciendo la ruta que permite que la corriente de falla opere el dispositivo de sobrecorriente."},
  {"id":299,"sec":"Planning & Estimation","block":3,"q":"Using NEC Table 220.55 Column C, what is the demand load for a single household electric range rated at 12 kW?","opts":["12 kW","6 kW","10 kW","8 kW"],"correct":3,"re":"NEC Table 220.55 Column C gives 8 kW for one range not over 12 kW.","qr":"Используя таблицу NEC 220.55, столбец C, какова нагрузка спроса для одной бытовой электрической плиты мощностью 12 кВт?","optsr":["12 кВт","6 кВт","10 кВт","8 кВт"],"rr":"Таблица NEC 220.55, столбец C, даёт 8 кВт для одной плиты не более 12 кВт.","qs":"Usando la Tabla 220.55 Columna C del NEC, ¿cuál es la carga de demanda para una sola estufa eléctrica doméstica clasificada en 12 kW?","optss":["12 kW","6 kW","10 kW","8 kW"],"rs":"La Tabla 220.55 Columna C del NEC da 8 kW para una estufa no mayor de 12 kW."},
  {"id":300,"sec":"Rough Wiring","block":3,"q":"Flexible metal conduit (FMC) used as a fixture whip for connection to a luminaire is generally permitted to be unsupported for a length not exceeding which distance?","opts":["3 feet","6 feet","4 1/2 feet","8 feet"],"correct":1,"re":"Per NEC 348.30(A), FMC is permitted to be unsupported up to 6 ft from a luminaire terminal for tap connections (fixture whips).","qr":"Гибкий металлический кабелепровод (FMC), используемый как гибкая подводка к светильнику, обычно разрешается оставлять без опоры на длину, не превышающую какое расстояние?","optsr":["3 фута","6 футов","4 1/2 фута","8 футов"],"rr":"Согласно NEC 348.30(A), FMC разрешается оставлять без опоры на длину до 6 футов от клеммы светильника для ответвлений (гибких подводок).","qs":"El conduit metálico flexible (FMC) usado como latiguillo de luminaria para la conexión a una luminaria generalmente se permite que esté sin soporte por una longitud que no exceda qué distancia?","optss":["3 pies","6 pies","4 1/2 pies","8 pies"],"rs":"Según NEC 348.30(A), el FMC se permite que esté sin soporte hasta 6 pies desde el terminal de una luminaria para conexiones de derivación (latiguillos de luminaria)."},
  {"id":301,"sec":"Safety","block":4,"q":"A worker is using a corded portable power tool outdoors in a damp area; which combination provides the best protection against electric shock?","opts":["An ungrounded tool with no GFCI","A properly grounded or double-insulated tool supplied through a GFCI","A tool with the grounding prong removed","A tool plugged into a frayed extension cord"],"correct":1,"re":"The safest combination is a tool that is either properly grounded or double-insulated and fed through GFCI protection, especially in damp locations.","qr":"Рабочий использует портативный электроинструмент со шнуром на улице во влажной зоне; какая комбинация обеспечивает наилучшую защиту от поражения током?","optsr":["Незаземлённый инструмент без GFCI","Правильно заземлённый или двойной изоляции инструмент, питаемый через GFCI","Инструмент со снятым заземляющим штырём","Инструмент, подключённый к перетёртому удлинителю"],"rr":"Самая безопасная комбинация — это инструмент, который либо правильно заземлён, либо двойной изоляции, и питается через защиту GFCI, особенно во влажных местах.","qs":"Un trabajador está usando una herramienta eléctrica portátil con cable en exteriores, en un área húmeda; ¿qué combinación brinda la mejor protección contra descargas eléctricas?","optss":["Una herramienta sin conexión a tierra y sin GFCI","Una herramienta correctamente conectada a tierra o con doble aislamiento, alimentada a través de un GFCI","Una herramienta con la espiga de conexión a tierra removida","Una herramienta conectada a un cable de extensión deshilachado"],"rs":"La combinación más segura es una herramienta que esté correctamente conectada a tierra o con doble aislamiento y alimentada a través de protección GFCI, especialmente en lugares húmedos."},
  {"id":302,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"Which instrument is specifically designed to measure how many ohms of resistance exist between a grounding electrode and the surrounding earth?","opts":["Ground-resistance tester (earth ground tester)","Standard multimeter on the ohms range","Megohmmeter","Non-contact voltage tester"],"correct":0,"re":"A ground-resistance (earth ground) tester is designed to measure electrode-to-earth resistance, using fall-of-potential or clamp-on methods that a standard ohmmeter cannot perform accurately.","qr":"Какой прибор специально предназначен для измерения, сколько ом сопротивления существует между заземляющим электродом и окружающей землёй?","optsr":["Измеритель сопротивления заземления (тестер заземления)","Стандартный мультиметр в режиме ом","Мегомметр","Бесконтактный индикатор напряжения"],"rr":"Измеритель сопротивления заземления предназначен для измерения сопротивления электрод-земля методами падения потенциала или клещевым, которые обычный омметр не может выполнить точно.","qs":"¿Cuál instrumento está diseñado específicamente para medir cuántos ohmios de resistencia existen entre un electrodo de puesta a tierra y la tierra circundante?","optss":["Medidor de resistencia de tierra (probador de tierra física)","Multímetro estándar en el rango de ohmios","Megóhmetro","Detector de voltaje sin contacto"],"rs":"Un medidor de resistencia de tierra (tierra física) está diseñado para medir la resistencia del electrodo a la tierra, usando métodos de caída de potencial o de pinza que un ohmímetro estándar no puede realizar con precisión."},
  {"id":303,"sec":"Rough Wiring","block":4,"q":"Securing of NM cable is NOT required in which of the following situations?","opts":["Where the cable is fished between access points through concealed spaces of finished buildings and supporting is impracticable","Where the cable enters a surface-mounted box","Where the cable runs exposed across the face of a finished wall","Where the cable is run across the bottom of floor joists"],"correct":0,"re":"Per NEC 334.30(B), securing is not required where cable is fished between access points through concealed spaces of finished buildings and supporting is impracticable.","qr":"Крепление кабеля NM НЕ требуется в какой из следующих ситуаций?","optsr":["Где кабель протянут между точками доступа через скрытые пространства отделанных зданий и установка опоры непрактична","Где кабель входит в коробку поверхностного монтажа","Где кабель проложен открыто по лицевой стороне отделанной стены","Где кабель проложен по нижней стороне балок перекрытия"],"rr":"Согласно NEC 334.30(B), крепление не требуется там, где кабель протянут между точками доступа через скрытые пространства отделанных зданий и установка опоры непрактична.","qs":"¿En cuál de las siguientes situaciones NO se requiere la fijación del cable NM?","optss":["Donde el cable se pasa con guía entre puntos de acceso a través de espacios ocultos de edificios terminados y el soporte es impracticable","Donde el cable entra a una caja montada en superficie","Donde el cable corre expuesto a lo largo de la cara de una pared terminada","Donde el cable corre por la parte inferior de las viguetas del piso"],"rs":"Según el NEC 334.30(B), no se requiere fijación donde el cable se pasa con guía entre puntos de acceso a través de espacios ocultos de edificios terminados y el soporte es impracticable."},
  {"id":304,"sec":"Planning & Estimation","block":4,"q":"Per NEC 220.54, what minimum value must a single household electric clothes dryer be calculated at, even if its nameplate rating is lower?","opts":["3,000 VA","5,000 VA","4,500 VA","1,500 VA"],"correct":1,"re":"NEC 220.54 requires a household electric dryer to be calculated at 5,000 VA or the nameplate rating, whichever is larger.","qr":"Согласно NEC 220.54, по какому минимальному значению должна рассчитываться одна бытовая электрическая сушилка для одежды, даже если её паспортная мощность ниже?","optsr":["3 000 ВА","5 000 ВА","4 500 ВА","1 500 ВА"],"rr":"NEC 220.54 требует рассчитывать бытовую электрическую сушилку на 5 000 ВА или паспортную мощность, в зависимости от того, что больше.","qs":"Según el NEC 220.54, ¿a qué valor mínimo debe calcularse una sola secadora eléctrica de ropa doméstica, aun si su placa de datos indica un valor menor?","optss":["3,000 VA","5,000 VA","4,500 VA","1,500 VA"],"rs":"El NEC 220.54 exige que una secadora eléctrica doméstica se calcule a 5,000 VA o al valor de placa, lo que sea mayor."},
  {"id":305,"sec":"Finish Wiring & Trim","block":4,"q":"To control a single luminaire from two different locations, which switching arrangement is used?","opts":["Two single-pole switches","One 4-way switch","Two 3-way switches","Two double-pole switches"],"correct":2,"re":"Control of one load from two locations is accomplished with a pair of 3-way switches connected by traveler conductors.","qr":"Чтобы управлять одним светильником из двух разных мест, какая схема переключения используется?","optsr":["Два однополюсных выключателя","Один четырёхпозиционный (4-way) выключатель","Два трёхпозиционных (3-way) выключателя","Два двухполюсных выключателя"],"rr":"Управление одной нагрузкой из двух мест достигается парой 3-way выключателей, соединённых транзитными (traveler) проводниками.","qs":"Para controlar una sola luminaria desde dos ubicaciones diferentes, ¿qué arreglo de interruptores se utiliza?","optss":["Dos interruptores de un polo","Un interruptor de 4 vías","Dos interruptores de 3 vías","Dos interruptores de doble polo"],"rs":"El control de una sola carga desde dos ubicaciones se logra con un par de interruptores de 3 vías conectados mediante conductores viajeros."},
  {"id":306,"sec":"Rough Wiring","block":4,"q":"An outlet box mounted in a finished wall of noncombustible material such as drywall must be installed so that the front edge is set back no more than what distance from the finished surface?","opts":["Flush, with no setback permitted","Not more than 1/4 inch back from the surface","Not more than 1 inch back from the surface","Not more than 1 1/4 inches back from the surface"],"correct":1,"re":"Per NEC 314.20, in walls of noncombustible material the box may be set back not more than 1/4 in. from the finished surface.","qr":"Распределительная коробка, установленная в отделанной стене из негорючего материала, такого как гипсокартон, должна быть смонтирована так, чтобы передний край был утоплен не более чем на какое расстояние от отделанной поверхности?","optsr":["Заподлицо, без допустимого утопления","Не более 1/4 дюйма от поверхности","Не более 1 дюйма от поверхности","Не более 1 1/4 дюйма от поверхности"],"rr":"Согласно NEC 314.20, в стенах из негорючего материала коробка может быть утоплена не более чем на 1/4 дюйма от отделанной поверхности.","qs":"Una caja de salida montada en una pared terminada de material no combustible, como el panel de yeso, debe instalarse de modo que el borde frontal quede retraído no más de qué distancia respecto de la superficie terminada?","optss":["Al ras, sin retraimiento permitido","No más de 1/4 de pulgada por detrás de la superficie","No más de 1 pulgada por detrás de la superficie","No más de 1 1/4 pulgadas por detrás de la superficie"],"rs":"Según el NEC 314.20, en paredes de material no combustible la caja puede quedar retraída no más de 1/4 in respecto de la superficie terminada."},
  {"id":307,"sec":"Safety","block":4,"q":"Electrical burns from contact with energized parts can be deceptively serious because the most severe tissue damage often occurs where?","opts":["Only on the surface of the skin","Only in the victim's clothing","Only in the hair and fingernails","Deep inside the body along the path the current takes between entry and exit points"],"correct":3,"re":"Current passing through the body generates heat deep within tissues, so internal damage along the current path is frequently far worse than the visible surface wounds.","qr":"Электрические ожоги от контакта с токоведущими частями могут быть обманчиво серьёзными, потому что наиболее тяжёлое повреждение тканей часто происходит где?","optsr":["Только на поверхности кожи","Только в одежде пострадавшего","Только в волосах и ногтях","Глубоко внутри тела по пути тока между точками входа и выхода"],"rr":"Ток, проходящий через тело, выделяет тепло глубоко в тканях, поэтому внутренние повреждения по пути тока часто гораздо тяжелее, чем видимые поверхностные раны.","qs":"Las quemaduras eléctricas por contacto con partes energizadas pueden ser engañosamente graves porque el daño tisular más severo a menudo ocurre ¿dónde?","optss":["Solo en la superficie de la piel","Solo en la ropa de la víctima","Solo en el cabello y las uñas","En el interior profundo del cuerpo, a lo largo de la trayectoria que toma la corriente entre los puntos de entrada y salida"],"rs":"La corriente que pasa a través del cuerpo genera calor en lo profundo de los tejidos, por lo que el daño interno a lo largo de la trayectoria de la corriente suele ser mucho peor que las heridas visibles en la superficie."},
  {"id":308,"sec":"Planning & Estimation","block":4,"q":"What is the minimum service size, in amperes, required for a single one-family dwelling under NEC 230.79(C)?","opts":["100 A","60 A","125 A","150 A"],"correct":0,"re":"NEC 230.79(C) requires a minimum 100 A service disconnect rating for a one-family dwelling.","qr":"Каков минимальный размер ввода в амперах, требуемый для одного односемейного жилья согласно NEC 230.79(C)?","optsr":["100 А","60 А","125 А","150 А"],"rr":"NEC 230.79(C) требует минимальный номинал отключающего устройства ввода 100 А для односемейного жилья.","qs":"¿Cuál es el tamaño mínimo de acometida, en amperios, requerido para una sola vivienda unifamiliar según el NEC 230.79(C)?","optss":["100 A","60 A","125 A","150 A"],"rs":"El NEC 230.79(C) exige una capacidad mínima de 100 A para el medio de desconexión de la acometida de una vivienda unifamiliar."},
  {"id":309,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"What is the most reliable way to verify a circuit is de-energized before beginning work, sometimes called the live-dead-live test?","opts":["Test the meter on a known live source, test the circuit, then re-test the known live source","Use a non-contact tester one time","Look at the breaker handle position only","Assume it is dead if the lights are off"],"correct":0,"re":"The live-dead-live (test-before-touch) method confirms the tester works on a known live source, shows the circuit is dead, then re-confirms the tester still works, proving the absence of voltage.","qr":"Какой самый надёжный способ убедиться, что цепь обесточена, перед началом работы, иногда называемый тестом живой-мёртвый-живой?","optsr":["Проверить прибор на известном источнике под напряжением, проверить цепь, затем снова проверить источник","Один раз использовать бесконтактный индикатор","Смотреть только на положение рукоятки автомата","Считать обесточенной, если свет выключен"],"rr":"Метод живой-мёртвый-живой подтверждает, что прибор работает на известном источнике под напряжением, показывает, что цепь обесточена, затем снова подтверждает работу прибора, доказывая отсутствие напряжения.","qs":"¿Cuál es la forma más confiable de verificar que un circuito esté desenergizado antes de comenzar a trabajar, a veces llamada prueba vivo-muerto-vivo?","optss":["Probar el medidor en una fuente viva conocida, probar el circuito, y luego volver a probar la fuente viva conocida","Usar un detector sin contacto una sola vez","Mirar únicamente la posición de la palanca del interruptor","Suponer que está muerto si las luces están apagadas"],"rs":"El método vivo-muerto-vivo (probar antes de tocar) confirma que el probador funciona en una fuente viva conocida, muestra que el circuito está muerto y luego vuelve a confirmar que el probador sigue funcionando, comprobando la ausencia de voltaje."},
  {"id":310,"sec":"Rough Wiring","block":4,"q":"An outlet box installed in a combustible wall surface such as wood paneling must be installed so that the front edge is positioned how relative to the finished surface?","opts":["Flush with or projecting from the finished surface","Set back 1/4 inch","Set back 1/2 inch","Set back 1 inch"],"correct":0,"re":"Per NEC 314.20, in walls of combustible material the box must be flush with or project from the finished surface.","qr":"Распределительная коробка, установленная в горючей поверхности стены, такой как деревянные панели, должна быть смонтирована так, чтобы передний край располагался как относительно отделанной поверхности?","optsr":["Заподлицо или выступать от отделанной поверхности","Утоплена на 1/4 дюйма","Утоплена на 1/2 дюйма","Утоплена на 1 дюйм"],"rr":"Согласно NEC 314.20, в стенах из горючего материала коробка должна быть заподлицо или выступать от отделанной поверхности.","qs":"Una caja de salida instalada en una superficie de pared combustible, como el revestimiento de madera, debe instalarse de modo que el borde frontal quede posicionado ¿cómo respecto de la superficie terminada?","optss":["Al ras o sobresaliendo de la superficie terminada","Retraída 1/4 de pulgada","Retraída 1/2 pulgada","Retraída 1 pulgada"],"rs":"Según el NEC 314.20, en paredes de material combustible la caja debe quedar al ras o sobresalir de la superficie terminada."},
  {"id":311,"sec":"Planning & Estimation","block":4,"q":"A 120/240 V single-phase dwelling has a calculated total demand load of 24,000 VA; what is the minimum service ampacity required?","opts":["200 A","150 A","125 A","100 A"],"correct":3,"re":"Service amperes = VA ÷ V = 24,000 ÷ 240 = 100 A.","qr":"Односемейное жильё 120/240 В однофазное имеет расчётную общую нагрузку спроса 24 000 ВА; какова минимальная требуемая токовая нагрузка ввода?","optsr":["200 А","150 А","125 А","100 А"],"rr":"Ток ввода = ВА ÷ В = 24 000 ÷ 240 = 100 А.","qs":"Una vivienda monofásica de 120/240 V tiene una carga de demanda total calculada de 24,000 VA; ¿cuál es la ampacidad mínima de acometida requerida?","optss":["200 A","150 A","125 A","100 A"],"rs":"Amperios de acometida = VA ÷ V = 24,000 ÷ 240 = 100 A."},
  {"id":312,"sec":"Safety","block":4,"q":"Which factor most directly determines the magnitude of current that will flow through a person who contacts an energized conductor at a fixed voltage?","opts":["The person's height","The color of the conductor insulation","The resistance of the body and contact points in the current path","The time of day"],"correct":2,"re":"By Ohm's law, for a given voltage the current equals voltage divided by resistance, so lower body and contact resistance (for example, wet skin) results in higher, more dangerous current.","qr":"Какой фактор наиболее непосредственно определяет величину тока, который протекает через человека, контактирующего с проводником под фиксированным напряжением?","optsr":["Рост человека","Цвет изоляции проводника","Сопротивление тела и точек контакта на пути тока","Время суток"],"rr":"По закону Ома при данном напряжении ток равен напряжению, делённому на сопротивление, поэтому меньшее сопротивление тела и контакта (например, мокрая кожа) приводит к большему, более опасному току.","qs":"¿Cuál factor determina de forma más directa la magnitud de la corriente que fluirá a través de una persona que entra en contacto con un conductor energizado a un voltaje fijo?","optss":["La estatura de la persona","El color del aislamiento del conductor","La resistencia del cuerpo y de los puntos de contacto en la trayectoria de la corriente","La hora del día"],"rs":"Por la ley de Ohm, para un voltaje dado la corriente es igual al voltaje dividido por la resistencia, por lo que una menor resistencia del cuerpo y de los puntos de contacto (por ejemplo, piel mojada) resulta en una corriente más alta y más peligrosa."},
  {"id":313,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A clamp-on ammeter is placed around all three phase conductors of a balanced three-phase circuit at the same time; what should it ideally read?","opts":["The line-to-line voltage","The sum of all three phase currents","The current of one phase only","Approximately zero, because the balanced currents cancel"],"correct":3,"re":"When all conductors of a balanced set pass through the clamp together, their magnetic fields cancel, so the meter reads near zero; this principle is the basis of ground-fault detection.","qr":"Токоизмерительные клещи надеты одновременно на все три фазных проводника сбалансированной трёхфазной цепи; что они должны идеально показать?","optsr":["Межфазное напряжение","Сумму всех трёх фазных токов","Ток только одной фазы","Приблизительно ноль, так как сбалансированные токи компенсируются"],"rr":"Когда все проводники сбалансированного набора проходят через клещи вместе, их магнитные поля компенсируются, поэтому прибор показывает почти ноль; на этом основано обнаружение тока утечки.","qs":"Se coloca un amperímetro de pinza alrededor de los tres conductores de fase de un circuito trifásico balanceado al mismo tiempo; ¿qué debería leer idealmente?","optss":["El voltaje de línea a línea","La suma de las tres corrientes de fase","La corriente de una sola fase","Aproximadamente cero, porque las corrientes balanceadas se cancelan"],"rs":"Cuando todos los conductores de un conjunto balanceado pasan juntos a través de la pinza, sus campos magnéticos se cancelan, por lo que el medidor lee casi cero; este principio es la base de la detección de fallas a tierra."},
  {"id":314,"sec":"Finish Wiring & Trim","block":4,"q":"To control a single luminaire from three or more locations, what combination of switches is required?","opts":["Three 3-way switches","Three single-pole switches","Three 4-way switches","Two 3-way switches and one or more 4-way switches"],"correct":3,"re":"Three-or-more-location control uses two 3-way switches at the ends and one or more 4-way switches in between, wired through traveler conductors.","qr":"Чтобы управлять одним светильником из трёх или более мест, какая комбинация выключателей требуется?","optsr":["Три 3-way выключателя","Три однополюсных выключателя","Три 4-way выключателя","Два 3-way выключателя и один или более 4-way выключателей"],"rr":"Управление из трёх или более мест использует два 3-way выключателя по концам и один или более 4-way выключателей между ними, подключённых через транзитные проводники.","qs":"Para controlar una sola luminaria desde tres o más ubicaciones, ¿qué combinación de interruptores se requiere?","optss":["Tres interruptores de 3 vías","Tres interruptores de un polo","Tres interruptores de 4 vías","Dos interruptores de 3 vías y uno o más interruptores de 4 vías"],"rs":"El control desde tres o más ubicaciones usa dos interruptores de 3 vías en los extremos y uno o más interruptores de 4 vías en el medio, cableados mediante conductores viajeros."},
  {"id":315,"sec":"Rough Wiring","block":4,"q":"Type MC (metal-clad) cable installed exposed and run on framing members must be secured at intervals not exceeding what distance?","opts":["3 feet","6 feet","4 feet","8 feet"],"correct":1,"re":"Per NEC 330.30, Type MC cable must be secured at intervals not exceeding 6 ft.","qr":"Кабель типа MC (металлобронированный), установленный открыто и проложенный по элементам каркаса, должен быть закреплён с интервалами, не превышающими какое расстояние?","optsr":["3 фута","6 футов","4 фута","8 футов"],"rr":"Согласно NEC 330.30, кабель типа MC должен быть закреплён с интервалами, не превышающими 6 футов.","qs":"El cable Tipo MC (blindado metálico) instalado expuesto y tendido sobre elementos de estructura debe fijarse a intervalos que no excedan qué distancia?","optss":["3 pies","6 pies","4 pies","8 pies"],"rs":"Según el NEC 330.30, el cable Tipo MC debe fijarse a intervalos que no excedan 6 ft."},
  {"id":316,"sec":"Planning & Estimation","block":4,"q":"When calculating a feeder or service load for a dwelling, fixed appliances such as a water heater and dishwasher are classified under which NEC term?","opts":["Fastened-in-place appliance loads","Continuous loads","Motor loads","General lighting loads"],"correct":0,"re":"NEC 220.53 covers fastened-in-place (fixed) appliances, allowing a 75% demand factor when four or more are present on a dwelling feeder.","qr":"При расчёте нагрузки фидера или ввода для жилья стационарные приборы, такие как водонагреватель и посудомоечная машина, классифицируются под каким термином NEC?","optsr":["Нагрузки стационарно закреплённых приборов","Непрерывные нагрузки","Нагрузки двигателей","Нагрузки общего освещения"],"rr":"NEC 220.53 охватывает стационарно закреплённые (фиксированные) приборы, допуская коэффициент спроса 75% при наличии четырёх или более на фидере жилья.","qs":"Al calcular la carga de un alimentador o acometida para una vivienda, los artefactos fijos como un calentador de agua y un lavavajillas se clasifican bajo cuál término del NEC?","optss":["Cargas de artefactos fijados en su lugar","Cargas continuas","Cargas de motor","Cargas de alumbrado general"],"rs":"El NEC 220.53 cubre los artefactos fijados en su lugar (fijos), permitiendo un factor de demanda del 75% cuando hay cuatro o más en un alimentador de vivienda."},
  {"id":317,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"When verifying transformer connections at startup, why is correct polarity (additive vs subtractive) important when paralleling or banking transformers?","opts":["Incorrect polarity can cause a short circuit or improper voltage when windings are interconnected","It only affects the color of the bushings","It determines the insulation class","It changes the kVA rating"],"correct":0,"re":"Transformer polarity must be verified so that interconnected or paralleled windings add correctly; reversed polarity can create a dead short or wrong output voltage.","qr":"При проверке соединений трансформатора на запуске, почему правильная полярность (суммирующая или вычитающая) важна при параллельном соединении или объединении трансформаторов?","optsr":["Неправильная полярность может вызвать короткое замыкание или неправильное напряжение при соединении обмоток","Она влияет только на цвет изоляторов","Она определяет класс изоляции","Она меняет номинал кВА"],"rr":"Полярность трансформатора необходимо проверять, чтобы соединённые или параллельные обмотки складывались правильно; обратная полярность может создать короткое замыкание или неправильное выходное напряжение.","qs":"Al verificar las conexiones de un transformador en el arranque, ¿por qué es importante la polaridad correcta (aditiva vs sustractiva) al poner en paralelo o en banco los transformadores?","optss":["Una polaridad incorrecta puede causar un cortocircuito o un voltaje inadecuado cuando los devanados se interconectan","Solo afecta el color de los bujes","Determina la clase de aislamiento","Cambia la capacidad en kVA"],"rs":"La polaridad del transformador debe verificarse para que los devanados interconectados o en paralelo se sumen correctamente; una polaridad invertida puede crear un cortocircuito directo o un voltaje de salida incorrecto."},
  {"id":318,"sec":"Safety","block":4,"q":"On a construction site, a 30-ampere, 125-volt single-phase receptacle that is not part of the permanent wiring and is used by employees must have what protection under OSHA 1926.404?","opts":["No special protection is required","Only a locking-type cover","Only a surge protector","GFCI protection or coverage under an assured equipment grounding conductor program"],"correct":3,"re":"OSHA extends the GFCI requirement to 15-, 20-, and 30-A single-phase 125-V receptacles not part of permanent wiring, with the assured grounding program as the alternative.","qr":"На стройплощадке розетка 30 А, 125 В, однофазная, не входящая в постоянную проводку и используемая работниками, должна иметь какую защиту согласно OSHA 1926.404?","optsr":["Никакой особой защиты не требуется","Только крышку с фиксацией","Только сетевой фильтр от перенапряжений","Защиту GFCI или охват программой обеспечения заземляющего проводника"],"rr":"OSHA распространяет требование GFCI на однофазные розетки 125 В на 15, 20 и 30 А, не входящие в постоянную проводку, с программой обеспечения заземления в качестве альтернативы.","qs":"En una obra de construcción, un receptáculo monofásico de 30 amperios y 125 voltios que no forma parte del cableado permanente y es usado por empleados debe contar con qué protección según OSHA 1926.404?","optss":["No se requiere protección especial","Solo una cubierta tipo seguro","Solo un protector contra sobretensiones","Protección GFCI o cobertura bajo un programa de conductor de puesta a tierra de equipos asegurado"],"rs":"OSHA extiende el requisito de GFCI a los receptáculos monofásicos de 125 V de 15, 20 y 30 A que no forman parte del cableado permanente, con el programa de puesta a tierra asegurado como alternativa."},
  {"id":319,"sec":"Rough Wiring","block":4,"q":"Which statement best describes the permitted use of intermediate metal conduit (IMC)?","opts":["It is permitted only in dry indoor locations","It is permitted only underground","It may never be threaded","It may be used in all the same atmospheric conditions and occupancies as RMC"],"correct":3,"re":"Per NEC Article 342, IMC is a lighter-wall steel raceway permitted in all the same locations and conditions as rigid metal conduit (RMC).","qr":"Какое утверждение лучше всего описывает разрешённое использование промежуточного металлического кабелепровода (IMC)?","optsr":["Он разрешён только в сухих внутренних помещениях","Он разрешён только под землёй","Он никогда не может иметь резьбу","Он может использоваться во всех тех же атмосферных условиях и помещениях, что и RMC"],"rr":"Согласно NEC Статья 342, IMC является стальным raceway с более тонкой стенкой, разрешённым во всех тех же местах и условиях, что и жёсткий металлический кабелепровод (RMC).","qs":"¿Cuál enunciado describe mejor el uso permitido del conduit metálico intermedio (IMC)?","optss":["Solo se permite en lugares interiores secos","Solo se permite bajo tierra","Nunca puede roscarse","Puede usarse en todas las mismas condiciones atmosféricas y ocupaciones que el RMC"],"rs":"Según el Artículo 342 del NEC, el IMC es una canalización de acero de pared más delgada permitida en todas las mismas ubicaciones y condiciones que el conduit metálico rígido (RMC)."},
  {"id":320,"sec":"Planning & Estimation","block":4,"q":"Per NEC 220.53, when four or more fastened-in-place appliances are on the same dwelling feeder, what demand factor may be applied to their total nameplate load?","opts":["50%","75%","65%","100%"],"correct":1,"re":"NEC 220.53 permits a 75% demand factor for four or more fastened-in-place appliances (excluding ranges, dryers, space heating, and air conditioning).","qr":"Согласно NEC 220.53, когда четыре или более стационарно закреплённых прибора находятся на одном фидере жилья, какой коэффициент спроса можно применить к их суммарной паспортной нагрузке?","optsr":["50%","75%","65%","100%"],"rr":"NEC 220.53 разрешает коэффициент спроса 75% для четырёх или более стационарно закреплённых приборов (исключая плиты, сушилки, отопление и кондиционирование).","qs":"Según el NEC 220.53, cuando hay cuatro o más artefactos fijados en su lugar en el mismo alimentador de vivienda, ¿qué factor de demanda puede aplicarse a su carga total de placa?","optss":["50%","75%","65%","100%"],"rs":"El NEC 220.53 permite un factor de demanda del 75% para cuatro o más artefactos fijados en su lugar (excluyendo estufas, secadoras, calefacción de espacios y aire acondicionado)."},
  {"id":321,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"During commissioning, a megger insulation-resistance reading is taken immediately and again after one minute to compute which useful diagnostic value?","opts":["Turns ratio","Phase rotation","Polarization index (PI)","Ground-electrode resistance"],"correct":2,"re":"The polarization index is the ratio of the 10-minute (or 1-minute) reading to the earlier reading, indicating insulation condition; a higher ratio generally indicates better, drier insulation.","qr":"При наладке показание сопротивления изоляции мегомметром снимается сразу и снова через одну минуту для вычисления какого полезного диагностического значения?","optsr":["Коэффициента трансформации","Чередования фаз","Индекса поляризации (PI)","Сопротивления заземляющего электрода"],"rr":"Индекс поляризации — это отношение показания через 10 минут (или 1 минуту) к более раннему, указывающее на состояние изоляции; более высокое отношение обычно означает лучшую, более сухую изоляцию.","qs":"Durante la puesta en servicio, se toma una lectura de resistencia de aislamiento con megger de inmediato y nuevamente después de un minuto para calcular cuál valor diagnóstico útil?","optss":["Relación de vueltas","Rotación de fases","Índice de polarización (PI)","Resistencia del electrodo de tierra"],"rs":"El índice de polarización es la relación entre la lectura de los 10 minutos (o 1 minuto) y la lectura anterior, indicando la condición del aislamiento; una relación más alta generalmente indica un aislamiento mejor y más seco."},
  {"id":322,"sec":"Safety","block":4,"q":"Before beginning CPR on an electric-shock victim, the single most important condition that must be satisfied is which of the following?","opts":["The victim's burns have been bandaged","The circuit breaker has been replaced with a new one","The victim has been given fluids","The victim is no longer in contact with any energized source"],"correct":3,"re":"CPR must not begin until the victim is completely clear of the energized source; otherwise the rescuer risks being shocked as well.","qr":"Перед началом СЛР для пострадавшего от удара током единственное наиболее важное условие, которое должно быть выполнено, какое из следующих?","optsr":["Ожоги пострадавшего перевязаны","Автоматический выключатель заменён на новый","Пострадавшему дали жидкости","Пострадавший больше не контактирует ни с каким источником под напряжением"],"rr":"СЛР нельзя начинать, пока пострадавший полностью не освобождён от источника под напряжением; иначе спасатель рискует также получить удар током.","qs":"Antes de comenzar la RCP en una víctima de descarga eléctrica, ¿cuál de las siguientes es la condición más importante que debe cumplirse?","optss":["Las quemaduras de la víctima han sido vendadas","El disyuntor ha sido reemplazado por uno nuevo","Se le han administrado líquidos a la víctima","La víctima ya no está en contacto con ninguna fuente energizada"],"rs":"La RCP no debe comenzar hasta que la víctima esté completamente libre de la fuente energizada; de lo contrario, el rescatista corre el riesgo de recibir también una descarga."},
  {"id":323,"sec":"Rough Wiring","block":4,"q":"When determining the minimum size of a box containing several conductors of different sizes, what is the correct total volume requirement?","opts":["The volume of the largest conductor times the number of conductors","The sum of the individual volume allowances for each conductor and component","Always a minimum of 18 cubic inches","The volume of the smallest conductor only"],"correct":1,"re":"Per NEC 314.16(B), the total box-fill is the sum of the individual volume allowances for all conductors, devices, clamps, and grounding conductors.","qr":"При определении минимального размера коробки, содержащей несколько проводников разного сечения, каково правильное требование к общему объёму?","optsr":["Объём самого большого проводника, умноженный на количество проводников","Сумма индивидуальных объёмов для каждого проводника и компонента","Всегда минимум 18 кубических дюймов","Объём только самого маленького проводника"],"rr":"Согласно NEC 314.16(B), общее заполнение коробки представляет собой сумму индивидуальных объёмов для всех проводников, устройств, зажимов и заземляющих проводников.","qs":"Al determinar el tamaño mínimo de una caja que contiene varios conductores de diferentes tamaños, ¿cuál es el requisito de volumen total correcto?","optss":["El volumen del conductor más grande multiplicado por el número de conductores","La suma de las asignaciones de volumen individuales para cada conductor y componente","Siempre un mínimo de 18 pulgadas cúbicas","El volumen del conductor más pequeño únicamente"],"rs":"Según el NEC 314.16(B), el llenado total de la caja es la suma de las asignaciones de volumen individuales para todos los conductores, dispositivos, abrazaderas y conductores de puesta a tierra."},
  {"id":324,"sec":"Finish Wiring & Trim","block":4,"q":"A 3-way switch has how many terminals not counting the grounding screw?","opts":["Two","Three","Four","Five"],"correct":1,"re":"A 3-way switch has three current-carrying terminals: one common (often darker) terminal and two traveler terminals.","qr":"Сколько клемм имеет 3-way выключатель, не считая винта заземления?","optsr":["Две","Три","Четыре","Пять"],"rr":"3-way выключатель имеет три токоведущих клеммы: одну общую (часто более тёмную) клемму и две транзитные (traveler) клеммы.","qs":"¿Cuántas terminales tiene un interruptor de 3 vías sin contar el tornillo de puesta a tierra?","optss":["Dos","Tres","Cuatro","Cinco"],"rs":"Un interruptor de 3 vías tiene tres terminales que conducen corriente: una terminal común (a menudo más oscura) y dos terminales viajeras."},
  {"id":325,"sec":"Planning & Estimation","block":4,"q":"Using NEC 220.12, the minimum number of 15 A, 120 V general lighting branch circuits required for 6,000 VA of dwelling lighting load is:","opts":["4 circuits","2 circuits","5 circuits","8 circuits"],"correct":0,"re":"Each 15 A, 120 V circuit carries 1,800 VA; 6,000 ÷ 1,800 = 3.33, rounded up to 4 circuits.","qr":"Используя NEC 220.12, минимальное количество цепей общего освещения 15 А, 120 В, требуемое для нагрузки освещения жилья 6 000 ВА, составляет:","optsr":["4 цепи","2 цепи","5 цепей","8 цепей"],"rr":"Каждая цепь 15 А, 120 В несёт 1 800 ВА; 6 000 ÷ 1 800 = 3.33, округляется вверх до 4 цепей.","qs":"Usando el NEC 220.12, el número mínimo de circuitos ramales de alumbrado general de 15 A, 120 V requeridos para 6,000 VA de carga de alumbrado de vivienda es:","optss":["4 circuitos","2 circuitos","5 circuitos","8 circuitos"],"rs":"Cada circuito de 15 A, 120 V soporta 1,800 VA; 6,000 ÷ 1,800 = 3.33, redondeado hacia arriba a 4 circuitos."},
  {"id":326,"sec":"Rough Wiring","block":4,"q":"Liquidtight flexible nonmetallic conduit (LFNC) and liquidtight flexible metal conduit (LFMC) require listed fittings primarily to maintain which characteristic of the installation?","opts":["The liquidtight integrity at terminations","Maximum bend radius","Color coding","Grounding continuity only"],"correct":0,"re":"Per NEC 350.42 and 356.42, only fittings listed and identified for the conduit may be used to preserve the liquidtight seal at connections.","qr":"Жидконепроницаемый гибкий неметаллический кабелепровод (LFNC) и жидконепроницаемый гибкий металлический кабелепровод (LFMC) требуют сертифицированных фитингов в первую очередь для поддержания какой характеристики установки?","optsr":["Жидконепроницаемой целостности в местах окончаний","Максимального радиуса изгиба","Цветовой маркировки","Только непрерывности заземления"],"rr":"Согласно NEC 350.42 и 356.42, только фитинги, сертифицированные и предназначенные для данного кабелепровода, могут использоваться для сохранения жидконепроницаемого уплотнения в соединениях.","qs":"El conduit no metálico flexible hermético a líquidos (LFNC) y el conduit metálico flexible hermético a líquidos (LFMC) requieren accesorios listados principalmente para mantener cuál característica de la instalación?","optss":["La integridad hermética a líquidos en las terminaciones","El radio máximo de doblez","La codificación por colores","Solo la continuidad de puesta a tierra"],"rs":"Según el NEC 350.42 y 356.42, solo pueden usarse accesorios listados e identificados para el conduit a fin de preservar el sello hermético a líquidos en las conexiones."},
  {"id":327,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"What is the correct first step to reverse the rotation of a running three-phase motor found to be turning the wrong way at startup?","opts":["De-energize and swap any two of the three line conductors","Increase the supply voltage","Add a buck-boost transformer","Reverse only the equipment grounding conductor"],"correct":0,"re":"Three-phase motor rotation is reversed by de-energizing the circuit and interchanging any two of the three line (phase) conductors at the motor terminals.","qr":"Каков правильный первый шаг для изменения направления вращения работающего трёхфазного двигателя, который при запуске вращается не в ту сторону?","optsr":["Обесточить и поменять местами любые два из трёх линейных проводников","Повысить напряжение питания","Добавить трансформатор buck-boost","Поменять только защитный проводник заземления"],"rr":"Направление вращения трёхфазного двигателя меняется обесточиванием цепи и перестановкой любых двух из трёх линейных (фазных) проводников на клеммах двигателя.","qs":"¿Cuál es el primer paso correcto para invertir la rotación de un motor trifásico en marcha que se encuentra girando en el sentido incorrecto en el arranque?","optss":["Desenergizar e intercambiar dos cualesquiera de los tres conductores de línea","Aumentar el voltaje de suministro","Agregar un transformador buck-boost","Invertir solamente el conductor de puesta a tierra de equipos"],"rs":"La rotación de un motor trifásico se invierte desenergizando el circuito e intercambiando dos cualesquiera de los tres conductores de línea (fase) en las terminales del motor."},
  {"id":328,"sec":"Safety","block":4,"q":"Why is human skin resistance an important factor in electrical shock severity, and how does moisture affect it?","opts":["Moisture increases skin resistance, reducing current flow","Dry skin always allows more current than wet skin","Moisture has no effect on skin resistance","Moisture lowers skin resistance, allowing more current to flow and increasing danger"],"correct":3,"re":"Wet or sweaty skin has much lower resistance than dry skin, so for the same voltage more current flows through the body, making the shock more dangerous.","qr":"Почему сопротивление кожи человека является важным фактором тяжести поражения током и как влага влияет на него?","optsr":["Влага повышает сопротивление кожи, снижая протекание тока","Сухая кожа всегда пропускает больше тока, чем мокрая","Влага не влияет на сопротивление кожи","Влага понижает сопротивление кожи, позволяя протекать большему току и увеличивая опасность"],"rr":"Мокрая или потная кожа имеет гораздо меньшее сопротивление, чем сухая, поэтому при том же напряжении через тело протекает больше тока, делая поражение более опасным.","qs":"¿Por qué la resistencia de la piel humana es un factor importante en la severidad de la descarga eléctrica, y cómo afecta la humedad?","optss":["La humedad aumenta la resistencia de la piel, reduciendo el flujo de corriente","La piel seca siempre permite más corriente que la piel mojada","La humedad no tiene efecto sobre la resistencia de la piel","La humedad reduce la resistencia de la piel, permitiendo que fluya más corriente y aumentando el peligro"],"rs":"La piel mojada o sudorosa tiene una resistencia mucho menor que la piel seca, por lo que para el mismo voltaje fluye más corriente a través del cuerpo, haciendo la descarga más peligrosa."},
  {"id":329,"sec":"Planning & Estimation","block":4,"q":"In the standard dwelling calculation, the range and dryer demand loads are added to the lighting/appliance demand at what percentage of their NEC-calculated demand values?","opts":["35%","100%","75%","40%"],"correct":1,"re":"After applying Tables 220.55 and 220.54 demand factors, the range and dryer demand values are added at 100% to the service/feeder calculation.","qr":"В стандартном расчёте жилья нагрузки спроса плиты и сушилки добавляются к спросу освещения/приборов по какому проценту их расчётных по NEC значений спроса?","optsr":["35%","100%","75%","40%"],"rr":"После применения коэффициентов спроса таблиц 220.55 и 220.54 значения спроса плиты и сушилки добавляются на 100% к расчёту ввода/фидера.","qs":"En el cálculo estándar de vivienda, las cargas de demanda de la estufa y la secadora se suman a la demanda de alumbrado/artefactos en qué porcentaje de sus valores de demanda calculados según el NEC?","optss":["35%","100%","75%","40%"],"rs":"Después de aplicar los factores de demanda de las Tablas 220.55 y 220.54, los valores de demanda de la estufa y la secadora se suman al 100% al cálculo de acometida/alimentador."},
  {"id":330,"sec":"Rough Wiring","block":4,"q":"A run of EMT contains three 90-degree bends and one 45-degree bend between two pull boxes; what is the total bend in degrees, and is it acceptable?","opts":["315 degrees, acceptable","315 degrees, not acceptable","405 degrees, not acceptable","270 degrees, acceptable"],"correct":0,"re":"Three 90-degree bends (270) plus one 45-degree bend equals 315 degrees, which is within the 360-degree maximum permitted between pull points per NEC 358.26.","qr":"Участок EMT содержит три изгиба по 90 градусов и один изгиб 45 градусов между двумя протяжными коробками; каков суммарный изгиб в градусах и допустим ли он?","optsr":["315 градусов, допустимо","315 градусов, недопустимо","405 градусов, недопустимо","270 градусов, допустимо"],"rr":"Три изгиба по 90 градусов (270) плюс один изгиб 45 градусов равны 315 градусам, что находится в пределах максимально допустимых 360 градусов между точками протяжки согласно NEC 358.26.","qs":"Un tramo de EMT contiene tres dobleces de 90 grados y un doblez de 45 grados entre dos cajas de jalado; ¿cuál es el total de dobleces en grados, y es aceptable?","optss":["315 grados, aceptable","315 grados, no aceptable","405 grados, no aceptable","270 grados, aceptable"],"rs":"Tres dobleces de 90 grados (270) más un doblez de 45 grados equivalen a 315 grados, lo cual está dentro del máximo de 360 grados permitido entre puntos de jalado según el NEC 358.26."},
  {"id":331,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A lower ground-electrode resistance value is generally considered better; which condition tends to reduce the measured resistance of a ground rod?","opts":["Moist soil and a longer or multiple bonded electrodes","Dry, sandy, high-resistivity soil","A loose, corroded ground clamp","A shorter rod driven only a few inches deep"],"correct":0,"re":"Moist soil and increased electrode surface area, such as a longer rod or multiple bonded rods, lower the contact resistance to earth and improve the grounding system.","qr":"Меньшее значение сопротивления заземляющего электрода обычно считается лучше; какое условие способствует снижению измеренного сопротивления заземляющего стержня?","optsr":["Влажная почва и более длинный или несколько соединённых электродов","Сухая песчаная почва с высоким удельным сопротивлением","Слабый коррозированный заземляющий зажим","Короткий стержень, забитый всего на несколько дюймов"],"rr":"Влажная почва и увеличенная площадь поверхности электрода, например более длинный стержень или несколько соединённых стержней, снижают переходное сопротивление к земле и улучшают систему заземления.","qs":"Un valor de resistencia del electrodo de tierra más bajo generalmente se considera mejor; ¿cuál condición tiende a reducir la resistencia medida de una varilla de tierra?","optss":["Suelo húmedo y un electrodo más largo o varios electrodos unidos","Suelo seco, arenoso y de alta resistividad","Una abrazadera de tierra floja y corroída","Una varilla más corta clavada solo unas pocas pulgadas de profundidad"],"rs":"El suelo húmedo y el aumento del área superficial del electrodo, como una varilla más larga o varias varillas unidas, reducen la resistencia de contacto con la tierra y mejoran el sistema de puesta a tierra."},
  {"id":332,"sec":"Safety","block":4,"q":"When a portable power tool is dropped into water while still plugged in, what is the correct first response?","opts":["Reach into the water and pull the tool out by its cord","De-energize the circuit at the breaker or unplug it without contacting the water, then retrieve the tool","Continue using the tool once it dries","Pour more water on it to rinse it"],"correct":1,"re":"The energized tool can make the water hazardous; first remove power safely without touching the water, then retrieve and inspect the tool before any further use.","qr":"Когда портативный электроинструмент падает в воду, оставаясь подключённым к сети, какова правильная первая реакция?","optsr":["Залезть в воду и вытащить инструмент за шнур","Обесточить цепь на автомате или отключить от сети, не касаясь воды, затем достать инструмент","Продолжить использовать инструмент после высыхания","Налить ещё воды, чтобы промыть его"],"rr":"Инструмент под напряжением может сделать воду опасной; сначала безопасно снимите питание, не касаясь воды, затем достаньте и осмотрите инструмент перед дальнейшим использованием.","qs":"Cuando una herramienta eléctrica portátil cae al agua mientras aún está conectada, ¿cuál es la primera respuesta correcta?","optss":["Meter la mano al agua y sacar la herramienta tirando de su cable","Desenergizar el circuito en el disyuntor o desconectarla sin tocar el agua, y luego recuperar la herramienta","Seguir usando la herramienta una vez que se seque","Verter más agua sobre ella para enjuagarla"],"rs":"La herramienta energizada puede volver peligrosa el agua; primero retire la energía de forma segura sin tocar el agua, luego recupere e inspeccione la herramienta antes de cualquier uso posterior."},
  {"id":333,"sec":"Finish Wiring & Trim","block":4,"q":"A 4-way switch has how many current-carrying terminals not counting the grounding screw?","opts":["Two","Four","Three","Six"],"correct":1,"re":"A 4-way switch has four terminals, arranged as two pairs of travelers, and is installed between two 3-way switches.","qr":"Сколько токоведущих клемм имеет 4-way выключатель, не считая винта заземления?","optsr":["Две","Четыре","Три","Шесть"],"rr":"4-way выключатель имеет четыре клеммы, расположенные как две пары транзитных проводников, и устанавливается между двумя 3-way выключателями.","qs":"¿Cuántas terminales que conducen corriente tiene un interruptor de 4 vías sin contar el tornillo de puesta a tierra?","optss":["Dos","Cuatro","Tres","Seis"],"rs":"Un interruptor de 4 vías tiene cuatro terminales, dispuestas como dos pares de viajeros, y se instala entre dos interruptores de 3 vías."},
  {"id":334,"sec":"Planning & Estimation","block":4,"q":"A three-phase, 208 V panel supplies a balanced load of 36 kVA; what is the approximate line current on each phase?","opts":["173 A","100 A","115 A","60 A"],"correct":1,"re":"IL = kVA × 1000 ÷ (√3 × VL) = 36,000 ÷ (1.732 × 208) = 36,000 ÷ 360.3 = 100 A.","qr":"Трёхфазная панель 208 В питает сбалансированную нагрузку 36 кВА; каков примерный линейный ток на каждой фазе?","optsr":["173 А","100 А","115 А","60 А"],"rr":"IL = кВА × 1000 ÷ (√3 × VL) = 36 000 ÷ (1.732 × 208) = 36 000 ÷ 360.3 = 100 А.","qs":"Un tablero trifásico de 208 V alimenta una carga balanceada de 36 kVA; ¿cuál es la corriente de línea aproximada en cada fase?","optss":["173 A","100 A","115 A","60 A"],"rs":"IL = kVA × 1000 ÷ (√3 × VL) = 36,000 ÷ (1.732 × 208) = 36,000 ÷ 360.3 = 100 A."},
  {"id":335,"sec":"Rough Wiring","block":4,"q":"Where a cable is installed in a notch cut into the face of a wood stud, what is required to protect the cable from screws and nails?","opts":["Nothing, a notch is always acceptable","Filling the notch with caulk","Painting the cable a bright color","A steel plate at least 1/16 inch thick installed across the face of the notch"],"correct":3,"re":"Per NEC 300.4(A)(2), cables installed in notches in wood must be protected by a steel plate at least 1/16 in. thick across the face of the notch.","qr":"Когда кабель проложен в пазу, вырезанном в лицевой стороне деревянной стойки, что требуется для защиты кабеля от шурупов и гвоздей?","optsr":["Ничего, паз всегда допустим","Заполнение паза герметиком","Окрашивание кабеля в яркий цвет","Стальная пластина толщиной не менее 1/16 дюйма, установленная по лицевой стороне паза"],"rr":"Согласно NEC 300.4(A)(2), кабели, проложенные в пазах в дереве, должны быть защищены стальной пластиной толщиной не менее 1/16 дюйма по лицевой стороне паза.","qs":"Donde un cable se instala en una muesca cortada en la cara de un montante de madera, ¿qué se requiere para proteger el cable de tornillos y clavos?","optss":["Nada, una muesca siempre es aceptable","Rellenar la muesca con sellador","Pintar el cable de un color brillante","Una placa de acero de al menos 1/16 de pulgada de espesor instalada a lo ancho de la cara de la muesca"],"rs":"Según el NEC 300.4(A)(2), los cables instalados en muescas en madera deben protegerse con una placa de acero de al menos 1/16 in de espesor a lo ancho de la cara de la muesca."},
  {"id":336,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"Which sequence best describes proper commissioning order before placing a new feeder into service?","opts":["Energize first, then check torque and grounding","Verify terminations torque and grounding/bonding, perform insulation-resistance testing, then energize and measure voltages","Measure phase rotation only after full load is applied","Apply load, then verify the equipment grounding conductor"],"correct":1,"re":"Proper commissioning is done de-energized first: verify torque and grounding/bonding, perform insulation-resistance tests, and only then energize to measure operating voltages.","qr":"Какая последовательность лучше всего описывает правильный порядок наладки перед вводом нового фидера в эксплуатацию?","optsr":["Сначала подать напряжение, затем проверить момент и заземление","Проверить момент соединений и заземление, выполнить проверку сопротивления изоляции, затем подать напряжение и измерить напряжения","Измерить чередование фаз только после приложения полной нагрузки","Приложить нагрузку, затем проверить защитный проводник заземления"],"rr":"Правильная наладка выполняется сначала на обесточенной системе: проверить момент и заземление, выполнить проверку сопротивления изоляции, и только затем подать напряжение для измерения рабочих напряжений.","qs":"¿Cuál secuencia describe mejor el orden correcto de puesta en servicio antes de poner en operación un nuevo alimentador?","optss":["Energizar primero, luego verificar el torque y la puesta a tierra","Verificar el torque de las terminaciones y la puesta a tierra/unión, realizar pruebas de resistencia de aislamiento, y luego energizar y medir voltajes","Medir la rotación de fases solo después de aplicar plena carga","Aplicar carga, luego verificar el conductor de puesta a tierra de equipos"],"rs":"La puesta en servicio correcta se realiza primero desenergizado: verificar el torque y la puesta a tierra/unión, realizar pruebas de resistencia de aislamiento, y solo entonces energizar para medir los voltajes de operación."},
  {"id":337,"sec":"Safety","block":4,"q":"What is the chief safety advantage of a double-insulated portable tool when the equipment grounding conductor of the supply might be unreliable?","opts":["It can be used on any voltage without limit","Its two independent insulation layers protect the user even without a grounding conductor","It never requires maintenance","It automatically increases its own current rating"],"correct":1,"re":"Double insulation provides a second, independent barrier between live parts and the user, giving shock protection that does not depend on an external grounding conductor.","qr":"В чём главное преимущество безопасности портативного инструмента двойной изоляции, когда заземляющий проводник источника питания может быть ненадёжным?","optsr":["Его можно использовать при любом напряжении без ограничений","Его два независимых слоя изоляции защищают пользователя даже без заземляющего проводника","Он никогда не требует обслуживания","Он автоматически повышает свой номинальный ток"],"rr":"Двойная изоляция обеспечивает второй независимый барьер между токоведущими частями и пользователем, давая защиту от поражения током, которая не зависит от внешнего заземляющего проводника.","qs":"¿Cuál es la principal ventaja de seguridad de una herramienta portátil con doble aislamiento cuando el conductor de puesta a tierra de equipos del suministro podría no ser confiable?","optss":["Puede usarse en cualquier voltaje sin límite","Sus dos capas de aislamiento independientes protegen al usuario incluso sin un conductor de puesta a tierra","Nunca requiere mantenimiento","Aumenta automáticamente su propia capacidad de corriente"],"rs":"El doble aislamiento proporciona una segunda barrera independiente entre las partes vivas y el usuario, brindando protección contra descargas que no depende de un conductor de puesta a tierra externo."},
  {"id":338,"sec":"Planning & Estimation","block":4,"q":"A dwelling's net calculated load is 27,600 VA on a 240 V single-phase service; what is the required minimum service rating from standard sizes?","opts":["100 A","150 A","125 A","200 A"],"correct":2,"re":"27,600 ÷ 240 = 115 A; the next standard service/overcurrent size up is 125 A.","qr":"Чистая расчётная нагрузка жилья составляет 27 600 ВА на однофазном вводе 240 В; каков требуемый минимальный номинал ввода из стандартных размеров?","optsr":["100 А","150 А","125 А","200 А"],"rr":"27 600 ÷ 240 = 115 А; следующий стандартный размер ввода/защиты — 125 А.","qs":"La carga neta calculada de una vivienda es de 27,600 VA en una acometida monofásica de 240 V; ¿cuál es la capacidad mínima de acometida requerida de entre los tamaños estándar?","optss":["100 A","150 A","125 A","200 A"],"rs":"27,600 ÷ 240 = 115 A; el siguiente tamaño estándar de acometida/sobrecorriente hacia arriba es 125 A."},
  {"id":339,"sec":"Rough Wiring","block":4,"q":"What is the maximum support spacing generally required for electrical metallic tubing (EMT) along an exposed straight run?","opts":["6 feet","8 feet","12 feet","10 feet"],"correct":3,"re":"Per NEC 358.30(A), EMT must be supported at intervals not exceeding 10 ft along the run.","qr":"Какое максимальное расстояние между опорами обычно требуется для электрической металлической трубки (EMT) вдоль открытого прямого участка?","optsr":["6 футов","8 футов","12 футов","10 футов"],"rr":"Согласно NEC 358.30(A), EMT должна поддерживаться с интервалами, не превышающими 10 футов вдоль участка.","qs":"¿Cuál es el espaciamiento máximo de soporte generalmente requerido para el tubo metálico eléctrico (EMT) a lo largo de un tramo recto expuesto?","optss":["6 pies","8 pies","12 pies","10 pies"],"rs":"Según el NEC 358.30(A), el EMT debe soportarse a intervalos que no excedan 10 ft a lo largo del tramo."},
  {"id":340,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"When testing a de-energized branch circuit with an ohmmeter, a reading of infinite (OL) resistance between the two ends of a single conductor indicates which condition?","opts":["An open circuit","A short circuit","A ground fault","Normal continuity"],"correct":0,"re":"Infinite resistance through one conductor means current cannot pass, which is the definition of an open. Good continuity would read near zero ohms.","qr":"При проверке обесточенной ответвлённой цепи омметром показание бесконечного (OL) сопротивления между двумя концами одного проводника указывает на какое состояние?","optsr":["Обрыв цепи","Короткое замыкание","Замыкание на землю","Нормальная целостность"],"rr":"Бесконечное сопротивление по одному проводнику означает, что ток не проходит, что и является определением обрыва. Хорошая целостность дала бы показание около нуля ом.","qs":"Al probar un circuito ramal desenergizado con un ohmímetro, una lectura de resistencia infinita (OL) entre los dos extremos de un solo conductor indica cuál condición?","optss":["Un circuito abierto","Un cortocircuito","Una falla a tierra","Continuidad normal"],"rs":"Una resistencia infinita a través de un conductor significa que la corriente no puede pasar, lo cual es la definición de un circuito abierto. Una buena continuidad leería cerca de cero ohmios."},
  {"id":341,"sec":"Finish Wiring & Trim","block":4,"q":"On a 3-way switch, the single terminal that connects to either the line or the load is commonly called the what?","opts":["Common terminal","Grounding terminal","Traveler terminal","Neutral terminal"],"correct":0,"re":"The common terminal of a 3-way switch (usually a dark or black-colored screw) connects to the line (source) at one switch and to the load at the other.","qr":"На 3-way выключателе одиночная клемма, которая соединяется либо с линией, либо с нагрузкой, обычно называется как?","optsr":["Общая клемма","Клемма заземления","Транзитная клемма","Нейтральная клемма"],"rr":"Общая клемма 3-way выключателя (обычно тёмный или чёрный винт) соединяется с линией (источником) на одном выключателе и с нагрузкой на другом.","qs":"En un interruptor de 3 vías, la terminal única que se conecta ya sea a la línea o a la carga se denomina comúnmente ¿qué?","optss":["Terminal común","Terminal de puesta a tierra","Terminal viajera","Terminal neutra"],"rs":"La terminal común de un interruptor de 3 vías (usualmente un tornillo de color oscuro o negro) se conecta a la línea (fuente) en un interruptor y a la carga en el otro."},
  {"id":342,"sec":"Rough Wiring","block":4,"q":"What is the minimum length of a single ground rod that must be in contact with the soil to serve as a grounding electrode?","opts":["6 ft","10 ft","8 ft","4 ft"],"correct":2,"re":"NEC 250.52(A)(5) requires a rod electrode to be at least 8 ft in length in contact with the soil.","qr":"Какова минимальная длина одиночного заземляющего стержня, который должен находиться в контакте с грунтом, чтобы служить заземляющим электродом?","optsr":["6 футов","10 футов","8 футов","4 фута"],"rr":"NEC 250.52(A)(5) требует, чтобы стержневой электрод имел длину не менее 8 футов в контакте с грунтом.","qs":"¿Cuál es la longitud mínima de una sola varilla de tierra que debe estar en contacto con el suelo para servir como electrodo de puesta a tierra?","optss":["6 ft","10 ft","8 ft","4 ft"],"rs":"El NEC 250.52(A)(5) exige que un electrodo de varilla tenga al menos 8 ft de longitud en contacto con el suelo."},
  {"id":343,"sec":"Planning & Estimation","block":4,"q":"Two 12 kW household ranges on the same feeder have a Table 220.55 Column C demand of 11 kW; this demonstrates that the demand factor for ranges:","opts":["Increases the calculated load above nameplate","Reduces the combined load below the sum of nameplate ratings","Has no effect on multiple ranges","Applies only to commercial kitchens"],"correct":1,"re":"Two 12 kW ranges total 24 kW nameplate, but Table 220.55 Column C allows only 11 kW, showing the demand factor reduces the load below the connected total.","qr":"Две бытовые плиты по 12 кВт на одном фидере имеют спрос по таблице 220.55, столбец C, равный 11 кВт; это показывает, что коэффициент спроса для плит:","optsr":["Увеличивает расчётную нагрузку выше паспортной","Уменьшает суммарную нагрузку ниже суммы паспортных значений","Не влияет на несколько плит","Применяется только к коммерческим кухням"],"rr":"Две плиты по 12 кВт дают 24 кВт паспортной мощности, но таблица 220.55, столбец C, допускает только 11 кВт, показывая, что коэффициент спроса снижает нагрузку ниже подключённой суммы.","qs":"Dos estufas domésticas de 12 kW en el mismo alimentador tienen una demanda de 11 kW según la Columna C de la Tabla 220.55; esto demuestra que el factor de demanda para estufas:","optss":["Aumenta la carga calculada por encima de la placa","Reduce la carga combinada por debajo de la suma de los valores de placa","No tiene efecto sobre múltiples estufas","Aplica solo a cocinas comerciales"],"rs":"Dos estufas de 12 kW suman 24 kW de placa, pero la Columna C de la Tabla 220.55 permite solo 11 kW, mostrando que el factor de demanda reduce la carga por debajo del total conectado."},
  {"id":344,"sec":"Safety","block":4,"q":"Per NEC 110.26(A)(1), what is the minimum depth of working space required in front of electrical equipment operating at 0-150 volts to ground where there are exposed live parts on one side and no live or grounded parts on the other side?","opts":["2 feet","3 feet","3.5 feet","4 feet"],"correct":1,"re":"NEC 110.26(A)(1) Condition 1 requires a minimum working clearance depth of 3 feet for equipment at 0-150 V to ground.","qr":"Согласно NEC 110.26(A)(1), какова минимальная глубина рабочего пространства перед электрооборудованием с напряжением 0-150 вольт относительно земли, если открытые токоведущие части находятся с одной стороны, а с другой стороны нет токоведущих или заземлённых частей?","optsr":["2 фута","3 фута","3,5 фута","4 фута"],"rr":"NEC 110.26(A)(1) Условие 1 требует минимальной глубины рабочего пространства 3 фута для оборудования с напряжением 0-150 В относительно земли.","qs":"Según el NEC 110.26(A)(1), ¿cuál es la profundidad mínima del espacio de trabajo requerida frente a equipo eléctrico que opera a 0-150 voltios a tierra, donde hay partes vivas expuestas en un lado y no hay partes vivas ni puestas a tierra en el otro lado?","optss":["2 pies","3 pies","3.5 pies","4 pies"],"rs":"El NEC 110.26(A)(1) Condición 1 exige una profundidad mínima de espacio de trabajo de 3 pies para equipo a 0-150 V a tierra."},
  {"id":345,"sec":"Rough Wiring","block":4,"q":"A single rod electrode that does not have a resistance to earth of 25 ohms or less must be supplemented by at least how many additional electrodes?","opts":["Two additional electrodes","One additional electrode","Three additional electrodes","No additional electrode is required"],"correct":1,"re":"NEC 250.53(A)(2) requires a single rod electrode exceeding 25 ohms to be supplemented by one additional electrode.","qr":"Одиночный стержневой электрод, не имеющий сопротивления заземления 25 Ом или менее, должен быть дополнен как минимум сколькими дополнительными электродами?","optsr":["Двумя дополнительными электродами","Одним дополнительным электродом","Тремя дополнительными электродами","Дополнительный электрод не требуется"],"rr":"NEC 250.53(A)(2) требует, чтобы одиночный стержневой электрод с сопротивлением более 25 Ом был дополнен одним дополнительным электродом.","qs":"Un solo electrodo de varilla que no tiene una resistencia a tierra de 25 ohmios o menos debe complementarse con al menos cuántos electrodos adicionales?","optss":["Dos electrodos adicionales","Un electrodo adicional","Tres electrodos adicionales","No se requiere ningún electrodo adicional"],"rs":"El NEC 250.53(A)(2) exige que un solo electrodo de varilla que exceda 25 ohmios se complemente con un electrodo adicional."},
  {"id":346,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A standard Class A GFCI device is designed to trip when the difference between the hot and neutral currents reaches approximately what value?","opts":["20 A","5 A","30 mA","5 mA"],"correct":3,"re":"A Class A GFCI trips at a ground-fault current of about 4 to 6 mA, nominally 5 mA, to protect people from shock.","qr":"Стандартное устройство GFCI класса A рассчитано на срабатывание, когда разница между токами фазы и нейтрали достигает примерно какого значения?","optsr":["20 А","5 А","30 мА","5 мА"],"rr":"GFCI класса A срабатывает при токе утечки на землю около 4–6 мА, номинально 5 мА, чтобы защитить людей от поражения током.","qs":"Un dispositivo GFCI Clase A estándar está diseñado para dispararse cuando la diferencia entre las corrientes de la fase y el neutro alcanza aproximadamente qué valor?","optss":["20 A","5 A","30 mA","5 mA"],"rs":"Un GFCI Clase A se dispara con una corriente de falla a tierra de aproximadamente 4 a 6 mA, nominalmente 5 mA, para proteger a las personas de una descarga."},
  {"id":347,"sec":"Planning & Estimation","block":4,"q":"What is the approximate full-load current of a three-phase 480 V load delivering 100 kW at a power factor of 1.0?","opts":["100 A","208 A","120 A","150 A"],"correct":2,"re":"IL = P ÷ (√3 × VL × PF) = 100,000 ÷ (1.732 × 480 × 1.0) = 100,000 ÷ 831.4 = 120 A.","qr":"Каков примерный ток полной нагрузки трёхфазной нагрузки 480 В, выдающей 100 кВт при коэффициенте мощности 1.0?","optsr":["100 А","208 А","120 А","150 А"],"rr":"IL = P ÷ (√3 × VL × PF) = 100 000 ÷ (1.732 × 480 × 1.0) = 100 000 ÷ 831.4 = 120 А.","qs":"¿Cuál es la corriente aproximada a plena carga de una carga trifásica de 480 V que entrega 100 kW con un factor de potencia de 1.0?","optss":["100 A","208 A","120 A","150 A"],"rs":"IL = P ÷ (√3 × VL × PF) = 100,000 ÷ (1.732 × 480 × 1.0) = 100,000 ÷ 831.4 = 120 A."},
  {"id":348,"sec":"Safety","block":4,"q":"Per NEC 110.26(A)(3), what is the minimum required headroom (height) of the working space about service equipment, panelboards, or motor control centers rated 1200 amperes or less?","opts":["7 feet 6 inches","6 feet","7 feet","6 feet 6 inches"],"correct":3,"re":"NEC 110.26(A)(3) requires minimum headroom of 6.5 feet (6 ft 6 in) for the working space about electrical equipment.","qr":"Согласно NEC 110.26(A)(3), какова минимальная требуемая высота (свободное пространство над головой) рабочего пространства вокруг сервисного оборудования, распределительных щитов или центров управления двигателями с номиналом 1200 ампер или менее?","optsr":["7 футов 6 дюймов","6 футов","7 футов","6 футов 6 дюймов"],"rr":"NEC 110.26(A)(3) требует минимальной высоты 6,5 футов (6 футов 6 дюймов) для рабочего пространства вокруг электрооборудования.","qs":"Según el NEC 110.26(A)(3), ¿cuál es la altura libre mínima requerida (altura del techo) del espacio de trabajo alrededor del equipo de acometida, tableros o centros de control de motores con capacidad de 1200 amperios o menos?","optss":["7 pies 6 pulgadas","6 pies","7 pies","6 pies 6 pulgadas"],"rs":"El NEC 110.26(A)(3) exige una altura libre mínima de 6.5 pies (6 ft 6 in) para el espacio de trabajo alrededor del equipo eléctrico."},
  {"id":349,"sec":"Rough Wiring","block":4,"q":"When two ground rods are used to form the grounding electrode, what is the minimum spacing required between them?","opts":["3 ft apart","6 ft apart","8 ft apart","10 ft apart"],"correct":1,"re":"NEC 250.53(A)(3) requires rod electrodes that are part of an array to be spaced at least 6 ft apart.","qr":"Когда два заземляющих стержня используются для образования заземляющего электрода, какое минимальное расстояние требуется между ними?","optsr":["На расстоянии 3 фута","На расстоянии 6 футов","На расстоянии 8 футов","На расстоянии 10 футов"],"rr":"NEC 250.53(A)(3) требует, чтобы стержневые электроды, входящие в группу, располагались на расстоянии не менее 6 футов друг от друга.","qs":"Cuando se usan dos varillas de tierra para formar el electrodo de puesta a tierra, ¿cuál es el espaciamiento mínimo requerido entre ellas?","optss":["3 ft de separación","6 ft de separación","8 ft de separación","10 ft de separación"],"rs":"El NEC 250.53(A)(3) exige que los electrodos de varilla que forman parte de un arreglo estén espaciados al menos 6 ft entre sí."},
  {"id":350,"sec":"Planning & Estimation","block":4,"q":"Using NEC Table 310.16 at the 60°C column, what is the allowable ampacity of a 12 AWG copper conductor?","opts":["15 A","20 A","25 A","30 A"],"correct":1,"re":"Per NEC Table 310.16, 12 AWG copper at the 60°C termination column has an allowable ampacity of 20 A.","qr":"Используя таблицу NEC 310.16 в колонке 60°C, какова допустимая токовая нагрузка медного проводника 12 AWG?","optsr":["15 A","20 A","25 A","30 A"],"rr":"Согласно таблице NEC 310.16, медный проводник 12 AWG в колонке клемм 60°C имеет допустимую ампацитету 20 A.","qs":"Usando la Tabla 310.16 del NEC en la columna de 60°C, ¿cuál es la ampacidad permitida de un conductor de cobre 12 AWG?","optss":["15 A","20 A","25 A","30 A"],"rs":"Según la Tabla 310.16 del NEC, el cobre 12 AWG en la columna de terminación de 60°C tiene una ampacidad permitida de 20 A."},
  {"id":351,"sec":"Finish Wiring & Trim","block":4,"q":"A switch controlling lighting in a dwelling generally must not switch which conductor?","opts":["The ungrounded (hot) conductor","The traveler conductor","The grounded (neutral) conductor","The switch leg"],"correct":2,"re":"NEC 404.2(B) requires switches to control the ungrounded conductor; the grounded (neutral) conductor is generally not to be switched (with limited exceptions).","qr":"Выключатель, управляющий освещением в жилье, как правило, не должен размыкать какой проводник?","optsr":["Незаземлённый (фазный) проводник","Транзитный проводник","Заземлённый (нейтральный) проводник","Отвод к выключателю"],"rr":"NEC 404.2(B) требует, чтобы выключатели управляли незаземлённым проводником; заземлённый (нейтральный) проводник, как правило, не должен размыкаться (с ограниченными исключениями).","qs":"Un interruptor que controla el alumbrado en una vivienda generalmente no debe interrumpir cuál conductor?","optss":["El conductor no puesto a tierra (fase)","El conductor viajero","El conductor puesto a tierra (neutro)","El conductor de retorno del interruptor"],"rs":"El NEC 404.2(B) exige que los interruptores controlen el conductor no puesto a tierra; el conductor puesto a tierra (neutro) generalmente no debe interrumpirse (con excepciones limitadas)."},
  {"id":352,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"An electrician notices that incandescent lights dim noticeably whenever a large motor starts on the same circuit; this symptom most directly points to which problem?","opts":["Excessive voltage drop from an undersized or overloaded conductor","A ground fault on the lighting circuit","A failed GFCI device","Reversed polarity at the receptacle"],"correct":0,"re":"Dimming during high-current draw indicates voltage drop, commonly caused by undersized conductors, long runs, or loose connections that cannot supply the inrush current.","qr":"Электрик замечает, что лампы накаливания заметно тускнеют каждый раз, когда на той же цепи запускается крупный двигатель; этот симптом наиболее прямо указывает на какую проблему?","optsr":["Чрезмерное падение напряжения из-за недостаточного сечения или перегруженного проводника","Замыкание на землю в осветительной цепи","Неисправное устройство GFCI","Обратная полярность на розетке"],"rr":"Потускнение при большом токе указывает на падение напряжения, чаще всего вызванное недостаточным сечением проводников, длинными трассами или ослабленными соединениями, которые не могут обеспечить пусковой ток.","qs":"Un electricista nota que las luces incandescentes se atenúan notablemente cada vez que un motor grande arranca en el mismo circuito; este síntoma apunta de forma más directa a cuál problema?","optss":["Caída de voltaje excesiva por un conductor subdimensionado o sobrecargado","Una falla a tierra en el circuito de alumbrado","Un dispositivo GFCI defectuoso","Polaridad invertida en el receptáculo"],"rs":"La atenuación durante una alta demanda de corriente indica caída de voltaje, comúnmente causada por conductores subdimensionados, tramos largos o conexiones flojas que no pueden suministrar la corriente de arranque."},
  {"id":353,"sec":"Safety","block":4,"q":"Per NEC 110.26(A)(2), the minimum width of the working space in front of electrical equipment must be the width of the equipment or what minimum dimension, whichever is greater?","opts":["24 inches","30 inches","42 inches","36 inches"],"correct":1,"re":"NEC 110.26(A)(2) requires the working space width to be a minimum of 30 inches or the width of the equipment, whichever is greater.","qr":"Согласно NEC 110.26(A)(2), минимальная ширина рабочего пространства перед электрооборудованием должна равняться ширине оборудования или какому минимальному размеру, в зависимости от того, что больше?","optsr":["24 дюйма","30 дюймов","42 дюйма","36 дюймов"],"rr":"NEC 110.26(A)(2) требует, чтобы ширина рабочего пространства составляла минимум 30 дюймов или ширину оборудования, в зависимости от того, что больше.","qs":"Según el NEC 110.26(A)(2), el ancho mínimo del espacio de trabajo frente al equipo eléctrico debe ser el ancho del equipo o qué dimensión mínima, lo que sea mayor?","optss":["24 pulgadas","30 pulgadas","42 pulgadas","36 pulgadas"],"rs":"El NEC 110.26(A)(2) exige que el ancho del espacio de trabajo sea un mínimo de 30 pulgadas o el ancho del equipo, lo que sea mayor."},
  {"id":354,"sec":"Rough Wiring","block":4,"q":"A concrete-encased electrode (Ufer) must consist of at least 20 ft of bare copper conductor not smaller than which size?","opts":["4 AWG","8 AWG","6 AWG","2 AWG"],"correct":0,"re":"NEC 250.52(A)(3) permits a concrete-encased electrode using at least 20 ft of bare copper conductor not smaller than 4 AWG.","qr":"Электрод, заключённый в бетон (Ufer), должен состоять не менее чем из 20 футов оголённого медного проводника не меньше какого сечения?","optsr":["4 AWG","8 AWG","6 AWG","2 AWG"],"rr":"NEC 250.52(A)(3) допускает использование электрода, заключённого в бетон, с использованием не менее 20 футов оголённого медного проводника сечением не менее 4 AWG.","qs":"Un electrodo embebido en concreto (Ufer) debe consistir en al menos 20 ft de conductor de cobre desnudo no menor que cuál tamaño?","optss":["4 AWG","8 AWG","6 AWG","2 AWG"],"rs":"El NEC 250.52(A)(3) permite un electrodo embebido en concreto usando al menos 20 ft de conductor de cobre desnudo no menor que 4 AWG."},
  {"id":355,"sec":"Planning & Estimation","block":4,"q":"What is the allowable ampacity of a 10 AWG copper conductor in the 60°C column of NEC Table 310.16?","opts":["30 A","25 A","20 A","40 A"],"correct":0,"re":"NEC Table 310.16 lists 10 AWG copper at 30 A in the 60°C column.","qr":"Какова допустимая ампацитета медного проводника 10 AWG в колонке 60°C таблицы NEC 310.16?","optsr":["30 A","25 A","20 A","40 A"],"rr":"Таблица NEC 310.16 указывает 10 AWG медь как 30 A в колонке 60°C.","qs":"¿Cuál es la ampacidad permitida de un conductor de cobre 10 AWG en la columna de 60°C de la Tabla 310.16 del NEC?","optss":["30 A","25 A","20 A","40 A"],"rs":"La Tabla 310.16 del NEC indica el cobre 10 AWG a 30 A en la columna de 60°C."},
  {"id":356,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"An AFCI device is specifically designed to detect and respond to which hazardous condition?","opts":["Overvoltage from utility surges","Small ground-fault currents to earth","Arcing faults in wiring and connections","Phase imbalance between legs"],"correct":2,"re":"An AFCI senses the high-frequency current signature of an arc fault, such as from damaged or loose wiring, and interrupts the circuit to prevent fires.","qr":"Устройство AFCI специально предназначено для обнаружения и реагирования на какое опасное состояние?","optsr":["Перенапряжение от скачков сети","Малые токи замыкания на землю","Дуговые замыкания в проводке и соединениях","Дисбаланс фаз между линиями"],"rr":"AFCI определяет высокочастотную сигнатуру тока дугового разряда, например от повреждённой или ослабленной проводки, и размыкает цепь для предотвращения пожаров.","qs":"Un dispositivo AFCI está diseñado específicamente para detectar y responder a cuál condición peligrosa?","optss":["Sobretensión por sobretensiones de la red eléctrica","Pequeñas corrientes de falla a tierra hacia la tierra","Fallas de arco en el cableado y las conexiones","Desbalance de fases entre las líneas"],"rs":"Un AFCI detecta la firma de corriente de alta frecuencia de una falla de arco, como la proveniente de cableado dañado o flojo, e interrumpe el circuito para prevenir incendios."},
  {"id":357,"sec":"Rough Wiring","block":4,"q":"When a concrete-encased electrode uses electrically conductive coated steel reinforcing bars, the bars must be at least which diameter?","opts":["1/4 in","1/2 in","3/8 in","5/8 in"],"correct":1,"re":"NEC 250.52(A)(3) requires reinforcing bars used as a concrete-encased electrode to be at least 1/2 in in diameter.","qr":"Когда электрод, заключённый в бетон, использует электропроводящую стальную арматуру с покрытием, арматура должна иметь диаметр не менее какого значения?","optsr":["1/4 дюйма","1/2 дюйма","3/8 дюйма","5/8 дюйма"],"rr":"NEC 250.52(A)(3) требует, чтобы арматура, используемая в качестве электрода, заключённого в бетон, имела диаметр не менее 1/2 дюйма.","qs":"Cuando un electrodo embebido en concreto utiliza barras de refuerzo de acero recubiertas eléctricamente conductoras, las barras deben tener al menos cuál diámetro?","optss":["1/4 in","1/2 in","3/8 in","5/8 in"],"rs":"El NEC 250.52(A)(3) exige que las barras de refuerzo usadas como electrodo embebido en concreto tengan al menos 1/2 in de diámetro."},
  {"id":358,"sec":"Safety","block":4,"q":"According to NEC 110.26(A)(2), the 30-inch-wide working space in front of a panelboard is permitted to be measured in which manner?","opts":["Only centered on the panelboard","Only from the left edge of the equipment","Measured diagonally across the equipment face","Either centered on the equipment or offset, as long as a 30-inch width is achieved"],"correct":3,"re":"NEC 110.26(A)(2) permits the 30-inch width to be measured either centered on the equipment or offset, provided the full 30-inch width is maintained.","qr":"Согласно NEC 110.26(A)(2), рабочее пространство шириной 30 дюймов перед распределительным щитом разрешается измерять каким образом?","optsr":["Только по центру распределительного щита","Только от левого края оборудования","По диагонали по лицевой стороне оборудования","Либо по центру оборудования, либо со смещением, при условии достижения ширины 30 дюймов"],"rr":"NEC 110.26(A)(2) разрешает измерять ширину 30 дюймов либо по центру оборудования, либо со смещением, при условии сохранения полной ширины 30 дюймов.","qs":"Según el NEC 110.26(A)(2), el espacio de trabajo de 30 pulgadas de ancho frente a un tablero puede medirse de cuál manera?","optss":["Solo centrado en el tablero","Solo desde el borde izquierdo del equipo","Medido en diagonal a través de la cara del equipo","Ya sea centrado en el equipo o desplazado, siempre que se logre un ancho de 30 pulgadas"],"rs":"El NEC 110.26(A)(2) permite que el ancho de 30 pulgadas se mida ya sea centrado en el equipo o desplazado, siempre que se mantenga el ancho completo de 30 pulgadas."},
  {"id":359,"sec":"Planning & Estimation","block":4,"q":"According to NEC 240.6(A), which of the following is NOT a standard ampere rating for a fuse or inverse-time circuit breaker?","opts":["35 A","45 A","70 A","55 A"],"correct":3,"re":"Per NEC 240.6(A), 55 A is not a standard rating; the standard ratings skip from 50 A to 60 A.","qr":"Согласно NEC 240.6(A), какое из следующих НЕ является стандартным номиналом тока для предохранителя или автоматического выключателя с обратнозависимой выдержкой?","optsr":["35 A","45 A","70 A","55 A"],"rr":"Согласно NEC 240.6(A), 55 A не является стандартным номиналом; стандартные номиналы перескакивают с 50 A на 60 A.","qs":"Según el NEC 240.6(A), ¿cuál de los siguientes NO es una capacidad estándar en amperios para un fusible o disyuntor de tiempo inverso?","optss":["35 A","45 A","70 A","55 A"],"rs":"Según el NEC 240.6(A), 55 A no es una capacidad estándar; las capacidades estándar saltan de 50 A a 60 A."},
  {"id":360,"sec":"Finish Wiring & Trim","block":4,"q":"A general-use snap switch installed in a metal box must generally be provided with what connection for safety?","opts":["A connection to the grounded (neutral) conductor","An equipment grounding connection to the switch yoke","A surge protective device","An isolated ground conductor"],"correct":1,"re":"NEC 404.9(B) requires snap switches, including metal faceplate types, to be effectively grounded by connecting the equipment grounding conductor to the switch metal yoke or strap.","qr":"Кнопочный выключатель общего назначения, установленный в металлической коробке, как правило, должен быть снабжён каким соединением для безопасности?","optsr":["Соединение с заземлённым (нейтральным) проводником","Заземляющее соединение оборудования с ярмом выключателя","Устройство защиты от перенапряжений","Изолированный заземляющий проводник"],"rr":"NEC 404.9(B) требует, чтобы кнопочные выключатели, включая типы с металлической лицевой панелью, были эффективно заземлены путём подключения заземляющего проводника оборудования к металлическому ярму или планке выключателя.","qs":"Un interruptor de acción rápida de uso general instalado en una caja metálica debe generalmente contar con qué conexión por seguridad?","optss":["Una conexión al conductor puesto a tierra (neutro)","Una conexión de puesta a tierra de equipos al yugo del interruptor","Un dispositivo de protección contra sobretensiones","Un conductor de tierra aislada"],"rs":"El NEC 404.9(B) exige que los interruptores de acción rápida, incluyendo los de placa frontal metálica, estén efectivamente puestos a tierra conectando el conductor de puesta a tierra de equipos al yugo o soporte metálico del interruptor."},
  {"id":361,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A circuit breaker trips immediately and violently the instant it is reset, with no load connected; this behavior most strongly suggests which fault?","opts":["A gradual overload","Normal thermal trip from heat","A high-resistance loose connection","A direct short circuit (hot-to-neutral or hot-to-ground)"],"correct":3,"re":"Instantaneous tripping with no load points to a short circuit, where very high fault current activates the breaker's magnetic instantaneous trip. An overload trips slowly under load.","qr":"Автоматический выключатель срабатывает мгновенно и резко сразу после повторного включения без подключённой нагрузки; такое поведение наиболее явно указывает на какую неисправность?","optsr":["Постепенную перегрузку","Нормальное тепловое срабатывание от нагрева","Высокоомное ослабленное соединение","Прямое короткое замыкание (фаза–нейтраль или фаза–земля)"],"rr":"Мгновенное срабатывание без нагрузки указывает на короткое замыкание, при котором очень большой ток короткого замыкания активирует магнитное мгновенное расцепление выключателя. Перегрузка срабатывает медленно под нагрузкой.","qs":"Un disyuntor se dispara de inmediato y violentamente en el instante en que se restablece, sin ninguna carga conectada; este comportamiento sugiere con mayor fuerza cuál falla?","optss":["Una sobrecarga gradual","Disparo térmico normal por calor","Una conexión floja de alta resistencia","Un cortocircuito directo (fase a neutro o fase a tierra)"],"rs":"Un disparo instantáneo sin carga apunta a un cortocircuito, donde una corriente de falla muy alta activa el disparo magnético instantáneo del disyuntor. Una sobrecarga se dispara lentamente bajo carga."},
  {"id":362,"sec":"Rough Wiring","block":4,"q":"A metal underground water pipe used as a grounding electrode must be in direct contact with the earth for at least how many feet?","opts":["5 ft","20 ft","8 ft","10 ft"],"correct":3,"re":"NEC 250.52(A)(1) requires a metal underground water pipe to be in direct contact with the earth for 10 ft or more to qualify as an electrode.","qr":"Металлическая подземная водопроводная труба, используемая в качестве заземляющего электрода, должна находиться в прямом контакте с землёй на протяжении не менее скольких футов?","optsr":["5 футов","20 футов","8 футов","10 футов"],"rr":"NEC 250.52(A)(1) требует, чтобы металлическая подземная водопроводная труба находилась в прямом контакте с землёй на протяжении 10 футов или более, чтобы квалифицироваться как электрод.","qs":"Una tubería metálica de agua subterránea usada como electrodo de puesta a tierra debe estar en contacto directo con la tierra durante al menos cuántos pies?","optss":["5 ft","20 ft","8 ft","10 ft"],"rs":"El NEC 250.52(A)(1) exige que una tubería metálica de agua subterránea esté en contacto directo con la tierra durante 10 ft o más para calificar como electrodo."},
  {"id":363,"sec":"Safety","block":4,"q":"Per NEC 110.26(E)(1), the dedicated equipment space above a panelboard or switchboard must extend from the top of the equipment to a height of how many feet above the equipment, or to the structural ceiling, whichever is lower?","opts":["3 feet","6.5 feet","6 feet","10 feet"],"correct":2,"re":"NEC 110.26(E)(1)(a) requires the dedicated electrical space to extend 6 feet above the equipment or to the structural ceiling, whichever is lower.","qr":"Согласно NEC 110.26(E)(1), выделенное пространство для оборудования над распределительным или коммутационным щитом должно простираться от верха оборудования на высоту скольких футов над оборудованием или до конструктивного потолка, в зависимости от того, что ниже?","optsr":["3 фута","6,5 фута","6 футов","10 футов"],"rr":"NEC 110.26(E)(1)(a) требует, чтобы выделенное электрическое пространство простиралось на 6 футов над оборудованием или до конструктивного потолка, в зависимости от того, что ниже.","qs":"Según el NEC 110.26(E)(1), el espacio dedicado de equipo sobre un tablero o cuadro de distribución debe extenderse desde la parte superior del equipo hasta una altura de cuántos pies sobre el equipo, o hasta el techo estructural, lo que sea más bajo?","optss":["3 pies","6.5 pies","6 pies","10 pies"],"rs":"El NEC 110.26(E)(1)(a) exige que el espacio eléctrico dedicado se extienda 6 pies sobre el equipo o hasta el techo estructural, lo que sea más bajo."},
  {"id":364,"sec":"Planning & Estimation","block":4,"q":"A continuous load draws 16 A; what minimum branch-circuit OCPD ampacity is required before applying any temperature or bundling adjustments?","opts":["20 A","18 A","16 A","25 A"],"correct":0,"re":"Per NEC 210.20(A), the OCPD must be at least 125% of the continuous load: 16 A × 1.25 = 20 A.","qr":"Непрерывная нагрузка потребляет 16 A; какая минимальная ампацитета OCPD ответвления требуется до применения поправок на температуру или групповую прокладку?","optsr":["20 A","18 A","16 A","25 A"],"rr":"Согласно NEC 210.20(A), OCPD должен быть не менее 125% непрерывной нагрузки: 16 A × 1,25 = 20 A.","qs":"Una carga continua consume 16 A; ¿cuál es la capacidad mínima del OCPD del circuito ramal requerida antes de aplicar cualquier ajuste por temperatura o agrupamiento?","optss":["20 A","18 A","16 A","25 A"],"rs":"Según el NEC 210.20(A), el OCPD debe ser al menos el 125% de la carga continua: 16 A × 1.25 = 20 A."},
  {"id":365,"sec":"Rough Wiring","block":4,"q":"A metal underground water pipe used as a grounding electrode must always be supplemented by which of the following?","opts":["An additional grounding electrode","A surge arrester","A second water meter","A larger service conductor"],"correct":0,"re":"NEC 250.53(D)(2) requires the metal underground water pipe electrode to be supplemented by an additional electrode of a type specified in 250.52.","qr":"Металлическая подземная водопроводная труба, используемая в качестве заземляющего электрода, всегда должна быть дополнена чем из следующего?","optsr":["Дополнительным заземляющим электродом","Грозовым разрядником","Вторым водомером","Более крупным вводным проводником"],"rr":"NEC 250.53(D)(2) требует, чтобы электрод в виде металлической подземной водопроводной трубы был дополнен дополнительным электродом одного из типов, указанных в 250.52.","qs":"Una tubería metálica de agua subterránea usada como electrodo de puesta a tierra siempre debe complementarse con cuál de los siguientes?","optss":["Un electrodo de puesta a tierra adicional","Un descargador de sobretensiones","Un segundo medidor de agua","Un conductor de acometida más grande"],"rs":"El NEC 250.53(D)(2) exige que el electrodo de tubería metálica de agua subterránea se complemente con un electrodo adicional de un tipo especificado en 250.52."},
  {"id":366,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"In a multiwire branch circuit, what is the primary danger if the shared neutral becomes loose or open while the circuit is energized?","opts":["The breakers will trip immediately on overload","The GFCI will fail to test","Connected loads can be exposed to abnormally high or low voltages","The grounding conductor carries the full load current"],"correct":2,"re":"With an open shared neutral, the line-to-neutral loads become series-connected across the two legs, so voltage divides unevenly and can damage equipment.","qr":"В многопроводной ответвлённой цепи какова основная опасность, если общая нейтраль становится ослабленной или оборванной при включённой цепи?","optsr":["Выключатели немедленно сработают от перегрузки","GFCI не пройдёт тестирование","Подключённые нагрузки могут оказаться под аномально высоким или низким напряжением","Заземляющий проводник несёт полный ток нагрузки"],"rr":"При обрыве общей нейтрали нагрузки фаза–нейтраль оказываются включёнными последовательно между двумя линиями, поэтому напряжение делится неравномерно и может повредить оборудование.","qs":"En un circuito ramal multiconductor, ¿cuál es el peligro principal si el neutro compartido se afloja o se abre mientras el circuito está energizado?","optss":["Los disyuntores se dispararán de inmediato por sobrecarga","El GFCI fallará la prueba","Las cargas conectadas pueden quedar expuestas a voltajes anormalmente altos o bajos","El conductor de puesta a tierra conduce toda la corriente de carga"],"rs":"Con un neutro compartido abierto, las cargas de línea a neutro quedan conectadas en serie a través de las dos líneas, por lo que el voltaje se divide de forma desigual y puede dañar el equipo."},
  {"id":367,"sec":"Safety","block":4,"q":"Within the dedicated equipment space above a panelboard required by NEC 110.26(E), which of the following is specifically permitted by the Code?","opts":["Foreign piping such as a water line","An HVAC duct passing through the space","A drain pan from equipment above","Sprinkler protection piping for the area"],"correct":3,"re":"NEC 110.26(E)(1)(b) prohibits foreign systems (piping, ducts, etc.) in the dedicated space but specifically permits sprinkler protection piping for the area.","qr":"В пределах выделенного пространства для оборудования над распределительным щитом, требуемого NEC 110.26(E), что из перечисленного специально разрешается Кодексом?","optsr":["Посторонние трубопроводы, такие как водопровод","Воздуховод системы ОВКВ, проходящий через пространство","Поддон для слива от оборудования сверху","Трубопровод спринклерной защиты для данной зоны"],"rr":"NEC 110.26(E)(1)(b) запрещает посторонние системы (трубопроводы, воздуховоды и т.д.) в выделенном пространстве, но специально разрешает трубопровод спринклерной защиты для данной зоны.","qs":"Dentro del espacio dedicado de equipo sobre un tablero requerido por el NEC 110.26(E), ¿cuál de los siguientes está permitido específicamente por el Código?","optss":["Tubería ajena, como una línea de agua","Un ducto de HVAC que atraviesa el espacio","Una bandeja de drenaje de equipo ubicado arriba","Tubería de protección contra incendios (rociadores) para el área"],"rs":"El NEC 110.26(E)(1)(b) prohíbe los sistemas ajenos (tuberías, ductos, etc.) en el espacio dedicado, pero permite específicamente la tubería de protección contra incendios (rociadores) para el área."},
  {"id":368,"sec":"Planning & Estimation","block":4,"q":"Per NEC Chapter 9, Table 1, what is the maximum percent of conduit cross-sectional area that may be filled when more than two conductors are installed in a raceway?","opts":["31%","60%","53%","40%"],"correct":3,"re":"NEC Chapter 9, Table 1 limits fill to 40% for more than two conductors in a conduit or tubing.","qr":"Согласно NEC, глава 9, таблица 1, каков максимальный процент площади поперечного сечения кабелепровода, который может быть заполнен при прокладке более двух проводников в трубе?","optsr":["31%","60%","53%","40%"],"rr":"NEC глава 9, таблица 1 ограничивает заполнение до 40% для более чем двух проводников в трубе.","qs":"Según el Capítulo 9, Tabla 1 del NEC, ¿cuál es el porcentaje máximo del área de sección transversal del conduit que puede llenarse cuando se instalan más de dos conductores en una canalización?","optss":["31%","60%","53%","40%"],"rs":"El Capítulo 9, Tabla 1 del NEC limita el llenado al 40% para más de dos conductores en un conduit o tubo."},
  {"id":369,"sec":"Rough Wiring","block":4,"q":"When a water meter is installed in a metal underground water pipe used as an electrode, what must be provided to maintain electrical continuity?","opts":["A dielectric union","A plastic spacer","A second ground rod only","A bonding jumper around the meter"],"correct":3,"re":"NEC 250.53(D)(1) requires a bonding jumper around insulating components such as a water meter to ensure continuity of the electrode.","qr":"Когда водомер установлен в металлической подземной водопроводной трубе, используемой в качестве электрода, что должно быть предусмотрено для поддержания электрической непрерывности?","optsr":["Диэлектрическая муфта","Пластиковая прокладка","Только второй заземляющий стержень","Соединительная перемычка вокруг счётчика"],"rr":"NEC 250.53(D)(1) требует установки соединительной перемычки вокруг изолирующих компонентов, таких как водомер, для обеспечения непрерывности электрода.","qs":"Cuando se instala un medidor de agua en una tubería metálica de agua subterránea usada como electrodo, ¿qué debe proporcionarse para mantener la continuidad eléctrica?","optss":["Una unión dieléctrica","Un espaciador de plástico","Solo una segunda varilla de tierra","Un puente de unión alrededor del medidor"],"rs":"El NEC 250.53(D)(1) exige un puente de unión alrededor de componentes aislantes como un medidor de agua para asegurar la continuidad del electrodo."},
  {"id":370,"sec":"Finish Wiring & Trim","block":4,"q":"A standard 15-amp, 125-volt duplex receptacle on a 20-amp branch circuit serving multiple outlets is permitted because of what reason?","opts":["A 15-amp receptacle is never allowed on a 20-amp circuit","NEC Table 210.21(B)(3) permits 15-amp receptacles on a 20-amp circuit with two or more outlets","Only single receptacles are allowed","Only if the receptacle is GFCI"],"correct":1,"re":"NEC Table 210.21(B)(3) permits 15-amp rated receptacles to be used on 20-amp branch circuits where two or more receptacles are supplied.","qr":"Стандартная сдвоенная розетка 15 А, 125 В на ответвлённой цепи 20 А, обслуживающей несколько выходов, разрешена по какой причине?","optsr":["Розетка 15 А никогда не допускается на цепи 20 А","NEC Таблица 210.21(B)(3) разрешает розетки 15 А на цепи 20 А с двумя или более выходами","Допускаются только одиночные розетки","Только если розетка GFCI"],"rr":"NEC Таблица 210.21(B)(3) разрешает использовать розетки с номиналом 15 А на ответвлённых цепях 20 А, где питаются две или более розетки.","qs":"Un receptáculo dúplex estándar de 15 amperios y 125 voltios en un circuito ramal de 20 amperios que sirve a múltiples salidas está permitido por cuál razón?","optss":["Un receptáculo de 15 amperios nunca se permite en un circuito de 20 amperios","La Tabla 210.21(B)(3) del NEC permite receptáculos de 15 amperios en un circuito de 20 amperios con dos o más salidas","Solo se permiten receptáculos sencillos","Solo si el receptáculo es GFCI"],"rs":"La Tabla 210.21(B)(3) del NEC permite que se usen receptáculos con capacidad de 15 amperios en circuitos ramales de 20 amperios donde se alimentan dos o más receptáculos."},
  {"id":371,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"What is the correct way to verify that a GFCI receptacle is functioning properly?","opts":["Press the TEST button and confirm the device trips and removes power","Read line voltage with the device energized","Measure resistance across the line terminals","Apply a 30 mA load and confirm it holds"],"correct":0,"re":"Pressing the TEST button creates a small simulated imbalance; a working GFCI must trip and de-energize the outlet, after which RESET restores power.","qr":"Каков правильный способ проверить, что розетка GFCI функционирует исправно?","optsr":["Нажать кнопку TEST и убедиться, что устройство срабатывает и снимает питание","Считать линейное напряжение при включённом устройстве","Измерить сопротивление между линейными клеммами","Подать нагрузку 30 мА и убедиться, что оно удерживается"],"rr":"Нажатие кнопки TEST создаёт небольшой имитированный дисбаланс; исправный GFCI должен сработать и обесточить розетку, после чего RESET восстанавливает питание.","qs":"¿Cuál es la forma correcta de verificar que un receptáculo GFCI esté funcionando correctamente?","optss":["Presionar el botón TEST y confirmar que el dispositivo se dispara y retira la energía","Leer el voltaje de línea con el dispositivo energizado","Medir la resistencia entre las terminales de línea","Aplicar una carga de 30 mA y confirmar que se mantiene"],"rs":"Presionar el botón TEST crea un pequeño desbalance simulado; un GFCI en buen estado debe dispararse y desenergizar la salida, tras lo cual RESET restablece la energía."},
  {"id":372,"sec":"Planning & Estimation","block":4,"q":"What is the maximum conduit fill percentage permitted for a single conductor per NEC Chapter 9, Table 1?","opts":["31%","53%","40%","60%"],"correct":1,"re":"NEC Chapter 9, Table 1 permits 53% fill for one conductor in a raceway.","qr":"Какой максимальный процент заполнения кабелепровода допускается для одного проводника согласно NEC, глава 9, таблица 1?","optsr":["31%","53%","40%","60%"],"rr":"NEC глава 9, таблица 1 допускает заполнение 53% для одного проводника в кабелепроводе.","qs":"¿Cuál es el porcentaje máximo de llenado de conduit permitido para un solo conductor según el Capítulo 9, Tabla 1 del NEC?","optss":["31%","53%","40%","60%"],"rs":"El Capítulo 9, Tabla 1 del NEC permite un llenado del 53% para un conductor en una canalización."},
  {"id":373,"sec":"Safety","block":4,"q":"Per NEC 110.27(A), live parts of electrical equipment operating at 50 volts or more must be guarded against accidental contact by which of the following methods?","opts":["Painting the live parts with insulating paint","Location in a room accessible only to qualified persons","Posting a warning sign within 10 feet","Applying dielectric grease to the conductors"],"correct":1,"re":"NEC 110.27(A) permits guarding live parts by location in a room, vault, or enclosure accessible only to qualified persons, among other listed methods.","qr":"Согласно NEC 110.27(A), токоведущие части электрооборудования с напряжением 50 вольт или более должны быть защищены от случайного контакта одним из следующих методов?","optsr":["Покраска токоведущих частей изоляционной краской","Размещение в помещении, доступном только квалифицированным лицам","Размещение предупреждающего знака в пределах 10 футов","Нанесение диэлектрической смазки на проводники"],"rr":"NEC 110.27(A) разрешает защищать токоведущие части путём размещения в помещении, хранилище или корпусе, доступном только квалифицированным лицам, среди прочих перечисленных методов.","qs":"Según el NEC 110.27(A), las partes vivas de equipo eléctrico que operan a 50 voltios o más deben protegerse contra el contacto accidental mediante cuál de los siguientes métodos?","optss":["Pintar las partes vivas con pintura aislante","Ubicación en un cuarto accesible solo para personas calificadas","Colocar un letrero de advertencia a 10 pies de distancia","Aplicar grasa dieléctrica a los conductores"],"rs":"El NEC 110.27(A) permite proteger las partes vivas mediante su ubicación en un cuarto, bóveda o gabinete accesible solo para personas calificadas, entre otros métodos listados."},
  {"id":374,"sec":"Rough Wiring","block":4,"q":"Where the upper end of a ground rod is exposed and subject to physical damage, how must it be installed to avoid additional protection requirements?","opts":["At least 6 in above grade","Flush with or below ground level","Painted with red paint","Wrapped in tape"],"correct":1,"re":"NEC 250.53(G) requires the rod to be installed flush with or below the ground unless the above-ground end and connection are protected.","qr":"Если верхний конец заземляющего стержня открыт и подвержен механическому повреждению, как он должен быть установлен, чтобы избежать дополнительных требований по защите?","optsr":["Не менее чем на 6 дюймов выше уровня грунта","Заподлицо с уровнем земли или ниже него","Окрашен красной краской","Обёрнут лентой"],"rr":"NEC 250.53(G) требует, чтобы стержень был установлен заподлицо с землёй или ниже неё, если только надземный конец и соединение не защищены.","qs":"Donde el extremo superior de una varilla de tierra está expuesto y sujeto a daño físico, ¿cómo debe instalarse para evitar requisitos de protección adicionales?","optss":["Al menos 6 in sobre el nivel del suelo","Al ras o por debajo del nivel del suelo","Pintada con pintura roja","Envuelta en cinta"],"rs":"El NEC 250.53(G) exige que la varilla se instale al ras o por debajo del suelo, a menos que el extremo sobre el suelo y la conexión estén protegidos."},
  {"id":375,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A motor runs sluggishly and stalls under load, and measurements show terminal voltage well below the nameplate rating during operation; the most likely cause is:","opts":["A failed AFCI breaker","Excessive voltage drop in the supply conductors","An oversized overcurrent device","Reversed line and neutral"],"correct":1,"re":"Low terminal voltage under load reduces motor torque, causing sluggish operation and stalling; this is a classic symptom of voltage drop from undersized or overloaded conductors.","qr":"Двигатель работает вяло и глохнет под нагрузкой, а измерения показывают напряжение на клеммах значительно ниже паспортного во время работы; наиболее вероятная причина:","optsr":["Неисправный автомат AFCI","Чрезмерное падение напряжения в питающих проводниках","Завышенный аппарат защиты от сверхтока","Перепутанные линия и нейтраль"],"rr":"Низкое напряжение на клеммах под нагрузкой снижает крутящий момент двигателя, вызывая вялую работу и остановку; это классический симптом падения напряжения из-за недостаточного сечения или перегруженных проводников.","qs":"Un motor funciona con dificultad y se detiene bajo carga, y las mediciones muestran un voltaje en terminales muy por debajo del valor de placa durante la operación; la causa más probable es:","optss":["Un disyuntor AFCI defectuoso","Caída de voltaje excesiva en los conductores de suministro","Un dispositivo de sobrecorriente sobredimensionado","Línea y neutro invertidos"],"rs":"Un voltaje bajo en terminales bajo carga reduce el par del motor, causando una operación lenta y detenciones; este es un síntoma clásico de caída de voltaje por conductores subdimensionados o sobrecargados."},
  {"id":376,"sec":"Rough Wiring","block":4,"q":"All grounding electrodes that are present at a building, such as a ground rod and a concrete-encased electrode, must be:","opts":["Connected only to the neutral bus","Kept electrically isolated from each other","Bonded together to form a grounding electrode system","Used one at a time on alternating days"],"correct":2,"re":"NEC 250.50 requires all electrodes present to be bonded together to form the grounding electrode system.","qr":"Все заземляющие электроды, имеющиеся в здании, такие как заземляющий стержень и электрод в бетоне, должны быть:","optsr":["Подключены только к нейтральной шине","Электрически изолированы друг от друга","Соединены вместе для образования системы заземляющих электродов","Использованы по одному в чередующиеся дни"],"rr":"NEC 250.50 требует, чтобы все имеющиеся электроды были соединены вместе для образования системы заземляющих электродов.","qs":"Todos los electrodos de puesta a tierra presentes en un edificio, como una varilla de tierra y un electrodo embebido en concreto, deben:","optss":["Conectarse solo a la barra de neutro","Mantenerse eléctricamente aislados entre sí","Unirse entre sí para formar un sistema de electrodos de puesta a tierra","Usarse uno a la vez en días alternos"],"rs":"El NEC 250.50 exige que todos los electrodos presentes se unan entre sí para formar el sistema de electrodos de puesta a tierra."},
  {"id":377,"sec":"Planning & Estimation","block":4,"q":"Per NEC Chapter 9, Table 1, what is the maximum conduit fill percentage when exactly two conductors are installed in a raceway?","opts":["26%","31%","40%","53%"],"correct":1,"re":"NEC Chapter 9, Table 1 limits two conductors in a raceway to 31% fill.","qr":"Согласно NEC, глава 9, таблица 1, каков максимальный процент заполнения кабелепровода при прокладке ровно двух проводников?","optsr":["26%","31%","40%","53%"],"rr":"NEC глава 9, таблица 1 ограничивает два проводника в кабелепроводе заполнением 31%.","qs":"Según el Capítulo 9, Tabla 1 del NEC, ¿cuál es el porcentaje máximo de llenado de conduit cuando se instalan exactamente dos conductores en una canalización?","optss":["26%","31%","40%","53%"],"rs":"El Capítulo 9, Tabla 1 del NEC limita dos conductores en una canalización a un llenado del 31%."},
  {"id":378,"sec":"Safety","block":4,"q":"Per NEC 110.27(A), at what voltage level do live parts of electrical equipment generally require guarding against accidental contact?","opts":["50 volts or more","30 volts or more","24 volts or more","120 volts or more"],"correct":0,"re":"NEC 110.27(A) requires that live parts operating at 50 volts or more be guarded against accidental contact.","qr":"Согласно NEC 110.27(A), при каком уровне напряжения токоведущие части электрооборудования обычно требуют защиты от случайного контакта?","optsr":["50 вольт или более","30 вольт или более","24 вольта или более","120 вольт или более"],"rr":"NEC 110.27(A) требует, чтобы токоведущие части с напряжением 50 вольт или более были защищены от случайного контакта.","qs":"Según el NEC 110.27(A), ¿a qué nivel de voltaje las partes vivas de equipo eléctrico generalmente requieren protección contra el contacto accidental?","optss":["50 voltios o más","30 voltios o más","24 voltios o más","120 voltios o más"],"rs":"El NEC 110.27(A) exige que las partes vivas que operan a 50 voltios o más se protejan contra el contacto accidental."},
  {"id":379,"sec":"Finish Wiring & Trim","block":4,"q":"A single receptacle installed on an individual branch circuit must have an ampere rating that is at least what value relative to the branch circuit?","opts":["Half the rating of the branch circuit","One-third the rating of the branch circuit","Exactly 15 amps regardless of circuit","Equal to or greater than the rating of the branch circuit"],"correct":3,"re":"NEC 210.21(B)(1) requires a single receptacle on an individual branch circuit to have an ampere rating not less than that of the branch circuit.","qr":"Одиночная розетка, установленная на индивидуальной ответвлённой цепи, должна иметь номинальный ток не менее какого значения относительно ответвлённой цепи?","optsr":["Половина номинала ответвлённой цепи","Одна треть номинала ответвлённой цепи","Ровно 15 А независимо от цепи","Равный или больше номинала ответвлённой цепи"],"rr":"NEC 210.21(B)(1) требует, чтобы одиночная розетка на индивидуальной ответвлённой цепи имела номинальный ток не менее номинала ответвлённой цепи.","qs":"Un solo receptáculo instalado en un circuito ramal individual debe tener una capacidad en amperios que sea al menos de qué valor en relación con el circuito ramal?","optss":["La mitad de la capacidad del circuito ramal","Un tercio de la capacidad del circuito ramal","Exactamente 15 amperios sin importar el circuito","Igual o mayor que la capacidad del circuito ramal"],"rs":"El NEC 210.21(B)(1) exige que un solo receptáculo en un circuito ramal individual tenga una capacidad en amperios no menor que la del circuito ramal."},
  {"id":380,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"An ohmmeter reading of nearly zero ohms between an ungrounded (hot) conductor and the equipment grounding conductor on a de-energized circuit indicates what?","opts":["A ground fault or short to ground","An open neutral","Normal insulation resistance","An overloaded conductor"],"correct":0,"re":"Near-zero resistance between the hot and the grounding conductor means they are unintentionally connected, which is a ground fault. Healthy insulation reads very high resistance.","qr":"Показание омметра почти ноль ом между незаземлённым (фазным) проводником и проводником заземления оборудования в обесточенной цепи указывает на что?","optsr":["Замыкание на землю или короткое замыкание на землю","Обрыв нейтрали","Нормальное сопротивление изоляции","Перегруженный проводник"],"rr":"Почти нулевое сопротивление между фазным и заземляющим проводниками означает, что они непреднамеренно соединены, что является замыканием на землю. Исправная изоляция показывает очень высокое сопротивление.","qs":"Una lectura de ohmímetro de casi cero ohmios entre un conductor no puesto a tierra (fase) y el conductor de puesta a tierra de equipos en un circuito desenergizado indica ¿qué?","optss":["Una falla a tierra o corto a tierra","Un neutro abierto","Resistencia de aislamiento normal","Un conductor sobrecargado"],"rs":"Una resistencia de casi cero entre la fase y el conductor de puesta a tierra significa que están conectados de forma no intencional, lo cual es una falla a tierra. Un aislamiento sano lee una resistencia muy alta."},
  {"id":381,"sec":"Rough Wiring","block":4,"q":"What is the maximum size copper grounding electrode conductor required where the only electrode is a single ground rod?","opts":["4 AWG","8 AWG","6 AWG","2 AWG"],"correct":2,"re":"NEC 250.66(A) states the GEC to a rod electrode is not required to be larger than 6 AWG copper.","qr":"Каков максимальный размер медного проводника заземляющего электрода, требуемый там, где единственным электродом является одиночный заземляющий стержень?","optsr":["4 AWG","8 AWG","6 AWG","2 AWG"],"rr":"NEC 250.66(A) устанавливает, что GEC к стержневому электроду не обязан быть больше 6 AWG из меди.","qs":"¿Cuál es el tamaño máximo de conductor de electrodo de puesta a tierra de cobre requerido cuando el único electrodo es una sola varilla de tierra?","optss":["4 AWG","8 AWG","6 AWG","2 AWG"],"rs":"El NEC 250.66(A) establece que el GEC a un electrodo de varilla no requiere ser mayor que 6 AWG de cobre."},
  {"id":382,"sec":"Planning & Estimation","block":4,"q":"For box-fill calculations under NEC 314.16(B), what volume allowance is assigned to each 14 AWG conductor?","opts":["2.00 in³","1.50 in³","2.25 in³","2.50 in³"],"correct":0,"re":"NEC Table 314.16(B) assigns 2.00 cubic inches per 14 AWG conductor.","qr":"Для расчётов заполнения коробки согласно NEC 314.16(B), какой объём отводится на каждый проводник 14 AWG?","optsr":["2,00 куб. дюйма","1,50 куб. дюйма","2,25 куб. дюйма","2,50 куб. дюйма"],"rr":"NEC, таблица 314.16(B) отводит 2,00 кубических дюйма на каждый проводник 14 AWG.","qs":"Para los cálculos de llenado de caja según el NEC 314.16(B), ¿qué asignación de volumen se asigna a cada conductor 14 AWG?","optss":["2.00 in³","1.50 in³","2.25 in³","2.50 in³"],"rs":"La Tabla 314.16(B) del NEC asigna 2.00 pulgadas cúbicas por conductor 14 AWG."},
  {"id":383,"sec":"Safety","block":4,"q":"An electrician must work on the face of a 480-volt panelboard with exposed live parts on one side and a grounded concrete block wall directly behind; which working-space condition and depth of NEC 110.26(A)(1) applies?","opts":["Condition 1, 3 feet","Condition 3, 4 feet","Condition 2, 3.5 feet","Condition 2, 3 feet"],"correct":2,"re":"For 151-600 V to ground with exposed live parts on one side and grounded parts (concrete) on the other, this is Condition 2, requiring 3.5 feet per NEC Table 110.26(A)(1).","qr":"Электрик должен работать на лицевой стороне распределительного щита 480 вольт с открытыми токоведущими частями с одной стороны и заземлённой бетонной блочной стеной непосредственно сзади; какое условие рабочего пространства и глубина по NEC 110.26(A)(1) применяется?","optsr":["Условие 1, 3 фута","Условие 3, 4 фута","Условие 2, 3,5 фута","Условие 2, 3 фута"],"rr":"Для 151-600 В относительно земли с открытыми токоведущими частями с одной стороны и заземлёнными частями (бетон) с другой это Условие 2, требующее 3,5 фута согласно NEC Таблица 110.26(A)(1).","qs":"Un electricista debe trabajar en la cara de un tablero de 480 voltios con partes vivas expuestas en un lado y una pared de bloques de concreto puesta a tierra directamente detrás; ¿cuál condición y profundidad de espacio de trabajo del NEC 110.26(A)(1) aplica?","optss":["Condición 1, 3 pies","Condición 3, 4 pies","Condición 2, 3.5 pies","Condición 2, 3 pies"],"rs":"Para 151-600 V a tierra con partes vivas expuestas en un lado y partes puestas a tierra (concreto) en el otro, esta es la Condición 2, que requiere 3.5 pies según la Tabla 110.26(A)(1) del NEC."},
  {"id":384,"sec":"Rough Wiring","block":4,"q":"What is the maximum size copper grounding electrode conductor required where the connection is to a concrete-encased electrode?","opts":["4 AWG","6 AWG","8 AWG","3 AWG"],"correct":0,"re":"NEC 250.66(B) states the GEC to a concrete-encased electrode is not required to be larger than 4 AWG copper.","qr":"Каков максимальный размер медного проводника заземляющего электрода, требуемый там, где соединение выполняется с электродом, заключённым в бетон?","optsr":["4 AWG","6 AWG","8 AWG","3 AWG"],"rr":"NEC 250.66(B) устанавливает, что GEC к электроду, заключённому в бетон, не обязан быть больше 4 AWG из меди.","qs":"¿Cuál es el tamaño máximo de conductor de electrodo de puesta a tierra de cobre requerido cuando la conexión es a un electrodo embebido en concreto?","optss":["4 AWG","6 AWG","8 AWG","3 AWG"],"rs":"El NEC 250.66(B) establece que el GEC a un electrodo embebido en concreto no requiere ser mayor que 4 AWG de cobre."},
  {"id":385,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"A 15-amp breaker trips after roughly 10 to 15 minutes of running several appliances, but resets and holds fine when fewer loads are used; this pattern indicates:","opts":["A bolted short circuit","A ground fault","A sustained overload","A defective AFCI sensor"],"correct":2,"re":"Delayed tripping that correlates with the number of loads is the signature of a thermal overload, where current modestly exceeds the rating and heats the bimetal element over time.","qr":"Автомат на 15 А срабатывает примерно через 10–15 минут работы нескольких приборов, но успешно включается и удерживается при меньшем числе нагрузок; такая картина указывает на:","optsr":["Глухое короткое замыкание","Замыкание на землю","Длительную перегрузку","Неисправный датчик AFCI"],"rr":"Задержанное срабатывание, коррелирующее с числом нагрузок, — это признак тепловой перегрузки, когда ток умеренно превышает номинал и со временем нагревает биметаллический элемент.","qs":"Un disyuntor de 15 amperios se dispara después de aproximadamente 10 a 15 minutos de operar varios artefactos, pero se restablece y se mantiene bien cuando se usan menos cargas; este patrón indica:","optss":["Un cortocircuito atornillado","Una falla a tierra","Una sobrecarga sostenida","Un sensor AFCI defectuoso"],"rs":"Un disparo retardado que se correlaciona con el número de cargas es la firma de una sobrecarga térmica, donde la corriente excede modestamente la capacidad y calienta el elemento bimetálico con el tiempo."},
  {"id":386,"sec":"Planning & Estimation","block":4,"q":"What single-conductor volume allowance does NEC Table 314.16(B) assign to a 12 AWG conductor?","opts":["2.25 in³","2.00 in³","2.50 in³","3.00 in³"],"correct":0,"re":"NEC Table 314.16(B) assigns 2.25 cubic inches for each 12 AWG conductor.","qr":"Какой объём для одного проводника NEC, таблица 314.16(B) отводит проводнику 12 AWG?","optsr":["2,25 куб. дюйма","2,00 куб. дюйма","2,50 куб. дюйма","3,00 куб. дюйма"],"rr":"NEC, таблица 314.16(B) отводит 2,25 кубических дюйма на каждый проводник 12 AWG.","qs":"¿Qué asignación de volumen por conductor individual asigna la Tabla 314.16(B) del NEC a un conductor 12 AWG?","optss":["2.25 in³","2.00 in³","2.50 in³","3.00 in³"],"rs":"La Tabla 314.16(B) del NEC asigna 2.25 pulgadas cúbicas por cada conductor 12 AWG."},
  {"id":387,"sec":"Finish Wiring & Trim","block":4,"q":"Which receptacle grade is built to a higher standard for impact, retention force, and durability for demanding applications?","opts":["Residential grade","Standard grade","Decorator grade","Hospital grade"],"correct":3,"re":"Hospital-grade receptacles are constructed to higher standards (identified by a green dot) for greater durability, contact retention, and reliability than residential or standard grades.","qr":"Какой класс розетки изготовлен по более высокому стандарту по ударопрочности, силе удержания и долговечности для требовательных применений?","optsr":["Бытовой класс","Стандартный класс","Декоративный класс","Больничный класс"],"rr":"Розетки больничного класса изготавливаются по более высоким стандартам (обозначены зелёной точкой) для большей долговечности, удержания контакта и надёжности, чем бытовой или стандартный классы.","qs":"¿Cuál grado de receptáculo está construido bajo un estándar más alto de impacto, fuerza de retención y durabilidad para aplicaciones exigentes?","optss":["Grado residencial","Grado estándar","Grado decorativo","Grado hospitalario"],"rs":"Los receptáculos de grado hospitalario están construidos bajo estándares más altos (identificados por un punto verde) para una mayor durabilidad, retención de contacto y confiabilidad que los grados residencial o estándar."},
  {"id":388,"sec":"Safety","block":4,"q":"Per NEC 110.26(C), at least one entrance giving access to and egress from the working space about electrical equipment is required primarily to protect against what hazard?","opts":["Equipment overheating","Unauthorized access by the public","Workers being trapped near energized equipment during an emergency","Moisture intrusion into the panel"],"correct":2,"re":"NEC 110.26(C) entrance/egress requirements ensure a worker can escape quickly from the working space in the event of an arc-flash or other emergency.","qr":"Согласно NEC 110.26(C), как минимум один вход, обеспечивающий доступ и выход из рабочего пространства вокруг электрооборудования, требуется в первую очередь для защиты от какой опасности?","optsr":["Перегрев оборудования","Несанкционированный доступ посторонних","Блокировка работников возле оборудования под напряжением во время аварийной ситуации","Проникновение влаги в щит"],"rr":"Требования NEC 110.26(C) к входу/выходу обеспечивают возможность быстрого покидания рабочего пространства работником в случае дугового разряда или другой аварийной ситуации.","qs":"Según el NEC 110.26(C), se requiere al menos una entrada que dé acceso y salida del espacio de trabajo alrededor del equipo eléctrico principalmente para proteger contra cuál peligro?","optss":["Sobrecalentamiento del equipo","Acceso no autorizado por parte del público","Que los trabajadores queden atrapados cerca de equipo energizado durante una emergencia","Intrusión de humedad en el tablero"],"rs":"Los requisitos de entrada/salida del NEC 110.26(C) aseguran que un trabajador pueda escapar rápidamente del espacio de trabajo en caso de un arco eléctrico u otra emergencia."},
  {"id":389,"sec":"Rough Wiring","block":4,"q":"A grounding electrode conductor that is the sole connection to a single ground rod and is run in free air must be protected if it is smaller than which size?","opts":["8 AWG","10 AWG","4 AWG","6 AWG"],"correct":3,"re":"NEC 250.64(B) permits a 6 AWG or larger copper GEC to be run along the surface without metal protection where not subject to severe physical damage.","qr":"Проводник заземляющего электрода, являющийся единственным соединением с одиночным заземляющим стержнем и проложенный открыто, должен быть защищён, если он меньше какого сечения?","optsr":["8 AWG","10 AWG","4 AWG","6 AWG"],"rr":"NEC 250.64(B) допускает прокладку медного GEC сечением 6 AWG или больше по поверхности без металлической защиты там, где он не подвержен серьёзному механическому повреждению.","qs":"Un conductor de electrodo de puesta a tierra que es la única conexión a una sola varilla de tierra y que se tiende al aire libre debe protegerse si es menor que cuál tamaño?","optss":["8 AWG","10 AWG","4 AWG","6 AWG"],"rs":"El NEC 250.64(B) permite que un GEC de cobre de 6 AWG o mayor se tienda a lo largo de la superficie sin protección metálica donde no esté sujeto a daño físico severo."},
  {"id":390,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"During a thermal imaging survey of an energized panel, one breaker terminal appears significantly hotter than identical adjacent terminals carrying similar current; this hot spot most likely indicates:","opts":["A loose or high-resistance connection","An oversized conductor","A tripped GFCI","A perfectly torqued connection"],"correct":0,"re":"A localized hot spot at a termination usually means a loose or corroded connection creating extra resistance, which generates heat under load and can lead to failure or fire.","qr":"При тепловизионном обследовании работающей панели одна клемма выключателя оказывается значительно горячее идентичных соседних клемм с похожим током; эта горячая точка наиболее вероятно указывает на:","optsr":["Ослабленное или высокоомное соединение","Завышенное сечение проводника","Сработавший GFCI","Идеально затянутое соединение"],"rr":"Локальная горячая точка на соединении обычно означает ослабленное или корродированное соединение, создающее дополнительное сопротивление, которое выделяет тепло под нагрузкой и может привести к отказу или пожару.","qs":"Durante un estudio de imágenes térmicas de un tablero energizado, una terminal de disyuntor aparece significativamente más caliente que las terminales adyacentes idénticas que conducen una corriente similar; este punto caliente indica con mayor probabilidad:","optss":["Una conexión floja o de alta resistencia","Un conductor sobredimensionado","Un GFCI disparado","Una conexión perfectamente torqueada"],"rs":"Un punto caliente localizado en una terminación usualmente significa una conexión floja o corroída que crea resistencia adicional, la cual genera calor bajo carga y puede llevar a una falla o incendio."},
  {"id":391,"sec":"Planning & Estimation","block":4,"q":"A device box contains six 12 AWG current-carrying conductors with no other fill items; what total box volume is required by NEC 314.16(B)?","opts":["12.0 in³","15.0 in³","13.5 in³","18.0 in³"],"correct":2,"re":"Six 12 AWG conductors at 2.25 in³ each equal 13.5 cubic inches per NEC Table 314.16(B).","qr":"Коробка устройства содержит шесть токоведущих проводников 12 AWG без других элементов заполнения; какой общий объём коробки требуется по NEC 314.16(B)?","optsr":["12,0 куб. дюйма","15,0 куб. дюйма","13,5 куб. дюйма","18,0 куб. дюйма"],"rr":"Шесть проводников 12 AWG по 2,25 куб. дюйма каждый составляют 13,5 кубических дюйма согласно NEC, таблица 314.16(B).","qs":"Una caja de dispositivo contiene seis conductores 12 AWG que conducen corriente sin ningún otro elemento de llenado; ¿qué volumen total de caja requiere el NEC 314.16(B)?","optss":["12.0 in³","15.0 in³","13.5 in³","18.0 in³"],"rs":"Seis conductores 12 AWG a 2.25 in³ cada uno equivalen a 13.5 pulgadas cúbicas según la Tabla 314.16(B) del NEC."},
  {"id":392,"sec":"Rough Wiring","block":4,"q":"For a service with 2 AWG copper ungrounded service-entrance conductors, what is the minimum size copper grounding electrode conductor per Table 250.66?","opts":["10 AWG","4 AWG","6 AWG","8 AWG"],"correct":3,"re":"Table 250.66 requires an 8 AWG copper GEC for service conductors of 2 AWG copper.","qr":"Для ввода с незаземлёнными вводными проводниками 2 AWG из меди, каков минимальный размер медного проводника заземляющего электрода согласно таблице 250.66?","optsr":["10 AWG","4 AWG","6 AWG","8 AWG"],"rr":"Таблица 250.66 требует медный GEC сечением 8 AWG для вводных проводников 2 AWG из меди.","qs":"Para una acometida con conductores de acometida no puestos a tierra de cobre 2 AWG, ¿cuál es el tamaño mínimo de conductor de electrodo de puesta a tierra de cobre según la Tabla 250.66?","optss":["10 AWG","4 AWG","6 AWG","8 AWG"],"rs":"La Tabla 250.66 requiere un GEC de cobre 8 AWG para conductores de acometida de cobre 2 AWG."},
  {"id":393,"sec":"Safety","block":4,"q":"Per NEC 110.26(C)(2), for equipment rated 1200 amperes or more and over 6 feet wide, how many entrances to the working space (one at each end) are generally required unless specific exceptions are met?","opts":["No entrance is required","One entrance only","Three entrances","Two entrances"],"correct":3,"re":"NEC 110.26(C)(2) requires two entrances/egress points, one at each end, for large equipment rated 1200 A or more and over 6 feet wide.","qr":"Согласно NEC 110.26(C)(2), для оборудования с номиналом 1200 ампер или более и шириной более 6 футов сколько входов в рабочее пространство (по одному с каждого конца) обычно требуется, если не выполнены особые исключения?","optsr":["Вход не требуется","Только один вход","Три входа","Два входа"],"rr":"NEC 110.26(C)(2) требует два входа/выхода, по одному с каждого конца, для крупного оборудования с номиналом 1200 А или более и шириной более 6 футов.","qs":"Según el NEC 110.26(C)(2), para equipo con capacidad de 1200 amperios o más y de más de 6 pies de ancho, ¿cuántas entradas al espacio de trabajo (una en cada extremo) se requieren generalmente a menos que se cumplan excepciones específicas?","optss":["No se requiere entrada","Solo una entrada","Tres entradas","Dos entradas"],"rs":"El NEC 110.26(C)(2) exige dos puntos de entrada/salida, uno en cada extremo, para equipo grande con capacidad de 1200 A o más y de más de 6 pies de ancho."},
  {"id":394,"sec":"Planning & Estimation","block":4,"q":"Under NEC 314.16(B), how many volume allowances do all the equipment grounding conductors entering a box collectively count as?","opts":["One per grounding conductor","Zero","One, based on the largest grounding conductor","Two total"],"correct":2,"re":"NEC 314.16(B)(5) counts all equipment grounding conductors as a single volume allowance based on the largest such conductor.","qr":"Согласно NEC 314.16(B), сколько объёмных единиц совокупно засчитываются все заземляющие проводники оборудования, входящие в коробку?","optsr":["Одну на каждый заземляющий проводник","Ноль","Одну, по наибольшему заземляющему проводнику","Две всего"],"rr":"NEC 314.16(B)(5) засчитывает все заземляющие проводники оборудования как одну объёмную единицу по наибольшему такому проводнику.","qs":"Según el NEC 314.16(B), ¿cuántas asignaciones de volumen cuentan colectivamente todos los conductores de puesta a tierra de equipos que entran a una caja?","optss":["Una por cada conductor de puesta a tierra","Cero","Una, basada en el conductor de puesta a tierra más grande","Dos en total"],"rs":"El NEC 314.16(B)(5) cuenta todos los conductores de puesta a tierra de equipos como una sola asignación de volumen basada en el conductor más grande de ese tipo."},
  {"id":395,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"When beginning to troubleshoot a dead receptacle, which step should logically be performed FIRST?","opts":["Replace the receptacle","Replace the service panel","Pull new wire to the outlet","Verify the problem and check for a tripped breaker or GFCI"],"correct":3,"re":"Good diagnostic sequence starts by confirming the symptom and checking the simplest, most likely causes first, such as a tripped breaker or upstream GFCI, before invasive work.","qr":"Приступая к поиску неисправности мёртвой розетки, какой шаг логично выполнить ПЕРВЫМ?","optsr":["Заменить розетку","Заменить вводную панель","Протянуть новый провод к розетке","Подтвердить проблему и проверить сработавший автомат или GFCI"],"rr":"Правильная последовательность диагностики начинается с подтверждения симптома и проверки самых простых и вероятных причин, таких как сработавший автомат или вышестоящий GFCI, до сложных работ.","qs":"Al comenzar a diagnosticar un receptáculo muerto, ¿cuál paso debería realizarse lógicamente PRIMERO?","optss":["Reemplazar el receptáculo","Reemplazar el tablero de acometida","Tender cable nuevo hasta la salida","Verificar el problema y revisar si hay un disyuntor o GFCI disparado"],"rs":"Una buena secuencia de diagnóstico comienza confirmando el síntoma y revisando primero las causas más simples y probables, como un disyuntor disparado o un GFCI aguas arriba, antes de un trabajo invasivo."},
  {"id":396,"sec":"Rough Wiring","block":4,"q":"For a service with 1/0 AWG copper ungrounded service-entrance conductors, what is the minimum size copper grounding electrode conductor per Table 250.66?","opts":["8 AWG","6 AWG","4 AWG","2 AWG"],"correct":1,"re":"Table 250.66 requires a 6 AWG copper GEC for service conductors over 2 AWG through 1/0 AWG copper.","qr":"Для ввода с незаземлёнными вводными проводниками 1/0 AWG из меди, каков минимальный размер медного проводника заземляющего электрода согласно таблице 250.66?","optsr":["8 AWG","6 AWG","4 AWG","2 AWG"],"rr":"Таблица 250.66 требует медный GEC сечением 6 AWG для вводных проводников от более чем 2 AWG до 1/0 AWG из меди.","qs":"Para una acometida con conductores de acometida no puestos a tierra de cobre 1/0 AWG, ¿cuál es el tamaño mínimo de conductor de electrodo de puesta a tierra de cobre según la Tabla 250.66?","optss":["8 AWG","6 AWG","4 AWG","2 AWG"],"rs":"La Tabla 250.66 requiere un GEC de cobre 6 AWG para conductores de acometida de cobre mayores que 2 AWG hasta 1/0 AWG."},
  {"id":397,"sec":"Finish Wiring & Trim","block":4,"q":"For storage-type clothes closets, a surface-mounted incandescent or LED luminaire with a completely enclosed lamp must maintain a minimum clearance of how much from the nearest storage space?","opts":["6 inches","18 inches","12 inches","24 inches"],"correct":2,"re":"NEC 410.16(C) requires a minimum 12-in. clearance between a surface-mounted, completely enclosed incandescent/LED luminaire and the nearest point of a closet storage space.","qr":"Для бельевых шкафов поверхностно-монтируемый накаливания или светодиодный светильник с полностью закрытой лампой должен сохранять минимальный зазор сколько от ближайшего пространства хранения?","optsr":["6 дюймов","18 дюймов","12 дюймов","24 дюйма"],"rr":"NEC 410.16(C) требует минимальный зазор 12 дюймов между поверхностно-монтируемым полностью закрытым светильником накаливания/светодиодным и ближайшей точкой пространства хранения шкафа.","qs":"Para los clósets de ropa tipo almacenamiento, una luminaria incandescente o LED montada en superficie con la lámpara completamente cerrada debe mantener una distancia mínima de cuánto desde el espacio de almacenamiento más cercano?","optss":["6 pulgadas","18 pulgadas","12 pulgadas","24 pulgadas"],"rs":"El NEC 410.16(C) exige una distancia mínima de 12 in entre una luminaria incandescente/LED completamente cerrada montada en superficie y el punto más cercano de un espacio de almacenamiento del clóset."},
  {"id":398,"sec":"Safety","block":4,"q":"Per NEC 110.26(D), what must be provided at the working space about service equipment, switchboards, panelboards, and motor control centers installed indoors?","opts":["A fire extinguisher","A grounding mat","Illumination","A telephone"],"correct":2,"re":"NEC 110.26(D) requires that illumination be provided for all working spaces about service equipment, switchboards, panelboards, and motor control centers located indoors.","qr":"Согласно NEC 110.26(D), что должно быть предусмотрено в рабочем пространстве вокруг сервисного оборудования, коммутационных щитов, распределительных щитов и центров управления двигателями, установленных внутри помещений?","optsr":["Огнетушитель","Заземляющий коврик","Освещение","Телефон"],"rr":"NEC 110.26(D) требует, чтобы освещение было предусмотрено для всех рабочих пространств вокруг сервисного оборудования, коммутационных щитов, распределительных щитов и центров управления двигателями, расположенных внутри помещений.","qs":"Según el NEC 110.26(D), ¿qué debe proporcionarse en el espacio de trabajo alrededor del equipo de acometida, cuadros de distribución, tableros y centros de control de motores instalados en interiores?","optss":["Un extintor de incendios","Un tapete de puesta a tierra","Iluminación","Un teléfono"],"rs":"El NEC 110.26(D) exige que se proporcione iluminación para todos los espacios de trabajo alrededor del equipo de acometida, cuadros de distribución, tableros y centros de control de motores ubicados en interiores."},
  {"id":399,"sec":"Planning & Estimation","block":4,"q":"When sizing branch-circuit conductors, the NEC recommends that voltage drop generally not exceed what percentage for the branch circuit alone?","opts":["1%","3%","5%","8%"],"correct":1,"re":"NEC 210.19 Informational Note recommends a maximum 3% voltage drop on a branch circuit, with 5% total for feeder plus branch circuit.","qr":"При выборе сечения проводников ответвления NEC рекомендует, чтобы падение напряжения, как правило, не превышало какого процента только для ответвления?","optsr":["1%","3%","5%","8%"],"rr":"Информационное примечание NEC 210.19 рекомендует максимальное падение напряжения 3% на ответвлении и 5% суммарно для фидера и ответвления.","qs":"Al dimensionar los conductores de un circuito ramal, el NEC recomienda que la caída de voltaje generalmente no exceda qué porcentaje solo para el circuito ramal?","optss":["1%","3%","5%","8%"],"rs":"La Nota Informativa del NEC 210.19 recomienda una caída de voltaje máxima del 3% en un circuito ramal, con un 5% total para el alimentador más el circuito ramal."},
  {"id":400,"sec":"Startup, Troubleshooting & Maintenance","block":4,"q":"On a 120-volt circuit, a voltmeter reads 120 V from hot to ground but 0 V from hot to neutral; this reading most likely indicates:","opts":["A short between hot and neutral","A solid ground fault","A normal, properly working circuit","An open neutral"],"correct":3,"re":"Full voltage to ground but no voltage to neutral means the neutral path is broken; the meter completes the circuit through ground, confirming an open neutral.","qr":"В цепи 120 вольт вольтметр показывает 120 В между фазой и землёй, но 0 В между фазой и нейтралью; это показание наиболее вероятно указывает на:","optsr":["Короткое замыкание между фазой и нейтралью","Глухое замыкание на землю","Нормальную исправно работающую цепь","Обрыв нейтрали"],"rr":"Полное напряжение относительно земли, но отсутствие напряжения относительно нейтрали означает, что путь нейтрали разорван; прибор замыкает цепь через землю, подтверждая обрыв нейтрали.","qs":"En un circuito de 120 voltios, un voltímetro lee 120 V de fase a tierra pero 0 V de fase a neutro; esta lectura indica con mayor probabilidad:","optss":["Un corto entre fase y neutro","Una falla a tierra sólida","Un circuito normal que funciona correctamente","Un neutro abierto"],"rs":"Voltaje pleno a tierra pero sin voltaje a neutro significa que la trayectoria del neutro está interrumpida; el medidor completa el circuito a través de tierra, confirmando un neutro abierto."},
  {"id":401,"sec":"Rough Wiring","block":5,"q":"What is the minimum size copper equipment grounding conductor required for a 15-ampere branch circuit per Table 250.122?","opts":["12 AWG","10 AWG","14 AWG","16 AWG"],"correct":2,"re":"Table 250.122 requires a 14 AWG copper EGC for an overcurrent device rated 15 amperes.","qr":"Каков минимальный размер медного проводника заземления оборудования, требуемый для ответвлённой цепи на 15 ампер согласно таблице 250.122?","optsr":["12 AWG","10 AWG","14 AWG","16 AWG"],"rr":"Таблица 250.122 требует медный EGC сечением 14 AWG для устройства защиты от сверхтока с номиналом 15 ампер.","qs":"¿Cuál es el tamaño mínimo del conductor de puesta a tierra de equipos de cobre requerido para un circuito derivado de 15 amperios según la Tabla 250.122?","optss":["12 AWG","10 AWG","14 AWG","16 AWG"],"rs":"La Tabla 250.122 requiere un EGC de cobre de 14 AWG para un dispositivo de sobrecorriente con clasificación de 15 amperios."},
  {"id":402,"sec":"Planning & Estimation","block":5,"q":"The NEC recommends that the combined voltage drop of the feeder and branch circuit to the farthest outlet not exceed what total percentage?","opts":["3%","5%","8%","10%"],"correct":1,"re":"NEC Informational Notes recommend total voltage drop of feeder plus branch circuit not exceed 5%.","qr":"NEC рекомендует, чтобы суммарное падение напряжения фидера и ответвления до самой дальней точки не превышало какого общего процента?","optsr":["3%","5%","8%","10%"],"rr":"Информационные примечания NEC рекомендуют, чтобы суммарное падение напряжения фидера и ответвления не превышало 5%.","qs":"El NEC recomienda que la caída de tensión combinada del alimentador y el circuito derivado hasta la salida más lejana no exceda qué porcentaje total?","optss":["3%","5%","8%","10%"],"rs":"Las Notas Informativas del NEC recomiendan que la caída de tensión total del alimentador más el circuito derivado no exceda el 5%."},
  {"id":403,"sec":"Safety","block":5,"q":"Per NEC 110.26(B), the working space required in front of electrical equipment must be kept clear and may NOT be used for which purpose?","opts":["Temporary access during installation","Passage of qualified persons","Storage of materials and equipment","Mounting of the required illumination fixture"],"correct":2,"re":"NEC 110.26(B) requires the working space to be clear and prohibits its use for storage; when normally enclosed live parts are exposed, the space must be suitably guarded.","qr":"Согласно NEC 110.26(B), рабочее пространство, требуемое перед электрооборудованием, должно содержаться свободным и НЕ может использоваться для какой цели?","optsr":["Временный доступ во время монтажа","Проход квалифицированных лиц","Хранение материалов и оборудования","Установка требуемого осветительного прибора"],"rr":"NEC 110.26(B) требует, чтобы рабочее пространство было свободным, и запрещает его использование для хранения; когда обычно закрытые токоведущие части открыты, пространство должно быть надлежащим образом защищено.","qs":"Según el NEC 110.26(B), el espacio de trabajo requerido frente al equipo eléctrico debe mantenerse despejado y NO puede usarse para cuál propósito?","optss":["Acceso temporal durante la instalación","Paso de personas calificadas","Almacenamiento de materiales y equipos","Montaje del artefacto de iluminación requerido"],"rs":"El NEC 110.26(B) requiere que el espacio de trabajo esté despejado y prohíbe su uso para almacenamiento; cuando las partes vivas normalmente encerradas quedan expuestas, el espacio debe estar debidamente resguardado."},
  {"id":404,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"In a properly balanced 120/240-volt multiwire branch circuit, the current carried by the shared neutral equals:","opts":["The sum of the two line currents","Twice the larger line current","The difference between the two line currents","Always zero regardless of load"],"correct":2,"re":"When the two ungrounded legs are on opposite phases, the neutral carries only the unbalanced (difference) current, which is why the neutral is shared safely when correctly connected.","qr":"В правильно сбалансированной многопроводной ответвлённой цепи 120/240 вольт ток, протекающий по общей нейтрали, равен:","optsr":["Сумме двух линейных токов","Удвоенному большему линейному току","Разности двух линейных токов","Всегда нулю независимо от нагрузки"],"rr":"Когда две незаземлённые линии находятся на противоположных фазах, нейтраль несёт только небаланс (разность) токов, поэтому при правильном подключении нейтраль можно безопасно использовать совместно.","qs":"En un circuito derivado multiconductor de 120/240 voltios correctamente balanceado, la corriente que transporta el neutro compartido es igual a:","optss":["La suma de las dos corrientes de línea","El doble de la corriente de línea mayor","La diferencia entre las dos corrientes de línea","Siempre cero, independientemente de la carga"],"rs":"Cuando las dos patas no aterrizadas están en fases opuestas, el neutro transporta solo la corriente desbalanceada (la diferencia), por lo que el neutro se comparte de forma segura cuando se conecta correctamente."},
  {"id":405,"sec":"Rough Wiring","block":5,"q":"What is the minimum size copper equipment grounding conductor required for a 20-ampere branch circuit per Table 250.122?","opts":["14 AWG","12 AWG","10 AWG","8 AWG"],"correct":1,"re":"Table 250.122 requires a 12 AWG copper EGC for an overcurrent device rated 20 amperes.","qr":"Каков минимальный размер медного проводника заземления оборудования, требуемый для ответвлённой цепи на 20 ампер согласно таблице 250.122?","optsr":["14 AWG","12 AWG","10 AWG","8 AWG"],"rr":"Таблица 250.122 требует медный EGC сечением 12 AWG для устройства защиты от сверхтока с номиналом 20 ампер.","qs":"¿Cuál es el tamaño mínimo del conductor de puesta a tierra de equipos de cobre requerido para un circuito derivado de 20 amperios según la Tabla 250.122?","optss":["14 AWG","12 AWG","10 AWG","8 AWG"],"rs":"La Tabla 250.122 requiere un EGC de cobre de 12 AWG para un dispositivo de sobrecorriente con clasificación de 20 amperios."},
  {"id":406,"sec":"Finish Wiring & Trim","block":5,"q":"A surface-mounted fluorescent luminaire on the wall or ceiling of a clothes closet must maintain a minimum clearance of how much from the nearest storage space?","opts":["6 inches","3 inches","12 inches","18 inches"],"correct":0,"re":"NEC 410.16(C) permits surface-mounted fluorescent luminaires in clothes closets with a minimum clearance of 6 in. from the nearest point of a storage space.","qr":"Поверхностно-монтируемый люминесцентный светильник на стене или потолке бельевого шкафа должен сохранять минимальный зазор сколько от ближайшего пространства хранения?","optsr":["6 дюймов","3 дюйма","12 дюймов","18 дюймов"],"rr":"NEC 410.16(C) разрешает поверхностно-монтируемые люминесцентные светильники в бельевых шкафах с минимальным зазором 6 дюймов от ближайшей точки пространства хранения.","qs":"Una luminaria fluorescente montada en superficie en la pared o el techo de un clóset de ropa debe mantener un espacio libre mínimo de cuánto desde el espacio de almacenamiento más cercano?","optss":["6 pulgadas","3 pulgadas","12 pulgadas","18 pulgadas"],"rs":"El NEC 410.16(C) permite luminarias fluorescentes montadas en superficie en clósets de ropa con un espacio libre mínimo de 6 in desde el punto más cercano de un espacio de almacenamiento."},
  {"id":407,"sec":"Planning & Estimation","block":5,"q":"Conductor terminations on equipment rated 100 A or less are generally based on which temperature column unless the equipment is listed and marked otherwise?","opts":["75°C","60°C","90°C","105°C"],"correct":1,"re":"Per NEC 110.14(C)(1)(a), terminations for circuits 100 A or less default to the 60°C column unless marked for higher.","qr":"Соединения проводников на оборудовании с номиналом 100 A или менее обычно основываются на какой температурной колонке, если оборудование не сертифицировано и не маркировано иначе?","optsr":["75°C","60°C","90°C","105°C"],"rr":"Согласно NEC 110.14(C)(1)(a), соединения для цепей 100 A или менее по умолчанию используют колонку 60°C, если не маркировано для более высокой.","qs":"Las terminaciones de conductores en equipos con clasificación de 100 A o menos generalmente se basan en cuál columna de temperatura, a menos que el equipo esté listado y marcado de otra manera?","optss":["75°C","60°C","90°C","105°C"],"rs":"Según el NEC 110.14(C)(1)(a), las terminaciones para circuitos de 100 A o menos se basan por defecto en la columna de 60°C, a menos que estén marcadas para una temperatura mayor."},
  {"id":408,"sec":"Rough Wiring","block":5,"q":"What is the minimum size copper equipment grounding conductor required for a 60-ampere circuit per Table 250.122?","opts":["8 AWG","10 AWG","12 AWG","6 AWG"],"correct":1,"re":"Table 250.122 requires a 10 AWG copper EGC for an overcurrent device rated 60 amperes.","qr":"Каков минимальный размер медного проводника заземления оборудования, требуемый для цепи на 60 ампер согласно таблице 250.122?","optsr":["8 AWG","10 AWG","12 AWG","6 AWG"],"rr":"Таблица 250.122 требует медный EGC сечением 10 AWG для устройства защиты от сверхтока с номиналом 60 ампер.","qs":"¿Cuál es el tamaño mínimo del conductor de puesta a tierra de equipos de cobre requerido para un circuito de 60 amperios según la Tabla 250.122?","optss":["8 AWG","10 AWG","12 AWG","6 AWG"],"rs":"La Tabla 250.122 requiere un EGC de cobre de 10 AWG para un dispositivo de sobrecorriente con clasificación de 60 amperios."},
  {"id":409,"sec":"Safety","block":5,"q":"For an overhead service drop of 120/240-volt conductors crossing over a residential driveway not subject to truck traffic, what is the minimum vertical clearance above the driveway required by the NEC?","opts":["10 feet","15 feet","12 feet","18 feet"],"correct":2,"re":"Per NEC 230.24(B), service-drop conductors not exceeding 300 V to ground require 12 feet of clearance over residential property and driveways not subject to truck traffic.","qr":"Для воздушного сервисного ввода проводников 120/240 вольт, пересекающего жилую подъездную дорогу, не подверженную движению грузовиков, каков минимальный вертикальный зазор над подъездной дорогой, требуемый NEC?","optsr":["10 футов","15 футов","12 футов","18 футов"],"rr":"Согласно NEC 230.24(B), проводники сервисного ввода с напряжением не более 300 В относительно земли требуют зазора 12 футов над жилой территорией и подъездными дорогами, не подверженными движению грузовиков.","qs":"Para una acometida aérea de conductores de 120/240 voltios que cruza sobre una entrada de vehículos residencial no sujeta a tráfico de camiones, ¿cuál es el espacio libre vertical mínimo sobre la entrada de vehículos requerido por el NEC?","optss":["10 pies","15 pies","12 pies","18 pies"],"rs":"Según el NEC 230.24(B), los conductores de acometida que no excedan 300 V a tierra requieren 12 pies de espacio libre sobre propiedad residencial y entradas de vehículos no sujetas a tráfico de camiones."},
  {"id":410,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"If pressing the TEST button on a GFCI receptacle does NOT cause it to trip, the correct conclusion is:","opts":["The GFCI is working perfectly","The downstream load is too small","The circuit voltage is too high","The GFCI is defective and should be replaced"],"correct":3,"re":"A GFCI that fails to trip on its TEST button has lost its protective function and must be replaced, since it can no longer interrupt a real ground fault.","qr":"Если нажатие кнопки TEST на розетке GFCI НЕ вызывает её срабатывания, правильный вывод:","optsr":["GFCI работает идеально","Нагрузка ниже по цепи слишком мала","Напряжение цепи слишком высокое","GFCI неисправен и подлежит замене"],"rr":"GFCI, который не срабатывает по своей кнопке TEST, утратил защитную функцию и подлежит замене, так как он больше не может прервать реальное замыкание на землю.","qs":"Si al presionar el botón TEST de un tomacorriente GFCI este NO se dispara, la conclusión correcta es:","optss":["El GFCI funciona perfectamente","La carga aguas abajo es demasiado pequeña","La tensión del circuito es demasiado alta","El GFCI está defectuoso y debe reemplazarse"],"rs":"Un GFCI que no se dispara con su botón TEST ha perdido su función protectora y debe reemplazarse, ya que no puede interrumpir una falla a tierra real."},
  {"id":411,"sec":"Planning & Estimation","block":5,"q":"Even when 90°C-rated conductors are installed, what is the primary permitted use of the 90°C ampacity column in NEC Table 310.16?","opts":["For final termination ampacity","For load calculations only","As the starting ampacity for applying adjustment and correction factors","It cannot be used at all"],"correct":2,"re":"Per NEC 110.14(C), the 90°C column is used as the starting point for derating, but the final ampacity must not exceed the termination temperature rating.","qr":"Даже при установке проводников с номиналом 90°C, каково основное разрешённое назначение колонки ампацитеты 90°C в таблице NEC 310.16?","optsr":["Для итоговой ампацитеты соединения","Только для расчётов нагрузки","Как исходная ампацитета для применения коэффициентов поправки и коррекции","Её вообще нельзя использовать"],"rr":"Согласно NEC 110.14(C), колонка 90°C используется как отправная точка для дерейтинга, но итоговая ампацитета не должна превышать номинал температуры соединения.","qs":"Incluso cuando se instalan conductores con clasificación de 90°C, ¿cuál es el uso principal permitido de la columna de ampacidad de 90°C en la Tabla 310.16 del NEC?","optss":["Para la ampacidad de terminación final","Solo para cálculos de carga","Como ampacidad inicial para aplicar factores de ajuste y corrección","No puede usarse en absoluto"],"rs":"Según el NEC 110.14(C), la columna de 90°C se usa como punto de partida para la reducción (derating), pero la ampacidad final no debe exceder la clasificación de temperatura de la terminación."},
  {"id":412,"sec":"Rough Wiring","block":5,"q":"What is the minimum size copper equipment grounding conductor required for a 100-ampere circuit per Table 250.122?","opts":["10 AWG","8 AWG","6 AWG","4 AWG"],"correct":1,"re":"Table 250.122 requires an 8 AWG copper EGC for an overcurrent device rated 100 amperes.","qr":"Каков минимальный размер медного проводника заземления оборудования, требуемый для цепи на 100 ампер согласно таблице 250.122?","optsr":["10 AWG","8 AWG","6 AWG","4 AWG"],"rr":"Таблица 250.122 требует медный EGC сечением 8 AWG для устройства защиты от сверхтока с номиналом 100 ампер.","qs":"¿Cuál es el tamaño mínimo del conductor de puesta a tierra de equipos de cobre requerido para un circuito de 100 amperios según la Tabla 250.122?","optss":["10 AWG","8 AWG","6 AWG","4 AWG"],"rs":"La Tabla 250.122 requiere un EGC de cobre de 8 AWG para un dispositivo de sobrecorriente con clasificación de 100 amperios."},
  {"id":413,"sec":"Safety","block":5,"q":"Per NEC 230.24(B), what is the minimum vertical clearance for overhead service-drop conductors above a public street, alley, or road subject to truck traffic?","opts":["12 feet","15 feet","22 feet","18 feet"],"correct":3,"re":"NEC 230.24(B)(4) requires 18 feet of clearance over public streets, alleys, roads, and other areas subject to truck traffic.","qr":"Согласно NEC 230.24(B), каков минимальный вертикальный зазор для проводников воздушного сервисного ввода над общественной улицей, переулком или дорогой, подверженной движению грузовиков?","optsr":["12 футов","15 футов","22 фута","18 футов"],"rr":"NEC 230.24(B)(4) требует зазора 18 футов над общественными улицами, переулками, дорогами и другими зонами, подверженными движению грузовиков.","qs":"Según el NEC 230.24(B), ¿cuál es el espacio libre vertical mínimo para los conductores de acometida aérea sobre una calle pública, callejón o camino sujeto a tráfico de camiones?","optss":["12 pies","15 pies","22 pies","18 pies"],"rs":"El NEC 230.24(B)(4) requiere 18 pies de espacio libre sobre calles públicas, callejones, caminos y otras áreas sujetas a tráfico de camiones."},
  {"id":414,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Which maintenance practice best helps prevent loose-connection heating at panel and device terminations over time?","opts":["Periodically retorquing connections to manufacturer specifications","Leaving terminals slightly loose for thermal expansion","Painting all terminals to prevent corrosion","Increasing the breaker size to reduce heat"],"correct":0,"re":"Connections can loosen from thermal cycling and vibration; periodic inspection and retorquing to the specified value keeps resistance low and prevents heat buildup.","qr":"Какая практика обслуживания лучше всего помогает предотвратить нагрев от ослабленных соединений на клеммах панелей и устройств со временем?","optsr":["Периодически перетягивать соединения по спецификациям производителя","Оставлять клеммы слегка ослабленными для теплового расширения","Красить все клеммы для предотвращения коррозии","Увеличивать номинал автомата для снижения нагрева"],"rr":"Соединения могут ослабевать из-за тепловых циклов и вибрации; периодический осмотр и затяжка до заданного значения сохраняют низкое сопротивление и предотвращают накопление тепла.","qs":"¿Cuál práctica de mantenimiento ayuda mejor a prevenir el calentamiento por conexiones flojas en las terminaciones de tableros y dispositivos con el tiempo?","optss":["Reapretar periódicamente las conexiones a las especificaciones del fabricante","Dejar las terminales ligeramente flojas para la expansión térmica","Pintar todas las terminales para prevenir la corrosión","Aumentar el tamaño del interruptor para reducir el calor"],"rs":"Las conexiones pueden aflojarse por los ciclos térmicos y la vibración; la inspección periódica y el reapriete al valor especificado mantienen baja la resistencia y previenen la acumulación de calor."},
  {"id":415,"sec":"Finish Wiring & Trim","block":5,"q":"Which type of luminaire is NOT permitted to be installed in a clothes closet?","opts":["An incandescent luminaire with an open or exposed lamp","Recessed fluorescent fixture","Surface-mounted LED fixture","A completely enclosed surface-mounted incandescent fixture"],"correct":0,"re":"NEC 410.16(B) prohibits incandescent luminaires with open or partially enclosed lamps and pendant luminaires in clothes closets due to fire risk.","qr":"Какой тип светильника НЕ разрешается устанавливать в бельевом шкафу?","optsr":["Светильник накаливания с открытой или незащищённой лампой","Встраиваемый люминесцентный светильник","Поверхностно-монтируемый светодиодный светильник","Полностью закрытый поверхностно-монтируемый светильник накаливания"],"rr":"NEC 410.16(B) запрещает светильники накаливания с открытыми или частично закрытыми лампами и подвесные светильники в бельевых шкафах из-за риска возгорания.","qs":"¿Qué tipo de luminaria NO está permitido instalar en un clóset de ropa?","optss":["Una luminaria incandescente con lámpara abierta o expuesta","Artefacto fluorescente empotrado","Artefacto LED montado en superficie","Un artefacto incandescente montado en superficie completamente cerrado"],"rs":"El NEC 410.16(B) prohíbe las luminarias incandescentes con lámparas abiertas o parcialmente cerradas y las luminarias colgantes en clósets de ropa debido al riesgo de incendio."},
  {"id":416,"sec":"Rough Wiring","block":5,"q":"What is the minimum size copper equipment grounding conductor required for a 40-ampere branch circuit per Table 250.122?","opts":["12 AWG","14 AWG","8 AWG","10 AWG"],"correct":3,"re":"Table 250.122 requires a 10 AWG copper EGC for an overcurrent device rated 40 amperes.","qr":"Каков минимальный размер медного проводника заземления оборудования, требуемый для ответвлённой цепи на 40 ампер согласно таблице 250.122?","optsr":["12 AWG","14 AWG","8 AWG","10 AWG"],"rr":"Таблица 250.122 требует медный EGC сечением 10 AWG для устройства защиты от сверхтока с номиналом 40 ампер.","qs":"¿Cuál es el tamaño mínimo del conductor de puesta a tierra de equipos de cobre requerido para un circuito derivado de 40 amperios según la Tabla 250.122?","optss":["12 AWG","14 AWG","8 AWG","10 AWG"],"rs":"La Tabla 250.122 requiere un EGC de cobre de 10 AWG para un dispositivo de sobrecorriente con clasificación de 40 amperios."},
  {"id":417,"sec":"Planning & Estimation","block":5,"q":"What is the allowable ampacity of a 14 AWG copper conductor at the 60°C column of NEC Table 310.16?","opts":["10 A","15 A","20 A","25 A"],"correct":1,"re":"NEC Table 310.16 lists 14 AWG copper at 15 A in the 60°C column.","qr":"Какова допустимая ампацитета медного проводника 14 AWG в колонке 60°C таблицы NEC 310.16?","optsr":["10 A","15 A","20 A","25 A"],"rr":"Таблица NEC 310.16 указывает 14 AWG медь как 15 A в колонке 60°C.","qs":"¿Cuál es la ampacidad permitida de un conductor de cobre de 14 AWG en la columna de 60°C de la Tabla 310.16 del NEC?","optss":["10 A","15 A","20 A","25 A"],"rs":"La Tabla 310.16 del NEC indica 15 A para el cobre de 14 AWG en la columna de 60°C."},
  {"id":418,"sec":"Safety","block":5,"q":"Per NEC 230.24(A), overhead service-drop conductors must maintain a minimum clearance of how many feet above the roof surface in the general case before any reduced-clearance exceptions apply?","opts":["3 feet","8 feet","6 feet","10 feet"],"correct":1,"re":"NEC 230.24(A) generally requires conductors to have a clearance of not less than 8 feet above the roof surface, with several reduced-clearance exceptions.","qr":"Согласно NEC 230.24(A), проводники воздушного сервисного ввода должны сохранять минимальный зазор скольких футов над поверхностью крыши в общем случае до применения каких-либо исключений с уменьшенным зазором?","optsr":["3 фута","8 футов","6 футов","10 футов"],"rr":"NEC 230.24(A) обычно требует, чтобы проводники имели зазор не менее 8 футов над поверхностью крыши, с несколькими исключениями для уменьшенного зазора.","qs":"Según el NEC 230.24(A), los conductores de acometida aérea deben mantener un espacio libre mínimo de cuántos pies sobre la superficie del techo en el caso general antes de que apliquen las excepciones de espacio libre reducido?","optss":["3 pies","8 pies","6 pies","10 pies"],"rs":"El NEC 230.24(A) generalmente requiere que los conductores tengan un espacio libre no menor a 8 pies sobre la superficie del techo, con varias excepciones de espacio libre reducido."},
  {"id":419,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Two 120-volt receptacle circuits fed from the SAME phase are wired to share one neutral; the most serious consequence is:","opts":["The neutral carries only the difference of the two currents","The grounding conductor becomes energized","The circuits will not energize at all","The shared neutral can be overloaded because the currents add instead of subtract"],"correct":3,"re":"When both hots are on the same phase, neutral currents add rather than cancel, so the single neutral can be forced to carry more than its rated current and overheat.","qr":"Две цепи розеток 120 вольт, питаемые от ОДНОЙ фазы, подключены к одной общей нейтрали; наиболее серьёзное последствие:","optsr":["Нейтраль несёт только разность двух токов","Заземляющий проводник оказывается под напряжением","Цепи вообще не включатся","Общая нейтраль может перегружаться, потому что токи складываются, а не вычитаются"],"rr":"Когда обе фазы на одной фазе, токи нейтрали складываются, а не компенсируются, поэтому единственная нейтраль может быть вынуждена нести ток выше номинала и перегреваться.","qs":"Dos circuitos de tomacorrientes de 120 voltios alimentados desde la MISMA fase se conectan para compartir un neutro; la consecuencia más grave es:","optss":["El neutro transporta solo la diferencia de las dos corrientes","El conductor de puesta a tierra se energiza","Los circuitos no se energizarán en absoluto","El neutro compartido puede sobrecargarse porque las corrientes se suman en lugar de restarse"],"rs":"Cuando ambos conductores vivos están en la misma fase, las corrientes del neutro se suman en lugar de cancelarse, por lo que el único neutro puede verse forzado a transportar más que su corriente nominal y sobrecalentarse."},
  {"id":420,"sec":"Rough Wiring","block":5,"q":"When an equipment grounding conductor is increased in size because the ungrounded conductors were upsized, the EGC must be increased in what manner?","opts":["It does not need to be increased","By exactly one AWG size","Doubled in size","Proportionally to the increase in circular mil area of the ungrounded conductors"],"correct":3,"re":"NEC 250.122(B) requires the EGC to be increased proportionally to the circular mil area increase of the ungrounded conductors.","qr":"Когда проводник заземления оборудования увеличивается в размере из-за увеличения сечения незаземлённых проводников, EGC должен быть увеличен каким образом?","optsr":["Его не нужно увеличивать","Ровно на один размер AWG","Удвоен в размере","Пропорционально увеличению площади в круговых милах незаземлённых проводников"],"rr":"NEC 250.122(B) требует, чтобы EGC был увеличен пропорционально увеличению площади в круговых милах незаземлённых проводников.","qs":"Cuando un conductor de puesta a tierra de equipos se aumenta de tamaño porque los conductores no aterrizados se aumentaron, ¿de qué manera debe aumentarse el EGC?","optss":["No necesita aumentarse","Exactamente un tamaño AWG","Duplicarse en tamaño","Proporcionalmente al aumento del área en mils circulares de los conductores no aterrizados"],"rs":"El NEC 250.122(B) requiere que el EGC se aumente proporcionalmente al aumento del área en mils circulares de los conductores no aterrizados."},
  {"id":421,"sec":"Planning & Estimation","block":5,"q":"A noncontinuous load of 24 A is supplied; selecting the next standard OCPD per NEC 240.6(A), what size overcurrent device is appropriate?","opts":["20 A","35 A","30 A","25 A"],"correct":3,"re":"Per NEC 240.6(A), 25 A is a standard rating and accommodates the 24 A noncontinuous load.","qr":"Питается некратковременная (непостоянная) нагрузка 24 A; выбирая следующий стандартный OCPD по NEC 240.6(A), какой номинал устройства защиты подходит?","optsr":["20 A","35 A","30 A","25 A"],"rr":"Согласно NEC 240.6(A), 25 A является стандартным номиналом и подходит для непостоянной нагрузки 24 A.","qs":"Se alimenta una carga no continua de 24 A; al seleccionar el siguiente OCPD estándar según el NEC 240.6(A), ¿qué tamaño de dispositivo de sobrecorriente es apropiado?","optss":["20 A","35 A","30 A","25 A"],"rs":"Según el NEC 240.6(A), 25 A es una clasificación estándar y acomoda la carga no continua de 24 A."},
  {"id":422,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"An AFCI breaker keeps tripping on a circuit, but a plug-in tester and visual inspection show no ground fault or obvious short; which is a reasonable next troubleshooting step?","opts":["Immediately replace the entire panel","Inspect for damaged cable, loose terminations, or arcing-prone connections on that circuit","Increase the breaker amperage rating","Disconnect the equipment grounding conductor"],"correct":1,"re":"Because AFCIs respond to arcing, repeated trips warrant inspecting for damaged insulation, staples through cable, or loose connections that produce arc signatures.","qr":"Автомат AFCI постоянно срабатывает на цепи, но штекерный тестер и визуальный осмотр не показывают замыкания на землю или явного короткого замыкания; какой разумный следующий шаг поиска неисправности?","optsr":["Немедленно заменить всю панель","Проверить кабель на повреждения, ослабленные соединения или склонные к дуге контакты в этой цепи","Увеличить номинал тока автомата","Отсоединить заземляющий проводник оборудования"],"rr":"Поскольку AFCI реагируют на дугу, повторные срабатывания требуют проверки повреждённой изоляции, скоб, пробивших кабель, или ослабленных соединений, создающих сигнатуры дуги.","qs":"Un interruptor AFCI sigue disparándose en un circuito, pero un probador de enchufe y una inspección visual no muestran falla a tierra ni cortocircuito evidente; ¿cuál es un siguiente paso razonable de diagnóstico?","optss":["Reemplazar inmediatamente todo el tablero","Inspeccionar en busca de cable dañado, terminaciones flojas o conexiones propensas a arqueo en ese circuito","Aumentar la clasificación de amperaje del interruptor","Desconectar el conductor de puesta a tierra de equipos"],"rs":"Dado que los AFCI responden al arqueo, los disparos repetidos justifican inspeccionar en busca de aislamiento dañado, grapas que atraviesen el cable o conexiones flojas que produzcan firmas de arco."},
  {"id":423,"sec":"Safety","block":5,"q":"Per NEC 230.24(B)(1), service-drop conductors limited to 150 volts to ground require a minimum vertical clearance of how many feet above finished grade, sidewalks, or platforms accessible only to pedestrians?","opts":["10 feet","8 feet","12 feet","15 feet"],"correct":0,"re":"NEC 230.24(B)(1) requires 10 feet of clearance above finished grade, sidewalks, or accessible surfaces from which they might be reached, for conductors limited to 150 V to ground.","qr":"Согласно NEC 230.24(B)(1), проводники сервисного ввода, ограниченные 150 вольтами относительно земли, требуют минимального вертикального зазора скольких футов над готовым грунтом, тротуарами или платформами, доступными только пешеходам?","optsr":["10 футов","8 футов","12 футов","15 футов"],"rr":"NEC 230.24(B)(1) требует зазора 10 футов над готовым грунтом, тротуарами или доступными поверхностями, с которых их можно достать, для проводников, ограниченных 150 В относительно земли.","qs":"Según el NEC 230.24(B)(1), los conductores de acometida limitados a 150 voltios a tierra requieren un espacio libre vertical mínimo de cuántos pies sobre el nivel terminado, aceras o plataformas accesibles solo a peatones?","optss":["10 pies","8 pies","12 pies","15 pies"],"rs":"El NEC 230.24(B)(1) requiere 10 pies de espacio libre sobre el nivel terminado, aceras o superficies accesibles desde las cuales podrían alcanzarse, para conductores limitados a 150 V a tierra."},
  {"id":424,"sec":"Rough Wiring","block":5,"q":"When a single equipment grounding conductor is run with multiple circuits in the same raceway, it must be sized based on which overcurrent device?","opts":["The largest overcurrent device protecting conductors in the raceway","The smallest in the group","The average of all devices","The first circuit installed"],"correct":0,"re":"NEC 250.122(C) requires a single EGC for multiple circuits to be sized for the largest overcurrent device in the raceway.","qr":"Когда один проводник заземления оборудования проложен с несколькими цепями в одном кабелепроводе, он должен выбираться на основе какого устройства защиты от сверхтока?","optsr":["Наибольшего устройства защиты от сверхтока, защищающего проводники в кабелепроводе","Наименьшего в группе","Среднего значения всех устройств","Первой установленной цепи"],"rr":"NEC 250.122(C) требует, чтобы один EGC для нескольких цепей выбирался по наибольшему устройству защиты от сверхтока в кабелепроводе.","qs":"Cuando un solo conductor de puesta a tierra de equipos se instala con múltiples circuitos en la misma canalización, debe dimensionarse según cuál dispositivo de sobrecorriente?","optss":["El dispositivo de sobrecorriente más grande que protege los conductores en la canalización","El más pequeño del grupo","El promedio de todos los dispositivos","El primer circuito instalado"],"rs":"El NEC 250.122(C) requiere que un solo EGC para múltiples circuitos se dimensione para el dispositivo de sobrecorriente más grande en la canalización."},
  {"id":425,"sec":"Finish Wiring & Trim","block":5,"q":"A luminaire used as a raceway for circuit conductors is permitted only when it is what?","opts":["Painted to match the ceiling","Installed below 8 ft","Listed and marked for use as a raceway","Rated for wet locations"],"correct":2,"re":"NEC 410.64 permits luminaires to be used as a raceway for circuit conductors only where listed and marked for use as a raceway (or where designed for end-to-end assembly).","qr":"Светильник, используемый как короб (raceway) для проводников цепи, разрешён только когда он какой?","optsr":["Окрашен под цвет потолка","Установлен ниже 8 футов","Сертифицирован и маркирован для использования как короб (raceway)","Рассчитан на мокрые места"],"rr":"NEC 410.64 разрешает использовать светильники как короб (raceway) для проводников цепи только если они сертифицированы и маркированы для использования как короб (или предназначены для торцевой сборки).","qs":"Una luminaria utilizada como canalización para conductores de circuito está permitida solo cuando es qué?","optss":["Pintada para combinar con el techo","Instalada por debajo de 8 ft","Listada y marcada para uso como canalización","Clasificada para ubicaciones húmedas"],"rs":"El NEC 410.64 permite que las luminarias se usen como canalización para conductores de circuito solo cuando están listadas y marcadas para uso como canalización (o cuando están diseñadas para ensamblaje de extremo a extremo)."},
  {"id":426,"sec":"Planning & Estimation","block":5,"q":"A continuous load requires conductors sized at 22 A minimum after the 125% factor; using the 75°C column of Table 310.16, what minimum copper conductor satisfies this 22 A requirement?","opts":["14 AWG","10 AWG","12 AWG","8 AWG"],"correct":1,"re":"In the 75°C column, 12 AWG is 25 A but is limited to 20 A by NEC 240.4(D); 10 AWG at 35 A is the smallest conductor providing at least 22 A.","qr":"Непрерывная нагрузка требует сечения проводников минимум на 22 A после коэффициента 125%; используя колонку 75°C таблицы 310.16, какой минимальный медный проводник удовлетворяет этому требованию 22 A?","optsr":["14 AWG","10 AWG","12 AWG","8 AWG"],"rr":"В колонке 75°C 12 AWG равен 25 A, но ограничен 20 A по NEC 240.4(D); 10 AWG при 35 A — наименьший проводник, обеспечивающий не менее 22 A.","qs":"Una carga continua requiere conductores dimensionados a un mínimo de 22 A después del factor de 125%; usando la columna de 75°C de la Tabla 310.16, ¿qué conductor de cobre mínimo satisface este requisito de 22 A?","optss":["14 AWG","10 AWG","12 AWG","8 AWG"],"rs":"En la columna de 75°C, el 12 AWG es 25 A pero está limitado a 20 A por el NEC 240.4(D); el 10 AWG a 35 A es el conductor más pequeño que proporciona al menos 22 A."},
  {"id":427,"sec":"Rough Wiring","block":5,"q":"The main bonding jumper, which connects the grounded (neutral) conductor to the equipment grounding system, is installed at which location?","opts":["At every subpanel","Only at the service disconnecting means","At the farthest receptacle","At each grounding electrode"],"correct":1,"re":"NEC 250.24(B) and 250.28 require the main bonding jumper to be installed at the service disconnecting means.","qr":"Главная соединительная перемычка, соединяющая заземлённый (нейтральный) проводник с системой заземления оборудования, устанавливается в каком месте?","optsr":["На каждом субпанели","Только на устройстве отключения ввода","На самой дальней розетке","На каждом заземляющем электроде"],"rr":"NEC 250.24(B) и 250.28 требуют, чтобы главная соединительная перемычка устанавливалась на устройстве отключения ввода.","qs":"El puente de unión principal, que conecta el conductor puesto a tierra (neutro) al sistema de puesta a tierra de equipos, se instala en cuál ubicación?","optss":["En cada subtablero","Solo en el medio de desconexión de la acometida","En el tomacorriente más lejano","En cada electrodo de puesta a tierra"],"rs":"El NEC 250.24(B) y 250.28 requieren que el puente de unión principal se instale en el medio de desconexión de la acometida."},
  {"id":428,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"When using a voltmeter to locate an open in a series string of three loads that are all dead, where will the full source voltage appear?","opts":["Across each load equally","Across the open (break) point","Across the grounding conductor","Nowhere, the meter reads zero everywhere"],"correct":1,"re":"In a series circuit with an open, the entire source voltage drops across the break because no current flows, so measuring full voltage across a component reveals the open.","qr":"При использовании вольтметра для поиска обрыва в последовательной цепочке из трёх нагрузок, которые все обесточены, где появится полное напряжение источника?","optsr":["На каждой нагрузке поровну","На точке обрыва (разрыва)","На заземляющем проводнике","Нигде, прибор везде показывает ноль"],"rr":"В последовательной цепи с обрывом всё напряжение источника падает на разрыве, поскольку ток не течёт, поэтому измерение полного напряжения на элементе выявляет обрыв.","qs":"Al usar un voltímetro para localizar una apertura en una cadena en serie de tres cargas que están todas sin energía, ¿dónde aparecerá la tensión completa de la fuente?","optss":["A través de cada carga por igual","A través del punto de apertura (interrupción)","A través del conductor de puesta a tierra","En ningún lugar, el medidor lee cero en todas partes"],"rs":"En un circuito en serie con una apertura, toda la tensión de la fuente cae a través de la interrupción porque no fluye corriente, por lo que medir la tensión completa a través de un componente revela la apertura."},
  {"id":429,"sec":"Safety","block":5,"q":"Treating cover as a safety issue, what is the minimum burial depth required by NEC Table 300.5 for direct-buried UF cable supplying a residential branch circuit of 120 volts or less protected by a 20-ampere GFCI, in a trench with no other protection?","opts":["6 inches","12 inches","18 inches","24 inches"],"correct":1,"re":"NEC Table 300.5 permits 12 inches of cover for residential branch circuits rated 120 V or less and protected by a GFCI at 20 amperes or less.","qr":"Рассматривая глубину укладки как вопрос безопасности, какова минимальная глубина закапывания, требуемая NEC Таблица 300.5 для кабеля UF прямого закапывания, питающего жилую ответвлённую цепь 120 вольт или менее, защищённую 20-амперным GFCI, в траншее без другой защиты?","optsr":["6 дюймов","12 дюймов","18 дюймов","24 дюйма"],"rr":"NEC Таблица 300.5 разрешает глубину укладки 12 дюймов для жилых ответвлённых цепей с номиналом 120 В или менее, защищённых GFCI на 20 ампер или менее.","qs":"Tratando la cobertura como un asunto de seguridad, ¿cuál es la profundidad de enterramiento mínima requerida por la Tabla 300.5 del NEC para cable UF enterrado directamente que alimenta un circuito derivado residencial de 120 voltios o menos protegido por un GFCI de 20 amperios, en una zanja sin otra protección?","optss":["6 pulgadas","12 pulgadas","18 pulgadas","24 pulgadas"],"rs":"La Tabla 300.5 del NEC permite 12 pulgadas de cobertura para circuitos derivados residenciales con clasificación de 120 V o menos y protegidos por un GFCI a 20 amperios o menos."},
  {"id":430,"sec":"Planning & Estimation","block":5,"q":"Per NEC 240.4(D), what is the maximum overcurrent protection generally permitted for a 14 AWG copper conductor regardless of its 90°C ampacity?","opts":["15 A","20 A","25 A","30 A"],"correct":0,"re":"NEC 240.4(D) limits 14 AWG copper to a maximum 15 A overcurrent device.","qr":"Согласно NEC 240.4(D), какова максимальная защита от сверхтока, обычно допускаемая для медного проводника 14 AWG независимо от его ампацитеты при 90°C?","optsr":["15 A","20 A","25 A","30 A"],"rr":"NEC 240.4(D) ограничивает медный проводник 14 AWG максимальным устройством защиты на 15 A.","qs":"Según el NEC 240.4(D), ¿cuál es la protección máxima contra sobrecorriente generalmente permitida para un conductor de cobre de 14 AWG, independientemente de su ampacidad de 90°C?","optss":["15 A","20 A","25 A","30 A"],"rs":"El NEC 240.4(D) limita el cobre de 14 AWG a un dispositivo de sobrecorriente máximo de 15 A."},
  {"id":431,"sec":"Rough Wiring","block":5,"q":"At a subpanel located in a separate enclosure downstream of the service, the neutral (grounded) conductor must be:","opts":["Bonded to the enclosure with a bonding screw","Isolated from the equipment grounding bus and enclosure","Connected to a local ground rod only","Connected to the equipment grounding bus only"],"correct":1,"re":"NEC 250.24(A)(5) prohibits the neutral-to-ground connection on the load side of the service; the neutral must be isolated at a subpanel.","qr":"На субпанели, расположенной в отдельном корпусе ниже по цепи от ввода, нейтральный (заземлённый) проводник должен быть:","optsr":["Соединён с корпусом соединительным винтом","Изолирован от шины заземления оборудования и корпуса","Подключён только к местному заземляющему стержню","Подключён только к шине заземления оборудования"],"rr":"NEC 250.24(A)(5) запрещает соединение нейтрали с землёй на стороне нагрузки от ввода; нейтраль должна быть изолирована на субпанели.","qs":"En un subtablero ubicado en un gabinete separado aguas abajo de la acometida, el conductor neutro (puesto a tierra) debe estar:","optss":["Unido al gabinete con un tornillo de unión","Aislado del bus de puesta a tierra de equipos y del gabinete","Conectado solo a una varilla de tierra local","Conectado solo al bus de puesta a tierra de equipos"],"rs":"El NEC 250.24(A)(5) prohíbe la conexión neutro-tierra en el lado de la carga de la acometida; el neutro debe estar aislado en un subtablero."},
  {"id":432,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Conductors and terminations that feel hot and show discoloration at a receptacle under normal load most commonly result from:","opts":["An open neutral elsewhere","A correctly sized conductor","An undersized or loosely connected conductor","A properly tripped GFCI"],"correct":2,"re":"Heat and discoloration indicate excessive resistance, typically from an undersized conductor or a loose, poorly made connection that dissipates power as heat.","qr":"Проводники и соединения, которые горячие на ощупь и обесцвечены на розетке при нормальной нагрузке, чаще всего возникают из-за:","optsr":["Обрыва нейтрали в другом месте","Правильно подобранного сечения проводника","Недостаточного сечения или ослабленного соединения проводника","Правильно сработавшего GFCI"],"rr":"Нагрев и обесцвечивание указывают на чрезмерное сопротивление, обычно из-за недостаточного сечения проводника или ослабленного, плохо выполненного соединения, рассеивающего мощность в виде тепла.","qs":"Los conductores y terminaciones que se sienten calientes y muestran decoloración en un tomacorriente bajo carga normal resultan más comúnmente de:","optss":["Un neutro abierto en otro lugar","Un conductor correctamente dimensionado","Un conductor subdimensionado o conectado de forma floja","Un GFCI correctamente disparado"],"rs":"El calor y la decoloración indican resistencia excesiva, típicamente por un conductor subdimensionado o una conexión floja y mal hecha que disipa potencia como calor."},
  {"id":433,"sec":"Finish Wiring & Trim","block":5,"q":"A standard incandescent dimmer is generally suitable for controlling which type of load?","opts":["A resistive (incandescent) lighting load","A receptacle outlet load","A standard motor load","A fluorescent ballast not rated for dimming"],"correct":0,"re":"A standard dimmer is designed for resistive incandescent (and listed compatible) lighting loads; it must not be used on motors or non-dimmable ballasts unless specifically rated.","qr":"Стандартный диммер накаливания, как правило, подходит для управления каким типом нагрузки?","optsr":["Резистивная (накаливания) осветительная нагрузка","Нагрузка розетки","Стандартная двигательная нагрузка","Люминесцентный балласт, не рассчитанный на регулировку"],"rr":"Стандартный диммер предназначен для резистивных осветительных нагрузок накаливания (и сертифицированных совместимых); его нельзя использовать на двигателях или нерегулируемых балластах, если он специально не рассчитан на это.","qs":"Un atenuador (dimmer) incandescente estándar es generalmente adecuado para controlar cuál tipo de carga?","optss":["Una carga de iluminación resistiva (incandescente)","Una carga de tomacorriente","Una carga de motor estándar","Un balasto fluorescente no clasificado para atenuación"],"rs":"Un atenuador estándar está diseñado para cargas de iluminación incandescente resistiva (y compatibles listadas); no debe usarse en motores ni balastos no atenuables, a menos que esté específicamente clasificado."},
  {"id":434,"sec":"Planning & Estimation","block":5,"q":"Per NEC 240.4(D), what is the maximum standard overcurrent device permitted to protect a 12 AWG copper conductor?","opts":["15 A","25 A","20 A","30 A"],"correct":2,"re":"NEC 240.4(D) limits 12 AWG copper to a maximum 20 A overcurrent device.","qr":"Согласно NEC 240.4(D), какое максимальное стандартное устройство защиты допускается для защиты медного проводника 12 AWG?","optsr":["15 A","25 A","20 A","30 A"],"rr":"NEC 240.4(D) ограничивает медный проводник 12 AWG максимальным устройством защиты на 20 A.","qs":"Según el NEC 240.4(D), ¿cuál es el dispositivo de sobrecorriente estándar máximo permitido para proteger un conductor de cobre de 12 AWG?","optss":["15 A","25 A","20 A","30 A"],"rs":"El NEC 240.4(D) limita el cobre de 12 AWG a un dispositivo de sobrecorriente máximo de 20 A."},
  {"id":435,"sec":"Safety","block":5,"q":"Per NEC Table 300.5, what is the general minimum burial depth (cover) for direct-buried cables or conductors rated 0-1000 volts where no special permitted reduction applies?","opts":["12 inches","24 inches","18 inches","30 inches"],"correct":1,"re":"NEC Table 300.5 Column 1 specifies 24 inches of cover as the general minimum for direct-buried conductors rated 0-1000 volts.","qr":"Согласно NEC Таблица 300.5, какова общая минимальная глубина закапывания (укрытие) для кабелей или проводников прямого закапывания с номиналом 0-1000 вольт, где не применяется специальное разрешённое уменьшение?","optsr":["12 дюймов","24 дюйма","18 дюймов","30 дюймов"],"rr":"NEC Таблица 300.5 Колонка 1 указывает 24 дюйма укрытия как общий минимум для проводников прямого закапывания с номиналом 0-1000 вольт.","qs":"Según la Tabla 300.5 del NEC, ¿cuál es la profundidad de enterramiento (cobertura) mínima general para cables o conductores enterrados directamente con clasificación de 0-1000 voltios donde no aplica ninguna reducción especial permitida?","optss":["12 pulgadas","24 pulgadas","18 pulgadas","30 pulgadas"],"rs":"La Columna 1 de la Tabla 300.5 del NEC especifica 24 pulgadas de cobertura como el mínimo general para conductores enterrados directamente con clasificación de 0-1000 voltios."},
  {"id":436,"sec":"Rough Wiring","block":5,"q":"The connection between the grounded (neutral) conductor and the equipment grounding conductors is permitted at which single point in a typical service?","opts":["At the meter socket only","At each branch-circuit panelboard","At the main service equipment","At every junction box"],"correct":2,"re":"NEC 250.24(A)(5) limits the neutral-to-ground bond to the service equipment; downstream connections are not permitted.","qr":"Соединение между заземлённым (нейтральным) проводником и проводниками заземления оборудования разрешается в какой единственной точке в типичном вводе?","optsr":["Только в гнезде счётчика","На каждом распределительном щите ответвлённых цепей","На главном вводном оборудовании","В каждой соединительной коробке"],"rr":"NEC 250.24(A)(5) ограничивает соединение нейтрали с землёй вводным оборудованием; соединения ниже по цепи не разрешаются.","qs":"La conexión entre el conductor puesto a tierra (neutro) y los conductores de puesta a tierra de equipos está permitida en cuál punto único en una acometida típica?","optss":["Solo en la base del medidor","En cada tablero de circuitos derivados","En el equipo de acometida principal","En cada caja de empalme"],"rs":"El NEC 250.24(A)(5) limita la unión neutro-tierra al equipo de acometida; las conexiones aguas abajo no están permitidas."},
  {"id":437,"sec":"Planning & Estimation","block":5,"q":"A panelboard supplies a continuous load of 40 A; what minimum OCPD rating is required to satisfy the 125% continuous-load rule?","opts":["50 A","45 A","40 A","60 A"],"correct":0,"re":"40 A × 1.25 = 50 A, and 50 A is a standard rating under NEC 240.6(A).","qr":"Распределительный щит питает непрерывную нагрузку 40 A; какой минимальный номинал OCPD требуется для соблюдения правила 125% непрерывной нагрузки?","optsr":["50 A","45 A","40 A","60 A"],"rr":"40 A × 1,25 = 50 A, и 50 A является стандартным номиналом согласно NEC 240.6(A).","qs":"Un tablero alimenta una carga continua de 40 A; ¿qué clasificación mínima de OCPD se requiere para satisfacer la regla del 125% de carga continua?","optss":["50 A","45 A","40 A","60 A"],"rs":"40 A × 1.25 = 50 A, y 50 A es una clasificación estándar según el NEC 240.6(A)."},
  {"id":438,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"A GFCI protects against shock by comparing the current in which two conductors?","opts":["The hot and the equipment grounding conductor","The two ungrounded legs of a 240-volt circuit","The ungrounded (hot) and the grounded (neutral) conductors","The neutral and the grounding conductor"],"correct":2,"re":"A GFCI continuously compares hot and neutral current; any difference means current is leaking by another path (a ground fault), and it trips at about 5 mA.","qr":"GFCI защищает от поражения током, сравнивая ток в каких двух проводниках?","optsr":["Фазном и заземляющем проводнике оборудования","Двух незаземлённых линиях цепи 240 вольт","Незаземлённом (фазном) и заземлённом (нейтральном) проводниках","Нейтральном и заземляющем проводнике"],"rr":"GFCI постоянно сравнивает ток фазы и нейтрали; любая разница означает, что ток утекает другим путём (замыкание на землю), и он срабатывает примерно при 5 мА.","qs":"Un GFCI protege contra descargas eléctricas comparando la corriente en cuáles dos conductores?","optss":["El vivo y el conductor de puesta a tierra de equipos","Las dos patas no aterrizadas de un circuito de 240 voltios","Los conductores no aterrizado (vivo) y puesto a tierra (neutro)","El neutro y el conductor de puesta a tierra"],"rs":"Un GFCI compara continuamente la corriente del vivo y del neutro; cualquier diferencia significa que hay corriente fugándose por otra trayectoria (una falla a tierra), y se dispara a aproximadamente 5 mA."},
  {"id":439,"sec":"Safety","block":5,"q":"Per NEC Table 300.5, what is the minimum cover for conductors installed in rigid metal conduit (RMC) or intermediate metal conduit (IMC) rated 0-1000 volts buried in a location not subject to vehicular traffic?","opts":["18 inches","12 inches","6 inches","24 inches"],"correct":2,"re":"NEC Table 300.5 Column 3 permits 6 inches of cover for conductors in RMC or IMC, since these raceways provide robust physical protection.","qr":"Согласно NEC Таблица 300.5, каково минимальное укрытие для проводников, установленных в жёсткой металлической трубе (RMC) или промежуточной металлической трубе (IMC) с номиналом 0-1000 вольт, закопанных в месте, не подверженном движению транспорта?","optsr":["18 дюймов","12 дюймов","6 дюймов","24 дюйма"],"rr":"NEC Таблица 300.5 Колонка 3 разрешает укрытие 6 дюймов для проводников в RMC или IMC, поскольку эти трубопроводы обеспечивают надёжную физическую защиту.","qs":"Según la Tabla 300.5 del NEC, ¿cuál es la cobertura mínima para conductores instalados en conduit metálico rígido (RMC) o conduit metálico intermedio (IMC) con clasificación de 0-1000 voltios, enterrados en una ubicación no sujeta a tráfico vehicular?","optss":["18 pulgadas","12 pulgadas","6 pulgadas","24 pulgadas"],"rs":"La Columna 3 de la Tabla 300.5 del NEC permite 6 pulgadas de cobertura para conductores en RMC o IMC, ya que estas canalizaciones proporcionan una protección física robusta."},
  {"id":440,"sec":"Rough Wiring","block":5,"q":"Metal raceways, cable trays, and enclosures used as equipment grounding conductors must be effectively bonded primarily to ensure what?","opts":["Reduced installation cost","A decorative appearance","A low-impedance fault-current path","Increased conductor ampacity"],"correct":2,"re":"NEC 250.4(A)(5) and 250.96 require bonding to provide an effective low-impedance path to clear ground faults.","qr":"Металлические кабелепроводы, кабельные лотки и корпуса, используемые в качестве проводников заземления оборудования, должны быть эффективно соединены прежде всего для обеспечения чего?","optsr":["Снижения стоимости монтажа","Декоративного внешнего вида","Пути тока замыкания с низким сопротивлением","Увеличения допустимой нагрузки проводника"],"rr":"NEC 250.4(A)(5) и 250.96 требуют соединения для обеспечения эффективного пути с низким сопротивлением для устранения замыканий на землю.","qs":"Las canalizaciones metálicas, charolas portacables y gabinetes utilizados como conductores de puesta a tierra de equipos deben estar efectivamente unidos principalmente para asegurar qué?","optss":["Costo de instalación reducido","Una apariencia decorativa","Una trayectoria de corriente de falla de baja impedancia","Mayor ampacidad del conductor"],"rs":"El NEC 250.4(A)(5) y 250.96 requieren la unión para proporcionar una trayectoria efectiva de baja impedancia que despeje las fallas a tierra."},
  {"id":441,"sec":"Planning & Estimation","block":5,"q":"When a single equipment grounding conductor and conductors of different sizes occupy a box, which conductor size determines the volume allowance for that grounding conductor under NEC 314.16(B)(5)?","opts":["The smallest grounding conductor","An average of all conductors","The largest equipment grounding conductor","Always 14 AWG"],"correct":2,"re":"NEC 314.16(B)(5) bases the single grounding-conductor allowance on the largest equipment grounding conductor present.","qr":"Когда один заземляющий проводник оборудования и проводники разных сечений занимают коробку, какое сечение проводника определяет объёмную единицу для этого заземляющего проводника согласно NEC 314.16(B)(5)?","optsr":["Наименьший заземляющий проводник","Среднее всех проводников","Наибольший заземляющий проводник оборудования","Всегда 14 AWG"],"rr":"NEC 314.16(B)(5) основывает единую единицу заземляющего проводника на наибольшем присутствующем заземляющем проводнике оборудования.","qs":"Cuando un solo conductor de puesta a tierra de equipos y conductores de diferentes tamaños ocupan una caja, ¿qué tamaño de conductor determina la asignación de volumen para ese conductor de puesta a tierra según el NEC 314.16(B)(5)?","optss":["El conductor de puesta a tierra más pequeño","Un promedio de todos los conductores","El conductor de puesta a tierra de equipos más grande","Siempre 14 AWG"],"rs":"El NEC 314.16(B)(5) basa la asignación del conductor único de puesta a tierra en el conductor de puesta a tierra de equipos más grande presente."},
  {"id":442,"sec":"Finish Wiring & Trim","block":5,"q":"An occupancy sensor switch used to control lighting based on detected movement most commonly operates on which principle?","opts":["Measuring conductor temperature","Detecting ground faults","Sensing line voltage drop","Passive infrared or ultrasonic motion detection"],"correct":3,"re":"Occupancy sensors typically use passive infrared (PIR), ultrasonic, or dual-technology motion detection to turn lighting on when a space is occupied and off after it is vacant.","qr":"Датчик присутствия, используемый для управления освещением на основе обнаруженного движения, чаще всего работает по какому принципу?","optsr":["Измерение температуры проводника","Обнаружение замыканий на землю","Определение падения напряжения линии","Пассивное инфракрасное или ультразвуковое обнаружение движения"],"rr":"Датчики присутствия обычно используют пассивное инфракрасное (PIR), ультразвуковое или двухтехнологическое обнаружение движения, чтобы включать освещение при наличии людей и выключать после освобождения помещения.","qs":"Un interruptor con sensor de ocupación utilizado para controlar la iluminación según el movimiento detectado opera más comúnmente bajo cuál principio?","optss":["Medición de la temperatura del conductor","Detección de fallas a tierra","Detección de caída de tensión de línea","Detección de movimiento por infrarrojo pasivo o ultrasonido"],"rs":"Los sensores de ocupación típicamente usan detección de movimiento por infrarrojo pasivo (PIR), ultrasonido o tecnología dual para encender la iluminación cuando un espacio está ocupado y apagarla después de que se desocupa."},
  {"id":443,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Which instrument is most appropriate for measuring insulation resistance to confirm a suspected high-resistance short between conductors?","opts":["A clamp-on ammeter","A non-contact voltage detector","A receptacle plug-in tester","An insulation resistance tester (megohmmeter)"],"correct":3,"re":"A megohmmeter applies a high DC test voltage to reveal insulation breakdown and leakage that an ordinary ohmmeter may miss, making it ideal for insulation faults.","qr":"Какой прибор наиболее подходит для измерения сопротивления изоляции, чтобы подтвердить предполагаемое высокоомное замыкание между проводниками?","optsr":["Токоизмерительные клещи","Бесконтактный индикатор напряжения","Штекерный тестер розеток","Тестер сопротивления изоляции (мегомметр)"],"rr":"Мегомметр подаёт высокое испытательное постоянное напряжение для выявления пробоя изоляции и утечки, которые обычный омметр может пропустить, что делает его идеальным для дефектов изоляции.","qs":"¿Cuál instrumento es el más apropiado para medir la resistencia de aislamiento para confirmar un sospechoso cortocircuito de alta resistencia entre conductores?","optss":["Un amperímetro de gancho","Un detector de tensión sin contacto","Un probador de enchufe para tomacorrientes","Un probador de resistencia de aislamiento (megóhmetro)"],"rs":"Un megóhmetro aplica una alta tensión de prueba en CC para revelar la ruptura del aislamiento y las fugas que un óhmetro común podría pasar por alto, lo que lo hace ideal para fallas de aislamiento."},
  {"id":444,"sec":"Rough Wiring","block":5,"q":"Where a metal raceway containing service conductors enters an enclosure with concentric or eccentric knockouts, the connection must be made with:","opts":["A standard locknut only","A plastic bushing only","Tape over the knockout","Bonding-type fittings such as bonding bushings or bonding locknuts"],"correct":3,"re":"NEC 250.92(B) requires bonding-type fittings for service raceways at enclosures with concentric or eccentric knockouts.","qr":"Когда металлический кабелепровод, содержащий вводные проводники, входит в корпус с концентрическими или эксцентрическими выбивными отверстиями, соединение должно выполняться с помощью:","optsr":["Только стандартной контргайки","Только пластиковой втулки","Ленты поверх выбивного отверстия","Соединительной арматуры, такой как соединительные втулки или соединительные контргайки"],"rr":"NEC 250.92(B) требует соединительной арматуры для вводных кабелепроводов на корпусах с концентрическими или эксцентрическими выбивными отверстиями.","qs":"Donde una canalización metálica que contiene conductores de acometida entra a un gabinete con perforaciones (knockouts) concéntricas o excéntricas, la conexión debe hacerse con:","optss":["Solo una contratuerca estándar","Solo un buje plástico","Cinta sobre la perforación","Accesorios tipo unión, como bujes de unión o contratuercas de unión"],"rs":"El NEC 250.92(B) requiere accesorios tipo unión para canalizaciones de acometida en gabinetes con perforaciones concéntricas o excéntricas."},
  {"id":445,"sec":"Safety","block":5,"q":"Per NEC 110.16(A), electrical equipment such as switchboards and panelboards in other than dwelling units that are likely to require examination while energized must be field- or factory-marked to warn of which hazard?","opts":["Electromagnetic interference","Carbon monoxide","Arc flash","Radiation exposure"],"correct":2,"re":"NEC 110.16(A) requires a field- or factory-applied marking warning qualified persons of potential electric arc-flash hazards.","qr":"Согласно NEC 110.16(A), электрооборудование, такое как коммутационные и распределительные щиты в зданиях, кроме жилых, которое может потребовать осмотра под напряжением, должно иметь полевую или заводскую маркировку для предупреждения о какой опасности?","optsr":["Электромагнитные помехи","Угарный газ","Дуговой разряд (arc flash)","Радиационное облучение"],"rr":"NEC 110.16(A) требует полевую или заводскую маркировку, предупреждающую квалифицированных лиц о потенциальной опасности электрического дугового разряда.","qs":"Según el NEC 110.16(A), los equipos eléctricos como tableros de distribución y tableros en lugares distintos a unidades de vivienda que probablemente requieran examinación mientras están energizados deben marcarse en campo o en fábrica para advertir sobre cuál peligro?","optss":["Interferencia electromagnética","Monóxido de carbono","Arco eléctrico (arc flash)","Exposición a radiación"],"rs":"El NEC 110.16(A) requiere una marca aplicada en campo o en fábrica que advierta a las personas calificadas sobre los peligros potenciales de arco eléctrico (arc flash)."},
  {"id":446,"sec":"Planning & Estimation","block":5,"q":"In a box-fill calculation, how many volume allowances does each yoke or strap holding a device (such as a switch or receptacle) count as per NEC 314.16(B)(4)?","opts":["One, based on the largest conductor connected to it","Two, based on the largest conductor connected to it","One per terminal","None"],"correct":1,"re":"NEC 314.16(B)(4) counts each yoke or strap as two volume allowances based on the largest conductor connected to the device.","qr":"В расчёте заполнения коробки сколько объёмных единиц засчитывается на каждое ярмо или планку, удерживающую устройство (например, выключатель или розетку), согласно NEC 314.16(B)(4)?","optsr":["Одну, по наибольшему подключённому проводнику","Две, по наибольшему подключённому проводнику","Одну на каждую клемму","Ни одной"],"rr":"NEC 314.16(B)(4) засчитывает каждое ярмо или планку как две объёмные единицы по наибольшему проводнику, подключённому к устройству.","qs":"En un cálculo de llenado de caja, ¿cuántas asignaciones de volumen cuenta cada yugo o brida que sostiene un dispositivo (como un interruptor o tomacorriente) según el NEC 314.16(B)(4)?","optss":["Una, basada en el conductor más grande conectado a él","Dos, basadas en el conductor más grande conectado a él","Una por terminal","Ninguna"],"rs":"El NEC 314.16(B)(4) cuenta cada yugo o brida como dos asignaciones de volumen basadas en el conductor más grande conectado al dispositivo."},
  {"id":447,"sec":"Rough Wiring","block":5,"q":"A bonding jumper used on the supply side of the service (a supply-side bonding jumper) is sized based on which table?","opts":["Table 250.122","Table 310.16","Table 250.66","Table 300.5"],"correct":2,"re":"NEC 250.102(C) sizes supply-side bonding jumpers using Table 250.66 based on the service conductor size.","qr":"Соединительная перемычка, используемая на стороне питания ввода (соединительная перемычка стороны питания), выбирается на основе какой таблицы?","optsr":["Таблицы 250.122","Таблицы 310.16","Таблицы 250.66","Таблицы 300.5"],"rr":"NEC 250.102(C) выбирает соединительные перемычки стороны питания по таблице 250.66 на основе размера вводного проводника.","qs":"Un puente de unión utilizado en el lado de alimentación de la acometida (un puente de unión del lado de alimentación) se dimensiona según cuál tabla?","optss":["Tabla 250.122","Tabla 310.16","Tabla 250.66","Tabla 300.5"],"rs":"El NEC 250.102(C) dimensiona los puentes de unión del lado de alimentación usando la Tabla 250.66 según el tamaño del conductor de acometida."},
  {"id":448,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Before taking resistance measurements with an ohmmeter to find an open or short, the circuit must be:","opts":["Fully energized at rated voltage","Loaded to full nameplate current","Connected to a running generator","De-energized and verified dead"],"correct":3,"re":"Ohmmeters supply their own test current and can be damaged or give false readings if applied to a live circuit, so the circuit must be de-energized and confirmed dead first.","qr":"Перед измерением сопротивления омметром для поиска обрыва или замыкания цепь должна быть:","optsr":["Полностью под номинальным напряжением","Нагружена до полного паспортного тока","Подключена к работающему генератору","Обесточена и проверена на отсутствие напряжения"],"rr":"Омметры подают собственный испытательный ток и могут быть повреждены или дать ложные показания при подключении к цепи под напряжением, поэтому цепь сначала должна быть обесточена и проверена на отсутствие напряжения.","qs":"Antes de tomar mediciones de resistencia con un óhmetro para encontrar una apertura o un cortocircuito, el circuito debe estar:","optss":["Totalmente energizado a la tensión nominal","Cargado a la corriente plena de placa","Conectado a un generador en funcionamiento","Desenergizado y verificado sin tensión"],"rs":"Los óhmetros suministran su propia corriente de prueba y pueden dañarse o dar lecturas falsas si se aplican a un circuito vivo, por lo que el circuito debe estar desenergizado y confirmado sin tensión primero."},
  {"id":449,"sec":"Safety","block":5,"q":"Per NEC 110.24(A), service equipment in other than dwelling units must be legibly field-marked with which of the following pieces of information?","opts":["The installer's contractor license number","The total connected load in kVA","The date of the next inspection","The maximum available fault current"],"correct":3,"re":"NEC 110.24(A) requires service equipment to be field-marked with the maximum available fault current, including the date the calculation was performed.","qr":"Согласно NEC 110.24(A), сервисное оборудование в зданиях, кроме жилых, должно иметь разборчивую полевую маркировку с какой из следующих частей информации?","optsr":["Номер лицензии подрядчика-установщика","Общая подключённая нагрузка в кВА","Дата следующей проверки","Максимальный доступный ток короткого замыкания"],"rr":"NEC 110.24(A) требует, чтобы сервисное оборудование имело полевую маркировку с максимальным доступным током короткого замыкания, включая дату выполнения расчёта.","qs":"Según el NEC 110.24(A), el equipo de acometida en lugares distintos a unidades de vivienda debe marcarse de forma legible en campo con cuál de la siguiente información?","optss":["El número de licencia de contratista del instalador","La carga total conectada en kVA","La fecha de la próxima inspección","La máxima corriente de falla disponible"],"rs":"El NEC 110.24(A) requiere que el equipo de acometida se marque en campo con la máxima corriente de falla disponible, incluyendo la fecha en que se realizó el cálculo."},
  {"id":450,"sec":"Rough Wiring","block":5,"q":"Which condition allows a reducing washer to be relied upon as the sole bonding means for a service raceway?","opts":["None; reducing washers are not permitted as the sole bonding means for service raceways","When the conductor is copper","When it is painted","When the raceway is PVC"],"correct":0,"re":"NEC 250.92(B) does not permit standard reducing washers as the bonding means for service raceways; listed bonding devices are required.","qr":"Какое условие позволяет полагаться на переходную шайбу как единственное средство соединения для вводного кабелепровода?","optsr":["Никакое; переходные шайбы не допускаются как единственное средство соединения для вводных кабелепроводов","Когда проводник медный","Когда она окрашена","Когда кабелепровод из ПВХ"],"rr":"NEC 250.92(B) не допускает стандартные переходные шайбы в качестве средства соединения для вводных кабелепроводов; требуются сертифицированные соединительные устройства.","qs":"¿Cuál condición permite que una arandela reductora se utilice como el único medio de unión para una canalización de acometida?","optss":["Ninguna; las arandelas reductoras no están permitidas como único medio de unión para canalizaciones de acometida","Cuando el conductor es de cobre","Cuando está pintada","Cuando la canalización es de PVC"],"rs":"El NEC 250.92(B) no permite las arandelas reductoras estándar como medio de unión para canalizaciones de acometida; se requieren dispositivos de unión listados."},
  {"id":451,"sec":"Planning & Estimation","block":5,"q":"All internal cable clamps present in a box collectively count as how many volume allowances under NEC 314.16(B)(2)?","opts":["One per clamp","Two total","One, based on the largest conductor in the box","Zero"],"correct":2,"re":"NEC 314.16(B)(2) counts all cable clamps together as a single volume allowance based on the largest conductor present.","qr":"Все внутренние кабельные зажимы в коробке совокупно засчитываются как сколько объёмных единиц согласно NEC 314.16(B)(2)?","optsr":["Одну на каждый зажим","Две всего","Одну, по наибольшему проводнику в коробке","Ноль"],"rr":"NEC 314.16(B)(2) засчитывает все кабельные зажимы вместе как одну объёмную единицу по наибольшему присутствующему проводнику.","qs":"Todas las abrazaderas internas para cable presentes en una caja cuentan colectivamente como cuántas asignaciones de volumen según el NEC 314.16(B)(2)?","optss":["Una por abrazadera","Dos en total","Una, basada en el conductor más grande de la caja","Cero"],"rs":"El NEC 314.16(B)(2) cuenta todas las abrazaderas para cable juntas como una sola asignación de volumen basada en el conductor más grande presente."},
  {"id":452,"sec":"Finish Wiring & Trim","block":5,"q":"Many modern electronic dimmers and occupancy sensors require which conductor to be present in the switch box to power their internal electronics?","opts":["A second ungrounded conductor","A bonding jumper only","An isolated ground conductor","A grounded (neutral) conductor"],"correct":3,"re":"Many electronic dimmers and sensors require a grounded (neutral) conductor at the device to power their electronics; NEC 404.2(C) generally requires a neutral at switch locations to support such devices.","qr":"Многие современные электронные диммеры и датчики присутствия требуют наличия какого проводника в коробке выключателя для питания их внутренней электроники?","optsr":["Второго незаземлённого проводника","Только перемычки выравнивания потенциалов","Изолированного заземляющего проводника","Заземлённого (нейтрального) проводника"],"rr":"Многие электронные диммеры и датчики требуют заземлённый (нейтральный) проводник у устройства для питания электроники; NEC 404.2(C) обычно требует нейтраль в местах выключателей для поддержки таких устройств.","qs":"Muchos atenuadores electrónicos y sensores de ocupación modernos requieren que cuál conductor esté presente en la caja del interruptor para alimentar su electrónica interna?","optss":["Un segundo conductor no aterrizado","Solo un puente de unión","Un conductor de tierra aislada","Un conductor puesto a tierra (neutro)"],"rs":"Muchos atenuadores electrónicos y sensores requieren un conductor puesto a tierra (neutro) en el dispositivo para alimentar su electrónica; el NEC 404.2(C) generalmente requiere un neutro en las ubicaciones de interruptores para soportar tales dispositivos."},
  {"id":453,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"A homeowner reports that a GFCI breaker trips only when it rains and an outdoor cord is plugged in; the most probable cause is:","opts":["A simple thermal overload","Moisture causing current leakage to ground","A reversed line and load connection only","An undersized service panel"],"correct":1,"re":"Weather-correlated GFCI tripping typically results from water intrusion creating a small leakage current to ground that exceeds the 5 mA trip threshold.","qr":"Домовладелец сообщает, что автомат GFCI срабатывает только во время дождя, когда подключён уличный удлинитель; наиболее вероятная причина:","optsr":["Простая тепловая перегрузка","Влага, вызывающая утечку тока на землю","Только перепутанное подключение линии и нагрузки","Недостаточный размер вводной панели"],"rr":"Срабатывание GFCI, связанное с погодой, обычно вызвано попаданием воды, создающим небольшой ток утечки на землю, превышающий порог срабатывания 5 мА.","qs":"Un propietario reporta que un interruptor GFCI se dispara solo cuando llueve y hay un cable de extensión exterior conectado; la causa más probable es:","optss":["Una simple sobrecarga térmica","Humedad que causa fuga de corriente a tierra","Solo una conexión invertida de línea y carga","Un tablero de acometida subdimensionado"],"rs":"El disparo de un GFCI correlacionado con el clima típicamente resulta de la intrusión de agua que crea una pequeña corriente de fuga a tierra que excede el umbral de disparo de 5 mA."},
  {"id":454,"sec":"Safety","block":5,"q":"Per NEC 110.22(A), each disconnecting means must be legibly marked to indicate its purpose unless what condition is true?","opts":["It is rated less than 100 amperes","It is installed by a licensed electrician","It is located within sight of the equipment it controls and the purpose is evident","It is a molded-case circuit breaker"],"correct":2,"re":"NEC 110.22(A) requires each disconnecting means to be legibly marked to identify its purpose unless located and arranged so the purpose is evident.","qr":"Согласно NEC 110.22(A), каждое отключающее устройство должно иметь разборчивую маркировку с указанием его назначения, если не выполняется какое условие?","optsr":["Оно рассчитано менее чем на 100 ампер","Оно установлено лицензированным электриком","Оно расположено в зоне видимости оборудования, которым управляет, и назначение очевидно","Это автоматический выключатель в литом корпусе"],"rr":"NEC 110.22(A) требует, чтобы каждое отключающее устройство имело разборчивую маркировку для идентификации его назначения, если оно не расположено и не устроено так, что назначение очевидно.","qs":"Según el NEC 110.22(A), cada medio de desconexión debe marcarse de forma legible para indicar su propósito, a menos que cuál condición sea verdadera?","optss":["Tiene una clasificación menor a 100 amperios","Está instalado por un electricista licenciado","Está ubicado a la vista del equipo que controla y el propósito es evidente","Es un interruptor de caja moldeada"],"rs":"El NEC 110.22(A) requiere que cada medio de desconexión se marque de forma legible para identificar su propósito, a menos que esté ubicado y dispuesto de manera que el propósito sea evidente."},
  {"id":455,"sec":"Rough Wiring","block":5,"q":"What is the minimum burial depth for direct-buried UF cable or conductors rated 0 to 1000 volts under a residential lawn, per Table 300.5?","opts":["12 in","18 in","24 in","6 in"],"correct":2,"re":"Table 300.5 Column 1 requires 24 in of cover for direct-buried cables and conductors not in raceway.","qr":"Какова минимальная глубина закладки для кабеля UF или проводников прямого заложения, рассчитанных на 0–1000 вольт, под жилой лужайкой согласно таблице 300.5?","optsr":["12 дюймов","18 дюймов","24 дюйма","6 дюймов"],"rr":"Таблица 300.5, столбец 1, требует 24 дюйма покрытия для кабелей и проводников прямого заложения не в кабелепроводе.","qs":"¿Cuál es la profundidad de enterramiento mínima para cable UF enterrado directamente o conductores con clasificación de 0 a 1000 voltios bajo un césped residencial, según la Tabla 300.5?","optss":["12 in","18 in","24 in","6 in"],"rs":"La Columna 1 de la Tabla 300.5 requiere 24 in de cobertura para cables y conductores enterrados directamente que no estén en canalización."},
  {"id":456,"sec":"Planning & Estimation","block":5,"q":"Which estimating term refers to the itemized list of all materials, devices, and fittings counted from the plans needed to complete a job?","opts":["Material takeoff","Labor unit","Overhead allocation","Change order"],"correct":0,"re":"A material takeoff is the itemized count of materials and devices derived from the construction documents.","qr":"Какой термин оценки обозначает детализированный перечень всех материалов, устройств и фитингов, подсчитанных по чертежам, необходимых для завершения работы?","optsr":["Ведомость материалов (material takeoff)","Трудовая единица (labor unit)","Распределение накладных расходов","Изменение заказа (change order)"],"rr":"Material takeoff — это детализированный подсчёт материалов и устройств, полученный из строительной документации.","qs":"¿Cuál término de estimación se refiere a la lista detallada de todos los materiales, dispositivos y accesorios contados a partir de los planos necesarios para completar un trabajo?","optss":["Despiece de materiales (takeoff)","Unidad de mano de obra","Asignación de gastos generales","Orden de cambio"],"rs":"Un despiece de materiales (takeoff) es el conteo detallado de materiales y dispositivos derivado de los documentos de construcción."},
  {"id":457,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Excessive voltage drop on a long branch-circuit run is best reduced by:","opts":["Increasing the conductor size (larger wire gauge)","Installing a larger overcurrent device","Adding more loads to the circuit","Lowering the supply voltage"],"correct":0,"re":"Voltage drop is proportional to conductor resistance and length; increasing wire size lowers resistance and reduces the drop for a given current.","qr":"Чрезмерное падение напряжения на длинной ответвлённой цепи лучше всего уменьшить путём:","optsr":["Увеличения сечения проводника (большего калибра провода)","Установки более крупного аппарата защиты от сверхтока","Добавления нагрузок в цепь","Снижения напряжения питания"],"rr":"Падение напряжения пропорционально сопротивлению и длине проводника; увеличение сечения провода снижает сопротивление и уменьшает падение при данном токе.","qs":"La caída de tensión excesiva en un tramo largo de circuito derivado se reduce mejor:","optss":["Aumentando el tamaño del conductor (calibre de cable más grande)","Instalando un dispositivo de sobrecorriente más grande","Agregando más cargas al circuito","Disminuyendo la tensión de alimentación"],"rs":"La caída de tensión es proporcional a la resistencia y la longitud del conductor; aumentar el tamaño del cable reduce la resistencia y disminuye la caída para una corriente dada."},
  {"id":458,"sec":"Rough Wiring","block":5,"q":"What is the minimum burial depth for conductors installed in rigid nonmetallic conduit (PVC) approved for direct burial, 0 to 1000 volts, per Table 300.5?","opts":["18 in","24 in","6 in","12 in"],"correct":0,"re":"Table 300.5 Column 4 requires 18 in of cover for conductors in nonmetallic raceways listed for direct burial.","qr":"Какова минимальная глубина закладки для проводников, проложенных в жёстком неметаллическом кабелепроводе (ПВХ), одобренном для прямого заложения, 0–1000 вольт, согласно таблице 300.5?","optsr":["18 дюймов","24 дюйма","6 дюймов","12 дюймов"],"rr":"Таблица 300.5, столбец 4, требует 18 дюймов покрытия для проводников в неметаллических кабелепроводах, сертифицированных для прямого заложения.","qs":"¿Cuál es la profundidad de enterramiento mínima para conductores instalados en conduit rígido no metálico (PVC) aprobado para enterramiento directo, de 0 a 1000 voltios, según la Tabla 300.5?","optss":["18 in","24 in","6 in","12 in"],"rs":"La Columna 4 de la Tabla 300.5 requiere 18 in de cobertura para conductores en canalizaciones no metálicas listadas para enterramiento directo."},
  {"id":459,"sec":"Safety","block":5,"q":"Per NEC 408.4(A), each circuit and circuit modification in a panelboard must be legibly identified as to its clear, evident, and specific purpose by which means?","opts":["A diagram taped to the nearest wall","A circuit directory located on the face or inside of the panel door","A verbal explanation to the building owner","A label on the main service conductors only"],"correct":1,"re":"NEC 408.4(A) requires a circuit directory or circuit identification located on the face or inside of the panel door, supporting safe identification of disconnects.","qr":"Согласно NEC 408.4(A), каждая цепь и модификация цепи в распределительном щите должна быть разборчиво идентифицирована по её ясному, очевидному и конкретному назначению каким способом?","optsr":["Схема, приклеенная к ближайшей стене","Каталог цепей, расположенный на лицевой стороне или внутри дверцы щита","Устное объяснение владельцу здания","Этикетка только на главных сервисных проводниках"],"rr":"NEC 408.4(A) требует каталог цепей или идентификацию цепей, расположенную на лицевой стороне или внутри дверцы щита, что поддерживает безопасную идентификацию отключающих устройств.","qs":"Según el NEC 408.4(A), cada circuito y modificación de circuito en un tablero debe identificarse de forma legible en cuanto a su propósito claro, evidente y específico mediante cuál medio?","optss":["Un diagrama pegado en la pared más cercana","Un directorio de circuitos ubicado en la cara o el interior de la puerta del tablero","Una explicación verbal al propietario del edificio","Una etiqueta solo en los conductores de acometida principal"],"rs":"El NEC 408.4(A) requiere un directorio de circuitos o identificación de circuitos ubicado en la cara o el interior de la puerta del tablero, lo que apoya la identificación segura de las desconexiones."},
  {"id":460,"sec":"Planning & Estimation","block":5,"q":"In electrical estimating, a 'labor unit' most directly represents which of the following?","opts":["The price of a material item","The total project overhead","The estimated time to install a specific item","The markup percentage on materials"],"correct":2,"re":"A labor unit is the standardized estimated installation time (often in hours) assigned to installing a particular item.","qr":"В электротехнической оценке 'трудовая единица' (labor unit) наиболее непосредственно представляет что из следующего?","optsr":["Цену материала","Общие накладные расходы проекта","Расчётное время на установку конкретного элемента","Процент наценки на материалы"],"rr":"Labor unit — это стандартизированное расчётное время установки (часто в часах), назначенное для монтажа определённого элемента.","qs":"En la estimación eléctrica, una 'unidad de mano de obra' representa más directamente cuál de las siguientes opciones?","optss":["El precio de un artículo de material","Los gastos generales totales del proyecto","El tiempo estimado para instalar un artículo específico","El porcentaje de recargo sobre los materiales"],"rs":"Una unidad de mano de obra es el tiempo de instalación estimado estandarizado (a menudo en horas) asignado a la instalación de un artículo en particular."},
  {"id":461,"sec":"Finish Wiring & Trim","block":5,"q":"When terminating a 12 AWG conductor under a device screw, the connection should be tightened to what guideline?","opts":["As tight as possible with maximum force","Until the screw head strips","Hand-tight only with no tool","To the manufacturer's specified torque value"],"correct":3,"re":"NEC 110.14(D) requires that terminations be tightened to the torque value specified by the manufacturer, typically using a calibrated torque tool, to ensure a reliable connection.","qr":"При подключении проводника 12 AWG под винт устройства соединение следует затягивать согласно какому правилу?","optsr":["Как можно туже с максимальным усилием","Пока головка винта не сорвётся","Только от руки без инструмента","До указанного производителем значения момента затяжки"],"rr":"NEC 110.14(D) требует, чтобы соединения затягивались до значения момента, указанного производителем, обычно с использованием калиброванного динамометрического инструмента, для обеспечения надёжного соединения.","qs":"Al terminar un conductor de 12 AWG bajo el tornillo de un dispositivo, la conexión debe apretarse según cuál pauta?","optss":["Lo más apretado posible con la máxima fuerza","Hasta que la cabeza del tornillo se barra","Solo apretado a mano sin herramienta","Al valor de torque especificado por el fabricante"],"rs":"El NEC 110.14(D) requiere que las terminaciones se aprieten al valor de torque especificado por el fabricante, típicamente usando una herramienta de torque calibrada, para asegurar una conexión confiable."},
  {"id":462,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"While the breaker handle stays in the ON position but no power reaches the circuit, the most appropriate first measurement is:","opts":["Resistance of the load with power on","The torque on the neutral bar screws","Insulation resistance of the panel enclosure","Voltage at the breaker's load terminal to neutral"],"correct":3,"re":"Measuring voltage at the breaker output tells you whether the breaker is actually delivering power, which logically separates a faulty breaker from a downstream wiring problem.","qr":"Хотя рукоятка автомата остаётся в положении ON, но питание не доходит до цепи, наиболее подходящее первое измерение:","optsr":["Сопротивления нагрузки при включённом питании","Момента затяжки винтов нейтральной шины","Сопротивления изоляции корпуса панели","Напряжения на выходной клемме автомата относительно нейтрали"],"rr":"Измерение напряжения на выходе автомата показывает, действительно ли автомат подаёт питание, что логически отделяет неисправный автомат от проблемы в проводке ниже по цепи.","qs":"Mientras la palanca del interruptor permanece en la posición ON pero no llega energía al circuito, la primera medición más apropiada es:","optss":["La resistencia de la carga con energía aplicada","El torque en los tornillos de la barra de neutro","La resistencia de aislamiento del gabinete del tablero","La tensión en la terminal de carga del interruptor a neutro"],"rs":"Medir la tensión en la salida del interruptor le indica si el interruptor está realmente entregando energía, lo que separa lógicamente un interruptor defectuoso de un problema de cableado aguas abajo."},
  {"id":463,"sec":"Rough Wiring","block":5,"q":"What is the minimum cover for a residential branch circuit rated 120 volts or less and 20 amperes or less, GFCI-protected, per Table 300.5?","opts":["24 in","18 in","6 in","12 in"],"correct":2,"re":"Table 300.5 Column 5 permits 6 in of cover for residential 120-volt, 20-ampere or less GFCI-protected circuits.","qr":"Каково минимальное покрытие для жилой ответвлённой цепи, рассчитанной на 120 вольт или менее и 20 ампер или менее, защищённой GFCI, согласно таблице 300.5?","optsr":["24 дюйма","18 дюймов","6 дюймов","12 дюймов"],"rr":"Таблица 300.5, столбец 5, допускает 6 дюймов покрытия для жилых цепей на 120 вольт, 20 ампер или менее, защищённых GFCI.","qs":"¿Cuál es la cobertura mínima para un circuito derivado residencial con clasificación de 120 voltios o menos y 20 amperios o menos, protegido por GFCI, según la Tabla 300.5?","optss":["24 in","18 in","6 in","12 in"],"rs":"La Columna 5 de la Tabla 300.5 permite 6 in de cobertura para circuitos residenciales de 120 voltios, 20 amperios o menos protegidos por GFCI."},
  {"id":464,"sec":"Planning & Estimation","block":5,"q":"Voltage drop in a single-phase circuit is directly proportional to which combination of factors?","opts":["Conductor cross-sectional area only","Conduit fill percentage","Voltage and conductor insulation rating","Current and one-way circuit length"],"correct":3,"re":"Single-phase voltage drop increases with both the load current and the circuit length (VD = 2 × K × I × L / CM).","qr":"Падение напряжения в однофазной цепи прямо пропорционально какой комбинации факторов?","optsr":["Только площади сечения проводника","Проценту заполнения кабелепровода","Напряжению и классу изоляции проводника","Току и длине цепи в одну сторону"],"rr":"Однофазное падение напряжения растёт с увеличением как тока нагрузки, так и длины цепи (VD = 2 × K × I × L / CM).","qs":"La caída de tensión en un circuito monofásico es directamente proporcional a cuál combinación de factores?","optss":["Solo el área de la sección transversal del conductor","El porcentaje de llenado del conduit","La tensión y la clasificación de aislamiento del conductor","La corriente y la longitud de un solo sentido del circuito"],"rs":"La caída de tensión monofásica aumenta tanto con la corriente de carga como con la longitud del circuito (VD = 2 × K × I × L / CM)."},
  {"id":465,"sec":"Safety","block":5,"q":"When taking voltage measurements on a 480-volt three-phase distribution panel inside a commercial building, which measurement category (CAT) rating should the digital multimeter and its leads have at minimum?","opts":["CAT I","CAT II","CAT III","CAT 0"],"correct":2,"re":"CAT III is the minimum rating for measurements on fixed installations such as distribution panels and branch circuits in commercial buildings; CAT IV is used at the service entrance.","qr":"При измерении напряжения на трёхфазном распределительном щите 480 вольт внутри коммерческого здания, какую категорию измерений (CAT) должны иметь цифровой мультиметр и его щупы как минимум?","optsr":["CAT I","CAT II","CAT III","CAT 0"],"rr":"CAT III — это минимальный рейтинг для измерений на стационарных установках, таких как распределительные щиты и ответвлённые цепи в коммерческих зданиях; CAT IV используется на сервисном вводе.","qs":"Al tomar mediciones de tensión en un tablero de distribución trifásico de 480 voltios dentro de un edificio comercial, ¿cuál clasificación de categoría de medición (CAT) deben tener como mínimo el multímetro digital y sus puntas?","optss":["CAT I","CAT II","CAT III","CAT 0"],"rs":"CAT III es la clasificación mínima para mediciones en instalaciones fijas como tableros de distribución y circuitos derivados en edificios comerciales; CAT IV se usa en la entrada de acometida."},
  {"id":466,"sec":"Rough Wiring","block":5,"q":"What is the minimum cover required for conductors in rigid metal conduit (RMC) buried directly in the earth, 0 to 1000 volts, per Table 300.5?","opts":["18 in","12 in","24 in","6 in"],"correct":3,"re":"Table 300.5 Column 2 requires 6 in of cover for rigid metal conduit and intermediate metal conduit.","qr":"Какое минимальное покрытие требуется для проводников в жёстком металлическом кабелепроводе (RMC), закопанном непосредственно в землю, 0–1000 вольт, согласно таблице 300.5?","optsr":["18 дюймов","12 дюймов","24 дюйма","6 дюймов"],"rr":"Таблица 300.5, столбец 2, требует 6 дюймов покрытия для жёсткого металлического кабелепровода и промежуточного металлического кабелепровода.","qs":"¿Cuál es la cobertura mínima requerida para conductores en conduit metálico rígido (RMC) enterrados directamente en la tierra, de 0 a 1000 voltios, según la Tabla 300.5?","optss":["18 in","12 in","24 in","6 in"],"rs":"La Columna 2 de la Tabla 300.5 requiere 6 in de cobertura para conduit metálico rígido y conduit metálico intermedio."},
  {"id":467,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"A key advantage of thermal imaging during electrical maintenance is that it allows the technician to:","opts":["De-energize equipment before inspection","Detect overheating connections without contact while the system is under load","Measure exact circuit resistance values","Replace the need for torque specifications"],"correct":1,"re":"Infrared thermography finds abnormal heat from loose or failing connections on energized, loaded equipment without physical contact, enabling early intervention.","qr":"Ключевое преимущество тепловизионной съёмки при электрическом обслуживании в том, что она позволяет технику:","optsr":["Обесточивать оборудование перед осмотром","Обнаруживать перегрев соединений бесконтактно, пока система под нагрузкой","Измерять точные значения сопротивления цепи","Заменить необходимость в спецификациях момента затяжки"],"rr":"Инфракрасная термография находит аномальное тепло от ослабленных или отказывающих соединений на работающем нагруженном оборудовании без физического контакта, обеспечивая раннее вмешательство.","qs":"Una ventaja clave de la imagen térmica durante el mantenimiento eléctrico es que permite al técnico:","optss":["Desenergizar el equipo antes de la inspección","Detectar conexiones sobrecalentadas sin contacto mientras el sistema está bajo carga","Medir valores exactos de resistencia del circuito","Reemplazar la necesidad de especificaciones de torque"],"rs":"La termografía infrarroja encuentra calor anormal por conexiones flojas o defectuosas en equipos energizados y cargados sin contacto físico, lo que permite una intervención temprana."},
  {"id":468,"sec":"Planning & Estimation","block":5,"q":"To reduce voltage drop on a long branch circuit without changing the load or length, what is the most direct method?","opts":["Increase the OCPD rating","Decrease the conductor size","Increase the conductor size","Use a smaller conduit"],"correct":2,"re":"Increasing conductor size (larger circular-mil area) lowers resistance and therefore reduces voltage drop.","qr":"Чтобы уменьшить падение напряжения на длинном ответвлении без изменения нагрузки или длины, какой самый прямой метод?","optsr":["Увеличить номинал OCPD","Уменьшить сечение проводника","Увеличить сечение проводника","Использовать меньший кабелепровод"],"rr":"Увеличение сечения проводника (большая площадь в круговых милах) снижает сопротивление и, следовательно, уменьшает падение напряжения.","qs":"Para reducir la caída de tensión en un circuito derivado largo sin cambiar la carga ni la longitud, ¿cuál es el método más directo?","optss":["Aumentar la clasificación del OCPD","Disminuir el tamaño del conductor","Aumentar el tamaño del conductor","Usar un conduit más pequeño"],"rs":"Aumentar el tamaño del conductor (mayor área en mils circulares) reduce la resistencia y, por lo tanto, disminuye la caída de tensión."},
  {"id":469,"sec":"Safety","block":5,"q":"An electrician needs to measure voltage at the line side of the main service disconnect of a commercial building; which CAT rating is most appropriate for the meter at this location?","opts":["CAT I","CAT II","CAT IV","CAT III"],"correct":2,"re":"CAT IV is intended for measurements at the origin of the installation, such as the service entrance and line side of the main disconnect, where available fault energy is highest.","qr":"Электрику необходимо измерить напряжение на линейной стороне главного сервисного отключающего устройства коммерческого здания; какой рейтинг CAT наиболее подходит для прибора в этом месте?","optsr":["CAT I","CAT II","CAT IV","CAT III"],"rr":"CAT IV предназначен для измерений в начале установки, таких как сервисный ввод и линейная сторона главного отключающего устройства, где доступная энергия короткого замыкания наибольшая.","qs":"Un electricista necesita medir la tensión en el lado de línea de la desconexión principal de acometida de un edificio comercial; ¿cuál clasificación CAT es la más apropiada para el medidor en esta ubicación?","optss":["CAT I","CAT II","CAT IV","CAT III"],"rs":"CAT IV está destinada para mediciones en el origen de la instalación, como la entrada de acometida y el lado de línea de la desconexión principal, donde la energía de falla disponible es más alta."},
  {"id":470,"sec":"Finish Wiring & Trim","block":5,"q":"The push-in 'back-wire' holes on the back of many 15-amp residential receptacles are generally limited to conductors of what size?","opts":["12 AWG solid only","14 AWG solid only","10 AWG stranded","8 AWG solid"],"correct":1,"re":"The screwless push-in (back-wire) terminals on standard 15-amp receptacles are typically listed for 14 AWG solid copper only; larger conductors must use the screw terminals.","qr":"Отверстия для безвинтового подключения ('back-wire') на задней стороне многих бытовых розеток 15 А, как правило, ограничены проводниками какого сечения?","optsr":["Только 12 AWG однопроволочный","Только 14 AWG однопроволочный","10 AWG многопроволочный","8 AWG однопроволочный"],"rr":"Безвинтовые контакты push-in ('back-wire') на стандартных розетках 15 А обычно сертифицированы только для 14 AWG однопроволочного медного; более крупные проводники должны использовать винтовые клеммы.","qs":"Los orificios de inserción 'back-wire' en la parte posterior de muchos tomacorrientes residenciales de 15 amperios están generalmente limitados a conductores de qué tamaño?","optss":["Solo 12 AWG sólido","Solo 14 AWG sólido","10 AWG trenzado","8 AWG sólido"],"rs":"Las terminales de inserción sin tornillo (back-wire) en los tomacorrientes estándar de 15 amperios están típicamente listadas solo para 14 AWG de cobre sólido; los conductores más grandes deben usar las terminales de tornillo."},
  {"id":471,"sec":"Rough Wiring","block":5,"q":"Direct-buried conductors and cables emerging from grade must be protected by an enclosure or raceway extending from the required cover depth up to at least what height above finished grade?","opts":["4 ft","6 ft","8 ft","3 ft"],"correct":2,"re":"NEC 300.5(D)(1) requires protection from the required cover depth to at least 8 ft above finished grade.","qr":"Проводники и кабели прямого заложения, выходящие из грунта, должны быть защищены корпусом или кабелепроводом, простирающимся от требуемой глубины покрытия вверх как минимум до какой высоты над законченным уровнем грунта?","optsr":["4 фута","6 футов","8 футов","3 фута"],"rr":"NEC 300.5(D)(1) требует защиты от требуемой глубины покрытия до не менее 8 футов над законченным уровнем грунта.","qs":"Los conductores y cables enterrados directamente que emergen del nivel del suelo deben protegerse con un gabinete o canalización que se extienda desde la profundidad de cobertura requerida hasta al menos qué altura sobre el nivel terminado?","optss":["4 ft","6 ft","8 ft","3 ft"],"rs":"El NEC 300.5(D)(1) requiere protección desde la profundidad de cobertura requerida hasta al menos 8 ft sobre el nivel terminado."},
  {"id":472,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"To isolate whether a tripping breaker is caused by a wiring fault or by a connected appliance, a sound troubleshooting step is to:","opts":["Disconnect all loads and reset; if it holds, reconnect loads one at a time","Increase the breaker rating and retest","Replace the neutral bus","Bridge the breaker with a jumper"],"correct":0,"re":"Disconnecting loads and reconnecting them one at a time logically narrows the fault to either the wiring or a specific device, following a systematic isolation method.","qr":"Чтобы определить, вызвано ли срабатывание автомата неисправностью проводки или подключённым прибором, разумный шаг поиска неисправности:","optsr":["Отключить все нагрузки и сбросить; если держит, подключать нагрузки по одной","Увеличить номинал автомата и повторить проверку","Заменить нейтральную шину","Замкнуть автомат перемычкой"],"rr":"Отключение нагрузок и их подключение по одной логически сужает неисправность до проводки или конкретного устройства, следуя систематическому методу изоляции.","qs":"Para aislar si un interruptor que se dispara es causado por una falla de cableado o por un electrodoméstico conectado, un paso de diagnóstico acertado es:","optss":["Desconectar todas las cargas y reiniciar; si se mantiene, reconectar las cargas una a la vez","Aumentar la clasificación del interruptor y volver a probar","Reemplazar el bus de neutro","Puentear el interruptor con un cable"],"rs":"Desconectar las cargas y reconectarlas una a la vez reduce lógicamente la falla ya sea al cableado o a un dispositivo específico, siguiendo un método sistemático de aislamiento."},
  {"id":473,"sec":"Planning & Estimation","block":5,"q":"A continuous load of 30 A is fed by conductors terminating at 75°C equipment; what minimum copper conductor size is required from the 75°C column of Table 310.16 to carry 125% of the load?","opts":["6 AWG","4 AWG","8 AWG","10 AWG"],"correct":2,"re":"30 A × 1.25 = 37.5 A; in the 75°C column, 8 AWG copper (50 A) is the smallest conductor that meets this, since 10 AWG is only 35 A.","qr":"Непрерывная нагрузка 30 A питается проводниками, оканчивающимися на оборудовании 75°C; какое минимальное сечение медного проводника требуется из колонки 75°C таблицы 310.16, чтобы нести 125% нагрузки?","optsr":["6 AWG","4 AWG","8 AWG","10 AWG"],"rr":"30 A × 1,25 = 37,5 A; в колонке 75°C медь 8 AWG (50 A) — наименьший проводник, отвечающий этому, так как 10 AWG всего 35 A.","qs":"Una carga continua de 30 A es alimentada por conductores que terminan en equipo de 75°C; ¿qué tamaño mínimo de conductor de cobre se requiere de la columna de 75°C de la Tabla 310.16 para transportar el 125% de la carga?","optss":["6 AWG","4 AWG","8 AWG","10 AWG"],"rs":"30 A × 1.25 = 37.5 A; en la columna de 75°C, el cobre de 8 AWG (50 A) es el conductor más pequeño que cumple con esto, ya que el 10 AWG es solo 35 A."},
  {"id":474,"sec":"Safety","block":5,"q":"Regarding measurement category ratings, why can a meter rated CAT III 600 V be safer than a meter rated CAT II 1000 V when measuring at a distribution panel?","opts":["The CAT II meter cannot physically read 600 volts","The steady-state voltage rating is the only factor that matters for safety","CAT II always means a higher-quality meter","The CAT III rating reflects a higher transient-overvoltage withstand for that location, which matters more than the steady-state voltage number"],"correct":3,"re":"The CAT rating reflects the meter's ability to withstand transient overvoltages and available fault energy at a given location; a higher CAT number suited to the location is more protective than a higher steady-state voltage rating at a lower category.","qr":"Что касается рейтингов категории измерений, почему прибор с рейтингом CAT III 600 В может быть безопаснее прибора с рейтингом CAT II 1000 В при измерении на распределительном щите?","optsr":["Прибор CAT II физически не может считывать 600 вольт","Рейтинг установившегося напряжения — единственный фактор, важный для безопасности","CAT II всегда означает прибор более высокого качества","Рейтинг CAT III отражает более высокую устойчивость к переходным перенапряжениям для данного места, что важнее, чем значение установившегося напряжения"],"rr":"Рейтинг CAT отражает способность прибора выдерживать переходные перенапряжения и доступную энергию короткого замыкания в данном месте; более высокий номер CAT, подходящий для места, более защищает, чем более высокий рейтинг установившегося напряжения при более низкой категории.","qs":"Con respecto a las clasificaciones de categoría de medición, ¿por qué un medidor clasificado CAT III 600 V puede ser más seguro que un medidor clasificado CAT II 1000 V al medir en un tablero de distribución?","optss":["El medidor CAT II no puede leer físicamente 600 voltios","La clasificación de tensión en estado estable es el único factor que importa para la seguridad","CAT II siempre significa un medidor de mayor calidad","La clasificación CAT III refleja una mayor resistencia a sobretensiones transitorias para esa ubicación, lo cual importa más que el número de tensión en estado estable"],"rs":"La clasificación CAT refleja la capacidad del medidor para resistir sobretensiones transitorias y la energía de falla disponible en una ubicación dada; un número CAT más alto adecuado para la ubicación es más protector que una clasificación de tensión en estado estable más alta en una categoría inferior."},
  {"id":475,"sec":"Rough Wiring","block":5,"q":"When a direct-buried cable is installed under a building, it must be:","opts":["Buried at 36 in regardless","Installed in a raceway","Left without any protection","Spliced every 10 ft"],"correct":1,"re":"Table 300.5 and 300.5(C) require cables routed under a building to be installed in a raceway extending beyond the building.","qr":"Когда кабель прямого заложения проложен под зданием, он должен быть:","optsr":["Закопан на 36 дюймов в любом случае","Проложен в кабелепроводе","Оставлен без какой-либо защиты","Соединён через каждые 10 футов"],"rr":"Таблица 300.5 и 300.5(C) требуют, чтобы кабели, проходящие под зданием, прокладывались в кабелепроводе, выходящем за пределы здания.","qs":"Cuando un cable enterrado directamente se instala debajo de un edificio, debe estar:","optss":["Enterrado a 36 in sin importar nada","Instalado en una canalización","Dejado sin ninguna protección","Empalmado cada 10 ft"],"rs":"La Tabla 300.5 y 300.5(C) requieren que los cables que pasan debajo de un edificio se instalen en una canalización que se extienda más allá del edificio."},
  {"id":476,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Reading 240 volts across the two ungrounded legs but only 95 volts on one leg to neutral and 145 volts on the other leg to neutral in a multiwire circuit indicates:","opts":["A normal balanced condition","A short circuit between the legs","An open or lost neutral causing unequal voltage division","A failed GFCI device"],"correct":2,"re":"Total line-to-line voltage is correct, but the unequal line-to-neutral readings that still sum to 240 V reveal an open neutral letting voltage divide by load impedance.","qr":"Показание 240 вольт между двумя незаземлёнными линиями, но только 95 вольт на одной линии относительно нейтрали и 145 вольт на другой линии относительно нейтрали в многопроводной цепи указывает на:","optsr":["Нормальное сбалансированное состояние","Короткое замыкание между линиями","Обрыв или потерю нейтрали, вызывающие неравное деление напряжения","Неисправное устройство GFCI"],"rr":"Полное междулинейное напряжение в норме, но неравные показания линия–нейтраль, которые в сумме дают 240 В, выявляют обрыв нейтрали, при котором напряжение делится по импедансу нагрузки.","qs":"Leer 240 voltios entre las dos patas no aterrizadas pero solo 95 voltios en una pata a neutro y 145 voltios en la otra pata a neutro en un circuito multiconductor indica:","optss":["Una condición balanceada normal","Un cortocircuito entre las patas","Un neutro abierto o perdido que causa una división de tensión desigual","Un dispositivo GFCI defectuoso"],"rs":"La tensión total de línea a línea es correcta, pero las lecturas desiguales de línea a neutro que aún suman 240 V revelan un neutro abierto que permite que la tensión se divida según la impedancia de la carga."},
  {"id":477,"sec":"Planning & Estimation","block":5,"q":"When the ampacity of a conductor does not correspond to a standard OCPD rating and the circuit is not a multioutlet receptacle branch circuit, NEC 240.4(B) permits what action for ratings of 800 A or less?","opts":["Use the next lower standard OCPD only","Round the ampacity to the nearest 5 A","Use the next higher standard OCPD","No OCPD adjustment is allowed"],"correct":2,"re":"NEC 240.4(B) allows the next higher standard OCPD rating when the conductor ampacity does not match a standard size, subject to the 800 A limit and other conditions.","qr":"Когда ампацитета проводника не соответствует стандартному номиналу OCPD, а цепь не является многоточечной розеточной цепью, NEC 240.4(B) разрешает какое действие для номиналов 800 A или менее?","optsr":["Использовать только следующий меньший стандартный OCPD","Округлить ампацитету до ближайших 5 A","Использовать следующий больший стандартный OCPD","Корректировка OCPD не допускается"],"rr":"NEC 240.4(B) позволяет использовать следующий больший стандартный номинал OCPD, когда ампацитета проводника не совпадает со стандартным, с учётом предела 800 A и других условий.","qs":"Cuando la ampacidad de un conductor no corresponde a una clasificación de OCPD estándar y el circuito no es un circuito derivado de tomacorrientes de múltiples salidas, el NEC 240.4(B) permite qué acción para clasificaciones de 800 A o menos?","optss":["Usar solo el siguiente OCPD estándar inferior","Redondear la ampacidad a los 5 A más cercanos","Usar el siguiente OCPD estándar superior","No se permite ajuste de OCPD"],"rs":"El NEC 240.4(B) permite la siguiente clasificación de OCPD estándar superior cuando la ampacidad del conductor no coincide con un tamaño estándar, sujeto al límite de 800 A y otras condiciones."},
  {"id":478,"sec":"Rough Wiring","block":5,"q":"A warning ribbon placed in the trench above an underground service is generally required to be located at least how far above the conductors?","opts":["12 in above the underground installation","Directly on top of the conductors","At the surface only","24 in above the conductors"],"correct":0,"re":"NEC 300.5(D)(3) requires a warning ribbon at least 12 in above underground service conductors not encased in concrete.","qr":"Предупреждающая лента, помещённая в траншею над подземным вводом, как правило, должна располагаться не менее чем на какой высоте над проводниками?","optsr":["На 12 дюймов выше подземной установки","Непосредственно поверх проводников","Только на поверхности","На 24 дюйма выше проводников"],"rr":"NEC 300.5(D)(3) требует предупреждающую ленту не менее чем на 12 дюймов выше подземных вводных проводников, не заключённых в бетон.","qs":"Una cinta de advertencia colocada en la zanja sobre una acometida subterránea generalmente debe ubicarse al menos a qué distancia por encima de los conductores?","optss":["12 in por encima de la instalación subterránea","Directamente sobre los conductores","Solo en la superficie","24 in por encima de los conductores"],"rs":"El NEC 300.5(D)(3) requiere una cinta de advertencia al menos 12 in por encima de los conductores de acometida subterráneos no encapsulados en concreto."},
  {"id":479,"sec":"Finish Wiring & Trim","block":5,"q":"When looping a solid conductor under a binding screw of a device, the loop should be formed so that it wraps around the screw in which direction?","opts":["Counterclockwise","Clockwise, the direction the screw tightens","Straight across without a loop","It does not matter"],"correct":1,"re":"A conductor loop should be wrapped clockwise (the tightening direction) around the binding screw so the screw draws the wire in rather than pushing it out as it is tightened.","qr":"При намотке однопроволочного проводника под зажимной винт устройства петля должна формироваться так, чтобы она оборачивалась вокруг винта в каком направлении?","optsr":["Против часовой стрелки","По часовой стрелке, в направлении затяжки винта","Прямо поперёк без петли","Это не имеет значения"],"rr":"Петля проводника должна оборачиваться по часовой стрелке (в направлении затяжки) вокруг зажимного винта, чтобы винт втягивал провод внутрь, а не выталкивал его при затяжке.","qs":"Al enlazar un conductor sólido bajo el tornillo de sujeción de un dispositivo, el lazo debe formarse de modo que envuelva el tornillo en cuál dirección?","optss":["En sentido antihorario","En sentido horario, la dirección en que se aprieta el tornillo","Recto sin formar un lazo","No importa"],"rs":"Un lazo de conductor debe envolverse en sentido horario (la dirección de apriete) alrededor del tornillo de sujeción para que el tornillo atraiga el cable hacia adentro en lugar de empujarlo hacia afuera al apretarse."},
  {"id":480,"sec":"Safety","block":5,"q":"Before using a digital multimeter to verify that a circuit is de-energized as part of a lockout/tagout procedure, what is the best practice to confirm the meter itself is functioning?","opts":["Tap the meter on a hard surface to reset it","Assume the meter works if its display powered on","Read the meter only once on the suspected dead circuit","Use the live-dead-live test by checking a known live source before and after the measurement"],"correct":3,"re":"The live-dead-live (test-before-touch) method confirms the meter reads a known energized source, then the suspected dead circuit, then the live source again to verify the meter did not fail during the test.","qr":"Перед использованием цифрового мультиметра для проверки обесточенности цепи в рамках процедуры блокировки/маркировки, какова наилучшая практика для подтверждения исправности самого прибора?","optsr":["Постучать прибором по твёрдой поверхности для сброса","Предположить, что прибор работает, если его дисплей включился","Считать показания прибора только один раз на предполагаемо обесточенной цепи","Использовать тест «живой-мёртвый-живой», проверяя известный источник под напряжением до и после измерения"],"rr":"Метод «живой-мёртвый-живой» (проверка перед прикосновением) подтверждает, что прибор считывает известный источник под напряжением, затем предполагаемо обесточенную цепь, затем снова источник под напряжением, чтобы убедиться, что прибор не вышел из строя во время теста.","qs":"Antes de usar un multímetro digital para verificar que un circuito está desenergizado como parte de un procedimiento de bloqueo/etiquetado (lockout/tagout), ¿cuál es la mejor práctica para confirmar que el propio medidor está funcionando?","optss":["Golpear el medidor sobre una superficie dura para reiniciarlo","Asumir que el medidor funciona si su pantalla se encendió","Leer el medidor solo una vez en el circuito presuntamente sin tensión","Usar la prueba vivo-muerto-vivo, verificando una fuente viva conocida antes y después de la medición"],"rs":"El método vivo-muerto-vivo (probar antes de tocar) confirma que el medidor lee una fuente energizada conocida, luego el circuito presuntamente sin tensión, y luego la fuente viva nuevamente para verificar que el medidor no falló durante la prueba."},
  {"id":481,"sec":"Planning & Estimation","block":5,"q":"A box contains four 12 AWG conductors and two 14 AWG conductors with no devices or clamps; what total box volume is required per NEC 314.16(B)?","opts":["11.0 in³","13.0 in³","13.5 in³","15.0 in³"],"correct":1,"re":"Four 12 AWG at 2.25 = 9.0 in³ plus two 14 AWG at 2.00 = 4.0 in³, totaling 13.0 cubic inches.","qr":"Коробка содержит четыре проводника 12 AWG и два проводника 14 AWG без устройств и зажимов; какой общий объём коробки требуется по NEC 314.16(B)?","optsr":["11,0 куб. дюйма","13,0 куб. дюйма","13,5 куб. дюйма","15,0 куб. дюйма"],"rr":"Четыре 12 AWG по 2,25 = 9,0 куб. дюйма плюс два 14 AWG по 2,00 = 4,0 куб. дюйма, итого 13,0 кубических дюйма.","qs":"Una caja contiene cuatro conductores de 12 AWG y dos conductores de 14 AWG sin dispositivos ni abrazaderas; ¿qué volumen total de caja se requiere según el NEC 314.16(B)?","optss":["11.0 in³","13.0 in³","13.5 in³","15.0 in³"],"rs":"Cuatro de 12 AWG a 2.25 = 9.0 in³ más dos de 14 AWG a 2.00 = 4.0 in³, sumando 13.0 pulgadas cúbicas."},
  {"id":482,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"Manufacturers recommend that GFCI and AFCI devices be tested using their test buttons how often as a maintenance practice?","opts":["Only once at installation","Only when a fault occurs","Periodically, such as monthly","Never, since they are maintenance-free"],"correct":2,"re":"Because these protective devices can fail silently, manufacturers commonly advise testing the TEST button periodically, typically monthly, to confirm protection remains functional.","qr":"Производители рекомендуют тестировать устройства GFCI и AFCI с помощью их кнопок тестирования как часто в рамках обслуживания?","optsr":["Только один раз при установке","Только при возникновении неисправности","Периодически, например ежемесячно","Никогда, так как они не требуют обслуживания"],"rr":"Поскольку эти защитные устройства могут отказать незаметно, производители обычно советуют периодически, как правило ежемесячно, нажимать кнопку TEST, чтобы убедиться, что защита остаётся работоспособной.","qs":"Los fabricantes recomiendan que los dispositivos GFCI y AFCI se prueben usando sus botones de prueba con qué frecuencia como práctica de mantenimiento?","optss":["Solo una vez en la instalación","Solo cuando ocurre una falla","Periódicamente, como mensualmente","Nunca, ya que no requieren mantenimiento"],"rs":"Debido a que estos dispositivos protectores pueden fallar de forma silenciosa, los fabricantes comúnmente recomiendan probar el botón TEST periódicamente, típicamente cada mes, para confirmar que la protección sigue siendo funcional."},
  {"id":483,"sec":"Rough Wiring","block":5,"q":"Where an underground raceway enters a building or stub-up, the open end must be:","opts":["Left fully open for ventilation","Sealed to prevent the entrance of moisture","Filled with concrete","Capped with tape only"],"correct":1,"re":"NEC 300.5(G) requires raceways and conductor ends to be sealed to prevent moisture or gases from entering.","qr":"Когда подземный кабелепровод входит в здание или выходит вертикально вверх, открытый конец должен быть:","optsr":["Оставлен полностью открытым для вентиляции","Загерметизирован для предотвращения проникновения влаги","Заполнен бетоном","Закрыт только лентой"],"rr":"NEC 300.5(G) требует герметизации концов кабелепроводов и проводников для предотвращения проникновения влаги или газов.","qs":"Donde una canalización subterránea entra a un edificio o sube a la superficie (stub-up), el extremo abierto debe estar:","optss":["Dejado completamente abierto para ventilación","Sellado para prevenir la entrada de humedad","Llenado con concreto","Tapado solo con cinta"],"rs":"El NEC 300.5(G) requiere que las canalizaciones y los extremos de los conductores se sellen para prevenir la entrada de humedad o gases."},
  {"id":484,"sec":"Safety","block":5,"q":"Which type of ladder should an electrician select when working near exposed energized electrical conductors or equipment?","opts":["A fiberglass ladder","An aluminum extension ladder","A steel platform ladder","A wet wooden ladder"],"correct":0,"re":"Fiberglass ladders are non-conductive and are the appropriate choice for electrical work near energized parts; metal ladders are conductive and should be avoided.","qr":"Какой тип лестницы должен выбрать электрик при работе вблизи открытых проводников или оборудования под напряжением?","optsr":["Стеклопластиковая лестница","Алюминиевая выдвижная лестница","Стальная платформенная лестница","Мокрая деревянная лестница"],"rr":"Стеклопластиковые лестницы непроводящие и являются подходящим выбором для электромонтажных работ вблизи частей под напряжением; металлические лестницы проводящие, и их следует избегать.","qs":"¿Qué tipo de escalera debe seleccionar un electricista al trabajar cerca de conductores o equipos eléctricos energizados expuestos?","optss":["Una escalera de fibra de vidrio","Una escalera de extensión de aluminio","Una escalera de plataforma de acero","Una escalera de madera mojada"],"rs":"Las escaleras de fibra de vidrio son no conductoras y son la opción apropiada para trabajo eléctrico cerca de partes energizadas; las escaleras metálicas son conductoras y deben evitarse."},
  {"id":485,"sec":"Planning & Estimation","block":5,"q":"Per NEC 240.6(A), which sequence correctly lists three consecutive standard fuse/breaker ampere ratings?","opts":["30, 40, 50","30, 35, 40","40, 45, 50","50, 55, 60"],"correct":0,"re":"Standard ratings in NEC 240.6(A) include 30, 40, and 50 A consecutively; 55 A is not standard, so 50/55/60 is invalid.","qr":"Согласно NEC 240.6(A), какая последовательность правильно перечисляет три последовательных стандартных номинала предохранителя/выключателя?","optsr":["30, 40, 50","30, 35, 40","40, 45, 50","50, 55, 60"],"rr":"Стандартные номиналы в NEC 240.6(A) включают 30, 40 и 50 A подряд; 55 A не стандартен, поэтому 50/55/60 неверно.","qs":"Según el NEC 240.6(A), ¿cuál secuencia enumera correctamente tres clasificaciones de amperios estándar consecutivas de fusible/interruptor?","optss":["30, 40, 50","30, 35, 40","40, 45, 50","50, 55, 60"],"rs":"Las clasificaciones estándar en el NEC 240.6(A) incluyen 30, 40 y 50 A de forma consecutiva; 55 A no es estándar, por lo que 50/55/60 es inválido."},
  {"id":486,"sec":"Rough Wiring","block":5,"q":"When roughing in a service mast used to support service-drop conductors, the mast and its attachments must be:","opts":["No larger than 1/2 in conduit","Made of plastic only","Of adequate strength to withstand the conductor strain","Limited to interior use"],"correct":2,"re":"NEC 230.28 requires the service mast to have adequate strength or be supported to withstand the strain of the service-drop conductors.","qr":"При черновом монтаже вводной мачты, используемой для поддержки проводников воздушного ввода, мачта и её крепления должны быть:","optsr":["Не больше кабелепровода 1/2 дюйма","Изготовлены только из пластика","Достаточной прочности, чтобы выдержать натяжение проводников","Ограничены внутренним использованием"],"rr":"NEC 230.28 требует, чтобы вводная мачта имела достаточную прочность или была закреплена так, чтобы выдержать натяжение проводников воздушного ввода.","qs":"Al hacer el armado (rough-in) de un mástil de acometida utilizado para soportar los conductores de acometida aérea, el mástil y sus accesorios deben ser:","optss":["No mayores que un conduit de 1/2 in","Hechos solo de plástico","De resistencia adecuada para soportar la tensión de los conductores","Limitados a uso interior"],"rs":"El NEC 230.28 requiere que el mástil de acometida tenga resistencia adecuada o esté soportado para resistir la tensión de los conductores de acometida aérea."},
  {"id":487,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"A circuit feels warm at the breaker and the breaker trips after long runtime, yet a short-circuit test shows no bolted fault; this combination best fits which diagnosis?","opts":["An overload, possibly worsened by a loose connection adding heat","A dead short to ground","A failed AFCI sensor only","An open circuit"],"correct":0,"re":"Heat building over runtime with delayed tripping and no bolted short points to overload conditions, and a loose connection can add resistive heating that accelerates the trip.","qr":"Цепь тёплая у автомата, и автомат срабатывает после долгой работы, но проверка на короткое замыкание не показывает глухой неисправности; такое сочетание лучше всего соответствует какому диагнозу?","optsr":["Перегрузке, возможно усугублённой ослабленным соединением, добавляющим нагрев","Глухому замыканию на землю","Только неисправному датчику AFCI","Обрыву цепи"],"rr":"Нагрев со временем работы при задержанном срабатывании и отсутствии глухого замыкания указывает на перегрузку, а ослабленное соединение может добавить резистивный нагрев, ускоряющий срабатывание.","qs":"Un circuito se siente caliente en el interruptor y el interruptor se dispara después de un tiempo de funcionamiento prolongado, pero una prueba de cortocircuito no muestra falla atornillada; esta combinación se ajusta mejor a cuál diagnóstico?","optss":["Una sobrecarga, posiblemente empeorada por una conexión floja que agrega calor","Un cortocircuito directo a tierra","Solo un sensor AFCI defectuoso","Un circuito abierto"],"rs":"El calor que se acumula con el tiempo de funcionamiento, con disparo retardado y sin cortocircuito atornillado, apunta a condiciones de sobrecarga, y una conexión floja puede agregar calentamiento resistivo que acelera el disparo."},
  {"id":488,"sec":"Finish Wiring & Trim","block":5,"q":"In a standard 120-volt branch circuit using NM cable, what is the required color of the equipment grounding conductor?","opts":["White or gray","Black or red","Green, green with a yellow stripe, or bare","Blue or yellow"],"correct":2,"re":"Per NEC 250.119, equipment grounding conductors must be green, green with one or more yellow stripes, or bare; white/gray is reserved for the grounded (neutral) conductor.","qr":"В стандартной ответвлённой цепи на 120 вольт с использованием кабеля NM какого цвета должен быть заземляющий проводник оборудования (EGC)?","optsr":["Белый или серый","Чёрный или красный","Зелёный, зелёный с жёлтой полосой или неизолированный","Синий или жёлтый"],"rr":"Согласно NEC 250.119, заземляющие проводники оборудования должны быть зелёными, зелёными с одной или несколькими жёлтыми полосами или неизолированными; белый/серый зарезервирован для заземлённого (нейтрального) проводника.","qs":"En un circuito derivado estándar de 120 voltios que usa cable NM, ¿cuál es el color requerido del conductor de puesta a tierra de equipos?","optss":["Blanco o gris","Negro o rojo","Verde, verde con franja amarilla, o desnudo","Azul o amarillo"],"rs":"Según el NEC 250.119, los conductores de puesta a tierra de equipos deben ser verdes, verdes con una o más franjas amarillas, o desnudos; el blanco/gris está reservado para el conductor puesto a tierra (neutro)."},
  {"id":489,"sec":"Safety","block":5,"q":"Following the 4-to-1 rule for a straight or extension ladder, where should the base be placed if the ladder contacts the wall at a point 12 feet up?","opts":["1 foot away from the wall","3 feet away from the wall","6 feet away from the wall","12 feet away from the wall"],"correct":1,"re":"The 4-to-1 rule places the base 1 foot away from the wall for every 4 feet of working height; 12 feet divided by 4 equals 3 feet from the wall.","qr":"Следуя правилу 4 к 1 для прямой или выдвижной лестницы, где должно быть размещено основание, если лестница касается стены в точке на высоте 12 футов?","optsr":["1 фут от стены","3 фута от стены","6 футов от стены","12 футов от стены"],"rr":"Правило 4 к 1 размещает основание на расстоянии 1 фута от стены на каждые 4 фута рабочей высоты; 12 футов, делённые на 4, равны 3 футам от стены.","qs":"Siguiendo la regla 4 a 1 para una escalera recta o de extensión, ¿dónde debe colocarse la base si la escalera toca la pared en un punto a 12 pies de altura?","optss":["1 pie de distancia de la pared","3 pies de distancia de la pared","6 pies de distancia de la pared","12 pies de distancia de la pared"],"rs":"La regla 4 a 1 coloca la base a 1 pie de distancia de la pared por cada 4 pies de altura de trabajo; 12 pies dividido entre 4 es igual a 3 pies de la pared."},
  {"id":490,"sec":"Rough Wiring","block":5,"q":"Only which of the following may be attached to a service mast?","opts":["Television antennas","Clothesline hardware","Communication cables","Service-drop or overhead service conductors"],"correct":3,"re":"NEC 230.28(B) permits only service-drop or overhead service conductors to be attached to the service mast.","qr":"Только что из следующего может быть прикреплено к вводной мачте?","optsr":["Телевизионные антенны","Фурнитура для бельевой верёвки","Кабели связи","Проводники воздушного ввода или верхнего ввода"],"rr":"NEC 230.28(B) разрешает прикреплять к вводной мачте только проводники воздушного ввода или верхнего ввода.","qs":"¿Solo cuál de los siguientes puede fijarse a un mástil de acometida?","optss":["Antenas de televisión","Herrajes de tendedero","Cables de comunicación","Conductores de acometida aérea"],"rs":"El NEC 230.28(B) permite que solo se fijen al mástil de acometida los conductores de acometida aérea."},
  {"id":491,"sec":"Planning & Estimation","block":5,"q":"A branch circuit serves a 12 A continuous load plus an 8 A noncontinuous load; what minimum OCPD rating is required?","opts":["25 A","23 A","20 A","30 A"],"correct":0,"re":"Per NEC 210.20(A), OCPD ≥ (12 A × 1.25) + 8 A = 23 A, and the next standard size is 25 A.","qr":"Ответвление обслуживает непрерывную нагрузку 12 A плюс непостоянную нагрузку 8 A; какой минимальный номинал OCPD требуется?","optsr":["25 A","23 A","20 A","30 A"],"rr":"Согласно NEC 210.20(A), OCPD ≥ (12 A × 1,25) + 8 A = 23 A, и следующий стандартный номинал — 25 A.","qs":"Un circuito derivado alimenta una carga continua de 12 A más una carga no continua de 8 A; ¿qué clasificación mínima de OCPD se requiere?","optss":["25 A","23 A","20 A","30 A"],"rs":"Según el NEC 210.20(A), OCPD ≥ (12 A × 1.25) + 8 A = 23 A, y el siguiente tamaño estándar es 25 A."},
  {"id":492,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"When a 120-volt circuit shows correct voltage with no load but voltage collapses far below normal the moment a load is applied, the fault most likely lies in:","opts":["A high-resistance (loose or corroded) connection in the supply path","The load device being undersized","The GFCI test button","The grounding electrode conductor"],"correct":0,"re":"Voltage that is normal at no load but sags badly under load indicates a high-resistance series connection that drops voltage only when current flows.","qr":"Когда цепь 120 вольт показывает правильное напряжение без нагрузки, но напряжение резко падает значительно ниже нормы в момент приложения нагрузки, неисправность наиболее вероятно в:","optsr":["Высокоомном (ослабленном или корродированном) соединении в питающем пути","Слишком малой мощности устройства нагрузки","Кнопке TEST устройства GFCI","Проводнике заземляющего электрода"],"rr":"Напряжение, нормальное без нагрузки, но сильно проседающее под нагрузкой, указывает на высокоомное последовательное соединение, которое снижает напряжение только при протекании тока.","qs":"Cuando un circuito de 120 voltios muestra la tensión correcta sin carga pero la tensión colapsa muy por debajo de lo normal en el momento en que se aplica una carga, la falla probablemente reside en:","optss":["Una conexión de alta resistencia (floja o corroída) en la trayectoria de alimentación","El dispositivo de carga está subdimensionado","El botón de prueba del GFCI","El conductor del electrodo de puesta a tierra"],"rs":"Una tensión que es normal sin carga pero que cae notablemente bajo carga indica una conexión en serie de alta resistencia que reduce la tensión solo cuando fluye corriente."},
  {"id":493,"sec":"Rough Wiring","block":5,"q":"What is the minimum vertical clearance for service-drop conductors passing over a residential driveway, where the voltage does not exceed 300 volts to ground?","opts":["10 ft","18 ft","15 ft","12 ft"],"correct":3,"re":"NEC 230.24(B) requires 12 ft of clearance over residential driveways and areas subject to vehicular traffic for circuits not exceeding 300 volts to ground.","qr":"Каков минимальный вертикальный зазор для проводников воздушного ввода, проходящих над жилой подъездной дорожкой, где напряжение не превышает 300 вольт относительно земли?","optsr":["10 футов","18 футов","15 футов","12 футов"],"rr":"NEC 230.24(B) требует зазор 12 футов над жилыми подъездными дорожками и зонами с автомобильным движением для цепей, не превышающих 300 вольт относительно земли.","qs":"¿Cuál es el espacio libre vertical mínimo para los conductores de acometida que pasan sobre una entrada de vehículos residencial, donde la tensión no excede 300 voltios a tierra?","optss":["10 ft","18 ft","15 ft","12 ft"],"rs":"El NEC 230.24(B) requiere 12 ft de espacio libre sobre entradas de vehículos residenciales y áreas sujetas a tráfico vehicular para circuitos que no exceden 300 voltios a tierra."},
  {"id":494,"sec":"Planning & Estimation","block":5,"q":"In voltage-drop calculations using the formula VD = 2 × K × I × L / CM, what does the variable 'CM' represent?","opts":["Conduit material","Conductor temperature in Celsius","Continuous-load multiplier","Circular mils of the conductor"],"correct":3,"re":"In the voltage-drop formula, CM is the conductor's cross-sectional area expressed in circular mils.","qr":"В расчётах падения напряжения по формуле VD = 2 × K × I × L / CM, что обозначает переменная 'CM'?","optsr":["Материал кабелепровода","Температуру проводника в Цельсиях","Множитель непрерывной нагрузки","Круговые милы проводника"],"rr":"В формуле падения напряжения CM — это площадь поперечного сечения проводника, выраженная в круговых милах.","qs":"En los cálculos de caída de tensión usando la fórmula VD = 2 × K × I × L / CM, ¿qué representa la variable 'CM'?","optss":["Material del conduit","Temperatura del conductor en Celsius","Multiplicador de carga continua","Mils circulares del conductor"],"rs":"En la fórmula de caída de tensión, CM es el área de la sección transversal del conductor expresada en mils circulares."},
  {"id":495,"sec":"Safety","block":5,"q":"Under the OSHA general industry standard (29 CFR 1910), at approximately what height above a lower level is fall protection generally required for workers on an elevated working surface?","opts":["2 feet","6 feet","4 feet","10 feet"],"correct":2,"re":"OSHA 29 CFR 1910.28 (general industry) generally requires fall protection at 4 feet above a lower level; the construction standard (1926) uses 6 feet.","qr":"Согласно стандарту OSHA для общей промышленности (29 CFR 1910), примерно на какой высоте над нижним уровнем обычно требуется защита от падения для работников на приподнятой рабочей поверхности?","optsr":["2 фута","6 футов","4 фута","10 футов"],"rr":"OSHA 29 CFR 1910.28 (общая промышленность) обычно требует защиту от падения на высоте 4 фута над нижним уровнем; строительный стандарт (1926) использует 6 футов.","qs":"Bajo la norma de industria general de OSHA (29 CFR 1910), ¿aproximadamente a qué altura sobre un nivel inferior se requiere generalmente protección contra caídas para trabajadores en una superficie de trabajo elevada?","optss":["2 pies","6 pies","4 pies","10 pies"],"rs":"OSHA 29 CFR 1910.28 (industria general) generalmente requiere protección contra caídas a 4 pies sobre un nivel inferior; la norma de construcción (1926) usa 6 pies."},
  {"id":496,"sec":"Startup, Troubleshooting & Maintenance","block":5,"q":"After verifying a symptom and gathering information, the next logical step in a structured troubleshooting process is to:","opts":["Form a hypothesis about the probable cause and test it","Replace random components until it works","Document the repair before testing","Energize the circuit and walk away"],"correct":0,"re":"Effective troubleshooting follows a logical sequence: observe the symptom, gather data, hypothesize the likely cause, then test to confirm before repairing.","qr":"После подтверждения симптома и сбора информации следующий логичный шаг в структурированном процессе поиска неисправности:","optsr":["Сформулировать гипотезу о вероятной причине и проверить её","Заменять случайные компоненты, пока не заработает","Задокументировать ремонт до проверки","Подать питание на цепь и уйти"],"rr":"Эффективный поиск неисправности следует логической последовательности: наблюдать симптом, собрать данные, выдвинуть гипотезу о вероятной причине, затем проверить её перед ремонтом.","qs":"Después de verificar un síntoma y recopilar información, el siguiente paso lógico en un proceso estructurado de diagnóstico es:","optss":["Formular una hipótesis sobre la causa probable y probarla","Reemplazar componentes al azar hasta que funcione","Documentar la reparación antes de probarla","Energizar el circuito y alejarse"],"rs":"El diagnóstico efectivo sigue una secuencia lógica: observar el síntoma, recopilar datos, plantear la hipótesis de la causa probable, y luego probar para confirmar antes de reparar."},
  {"id":497,"sec":"Finish Wiring & Trim","block":5,"q":"Which of the following best describes the primary protective function of a GFCI (ground-fault circuit interrupter) receptacle?","opts":["It protects equipment from overheating due to overload","It detects arcing faults in the branch-circuit wiring","It protects people from electric shock by detecting small current imbalances between the hot and neutral conductors","It limits voltage spikes from lightning or switching surges"],"correct":2,"re":"A GFCI compares current on the hot and neutral and trips at a small imbalance (about 4-6 mA), protecting people from shock; an AFCI detects arcing and a surge device handles voltage spikes (NEC 210.8).","qr":"Что из перечисленного лучше всего описывает основную защитную функцию розетки GFCI (устройства защитного отключения по току утечки на землю)?","optsr":["Она защищает оборудование от перегрева из-за перегрузки","Она обнаруживает дуговые замыкания в проводке ответвлённой цепи","Она защищает людей от поражения электрическим током, обнаруживая малый дисбаланс тока между фазным и нейтральным проводниками","Она ограничивает скачки напряжения от молнии или коммутационных перенапряжений"],"rr":"GFCI сравнивает ток в фазном и нейтральном проводниках и отключается при малом дисбалансе (около 4-6 мА), защищая людей от поражения током; AFCI обнаруживает дугу, а устройство защиты от перенапряжений справляется со скачками напряжения (NEC 210.8).","qs":"¿Cuál de las siguientes describe mejor la función protectora principal de un tomacorriente GFCI (interruptor de circuito por falla a tierra)?","optss":["Protege el equipo contra el sobrecalentamiento por sobrecarga","Detecta fallas de arqueo en el cableado del circuito derivado","Protege a las personas contra descargas eléctricas detectando pequeños desbalances de corriente entre los conductores vivo y neutro","Limita los picos de tensión de rayos o sobretensiones de conmutación"],"rs":"Un GFCI compara la corriente en el vivo y el neutro y se dispara ante un pequeño desbalance (aproximadamente 4-6 mA), protegiendo a las personas contra descargas; un AFCI detecta el arqueo y un dispositivo de sobretensión maneja los picos de tensión (NEC 210.8)."},
  {"id":498,"sec":"Rough Wiring","block":5,"q":"What is the minimum depth of clear working space required in front of electrical equipment likely to require examination while energized, under typical Condition 1 (600 volts or less), per 110.26?","opts":["2 ft","5 ft","4 ft","3 ft"],"correct":3,"re":"Table 110.26(A)(1) requires a minimum 3 ft (900 mm) of clear working depth under Condition 1.","qr":"Какова минимальная глубина свободного рабочего пространства, требуемая перед электрооборудованием, которое, вероятно, потребует осмотра под напряжением, при типичном Условии 1 (600 вольт или менее) согласно 110.26?","optsr":["2 фута","5 футов","4 фута","3 фута"],"rr":"Таблица 110.26(A)(1) требует минимум 3 фута (900 мм) свободной рабочей глубины при Условии 1.","qs":"¿Cuál es la profundidad mínima del espacio de trabajo despejado requerido frente a un equipo eléctrico que probablemente requiera examinación mientras está energizado, bajo la Condición 1 típica (600 voltios o menos), según 110.26?","optss":["2 ft","5 ft","4 ft","3 ft"],"rs":"La Tabla 110.26(A)(1) requiere un mínimo de 3 ft (900 mm) de profundidad de trabajo despejada bajo la Condición 1."},
  {"id":499,"sec":"Planning & Estimation","block":5,"q":"For an existing one-gang device box, which value must be known to perform a box-fill calculation when the box is not listed in NEC Table 314.16(A)?","opts":["The box color","The conduit trade size","The breaker rating","The marked cubic-inch volume of the box"],"correct":3,"re":"Per NEC 314.16(A), nonstandard boxes must be durably marked with their volume in cubic inches for use in the calculation.","qr":"Для существующей одногнёздной коробки устройства какое значение должно быть известно для расчёта заполнения коробки, когда коробка не указана в таблице NEC 314.16(A)?","optsr":["Цвет коробки","Типоразмер кабелепровода","Номинал автомата","Маркированный объём коробки в кубических дюймах"],"rr":"Согласно NEC 314.16(A), нестандартные коробки должны иметь долговечную маркировку их объёма в кубических дюймах для использования в расчёте.","qs":"Para una caja de dispositivo de un solo módulo existente, ¿cuál valor debe conocerse para realizar un cálculo de llenado de caja cuando la caja no está listada en la Tabla 314.16(A) del NEC?","optss":["El color de la caja","El tamaño comercial del conduit","La clasificación del interruptor","El volumen marcado en pulgadas cúbicas de la caja"],"rs":"Según el NEC 314.16(A), las cajas no estándar deben estar marcadas de forma duradera con su volumen en pulgadas cúbicas para su uso en el cálculo."},
  {"id":500,"sec":"Safety","block":5,"q":"Which combination of personal protective equipment is most appropriate when an electrician must perform an arc-flash-risk task such as racking a 480-volt breaker that cannot be de-energized?","opts":["Cotton T-shirt, standard sunglasses, and leather work gloves","Synthetic nylon jacket and latex examination gloves","Reflective vest, hard hat, and bare hands for better dexterity","Arc-rated clothing, a face shield or hood rated for the incident energy, and voltage-rated rubber gloves with leather protectors"],"correct":3,"re":"Energized work with arc-flash risk requires arc-rated clothing and face protection matched to the incident energy, plus voltage-rated rubber insulating gloves with leather protectors per NFPA 70E.","qr":"Какая комбинация средств индивидуальной защиты наиболее подходит, когда электрик должен выполнить задачу с риском дугового разряда, например установку выключателя 480 вольт, который нельзя обесточить?","optsr":["Хлопковая футболка, обычные солнцезащитные очки и кожаные рабочие перчатки","Синтетическая нейлоновая куртка и латексные смотровые перчатки","Светоотражающий жилет, каска и голые руки для лучшей ловкости","Дугостойкая одежда, лицевой щиток или капюшон, рассчитанный на энергию воздействия, и резиновые перчатки с рейтингом напряжения с кожаными защитными чехлами"],"rr":"Работа под напряжением с риском дугового разряда требует дугостойкой одежды и защиты лица, соответствующей энергии воздействия, а также резиновых изолирующих перчаток с рейтингом напряжения с кожаными защитными чехлами согласно NFPA 70E.","qs":"¿Cuál combinación de equipo de protección personal es la más apropiada cuando un electricista debe realizar una tarea con riesgo de arco eléctrico, como insertar (racking) un interruptor de 480 voltios que no puede desenergizarse?","optss":["Camiseta de algodón, gafas de sol estándar y guantes de trabajo de cuero","Chaqueta de nylon sintético y guantes de examinación de látex","Chaleco reflectante, casco y manos descubiertas para mejor destreza","Ropa con clasificación de arco, una careta o capucha clasificada para la energía incidente, y guantes de goma con clasificación de tensión con protectores de cuero"],"rs":"El trabajo energizado con riesgo de arco eléctrico requiere ropa con clasificación de arco y protección facial acordes a la energía incidente, además de guantes aislantes de goma con clasificación de tensión con protectores de cuero, según la NFPA 70E."}
];
